// ============================================================
// FEATURE 2: MANA SPENDING VALIDATION
// ============================================================

function canPayManaCost(manaCost, manaPool) {
  if (!manaCost || !manaPool) return false;
  var pool = { W: manaPool.W||0, U: manaPool.U||0, B: manaPool.B||0, R: manaPool.R||0, G: manaPool.G||0, C: manaPool.C||0 };
  var generic = 0;
  var tokens = manaCost.match(/\{[^}]+\}/g) || [];
  for (var i = 0; i < tokens.length; i++) {
    var sym = tokens[i].replace(/[{}]/g, '').toUpperCase();
    if (sym === 'W' || sym === 'U' || sym === 'B' || sym === 'R' || sym === 'G') {
      if (pool[sym] > 0) { pool[sym]--; }
      else { return false; }
    } else if (sym === 'C') {
      if (pool.C > 0) { pool.C--; }
      else { return false; }
    } else if (/^\d+$/.test(sym)) {
      generic += parseInt(sym, 10);
    } else if (sym === 'X') {
      // X costs — treat as 0 for castability display
    }
  }
  if (generic > 0) {
    var available = pool.W + pool.U + pool.B + pool.R + pool.G + pool.C;
    if (available < generic) return false;
  }
  return true;
}

function getManaPoolTotal(manaPool) {
  if (!manaPool) return 0;
  return (manaPool.W||0)+(manaPool.U||0)+(manaPool.B||0)+(manaPool.R||0)+(manaPool.G||0)+(manaPool.C||0);
}

function hexToRgba(hex, alpha) {
  if (!hex || hex.charAt(0) !== '#') return 'rgba(102,102,102,' + alpha + ')';
  let r, g, b;
  if (hex.length === 4) {
    r = parseInt(hex[1] + hex[1], 16);
    g = parseInt(hex[2] + hex[2], 16);
    b = parseInt(hex[3] + hex[3], 16);
  } else {
    r = parseInt(hex.substring(1, 3), 16);
    g = parseInt(hex.substring(3, 5), 16);
    b = parseInt(hex.substring(5, 7), 16);
  }
  return 'rgba(' + r + ',' + g + ',' + b + ',' + alpha + ')';
}

function createInitialState(playerCount, playerNames, startingLife) {
  const players = [];
  for (let i = 0; i < playerCount; i++) {
    const player = {
      id: i,
      name: playerNames[i] || `Player ${i + 1}`,
      color: PLAYER_COLORS[i],
      life: startingLife,
      startingLife,
      poison: 0,
      energy: 0,
      experience: 0,
      rad: 0,
      emblems: [],
      eliminated: false,
      commanderDamage: {}, // keyed by opponent player id
      zones: {
        graveyard: [],
        exile: [],
        command: [],
        hand: [],
        library: [],
      },
      manaPool: { W: 0, U: 0, B: 0, R: 0, G: 0, C: 0 },
      commanderCastCount: 0,
      commanderCardName: '',
      commanderCastCount2: 0,
      commanderCardName2: '',
    };
    // Initialize commander damage counters
    for (let j = 0; j < playerCount; j++) {
      if (j !== i) {
        player.commanderDamage[j] = 0;
      }
    }
    players.push(player);
  }

  return {
    players,
    currentPlayerIndex: 0,
    currentPhaseIndex: 0,
    inCombat: false,
    combatPhaseIndex: 0,
    turnNumber: 1,
    stormCount: 0,
    manaAutoClear: true,
    battlefieldCards: [],
    log: [],
    startingLife,
    triggerStack: [],
    triggersPaused: false,
    turnHistory: [],          // [{turnNumber, playerIndex, playerName, playerColor}]
    rulesEngine: {
      autoUntap: true,
      autoDraw: true,
      sbaChecks: true,
      enforceLandLimit: true,
      enforceHandSize: true,
      commanderTaxEnabled: true,
      commanderZoneReplacement: true,
      useStack: false,
      enforceTurnStructure: false,
      enforceColorIdentity: false,
      turnTimerEnabled: false,
      turnTimerMinutes: 30,
      autoResolveTriggers: true,
      autoEliminateOnSBA: false,
      autoTapLands: true,
      autoSpendMana: true,
    },
    turnTimer: {
      enabled: false,
      timePerPlayer: {},
      activePlayerId: null,
      intervalId: null,
    },
    theStack: [],
    monarchPlayerIndex: null,
    priority: {
      active: false,
      playerIndex: 0,
      passCount: 0,
      reason: '',       // 'phase', 'spell_cast', 'spell_resolve', 'trigger', 'combat_damage'
      sourcePhase: '',  // phase id that triggered the priority window
    },
    landsPlayedThisTurn: 0,
    replacementEffects: [],  // Forge: replacement effects registry
    maxLandsPerTurn: 1,
    combat: {
      attackers: [],           // [{cardId, targetPlayerId}]
      blockers: [],            // [{cardId, blockingCardId}]
      damageAssignments: [],   // calculated during damage step
      phase: null,             // 'declaring-attackers' | 'declaring-blockers' | 'previewing-damage' | 'resolving-damage' | null
      pendingBlockerFor: null, // cardId of attacker awaiting blocker click
      damagePreview: null,     // damage calculator preview data
    },
  };
}

