// ============================================================
// 1. MANA POOL SYSTEM
// ============================================================

/**
 * Initialize mana pool for a player.
 * Colors: W(white), U(blue), B(black), R(red), G(green), C(colorless)
 */
function initManaPool() {
  return { W: 0, U: 0, B: 0, R: 0, G: 0, C: 0 };
}

/**
 * Get a player's current mana pool (lazy-init if missing)
 */
function getManaPool(playerIdx) {
  if (!gameState || !gameState.players[playerIdx]) return initManaPool();
  if (!gameState.players[playerIdx].manaPool) {
    gameState.players[playerIdx].manaPool = initManaPool();
  }
  return gameState.players[playerIdx].manaPool;
}

/**
 * Add mana to a player's pool.
 * @param {number} playerIdx
 * @param {string} color - 'W','U','B','R','G','C'
 * @param {number} amount
 */
function addMana(playerIdx, color, amount) {
  if (!gameState) return;
  var pool = getManaPool(playerIdx);
  var c = color.toUpperCase();
  if (pool[c] === undefined) c = 'C';
  pool[c] = (pool[c] || 0) + (amount || 1);
  renderManaPool(playerIdx);
  addLogEntry('+ <strong>' + gameState.players[playerIdx].name + '</strong> adds ' + (amount || 1) + ' ' + getManaColorName(c) + ' mana');
}

/**
 * Spend mana from a player's pool. Returns true if successful.
 * @param {number} playerIdx
 * @param {object} cost - e.g. {W:1, R:2, C:3} meaning 1 white, 2 red, 3 generic
 */
function spendMana(playerIdx, cost) {
  if (!gameState) return false;
  var pool = getManaPool(playerIdx);
  // Check colored costs
  var colors = ['W', 'U', 'B', 'R', 'G'];
  for (var i = 0; i < colors.length; i++) {
    var c = colors[i];
    if (cost[c] && pool[c] < cost[c]) return false;
  }
  // Check generic/colorless cost
  var genericNeeded = cost.C || cost.generic || 0;
  var totalAvailable = 0;
  for (var ci = 0; ci < colors.length; ci++) {
    totalAvailable += pool[colors[ci]] - (cost[colors[ci]] || 0);
  }
  totalAvailable += pool.C;
  if (totalAvailable < genericNeeded) return false;

  // Actually spend
  for (var j = 0; j < colors.length; j++) {
    if (cost[colors[j]]) pool[colors[j]] -= cost[colors[j]];
  }
  // Spend generic from colorless first, then any color
  var remaining = genericNeeded;
  if (remaining > 0 && pool.C > 0) {
    var fromC = Math.min(pool.C, remaining);
    pool.C -= fromC;
    remaining -= fromC;
  }
  for (var k = 0; k < colors.length && remaining > 0; k++) {
    var avail = pool[colors[k]] - (cost[colors[k]] || 0);
    // pool already reduced for color costs, so pool[colors[k]] is post-color-cost
    if (pool[colors[k]] > 0 && remaining > 0) {
      var take = Math.min(pool[colors[k]], remaining);
      pool[colors[k]] -= take;
      remaining -= take;
    }
  }

  renderManaPool(playerIdx);
  return true;
}

/**
 * Clear a player's mana pool (end of phase/step)
 */
function clearManaPool(playerIdx) {
  if (!gameState || !gameState.players[playerIdx]) return;
  gameState.players[playerIdx].manaPool = initManaPool();
  renderManaPool(playerIdx);
}

/**
 * Clear all players' mana pools
 */
function clearAllManaPools() {
  if (!gameState) return;
  for (var p = 0; p < gameState.players.length; p++) {
    clearManaPool(p);
  }
}

/**
 * Total mana in pool
 */
function getTotalMana(playerIdx) {
  var pool = getManaPool(playerIdx);
  return pool.W + pool.U + pool.B + pool.R + pool.G + pool.C;
}

function getManaColorName(c) {
  var names = { W: 'White', U: 'Blue', B: 'Black', R: 'Red', G: 'Green', C: 'Colorless' };
  return names[c] || c;
}

var MANA_SYMBOLS = { W: '{W}', U: '{U}', B: '{B}', R: '{R}', G: '{G}', C: '{C}' };
var MANA_COLORS_CSS = {
  W: '#F9FAF4', U: '#0E68AB', B: '#150B00',
  R: '#D3202A', G: '#00733E', C: '#CAC5C0'
};
var MANA_TEXT_CSS = {
  W: '#333', U: '#fff', B: '#fff',
  R: '#fff', G: '#fff', C: '#333'
};

/**
 * Parse mana cost string like "{2}{W}{U}" into cost object
 * Returns { W:1, U:1, C:2 } (C = generic)
 */
function parseManaCost(costStr) {
  if (!costStr) return null;
  var cost = { W: 0, U: 0, B: 0, R: 0, G: 0, C: 0 };
  var matches = costStr.match(/\{([^}]+)\}/g);
  if (!matches) return null;
  for (var i = 0; i < matches.length; i++) {
    var val = matches[i].replace(/[{}]/g, '').toUpperCase();
    if (/^\d+$/.test(val)) {
      cost.C += parseInt(val, 10);
    } else if (cost[val] !== undefined) {
      cost[val]++;
    } else if (val === 'X') {
      // X costs — skip for now
    }
  }
  return cost;
}

/**
 * Tap a land to produce mana — auto-detect color from card data
 */
function tapLandForMana(cardId) {
  if (!gameState) return;
  var card = gameState.battlefieldCards.find(function(c) { return c.id === cardId; });
  if (!card) return;
  if (card.tapped) {
    addLogEntry('!! ' + card.name + ' is already tapped');
    return;
  }

  card.tapped = true;
  var el = document.getElementById('bc-' + cardId);
  if (el) el.classList.add('tapped');

  // Determine what color(s) this land produces
  var colors = detectLandManaColors(card);
  if (colors.length === 1) {
    addMana(card.ownerIndex, colors[0], 1);
  } else if (colors.length > 1) {
    // Multi-color land — show picker
    showManaColorPicker(card.ownerIndex, cardId, colors);
  } else {
    // Unknown land — default to colorless
    addMana(card.ownerIndex, 'C', 1);
  }
}

/**
 * Detect what colors a land can produce from its oracle text
 */
function detectLandManaColors(card) {
  var name = (card.name || '').toLowerCase();
  var oracle = (card.oracleText || '').toLowerCase();
  var colors = [];

  // Basic lands
  if (/\bplains\b/.test(name) || /\bplains\b/.test(card.typeLine || '')) colors.push('W');
  if (/\bisland\b/.test(name) || /\bisland\b/.test(card.typeLine || '')) colors.push('U');
  if (/\bswamp\b/.test(name) || /\bswamp\b/.test(card.typeLine || '')) colors.push('B');
  if (/\bmountain\b/.test(name) || /\bmountain\b/.test(card.typeLine || '')) colors.push('R');
  if (/\bforest\b/.test(name) || /\bforest\b/.test(card.typeLine || '')) colors.push('G');

  // Oracle text: "Add {W}" patterns
  var addMatch = oracle.match(/add\s+(\{[WUBRGC]\}(?:\s*(?:,|or)\s*\{[WUBRGC]\})*)/gi);
  if (addMatch) {
    for (var i = 0; i < addMatch.length; i++) {
      var syms = addMatch[i].match(/\{([WUBRGC])\}/gi);
      if (syms) {
        for (var j = 0; j < syms.length; j++) {
          var c = syms[j].replace(/[{}]/g, '').toUpperCase();
          if (colors.indexOf(c) === -1) colors.push(c);
        }
      }
    }
  }

  // "Add one mana of any color"
  if (/add one mana of any color/i.test(oracle) || /add \{.\} of any color/i.test(oracle)) {
    colors = ['W', 'U', 'B', 'R', 'G'];
  }

  // "any type" or "any combination"
  if (/any (?:type|combination)/i.test(oracle)) {
    colors = ['W', 'U', 'B', 'R', 'G'];
  }

  return colors.length > 0 ? colors : ['C'];
}

/**
 * Show a mana color picker popup for multi-color lands
 */
function showManaColorPicker(playerIdx, cardId, colors) {
  var existing = document.getElementById('mana-color-picker');
  if (existing) existing.remove();

  var picker = document.createElement('div');
  picker.id = 'mana-color-picker';
  picker.className = 'mana-color-picker-overlay';
  var html = '<div class="mana-color-picker-panel">';
  html += '<div class="mana-picker-title">Choose mana color</div>';
  html += '<div class="mana-picker-buttons">';
  for (var i = 0; i < colors.length; i++) {
    var c = colors[i];
    html += '<button class="mana-picker-btn" style="background:' + MANA_COLORS_CSS[c] + ';color:' + MANA_TEXT_CSS[c] + '" ';
    html += 'onclick="addMana(' + playerIdx + ',\'' + c + '\',1);closeManaColorPicker()">';
    html += getManaColorName(c) + '</button>';
  }
  html += '</div></div>';
  picker.innerHTML = html;
  document.body.appendChild(picker);
}

function closeManaColorPicker() {
  var el = document.getElementById('mana-color-picker');
  if (el) el.remove();
}

/**
 * Render mana pool display in the player panel
 */
function renderManaPool(playerIdx) {
  var el = document.getElementById('mana-pool-' + playerIdx);
  if (!el) return;
  var pool = getManaPool(playerIdx);
  var total = getTotalMana(playerIdx);
  var html = '';
  var colors = ['W', 'U', 'B', 'R', 'G', 'C'];
  for (var i = 0; i < colors.length; i++) {
    var c = colors[i];
    if (pool[c] > 0) {
      html += '<span class="mana-pip mana-' + c.toLowerCase() + '" title="' + getManaColorName(c) + ': ' + pool[c] + '">';
      html += pool[c] + '</span>';
    }
  }
  el.innerHTML = html || '<span class="mana-empty">Empty</span>';
  // Update total mana indicator
  var totalEl = document.getElementById('mana-total-' + playerIdx);
  if (totalEl) totalEl.textContent = total;
}


// ============================================================
// 2. ACTIVATED ABILITIES SYSTEM
// ============================================================

/**
 * Parse activated abilities from oracle text.
 * Looks for patterns like: "{cost}: {effect}" or "{T}: {effect}"
 * Returns array of ability objects.
 */
function parseActivatedAbilities(cardData) {
  if (!cardData || !cardData.oracleText) return [];
  var text = cardData.oracleText;
  var abilities = [];

  // Split on newlines / sentence boundaries to get individual abilities
  var sentences = text.split(/\n|(?<=\.)(?=\s*[A-Z{])/);

  for (var i = 0; i < sentences.length; i++) {
    var s = sentences[i].trim();
    if (!s) continue;

    // Match: {cost}: {effect} pattern
    // Cost can be: {T}, {mana}, "Pay N life", "Sacrifice", combination
    var abilityMatch = s.match(/^((?:\{[^}]+\}[\s,]*)+(?:,\s*(?:Pay \d+ life|Sacrifice [^:]+|Discard [^:]+|Remove [^:]+|Tap [^:]+))?)\s*:\s*(.+)$/i);
    if (!abilityMatch) {
      // Also match text costs like "Pay 2 life, {T}: effect"
      abilityMatch = s.match(/^((?:Pay \d+ life|Sacrifice [^:]+|Discard [^:]+)(?:\s*,\s*(?:\{[^}]+\}|Pay \d+ life|Sacrifice [^:]+))*)\s*:\s*(.+)$/i);
    }

    if (abilityMatch) {
      var costText = abilityMatch[1].trim();
      var effectText = abilityMatch[2].trim();

      var ability = {
        costText: costText,
        effectText: effectText,
        fullText: s,
        requiresTap: /\{T\}/.test(costText),
        requiresUntap: /\{Q\}/.test(costText),
        manaCost: null,
        lifeCost: 0,
        requiresSacrifice: false,
        sacrificeTarget: '',
        requiresDiscard: false,
        discardCount: 0,
      };

      // Parse mana cost from activation
      var manaParts = costText.match(/\{([WUBRGC0-9X]+)\}/g);
      if (manaParts) {
        var manaStr = manaParts.filter(function(p) { return !/\{[TQ]\}/.test(p); }).join('');
        if (manaStr) ability.manaCost = parseManaCost(manaStr);
      }

      // Parse life cost
      var lifeMatch = costText.match(/Pay (\d+) life/i);
      if (lifeMatch) ability.lifeCost = parseInt(lifeMatch[1], 10);

      // Parse sacrifice requirement
      if (/Sacrifice/i.test(costText)) {
        ability.requiresSacrifice = true;
        var sacMatch = costText.match(/Sacrifice\s+(.+?)(?:,|$)/i);
        if (sacMatch) ability.sacrificeTarget = sacMatch[1].trim();
      }

      // Parse discard requirement
      if (/Discard/i.test(costText)) {
        ability.requiresDiscard = true;
        var discMatch = costText.match(/Discard\s+(\d+|a)\s+cards?/i);
        ability.discardCount = discMatch ? (discMatch[1] === 'a' ? 1 : parseInt(discMatch[1], 10)) : 1;
      }

      // Parse the effect (what happens on resolution)
      ability.parsedEffect = parseTriggerEffect(effectText);

      abilities.push(ability);
    }
  }

  return abilities;
}

/**
 * Check if a player can pay an activated ability's cost
 */
function canPayAbilityCost(playerIdx, cardData, ability) {
  if (!gameState || !ability) return false;
  var player = gameState.players[playerIdx];
  if (!player) return false;

  // Tap cost — card must be untapped
  if (ability.requiresTap && cardData.tapped) return false;

  // Mana cost
  if (ability.manaCost) {
    var pool = getManaPool(playerIdx);
    var colors = ['W', 'U', 'B', 'R', 'G'];
    for (var i = 0; i < colors.length; i++) {
      if ((ability.manaCost[colors[i]] || 0) > (pool[colors[i]] || 0)) return false;
    }
    var generic = ability.manaCost.C || 0;
    var totalAvail = 0;
    for (var j = 0; j < colors.length; j++) {
      totalAvail += Math.max(0, (pool[colors[j]] || 0) - (ability.manaCost[colors[j]] || 0));
    }
    totalAvail += pool.C || 0;
    if (totalAvail < generic) return false;
  }

  // Life cost
  if (ability.lifeCost > 0 && player.life <= ability.lifeCost) return false;

  // Sacrifice — must have a valid target
  if (ability.requiresSacrifice) {
    // Check if they control a matching permanent (simplified: "another creature" check)
    if (/another creature/i.test(ability.sacrificeTarget)) {
      var otherCreatures = gameState.battlefieldCards.filter(function(c) {
        return c.ownerIndex === playerIdx && c.id !== cardData.id &&
               c.typeLine && /creature/i.test(c.typeLine);
      });
      if (otherCreatures.length === 0) return false;
    }
  }

  // Discard — must have cards in hand
  if (ability.requiresDiscard && player.zones.hand.length < ability.discardCount) return false;

  return true;
}

/**
 * Execute an activated ability: pay costs + resolve effect
 */
function activateAbility(cardId, abilityIndex) {
  if (!gameState) return;
  var card = gameState.battlefieldCards.find(function(c) { return c.id === cardId; });
  if (!card) return;

  var abilities = parseActivatedAbilities(card);
  if (!abilities[abilityIndex]) return;
  var ability = abilities[abilityIndex];
  var playerIdx = card.ownerIndex;

  if (!canPayAbilityCost(playerIdx, card, ability)) {
    addLogEntry('!! Cannot activate ability on <strong>' + card.name + '</strong> -- insufficient resources');
    return;
  }

  pushUndoState('Activate ' + card.name);

  // Pay costs
  if (ability.requiresTap) {
    card.tapped = true;
    var el = document.getElementById('bc-' + cardId);
    if (el) el.classList.add('tapped');
  }

  if (ability.manaCost) {
    spendMana(playerIdx, ability.manaCost);
  }

  if (ability.lifeCost > 0) {
    adjustLife(playerIdx, -ability.lifeCost);
  }

  if (ability.requiresSacrifice) {
    if (/^(this|it|~|itself)/i.test(ability.sacrificeTarget) || ability.sacrificeTarget === '') {
      // Sacrifice self
      moveCardToZone(cardId, 'graveyard');
      addLogEntry('>> Sacrificed <strong>' + card.name + '</strong>');
    }
    // For "Sacrifice another creature" — would need target selection UI
  }

  if (ability.requiresDiscard) {
    var hand = gameState.players[playerIdx].zones.hand;
    for (var d = 0; d < ability.discardCount && hand.length > 0; d++) {
      var discarded = hand.pop();
      gameState.players[playerIdx].zones.graveyard = gameState.players[playerIdx].zones.graveyard || [];
      gameState.players[playerIdx].zones.graveyard.push(discarded);
      addLogEntry('>> ' + gameState.players[playerIdx].name + ' discards ' + (discarded.name || 'a card'));
    }
  }

  // Resolve effect
  addLogEntry('>> <strong>' + card.name + '</strong> ability activated: ' + ability.effectText.substring(0, 80));

  // Auto-resolve if we can
  if (ability.parsedEffect && ability.parsedEffect.autoResolvable) {
    autoResolveTriggerEffect({
      autoResolvable: true,
      effectType: ability.parsedEffect.effectType,
      ownerIndex: playerIdx,
      cardName: card.name,
      oracleSnippet: ability.effectText
    });
  } else {
    // Push to trigger stack for manual resolution
    pushTrigger('activated', card.name, ability.effectText, playerIdx, cardId);
  }

  renderPlayerPanels();
}

/**
 * Show activated abilities panel for a card
 */
function showActivatedAbilitiesPanel(cardId) {
  var card = gameState.battlefieldCards.find(function(c) { return c.id === cardId; });
  if (!card) return;

  var abilities = parseActivatedAbilities(card);
  if (abilities.length === 0) {
    addLogEntry('!! <strong>' + card.name + '</strong> has no activated abilities');
    return;
  }

  var existing = document.getElementById('activated-ability-panel');
  if (existing) existing.remove();

  var panel = document.createElement('div');
  panel.id = 'activated-ability-panel';
  panel.className = 'activated-ability-overlay';

  var html = '<div class="activated-ability-dialog">';
  html += '<div class="aa-header"><span class="aa-header-title">Activated Abilities: ' + escapeHtml(card.name) + '</span>';
  html += '<button class="aa-close-btn" onclick="closeActivatedAbilityPanel()">\u2715</button></div>';
  html += '<div class="aa-body">';

  for (var i = 0; i < abilities.length; i++) {
    var ab = abilities[i];
    var canPay = canPayAbilityCost(card.ownerIndex, card, ab);
    html += '<div class="aa-item' + (canPay ? '' : ' aa-disabled') + '">';
    html += '<div class="aa-cost-line">' + escapeHtml(ab.costText) + '</div>';
    html += '<div class="aa-effect-line">' + escapeHtml(ab.effectText) + '</div>';
    html += '<button class="aa-activate-btn" ' + (canPay ? '' : 'disabled') + ' ';
    html += 'onclick="activateAbility(' + cardId + ',' + i + ');closeActivatedAbilityPanel()">Activate</button>';
    html += '</div>';
  }

  html += '</div></div>';
  panel.innerHTML = html;
  document.body.appendChild(panel);
}

function closeActivatedAbilityPanel() {
  var el = document.getElementById('activated-ability-panel');
  if (el) el.remove();
}


// ============================================================
// 3. REPLACEMENT EFFECTS ENGINE
// ============================================================

/**
 * Replacement effects registry.
 * Each replacement effect is an object:
 * {
 *   id: unique,
 *   sourceCardId: battlefield card id,
 *   ownerIndex: player index,
 *   event: 'draw' | 'damage' | 'die' | 'gain_life' | 'lose_life' | 'etb' | 'to_graveyard',
 *   condition: function(eventData) -> bool,
 *   replace: function(eventData) -> modifiedEventData,
 *   description: string
 * }
 */
var replacementEffects = [];
var nextReplacementId = 1;

/**
 * Register a replacement effect from a card on the battlefield
 */
function registerReplacementEffect(effect) {
  effect.id = nextReplacementId++;
  replacementEffects.push(effect);
  return effect.id;
}

/**
 * Remove all replacement effects from a specific card
 */
function removeReplacementEffects(sourceCardId) {
  replacementEffects = replacementEffects.filter(function(r) {
    return r.sourceCardId !== sourceCardId;
  });
}

/**
 * Apply replacement effects to an event.
 * Returns the modified event data (or null if the event is fully replaced/prevented).
 */
function applyReplacements(eventType, eventData) {
  var applicable = replacementEffects.filter(function(r) {
    return r.event === eventType && (!r.condition || r.condition(eventData));
  });
  if (applicable.length === 0) return eventData;

  var result = eventData;
  for (var i = 0; i < applicable.length; i++) {
    if (!result) break; // Event was fully prevented
    result = applicable[i].replace(result);
    if (result && result._prevented) {
      addLogEntry('>> Replacement: ' + applicable[i].description);
      return null;
    }
    if (result && result._modified) {
      addLogEntry('>> Replacement: ' + applicable[i].description);
    }
  }
  return result;
}

/**
 * Scan battlefield cards and register known replacement effects.
 * Call this whenever a card enters or leaves the battlefield.
 */
function scanReplacementEffects() {
  replacementEffects = [];
  if (!gameState) return;

  gameState.battlefieldCards.forEach(function(card) {
    var oracle = (card.oracleText || '').toLowerCase();
    var oi = card.ownerIndex;

    // "If you would draw a card, instead..." (e.g., Notion Thief for opponents)
    if (/if .* would draw a card.* instead/i.test(oracle)) {
      registerReplacementEffect({
        sourceCardId: card.id,
        ownerIndex: oi,
        event: 'draw',
        condition: function(data) {
          // Check if applies to controller or opponents based on card text
          if (/each opponent/i.test(oracle) || /another player/i.test(oracle)) {
            return data.playerIdx !== oi;
          }
          return data.playerIdx === oi;
        },
        replace: function(data) {
          if (/that player.*instead/i.test(oracle) || /you draw/i.test(oracle)) {
            // Redirect draw to controller
            data.playerIdx = oi;
            data._modified = true;
          }
          return data;
        },
        description: card.name + ' replaces a draw'
      });
    }

    // "If a creature would die, exile it instead" (e.g., Rest in Peace)
    if (/would (?:die|be put into a graveyard).*exile.*instead/i.test(oracle)) {
      registerReplacementEffect({
        sourceCardId: card.id,
        ownerIndex: oi,
        event: 'die',
        condition: function() { return true; },
        replace: function(data) {
          data.destination = 'exile';
          data._modified = true;
          return data;
        },
        description: card.name + ' exiles instead of graveyard'
      });
    }

    // "If you would gain life, you lose that much life instead" (e.g., Tainted Remedy for opponents)
    if (/would gain life.*lose that much life instead/i.test(oracle)) {
      registerReplacementEffect({
        sourceCardId: card.id,
        ownerIndex: oi,
        event: 'gain_life',
        condition: function(data) {
          // Usually applies to opponents
          if (/opponent/i.test(oracle)) return data.playerIdx !== oi;
          return true;
        },
        replace: function(data) {
          data.amount = -Math.abs(data.amount);
          data._modified = true;
          return data;
        },
        description: card.name + ' reverses life gain to life loss'
      });
    }

    // "Damage can't be prevented" (e.g., Leyline of Punishment) — flag
    if (/damage.*can't be prevented/i.test(oracle)) {
      registerReplacementEffect({
        sourceCardId: card.id,
        ownerIndex: oi,
        event: 'prevent_damage',
        condition: function() { return true; },
        replace: function(data) {
          data._prevented = false; // Override any prevention
          data._modified = true;
          return data;
        },
        description: card.name + ' prevents damage prevention'
      });
    }

    // "If a nontoken creature you control would die, instead [effect]"
    if (/nontoken creature you control would die.*instead/i.test(oracle)) {
      registerReplacementEffect({
        sourceCardId: card.id,
        ownerIndex: oi,
        event: 'die',
        condition: function(data) {
          return data.ownerIndex === oi && !data.isToken;
        },
        replace: function(data) {
          // Common: return to hand, exile, etc.
          if (/return.*to.*hand/i.test(oracle)) {
            data.destination = 'hand';
          } else if (/exile/i.test(oracle)) {
            data.destination = 'exile';
          }
          data._modified = true;
          return data;
        },
        description: card.name + ' replaces creature death'
      });
    }

    // "If a permanent entering the battlefield causes a triggered ability..."
    // "Enters the battlefield tapped" is handled by applyStaticETBEffects already

    // "Double that amount" / "If you would create a token, create an additional"
    if (/create (?:one|an?) additional/i.test(oracle) || /twice that many.*instead/i.test(oracle)) {
      if (/token/i.test(oracle)) {
        registerReplacementEffect({
          sourceCardId: card.id,
          ownerIndex: oi,
          event: 'create_token',
          condition: function(data) { return data.ownerIndex === oi; },
          replace: function(data) {
            data.count = (data.count || 1) * 2;
            data._modified = true;
            return data;
          },
          description: card.name + ' doubles token creation'
        });
      }
    }

    // "If you would gain life, gain twice that much instead" (e.g., Boon Reflection)
    if (/would gain life.*gain twice that much/i.test(oracle)) {
      registerReplacementEffect({
        sourceCardId: card.id,
        ownerIndex: oi,
        event: 'gain_life',
        condition: function(data) { return data.playerIdx === oi; },
        replace: function(data) {
          data.amount = data.amount * 2;
          data._modified = true;
          return data;
        },
        description: card.name + ' doubles life gain'
      });
    }
  });
}


// ============================================================
// 4. DAMAGE MARKING & CLEANUP STEP
// ============================================================

/**
 * Mark damage on a creature (instead of instant kill).
 * Damage is tracked on cardData.damageMarked.
 * Creatures die from SBA check when damageMarked >= toughness.
 */
function markDamage(cardId, amount, sourceData) {
  if (!gameState || amount <= 0) return;
  var card = gameState.battlefieldCards.find(function(c) { return c.id === cardId; });
  if (!card) return;

  // Apply replacement effects to damage
  var eventData = applyReplacements('damage', {
    targetCardId: cardId,
    amount: amount,
    source: sourceData || null,
    ownerIndex: card.ownerIndex
  });
  if (!eventData) return; // Damage was prevented

  card.damageMarked = (card.damageMarked || 0) + (eventData.amount || amount);

  // Update visual
  var el = document.getElementById('bc-' + cardId);
  if (el) {
    var badge = el.querySelector('.damage-badge');
    if (!badge) {
      badge = document.createElement('div');
      badge.className = 'damage-badge';
      el.appendChild(badge);
    }
    badge.textContent = card.damageMarked;
    badge.style.display = card.damageMarked > 0 ? 'flex' : 'none';
  }

  return card.damageMarked;
}

/**
 * Clear all damage marked on all creatures (cleanup step)
 */
function clearAllDamageMarks() {
  if (!gameState) return;
  gameState.battlefieldCards.forEach(function(card) {
    if (card.damageMarked && card.damageMarked > 0) {
      card.damageMarked = 0;
      var el = document.getElementById('bc-' + card.id);
      if (el) {
        var badge = el.querySelector('.damage-badge');
        if (badge) badge.style.display = 'none';
      }
    }
  });
}

/**
 * Remove "until end of turn" effects from all cards
 */
function clearEndOfTurnEffects() {
  if (!gameState) return;
  gameState.battlefieldCards.forEach(function(card) {
    // Clear temp keywords
    if (card.tempKeywords && card.tempKeywords.length > 0) {
      addLogEntry('>> Cleanup: Removed temporary keywords from <strong>' + card.name + '</strong>');
      card.tempKeywords = [];
    }
    // Clear power/toughness mods from "until end of turn" effects
    if (card.powerMod && card.powerMod !== 0) {
      card.powerMod = 0;
    }
    if (card.toughnessMod && card.toughnessMod !== 0) {
      card.toughnessMod = 0;
    }
  });
}

/**
 * Full cleanup step — called at end of each turn.
 * 1. Remove "until end of turn" effects
 * 2. Clear damage marked on creatures
 * 3. Discard to hand size (already handled)
 * 4. Clear mana pools (if auto-clear enabled)
 */
function performCleanupStep() {
  if (!gameState) return;

  addLogEntry('Phase: <strong>Cleanup Step</strong>');

  // 1. Remove temporary effects
  clearEndOfTurnEffects();

  // 2. Clear damage
  clearAllDamageMarks();

  // 3. Hand size enforcement (already exists elsewhere)

  // 4. Clear mana pools
  if (gameState.manaAutoClear !== false) {
    clearAllManaPools();
  }

  // 5. Check SBA after cleanup
  if (gameState.rulesEngine && gameState.rulesEngine.sbaChecks) {
    checkStateBasedActions();
  }

  renderPlayerPanels();
}

/**
 * Enhanced SBA check: creatures with damage >= toughness die
 */
function checkDamageBasedSBA() {
  if (!gameState) return [];
  var alerts = [];
  gameState.battlefieldCards.forEach(function(card) {
    if (!card.typeLine || !/creature/i.test(card.typeLine)) return;
    if (!card.damageMarked || card.damageMarked <= 0) return;
    var toughness = getCreatureToughness(card);
    if (card.damageMarked >= toughness) {
      if (hasKeyword(card, 'indestructible')) return;
      alerts.push({
        type: 'lethal_damage_marked',
        player: (gameState.players[card.ownerIndex] || {}).name || 'Unknown',
        playerIdx: card.ownerIndex,
        cardId: card.id,
        cardName: card.name,
        msg: card.name + ' has ' + card.damageMarked + ' damage marked (toughness ' + toughness + ') -- lethal',
      });
    }
  });
  return alerts;
}

// ============================================================
// UNDO / REDO SYSTEM
// ============================================================

const UNDO_MAX = 100;
let undoStack = [];
let redoStack = [];
let undoDisabled = false; // temporarily suppress snapshots during restore

function deepCloneState() {
  if (!gameState) return null;
  const snapshot = {
    gameState: JSON.parse(JSON.stringify(gameState)),
    nextStackGroupId: nextStackGroupId,
  };
  return snapshot;
}

function pushUndoState(description) {
  if (undoDisabled || !gameState) return;
  const snap = deepCloneState();
  if (!snap) return;
  if (description) snap._description = description;
  undoStack.push(snap);
  if (undoStack.length > UNDO_MAX) undoStack.shift();
  redoStack = []; // any new action clears redo
  updateUndoRedoButtons();
}

function undo() {
  if (undoStack.length === 0 || !gameState) return;
  // Push current state onto redo
  const current = deepCloneState();
  if (current) redoStack.push(current);
  // Pop previous state
  const prev = undoStack.pop();
  restoreFromSnapshot(prev);
  addLogEntry('\u21A9\uFE0F <em>Undo</em>');
  updateUndoRedoButtons();
}

function redo() {
  if (redoStack.length === 0 || !gameState) return;
  // Push current state onto undo
  const current = deepCloneState();
  if (current) undoStack.push(current);
  // Pop redo state
  const next = redoStack.pop();
  restoreFromSnapshot(next);
  addLogEntry('\u21AA\uFE0F <em>Redo</em>');
  updateUndoRedoButtons();
}

function restoreFromSnapshot(snapshot) {
  if (!snapshot) return;
  undoDisabled = true;

  // Restore game state
  gameState = snapshot.gameState;
  nextStackGroupId = snapshot.nextStackGroupId;

  // Clear existing battlefield card DOM elements (from section areas and battlefield fallback)
  document.querySelectorAll('.bf-section-area .battlefield-card, #battlefield > .battlefield-card').forEach(function(c) { c.remove(); });

  // Rebuild section divs for the restored game state (player count may differ)
  buildBattlefieldSections();

  // Re-render all battlefield cards
  for (const cardData of gameState.battlefieldCards) {
    renderBattlefieldCard(cardData);
  }
  refreshStackVisuals();

  // Re-render all UI panels
  renderPlayerPanels();
  renderHandArea();
  renderPhaseTracker();
  updateTurnDisplay();
  updateStormCounter();
  renderManaPool();
  updatePlayerZones();

  // Sync mana auto-clear checkbox
  const acCb = document.getElementById('mana-autoclear-toggle');
  if (acCb) acCb.checked = gameState.manaAutoClear !== false;

  // Hide battlefield label if cards exist
  var bfEl = document.getElementById('battlefield');
  if (gameState.battlefieldCards.length > 0) {
    var label2 = bfEl ? bfEl.querySelector('.battlefield-label') : null;
    if (label2) label2.style.opacity = '0';
  } else {
    var label3 = bfEl ? bfEl.querySelector('.battlefield-label') : null;
    if (label3) label3.style.opacity = '';
  }

  undoDisabled = false;
}

function updateUndoRedoButtons() {
  // Refresh undo history panel if visible
  if (undoHistoryVisible) renderUndoHistory();
  const undoBtn = document.getElementById('btn-undo');
  const redoBtn = document.getElementById('btn-redo');
  if (undoBtn) {
    undoBtn.disabled = undoStack.length === 0;
    var lastSnap = undoStack.length > 0 ? undoStack[undoStack.length - 1] : null;
    var undoDesc = lastSnap && lastSnap._description ? lastSnap._description : 'last action';
    undoBtn.title = undoStack.length > 0 ? `Undo: ${undoDesc} (${undoStack.length} steps)` : 'Nothing to undo';
    // Badge showing count
    var undoBadge = undoBtn.querySelector('.undo-count-badge');
    if (!undoBadge) {
      undoBadge = document.createElement('span');
      undoBadge.className = 'undo-count-badge';
      undoBtn.appendChild(undoBadge);
    }
    undoBadge.textContent = undoStack.length > 0 ? undoStack.length : '';
    undoBadge.style.display = undoStack.length > 0 ? 'inline' : 'none';
  }
  if (redoBtn) {
    redoBtn.disabled = redoStack.length === 0;
    redoBtn.title = redoStack.length > 0 ? `Redo (${redoStack.length} steps)` : 'Nothing to redo';
  }
}

