/**
 * Parse oracle text to identify trigger patterns.
 * Returns an array of trigger descriptors.
 */
function parseTriggers(cardName, oracleText) {
  if (!oracleText) return [];
  const triggers = [];
  const text = oracleText;
  const safeName = cardName.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');

  function extractSnippet(matchStr) {
    const idx = text.indexOf(matchStr);
    if (idx === -1) return matchStr.slice(0, 80);
    const snippet = text.slice(idx, Math.min(text.length, idx + 90));
    return snippet + (idx + 90 < text.length ? '\u2026' : '');
  }

  // ETB
  const etbPatterns = [
    new RegExp('when ' + safeName + ' enters the battlefield', 'i'),
    new RegExp('when ' + safeName + ' enters', 'i'),
    /whenever a creature enters the battlefield/i,
    /whenever a creature enters/i,
    /when a creature enters the battlefield/i,
    /whenever another creature enters/i,
    /whenever a permanent enters the battlefield/i,
    /whenever a nontoken creature enters/i,
    /whenever one or more creatures enter/i,
    /whenever a land enters the battlefield/i,
    /whenever an artifact enters the battlefield/i,
    /whenever a creature enters the battlefield under your control/i,
  ];
  for (const pat of etbPatterns) {
    const m = text.match(pat);
    if (m) { triggers.push({ type: 'etb', text: extractSnippet(m[0]), cardName }); break; }
  }

  // Nontoken ETB (separate trigger type for cards that specifically care)
  {
    const m = text.match(/whenever a nontoken creature enters/i);
    if (m) triggers.push({ type: 'nontoken_etb', text: extractSnippet(m[0]), cardName });
  }

  // LTB
  const ltbPatterns = [
    new RegExp('when ' + safeName + ' leaves the battlefield', 'i'),
    /whenever a creature leaves the battlefield/i,
    /when a permanent leaves the battlefield/i,
    /whenever .+ leaves the battlefield/i,
  ];
  for (const pat of ltbPatterns) {
    const m = text.match(pat);
    if (m) { triggers.push({ type: 'ltb', text: extractSnippet(m[0]), cardName }); break; }
  }

  // Dies
  const diesPatterns = [
    new RegExp('when ' + safeName + ' dies', 'i'),
    /whenever a creature you control dies/i,
    /whenever a creature dies/i,
    /whenever another creature dies/i,
    /whenever a nontoken creature dies/i,
    /whenever a creature an opponent controls dies/i,
    /whenever .+ dies/i,
  ];
  for (const pat of diesPatterns) {
    const m = text.match(pat);
    if (m) { triggers.push({ type: 'dies', text: extractSnippet(m[0]), cardName }); break; }
  }

  // Cast
  const castPatterns = [
    new RegExp('when you cast ' + safeName, 'i'),
    /whenever you cast a spell/i,
    /whenever a player casts a spell/i,
    /whenever you cast an instant or sorcery spell/i,
    /whenever you cast a noncreature spell/i,
    /whenever you cast a creature spell/i,
    /whenever you cast a historic spell/i,
    /whenever you cast .+ spell/i,
  ];
  for (const pat of castPatterns) {
    const m = text.match(pat);
    if (m) { triggers.push({ type: 'cast', text: extractSnippet(m[0]), cardName }); break; }
  }

  // Attack
  const attackPatterns = [
    new RegExp('whenever ' + safeName + ' attacks', 'i'),
    /whenever a creature attacks/i,
    /whenever one or more creatures attack/i,
    /whenever you attack/i,
    /whenever .+ attacks/i,
  ];
  for (const pat of attackPatterns) {
    const m = text.match(pat);
    if (m) { triggers.push({ type: 'attack', text: extractSnippet(m[0]), cardName }); break; }
  }

  // Block
  const blockPatterns = [
    new RegExp('whenever ' + safeName + ' blocks', 'i'),
    new RegExp('when ' + safeName + ' becomes blocked', 'i'),
    /whenever a creature blocks/i,
    /whenever .+ blocks/i,
  ];
  for (const pat of blockPatterns) {
    const m = text.match(pat);
    if (m) { triggers.push({ type: 'block', text: extractSnippet(m[0]), cardName }); break; }
  }

  // Upkeep
  const upkeepPatterns = [
    /at the beginning of your upkeep/i,
    /at the beginning of each player's upkeep/i,
    /at the beginning of each upkeep/i,
    /at the beginning of .+ upkeep/i,
  ];
  for (const pat of upkeepPatterns) {
    const m = text.match(pat);
    if (m) { triggers.push({ type: 'upkeep', text: extractSnippet(m[0]), cardName }); break; }
  }

  // Combat begin
  const combatBeginPatterns = [
    /at the beginning of combat on your turn/i,
    /at the beginning of combat/i,
    /at the beginning of each combat/i,
  ];
  for (const pat of combatBeginPatterns) {
    const m = text.match(pat);
    if (m) { triggers.push({ type: 'combat_begin', text: extractSnippet(m[0]), cardName }); break; }
  }

  // End step
  const endStepPatterns = [
    /at the beginning of your end step/i,
    /at the beginning of each end step/i,
    /at the beginning of the end step/i,
    /at the beginning of .+ end step/i,
  ];
  for (const pat of endStepPatterns) {
    const m = text.match(pat);
    if (m) { triggers.push({ type: 'end_step', text: extractSnippet(m[0]), cardName }); break; }
  }

  // Damage
  const damagePatterns = [
    new RegExp('whenever ' + safeName + ' deals combat damage to a player', 'i'),
    new RegExp('whenever ' + safeName + ' deals damage', 'i'),
    /whenever .+ deals combat damage to a player/i,
    /whenever .+ deals damage/i,
  ];
  for (const pat of damagePatterns) {
    const m = text.match(pat);
    if (m) { triggers.push({ type: 'damage', text: extractSnippet(m[0]), cardName }); break; }
  }

  // Life gain
  {
    const m = text.match(/whenever you gain life/i);
    if (m) triggers.push({ type: 'life_gain', text: extractSnippet(m[0]), cardName });
  }

  // Life loss
  {
    const m = text.match(/whenever you lose life/i);
    if (m) triggers.push({ type: 'life_loss', text: extractSnippet(m[0]), cardName });
  }

  // Draw
  const drawPatterns = [
    /whenever you draw a card/i,
    /whenever a player draws a card/i,
    /whenever you draw one or more cards/i,
    /whenever an opponent draws a card/i,
    /whenever a card is drawn/i,
  ];
  for (const pat of drawPatterns) {
    const m = text.match(pat);
    if (m) { triggers.push({ type: 'draw', text: extractSnippet(m[0]), cardName }); break; }
  }

  // Discard
  const discardPatterns = [
    /whenever you discard a card/i,
    /whenever a player discards a card/i,
    /whenever you discard one or more cards/i,
    /whenever a card is discarded/i,
    /whenever an opponent discards a card/i,
  ];
  for (const pat of discardPatterns) {
    const m = text.match(pat);
    if (m) { triggers.push({ type: 'discard', text: extractSnippet(m[0]), cardName }); break; }
  }

  // Mill
  const millPatterns = [
    /whenever one or more cards are put into your graveyard from your library/i,
    /whenever a card is put into a graveyard from a library/i,
    /whenever you mill/i,
    /whenever a player mills/i,
    /whenever one or more cards are milled/i,
  ];
  for (const pat of millPatterns) {
    const m = text.match(pat);
    if (m) { triggers.push({ type: 'mill', text: extractSnippet(m[0]), cardName }); break; }
  }

  // Token creation
  const tokenPatterns = [
    /whenever you create a token/i,
    /whenever one or more tokens are created/i,
    /whenever a creature token enters/i,
    /whenever you create one or more tokens/i,
    /whenever a token enters the battlefield/i,
    /whenever a token is created/i,
  ];
  for (const pat of tokenPatterns) {
    const m = text.match(pat);
    if (m) { triggers.push({ type: 'token_create', text: extractSnippet(m[0]), cardName }); break; }
  }

  // Sacrifice
  const sacrificePatterns = [
    /whenever you sacrifice a/i,
    /whenever a player sacrifices a/i,
    /whenever a creature is sacrificed/i,
    /whenever a permanent is sacrificed/i,
    /whenever you sacrifice another/i,
  ];
  for (const pat of sacrificePatterns) {
    const m = text.match(pat);
    if (m) { triggers.push({ type: 'sacrifice', text: extractSnippet(m[0]), cardName }); break; }
  }

  // Landfall (dedicated — not just generic ETB land)
  const landfallPatterns = [
    /landfall/i,
    /whenever a land enters the battlefield under your control/i,
  ];
  for (const pat of landfallPatterns) {
    const m = text.match(pat);
    if (m) { triggers.push({ type: 'landfall', text: extractSnippet(m[0]), cardName }); break; }
  }

  // Enchantment ETB (Constellation)
  const enchantmentEtbPatterns = [
    /constellation/i,
    /whenever an enchantment enters the battlefield/i,
    /whenever an enchantment you control enters/i,
    /whenever an enchantment enters the battlefield under your control/i,
  ];
  for (const pat of enchantmentEtbPatterns) {
    const m = text.match(pat);
    if (m) { triggers.push({ type: 'enchantment_etb', text: extractSnippet(m[0]), cardName }); break; }
  }

  // Artifact ETB
  const artifactEtbPatterns = [
    /whenever an artifact enters the battlefield under your control/i,
    /whenever an artifact enters the battlefield/i,
    /whenever an artifact you control enters/i,
  ];
  for (const pat of artifactEtbPatterns) {
    const m = text.match(pat);
    if (m) { triggers.push({ type: 'artifact_etb', text: extractSnippet(m[0]), cardName }); break; }
  }

  // Counter placed
  const counterPlacedPatterns = [
    /whenever a counter is placed/i,
    /whenever you put a counter/i,
    /whenever one or more counters are put/i,
    /whenever a \+1\/\+1 counter is placed/i,
    /whenever a counter is put on/i,
  ];
  for (const pat of counterPlacedPatterns) {
    const m = text.match(pat);
    if (m) { triggers.push({ type: 'counter_placed', text: extractSnippet(m[0]), cardName }); break; }
  }

  // Equipped / attached
  const equippedPatterns = [
    /whenever equipped creature/i,
    /whenever this becomes attached/i,
    /whenever .+ becomes equipped/i,
    /whenever .+ becomes attached/i,
  ];
  for (const pat of equippedPatterns) {
    const m = text.match(pat);
    if (m) { triggers.push({ type: 'equipped', text: extractSnippet(m[0]), cardName }); break; }
  }

  // Target
  const targetTrigPatterns = [
    /whenever you become the target/i,
    /whenever a creature becomes the target/i,
    /whenever .+ becomes the target of/i,
    /whenever .+ is the target of/i,
  ];
  for (const pat of targetTrigPatterns) {
    const m = text.match(pat);
    if (m) { triggers.push({ type: 'target', text: extractSnippet(m[0]), cardName }); break; }
  }

  // Tap
  const tapTriggerPatterns = [
    /whenever you tap/i,
    /whenever a creature becomes tapped/i,
    /whenever .+ becomes tapped/i,
    /whenever .+ is tapped/i,
  ];
  for (const pat of tapTriggerPatterns) {
    const m = text.match(pat);
    if (m) { triggers.push({ type: 'tap', text: extractSnippet(m[0]), cardName }); break; }
  }

  // Transform / daybound / nightbound
  const transformPatterns = [
    /when this (creature )?transforms/i,
    /daybound/i,
    /nightbound/i,
    /whenever this (permanent|creature|card) transforms/i,
  ];
  for (const pat of transformPatterns) {
    const m = text.match(pat);
    if (m) { triggers.push({ type: 'transform', text: extractSnippet(m[0]), cardName }); break; }
  }

  // Exile from graveyard
  const exileFromGravePatterns = [
    /whenever a card is exiled from a graveyard/i,
    /whenever a card is exiled from your graveyard/i,
    /whenever a card leaves your graveyard/i,
    /whenever a card leaves a graveyard/i,
    /whenever .+ is exiled from a graveyard/i,
  ];
  for (const pat of exileFromGravePatterns) {
    const m = text.match(pat);
    if (m) { triggers.push({ type: 'exile_from_grave', text: extractSnippet(m[0]), cardName }); break; }
  }

  // Mana spent
  const manaSpentPatterns = [
    /whenever you spend mana/i,
    /whenever you cast a spell, you may pay/i,
    /whenever .+ mana is spent/i,
    /whenever mana of any type is spent/i,
  ];
  for (const pat of manaSpentPatterns) {
    const m = text.match(pat);
    if (m) { triggers.push({ type: 'mana_spent', text: extractSnippet(m[0]), cardName }); break; }
  }

  // Commander cast
  {
    const m = text.match(/whenever you cast your commander/i);
    if (m) triggers.push({ type: 'commander_cast', text: extractSnippet(m[0]), cardName });
  }

  // Player eliminated
  const playerEliminatedPatterns = [
    /whenever a player loses the game/i,
    /whenever an opponent loses the game/i,
    /whenever a player leaves the game/i,
  ];
  for (const pat of playerEliminatedPatterns) {
    const m = text.match(pat);
    if (m) { triggers.push({ type: 'player_eliminated', text: extractSnippet(m[0]), cardName }); break; }
  }

  // Combat damage to a player (dedicated — separate from generic damage)
  {
    const m = text.match(new RegExp('whenever ' + safeName + ' deals combat damage to a player', 'i'));
    if (m) triggers.push({ type: 'combat_damage_player', text: extractSnippet(m[0]), cardName });
  }

  return triggers;
}

// ============================================================
// TRIGGER EFFECT HINTS
// ============================================================

/**
 * Parse the effect portion of a trigger from Oracle text.
 * Returns { hint: string, autoResolvable: bool, effectType: string|null }
 */
const EFFECT_PATTERNS = [
  // ---- Compound effects (must come BEFORE single-effect patterns) ----
  { pattern: /draw a card and you lose (\d+) life/i,    hint: 'Draw + lose life',     effectType: 'draw_lose',  auto: true },
  { pattern: /draw a card.{0,15}lose (\d+) life/i,      hint: 'Draw + lose life',     effectType: 'draw_lose',  auto: true },
  { pattern: /gain (\d+) life.{0,20}draw a card/i,      hint: 'Gain life + draw',     effectType: 'gain_draw',  auto: true },
  { pattern: /deals? (\d+) damage.{0,30}gains? that much life/i, hint: 'Damage + lifegain', effectType: 'damage_lifegain', auto: false },
  // ---- Draw ----
  { pattern: /draw a card/i,                          hint: 'Draw a card',          effectType: 'draw',       auto: true },
  { pattern: /draw (two|three|four|five|six|seven|\d+) cards?/i, hint: 'Draw cards',  effectType: 'draw_n',     auto: true },
  // ---- Life ----
  { pattern: /gain (\d+) life/i,                       hint: 'Gain life',            effectType: 'gain_life',  auto: true },
  { pattern: /lose (\d+) life/i,                       hint: 'Lose life',            effectType: 'lose_life',  auto: true },
  { pattern: /each opponent loses (\d+) life/i,        hint: 'Opponents lose life',  effectType: 'opp_lose',   auto: true },
  { pattern: /each opponent loses (\d+) life and you gain .* life/i, hint: 'Drain',  effectType: 'drain',      auto: true },
  { pattern: /you gain life equal to/i,                hint: 'Gain life (variable)',  effectType: 'gain_life_var', auto: false },
  // ---- Tokens ----
  { pattern: /create a? ?\d*\/\d* .* token/i,          hint: 'Create token',         effectType: 'token',      auto: true },
  { pattern: /create a? ?[A-Z].* token/i,             hint: 'Create token',         effectType: 'token',      auto: true },
  { pattern: /create two? .*token/i,                   hint: 'Create tokens',        effectType: 'tokens',     auto: true },
  { pattern: /create a? ?treasure/i,                   hint: 'Create Treasure',      effectType: 'treasure',   auto: true },
  { pattern: /create a? ?food/i,                       hint: 'Create Food',          effectType: 'food',       auto: true },
  { pattern: /investigate|create a? ?clue/i,           hint: 'Investigate',          effectType: 'investigate',auto: true },
  // ---- Counters ----
  { pattern: /put a \+1\/\+1 counter on (.+?)(?:\.|$)/i,          hint: '+1/+1 counter',  effectType: 'counter_plus',  auto: true },
  { pattern: /put (two|three|four|\d+) \+1\/\+1 counters? on/i,   hint: '+1/+1 counters', effectType: 'counter_plus_n',auto: true },
  { pattern: /put a \-1\/\-1 counter on (.+?)(?:\.|$)/i,          hint: '-1/-1 counter',  effectType: 'counter_minus', auto: true },
  { pattern: /put a \+1\/\+1 counter on each creature you control/i, hint: '+1/+1 all', effectType: 'counter_all', auto: true },
  { pattern: /proliferate/i,                           hint: 'Proliferate',          effectType: 'proliferate',auto: false },
  // ---- Damage ----
  { pattern: /deals? (\d+) damage to (?:each|any) opponent/i, hint: 'Damage opponents', effectType: 'damage_opp', auto: true },
  { pattern: /deals? (\d+) damage to each player/i,   hint: 'Damage all players',   effectType: 'damage_all', auto: true },
  { pattern: /deals? (\d+) damage/i,                   hint: 'Deal damage',          effectType: 'damage',     auto: false },
  // ---- Destroy / Exile / Bounce ----
  { pattern: /destroy target/i,                        hint: 'Destroy',              effectType: 'destroy',    auto: false },
  { pattern: /exile target/i,                          hint: 'Exile',                effectType: 'exile',      auto: false },
  { pattern: /return .* to (your|its owner's) hand/i,  hint: 'Bounce',               effectType: 'bounce',     auto: false },
  // ---- Mill ----
  { pattern: /mill (\d+)/i,                            hint: 'Mill',                 effectType: 'mill_ef',    auto: true },
  { pattern: /put the top (\w+|\d+) cards? of your library into your graveyard/i, hint: 'Self mill', effectType: 'self_mill_n', auto: true },
  { pattern: /put the top card of your library into your graveyard/i, hint: 'Self mill 1', effectType: 'self_mill', auto: true },
  { pattern: /each opponent mills (\d+)/i,             hint: 'Opponents mill',       effectType: 'opp_mill',   auto: true },
  // ---- Scry ----
  { pattern: /scry (\d+)/i,                            hint: 'Scry',                 effectType: 'scry',       auto: true },
  // ---- Library ----
  { pattern: /search your library/i,                   hint: 'Tutor',                effectType: 'tutor',      auto: false },
  { pattern: /return .* from .* graveyard/i,           hint: 'Return from graveyard',effectType: 'reanimate',  auto: false },
  // ---- Sacrifice / Discard ----
  { pattern: /sacrifice a/i,                           hint: 'Sacrifice',            effectType: 'sacrifice',  auto: false },
  { pattern: /discard a card/i,                        hint: 'Discard',              effectType: 'discard_ef', auto: false },
  { pattern: /each opponent discards a card/i,         hint: 'Opponents discard',    effectType: 'opp_discard',auto: true },
  { pattern: /each opponent sacrifices a/i,            hint: 'Opponents sacrifice',  effectType: 'opp_sacrifice', auto: false },
  // ---- Mana / Pump / Keywords ----
  { pattern: /add (\{[WUBRGC]\}|one mana)/i,          hint: 'Add mana',             effectType: 'mana',       auto: false },
  { pattern: /\+\d+\/\+\d+ until end of turn/i,        hint: 'Pump',                 effectType: 'pump',       auto: false },
  { pattern: /gains? (flying|haste|trample|vigilance|lifelink|deathtouch|first strike|double strike|indestructible|hexproof|menace|reach) until end of turn/i, hint: 'Grant keyword', effectType: 'keyword_temp', auto: true },
  { pattern: /gains? (flying|haste|trample|vigilance|lifelink|deathtouch|first strike|double strike|indestructible|hexproof|menace|reach)/i, hint: 'Grant keyword', effectType: 'keyword', auto: false },
  // ---- Other ----
  { pattern: /untap all .* you control/i,              hint: 'Untap all',            effectType: 'untap_all',  auto: true },
  { pattern: /untap target/i,                          hint: 'Untap',                effectType: 'untap',      auto: false },
  { pattern: /tap target/i,                            hint: 'Tap',                  effectType: 'tap',        auto: false },
  { pattern: /each player draws a card/i,              hint: 'All players draw',     effectType: 'all_draw',   auto: true },
  { pattern: /target player draws a card/i,            hint: 'Target draws',         effectType: 'target_draw',auto: false },
  { pattern: /counter target spell/i,                  hint: 'Counter spell',        effectType: 'counter_spell', auto: false },
  { pattern: /you may/i,                               hint: 'Optional',             effectType: 'optional',   auto: false },
];

function parseTriggerEffect(oracleText) {
  if (!oracleText) return { hint: '', autoResolvable: false, effectType: null };
  // Get the part after the trigger condition (after the comma typically)
  var effectText = oracleText;
  var commaIdx = oracleText.indexOf(',');
  if (commaIdx > 10 && commaIdx < oracleText.length - 5) {
    effectText = oracleText.slice(commaIdx + 1);
  }
  for (var i = 0; i < EFFECT_PATTERNS.length; i++) {
    var ep = EFFECT_PATTERNS[i];
    var m = effectText.match(ep.pattern);
    if (m) {
      var hint = ep.hint;
      // Add specifics from capture groups
      if (ep.effectType === 'gain_life' && m[1]) hint = 'Gain ' + m[1] + ' life';
      if (ep.effectType === 'lose_life' && m[1]) hint = 'Lose ' + m[1] + ' life';
      if (ep.effectType === 'opp_lose' && m[1]) hint = 'Each opponent loses ' + m[1] + ' life';
      if (ep.effectType === 'damage' && m[1]) hint = 'Deal ' + m[1] + ' damage';
      return { hint: hint, autoResolvable: ep.auto, effectType: ep.effectType };
    }
  }
  return { hint: '', autoResolvable: false, effectType: null };
}

/**
 * Push a trigger onto the game state trigger stack.
 */
function pushTrigger(type, cardName, oracleSnippet, ownerIndex, sourceCardId) {
  if (!gameState) return;
  var effect = parseTriggerEffect(oracleSnippet);
  const trigger = {
    id: nextTriggerId++,
    type,
    cardName,
    oracleSnippet: oracleSnippet || '',
    ownerIndex: ownerIndex != null ? ownerIndex : (gameState.currentPlayerIndex),
    sourceCardId: sourceCardId || null,
    resolved: false,
    effectHint: effect.hint,
    autoResolvable: effect.autoResolvable,
    effectType: effect.effectType,
  };
  gameState.triggerStack.push(trigger);
  updateTriggerBadge();
  renderTriggerStack();
  updateUnifiedStack();
  addLogEntry('⚡ Trigger: <strong>' + cardName + '</strong> — ' + (TRIGGER_TYPE_LABELS[type] || type) + (effect.hint ? ' <em style="opacity:0.65">(' + effect.hint + ')</em>' : ''));
  // Auto-resolve immediately if eligible
  if (trigger.autoResolvable && gameState.rulesEngine && gameState.rulesEngine.autoResolveTriggers) {
    setTimeout(function() { autoResolveTrigger(trigger); }, 150);
  }
}

/**
 * Fire all battlefield permanents that have triggers of triggerType.
 * filterFn(cardData) => bool optional filter.
 */
function fireBattlefieldTriggers(triggerType, filterFn) {
  if (!gameState) return;
  let firedAny = false;
  var currentPlayerIdx = gameState.currentPlayerIndex;
  gameState.battlefieldCards.forEach(cardData => {
    if (!cardData.triggers || !cardData.triggers.length) return;
    if (filterFn && !filterFn(cardData)) return;
    const matching = cardData.triggers.filter(t => t.type === triggerType);
    matching.forEach(t => {
      // For upkeep/end_step triggers: check if they should fire this turn
      if (triggerType === 'upkeep' || triggerType === 'end_step') {
        var trigText = (t.text || '').toLowerCase();
        var isYourOnly = /\byour\b/.test(trigText) && !/\beach\b/.test(trigText);
        // "your upkeep" only fires on the card owner's turn
        if (isYourOnly && cardData.ownerIndex !== currentPlayerIdx) return;
      }
      pushTrigger(t.type, t.cardName, t.text, cardData.ownerIndex, cardData.id);
      firedAny = true;
    });
  });
  // Flash the active phase step when triggers fire
  if (firedAny) flashActivePhaseStep();
}

/**
 * Fire triggers for a single card (by type array).
 */
function fireCardTriggers(cardData, triggerTypes) {
  if (!cardData || !cardData.triggers) return;
  cardData.triggers
    .filter(t => triggerTypes.includes(t.type))
    .forEach(t => pushTrigger(t.type, t.cardName, t.text, cardData.ownerIndex, cardData.id));
}

// ============================================================
// TRIGGER STACK UI
// ============================================================

function updateTriggerBadge() {
  if (!gameState) return;
  const count = gameState.triggerStack.filter(t => !t.resolved).length;
  const badgeEl = document.getElementById('trigger-count');
  const inlineEl = document.getElementById('trigger-count-inline');
  const btnEl = document.getElementById('btn-trigger-stack');
  if (badgeEl) badgeEl.textContent = count;
  if (inlineEl) inlineEl.textContent = count;
  if (btnEl) btnEl.classList.toggle('has-triggers', count > 0);
}

function openTriggerStack() {
  const panel = document.getElementById('trigger-stack-panel');
  if (panel) panel.classList.add('visible');
  renderTriggerStack();
}

function closeTriggerStack() {
  const panel = document.getElementById('trigger-stack-panel');
  if (panel) panel.classList.remove('visible');
}

function toggleTriggerStack() {
  const panel = document.getElementById('trigger-stack-panel');
  if (!panel) return;
  panel.classList.contains('visible') ? closeTriggerStack() : openTriggerStack();
}

function escapeHtml(str) {
  if (!str) return '';
  return str
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#39;');
}

function renderTriggerStack() {
  const body = document.getElementById('trigger-stack-body');
  if (!body || !gameState) return;

  const pending = gameState.triggerStack.filter(t => !t.resolved);

  if (!pending.length) {
    body.innerHTML = '<div class="trigger-stack-empty">No pending triggers</div>';
    return;
  }

  body.innerHTML = '';
  pending.forEach((trigger, idx) => {
    const ownerColor = (gameState.players[trigger.ownerIndex] || {}).color || '#888';
    const typeIcon   = TRIGGER_TYPE_ICONS[trigger.type]  || '?';
    const typeLabel  = TRIGGER_TYPE_LABELS[trigger.type] || trigger.type;

    const item = document.createElement('div');
    item.className = 'trigger-item';
    item.dataset.triggerId = trigger.id;

    var effectBadge = '';
    if (trigger.effectHint) {
      effectBadge = '<span class="trigger-effect-badge' + (trigger.autoResolvable ? ' auto' : '') + '">' + escapeHtml(trigger.effectHint) + '</span>';
    }

    item.innerHTML =
      '<div class="trigger-drag-handle" title="Drag to reorder">≡</div>' +
      '<div class="trigger-type-icon ' + trigger.type + '">' + typeIcon + '</div>' +
      '<div class="trigger-item-body">' +
        '<div class="trigger-item-title">' + escapeHtml(trigger.cardName) + effectBadge + '</div>' +
        '<div class="trigger-item-type">' + escapeHtml(typeLabel) + '</div>' +
        '<div class="trigger-item-text">' + escapeHtml(trigger.oracleSnippet) + '</div>' +
      '</div>' +
      '<div class="trigger-owner-dot" style="background:' + ownerColor + '" title="' +
        escapeHtml((gameState.players[trigger.ownerIndex] || {}).name || 'Unknown') + '"></div>' +
      '<button class="trigger-item-dismiss" title="Dismiss">✕</button>';

    // Dismiss button — use inline onclick for Comet browser compatibility
    var dismissBtn = item.querySelector('.trigger-item-dismiss');
    if (dismissBtn) dismissBtn.setAttribute('onclick', 'event.stopPropagation();dismissTrigger(' + trigger.id + ')');

    setupTriggerItemDrag(item, trigger.id);
    body.appendChild(item);
  });

  // Auto-open when triggers arrive
  const panel = document.getElementById('trigger-stack-panel');
  if (panel && !panel.classList.contains('visible')) {
    openTriggerStack();
  }
  updateUnifiedStack();
}


/**
 * Automatically apply simple trigger effects when resolved.
 * Only handles unambiguous, single-player effects.
 */
function autoResolveTriggerEffect(trigger) {
  if (!trigger || !trigger.autoResolvable || !trigger.effectType) return;
  var owner = gameState.players[trigger.ownerIndex];
  if (!owner) return;
  var snippet = trigger.oracleSnippet || '';
  var cname = trigger.cardName || 'Unknown';
  var oi = trigger.ownerIndex;

  // Helper: get opponent indices
  function getOpponents(ownerIdx) {
    var opps = [];
    for (var p = 0; p < gameState.players.length; p++) {
      if (p !== ownerIdx) opps.push(p);
    }
    return opps;
  }

  // Helper: find the card on battlefield for counter placement
  function findCardOnBattlefield(cardName, ownerIdx) {
    var bf = (gameState.players[ownerIdx] || {}).battlefield || [];
    for (var i = 0; i < bf.length; i++) {
      if (bf[i].name === cardName) return bf[i];
    }
    return null;
  }

  switch (trigger.effectType) {
    // ---- Compound effects ----
    case 'draw_lose': {
      drawCard(oi);
      var dlMatch = snippet.match(/lose (\d+) life/i);
      var dlAmt = dlMatch ? parseInt(dlMatch[1], 10) : 1;
      adjustLife(oi, -dlAmt);
      addLogEntry('>> Auto-resolved: <strong>' + cname + '</strong> -- Draw a card and lose ' + dlAmt + ' life');
      break;
    }

    case 'gain_draw': {
      var gdMatch = snippet.match(/gain (\d+) life/i);
      var gdAmt = gdMatch ? parseInt(gdMatch[1], 10) : 1;
      adjustLife(oi, gdAmt);
      drawCard(oi);
      addLogEntry('>> Auto-resolved: <strong>' + cname + '</strong> -- Gain ' + gdAmt + ' life and draw a card');
      break;
    }

    case 'draw':
      drawCard(oi);
      addLogEntry('>> Auto-resolved: <strong>' + cname + '</strong> -- Draw a card');
      break;

    case 'draw_n': {
      var dnMatch = snippet.match(/draws?\s+(\w+|\d+)\s+cards?/i);
      var dnCount = 1;
      if (dnMatch) {
        var wordMap = {one:1,two:2,three:3,four:4,five:5,six:6,seven:7,eight:8,nine:9,ten:10};
        dnCount = wordMap[dnMatch[1].toLowerCase()] || parseInt(dnMatch[1], 10) || 1;
      }
      for (var dn = 0; dn < dnCount; dn++) drawCard(oi);
      addLogEntry('>> Auto-resolved: <strong>' + cname + '</strong> -- Draw ' + dnCount + ' cards');
      break;
    }

    case 'all_draw': {
      var adMatch = snippet.match(/each player draws?\s+(\w+|\d+)?/i);
      var adCount = 1;
      if (adMatch && adMatch[1]) {
        var adMap = {a:1,one:1,two:2,three:3,four:4,five:5};
        adCount = adMap[adMatch[1].toLowerCase()] || parseInt(adMatch[1], 10) || 1;
      }
      for (var ap = 0; ap < gameState.players.length; ap++) {
        for (var adc = 0; adc < adCount; adc++) drawCard(ap);
      }
      addLogEntry('>> Auto-resolved: <strong>' + cname + '</strong> -- Each player draws ' + adCount);
      break;
    }

    case 'gain_life': {
      var gainMatch = snippet.match(/gain\s+(\d+)\s+life/i);
      var gainAmt = gainMatch ? parseInt(gainMatch[1], 10) : 1;
      adjustLife(oi, gainAmt);
      addLogEntry('>> Auto-resolved: <strong>' + cname + '</strong> -- Gain ' + gainAmt + ' life');
      break;
    }

    case 'lose_life': {
      var loseMatch = snippet.match(/lose\s+(\d+)\s+life/i);
      var loseAmt = loseMatch ? parseInt(loseMatch[1], 10) : 1;
      adjustLife(oi, -loseAmt);
      addLogEntry('>> Auto-resolved: <strong>' + cname + '</strong> -- Lose ' + loseAmt + ' life');
      break;
    }

    case 'opp_lose': {
      var olMatch = snippet.match(/(?:each opponent|opponents?)\s+loses?\s+(\d+)\s+life/i);
      var olAmt = olMatch ? parseInt(olMatch[1], 10) : 1;
      var opps1 = getOpponents(oi);
      for (var ol = 0; ol < opps1.length; ol++) adjustLife(opps1[ol], -olAmt);
      addLogEntry('>> Auto-resolved: <strong>' + cname + '</strong> -- Each opponent loses ' + olAmt + ' life');
      break;
    }

    case 'drain': {
      var drainLose = snippet.match(/(?:each opponent|opponents?)\s+loses?\s+(\d+)\s+life/i);
      var drainGain = snippet.match(/you gain\s+(?:that much life|(\d+)\s+life)/i);
      var drLose = drainLose ? parseInt(drainLose[1], 10) : 1;
      var drGain = drainGain && drainGain[1] ? parseInt(drainGain[1], 10) : drLose;
      var opps2 = getOpponents(oi);
      for (var dr = 0; dr < opps2.length; dr++) adjustLife(opps2[dr], -drLose);
      adjustLife(oi, drGain * opps2.length);
      addLogEntry('>> Auto-resolved: <strong>' + cname + '</strong> -- Drain ' + drLose + ' from each opponent, gain ' + (drGain * opps2.length));
      break;
    }

    case 'damage_opp': {
      var doMatch = snippet.match(/deals?\s+(\d+)\s+damage\s+to\s+each\s+opponent/i);
      var doDmg = doMatch ? parseInt(doMatch[1], 10) : 1;
      var opps3 = getOpponents(oi);
      for (var dop = 0; dop < opps3.length; dop++) adjustLife(opps3[dop], -doDmg);
      addLogEntry('>> Auto-resolved: <strong>' + cname + '</strong> -- Deal ' + doDmg + ' damage to each opponent');
      break;
    }

    case 'damage_all': {
      var daMatch = snippet.match(/deals?\s+(\d+)\s+damage\s+to\s+each\s+(?:player|creature and each player)/i);
      var daDmg = daMatch ? parseInt(daMatch[1], 10) : 1;
      for (var dap = 0; dap < gameState.players.length; dap++) adjustLife(dap, -daDmg);
      addLogEntry('>> Auto-resolved: <strong>' + cname + '</strong> -- Deal ' + daDmg + ' damage to each player');
      break;
    }

    case 'counter_plus': {
      var cpCard = findCardOnBattlefield(cname, oi);
      if (cpCard) {
        cpCard.counters = cpCard.counters || {};
        cpCard.counters['+1/+1'] = (cpCard.counters['+1/+1'] || 0) + 1;
        if (typeof renderBattlefieldCard === 'function') renderBattlefieldCard(cpCard);
      }
      addLogEntry('>> Auto-resolved: <strong>' + cname + '</strong> -- Put a +1/+1 counter on it');
      break;
    }

    case 'counter_plus_n': {
      var cpnMatch = snippet.match(/(\w+|\d+)\s+\+1\/\+1\s+counters?/i);
      var cpnCount = 1;
      if (cpnMatch) {
        var cpnMap = {a:1,one:1,two:2,three:3,four:4,five:5,six:6};
        cpnCount = cpnMap[cpnMatch[1].toLowerCase()] || parseInt(cpnMatch[1], 10) || 1;
      }
      var cpnCard = findCardOnBattlefield(cname, oi);
      if (cpnCard) {
        cpnCard.counters = cpnCard.counters || {};
        cpnCard.counters['+1/+1'] = (cpnCard.counters['+1/+1'] || 0) + cpnCount;
        if (typeof renderBattlefieldCard === 'function') renderBattlefieldCard(cpnCard);
      }
      addLogEntry('>> Auto-resolved: <strong>' + cname + '</strong> -- Put ' + cpnCount + ' +1/+1 counters');
      break;
    }

    case 'counter_minus': {
      // -1/-1 counter on target — place on first opponent creature as default
      var opps4 = getOpponents(oi);
      var placed = false;
      for (var cmi = 0; cmi < opps4.length && !placed; cmi++) {
        var cmBf = (gameState.players[opps4[cmi]] || {}).battlefield || [];
        for (var cmj = 0; cmj < cmBf.length && !placed; cmj++) {
          if (cmBf[cmj].type_line && cmBf[cmj].type_line.toLowerCase().indexOf('creature') !== -1) {
            cmBf[cmj].counters = cmBf[cmj].counters || {};
            cmBf[cmj].counters['-1/-1'] = (cmBf[cmj].counters['-1/-1'] || 0) + 1;
            if (typeof renderBattlefieldCard === 'function') renderBattlefieldCard(cmBf[cmj]);
            addLogEntry('>> Auto-resolved: <strong>' + cname + '</strong> -- Put -1/-1 counter on ' + cmBf[cmj].name);
            placed = true;
          }
        }
      }
      if (!placed) addLogEntry('>> Auto-resolved: <strong>' + cname + '</strong> -- -1/-1 counter (no valid target)');
      break;
    }

    case 'counter_all': {
      // +1/+1 counter on each creature you control
      var caBf = (gameState.players[oi] || {}).battlefield || [];
      var caCount = 0;
      for (var cai = 0; cai < caBf.length; cai++) {
        if (caBf[cai].type_line && caBf[cai].type_line.toLowerCase().indexOf('creature') !== -1) {
          caBf[cai].counters = caBf[cai].counters || {};
          caBf[cai].counters['+1/+1'] = (caBf[cai].counters['+1/+1'] || 0) + 1;
          if (typeof renderBattlefieldCard === 'function') renderBattlefieldCard(caBf[cai]);
          caCount++;
        }
      }
      addLogEntry('>> Auto-resolved: <strong>' + cname + '</strong> -- +1/+1 counter on ' + caCount + ' creatures');
      break;
    }

    case 'self_mill':
      millCards(oi, 1);
      addLogEntry('>> Auto-resolved: <strong>' + cname + '</strong> -- Mill 1');
      break;

    case 'self_mill_n': {
      var smnMatch = snippet.match(/mills?\s+(\w+|\d+)/i);
      var smnCount = 1;
      if (smnMatch) {
        var smnMap = {one:1,two:2,three:3,four:4,five:5,six:6,seven:7,eight:8,ten:10};
        smnCount = smnMap[smnMatch[1].toLowerCase()] || parseInt(smnMatch[1], 10) || 1;
      }
      millCards(oi, smnCount);
      addLogEntry('>> Auto-resolved: <strong>' + cname + '</strong> -- Mill ' + smnCount);
      break;
    }

    case 'mill_ef': {
      var meMatch = snippet.match(/(?:target|each)\s+(?:player|opponent)\s+(?:mills?|puts?).*?(\w+|\d+)/i);
      var meCount = 1;
      if (meMatch) {
        var meMap = {one:1,two:2,three:3,four:4,five:5,ten:10};
        meCount = meMap[meMatch[1].toLowerCase()] || parseInt(meMatch[1], 10) || 1;
      }
      var isOppOnly = /each opponent|target opponent/i.test(snippet);
      if (isOppOnly) {
        var opps5 = getOpponents(oi);
        for (var mei = 0; mei < opps5.length; mei++) millCards(opps5[mei], meCount);
        addLogEntry('>> Auto-resolved: <strong>' + cname + '</strong> -- Each opponent mills ' + meCount);
      } else {
        for (var mep = 0; mep < gameState.players.length; mep++) millCards(mep, meCount);
        addLogEntry('>> Auto-resolved: <strong>' + cname + '</strong> -- Each player mills ' + meCount);
      }
      break;
    }

    case 'opp_mill': {
      var omMatch = snippet.match(/opponent\s+mills?\s+(\w+|\d+)/i);
      var omCount = 1;
      if (omMatch) {
        var omMap = {one:1,two:2,three:3,four:4,five:5,ten:10};
        omCount = omMap[omMatch[1].toLowerCase()] || parseInt(omMatch[1], 10) || 1;
      }
      var opps6 = getOpponents(oi);
      for (var omi = 0; omi < opps6.length; omi++) millCards(opps6[omi], omCount);
      addLogEntry('>> Auto-resolved: <strong>' + cname + '</strong> -- Each opponent mills ' + omCount);
      break;
    }

    case 'scry': {
      var scryMatch = snippet.match(/scry\s+(\d+)/i);
      var scryN = scryMatch ? parseInt(scryMatch[1], 10) : 1;
      if (typeof openScryModal === 'function') {
        openScryModal(oi, scryN);
      }
      addLogEntry('>> Auto-resolved: <strong>' + cname + '</strong> -- Scry ' + scryN);
      break;
    }

    case 'opp_discard': {
      var odMatch = snippet.match(/(?:each opponent|opponents?)\s+discards?\s+(?:a|one|\d+)\s+cards?/i);
      var odCount = 1;
      if (odMatch) {
        var odNumMatch = odMatch[0].match(/(\d+)/);
        odCount = odNumMatch ? parseInt(odNumMatch[1], 10) : 1;
      }
      var opps7 = getOpponents(oi);
      for (var odi = 0; odi < opps7.length; odi++) {
        var odHand = (gameState.players[opps7[odi]] || {}).hand || [];
        for (var odj = 0; odj < odCount && odHand.length > 0; odj++) {
          var randIdx = Math.floor(Math.random() * odHand.length);
          var discarded = odHand.splice(randIdx, 1)[0];
          gameState.players[opps7[odi]].graveyard = gameState.players[opps7[odi]].graveyard || [];
          gameState.players[opps7[odi]].graveyard.push(discarded);
          addLogEntry('>> ' + gameState.players[opps7[odi]].name + ' discards ' + (discarded.name || 'a card'));
        }
      }
      addLogEntry('>> Auto-resolved: <strong>' + cname + '</strong> -- Each opponent discards ' + odCount);
      break;
    }

    case 'keyword_temp': {
      // Grants a temporary keyword (haste, lifelink, etc.) — tag the card
      var kwMatch = snippet.match(/gains?\s+(haste|lifelink|deathtouch|flying|trample|vigilance|menace|first strike|double strike|hexproof|indestructible|reach)/i);
      if (kwMatch) {
        var kw = kwMatch[1].toLowerCase();
        var kwCard = findCardOnBattlefield(cname, oi);
        if (kwCard) {
          kwCard.tempKeywords = kwCard.tempKeywords || [];
          if (kwCard.tempKeywords.indexOf(kw) === -1) kwCard.tempKeywords.push(kw);
          if (typeof renderBattlefieldCard === 'function') renderBattlefieldCard(kwCard);
        }
        addLogEntry('>> Auto-resolved: <strong>' + cname + '</strong> -- Gains ' + kw);
      }
      break;
    }

    case 'untap_all': {
      var uaBf = (gameState.players[oi] || {}).battlefield || [];
      var uaCount = 0;
      for (var uai = 0; uai < uaBf.length; uai++) {
        if (uaBf[uai].tapped) {
          uaBf[uai].tapped = false;
          uaCount++;
        }
      }
      addLogEntry('>> Auto-resolved: <strong>' + cname + '</strong> -- Untapped ' + uaCount + ' permanents');
      break;
    }

    case 'token':
    case 'tokens': {
      var tokenSpecs = parseTokenCreationAbilities(snippet);
      if (tokenSpecs.length > 0) {
        for (var ti = 0; ti < tokenSpecs.length; ti++) {
          var ts = tokenSpecs[ti];
          createQuickToken(oi, ts.name, ts.power, ts.toughness, ts.typeLine, ts.color, ts.abilities, ts.count);
          addLogEntry('>> Auto-resolved: <strong>' + cname + '</strong> -- Created ' + ts.displayLabel);
        }
      } else {
        addLogEntry('!! Could not auto-parse token from: <strong>' + cname + '</strong> -- resolve manually');
      }
      break;
    }

    case 'treasure': {
      createQuickToken(oi, 'Treasure', '', '', 'Artifact -- Treasure', 'C', 'Sacrifice: Add one mana of any color', 1);
      addLogEntry('>> Auto-resolved: <strong>' + cname + '</strong> -- Created 1x Treasure');
      break;
    }

    case 'food': {
      createQuickToken(oi, 'Food', '', '', 'Artifact -- Food', 'C', '{2}, Sacrifice: Gain 3 life', 1);
      addLogEntry('>> Auto-resolved: <strong>' + cname + '</strong> -- Created 1x Food');
      break;
    }

    case 'investigate': {
      createQuickToken(oi, 'Clue', '', '', 'Artifact -- Clue', 'C', '{2}, Sacrifice: Draw a card', 1);
      addLogEntry('>> Auto-resolved: <strong>' + cname + '</strong> -- Investigated (Created 1x Clue)');
      break;
    }

    default:
      addLogEntry('!! Unhandled auto-trigger type "' + trigger.effectType + '" for <strong>' + cname + '</strong> -- resolve manually');
      break;
  }

  // Refresh UI after any auto-resolution
  if (typeof renderPlayerPanels === 'function') renderPlayerPanels();
}

/**
 * autoResolveTrigger(trigger) — gated by rulesEngine.autoResolveTriggers setting.
 * Auto-resolves simple effects, removes from stack, and chains to next auto trigger.
 * @returns {boolean} true if auto-resolved, false if manual needed
 */
function autoResolveTrigger(trigger) {
  if (!gameState || !gameState.rulesEngine || !gameState.rulesEngine.autoResolveTriggers) return false;
  if (!trigger || !trigger.autoResolvable || !trigger.effectType) return false;
  // Verify trigger is still on stack
  var stillPending = gameState.triggerStack.find(function(t) { return t.id === trigger.id && !t.resolved; });
  if (!stillPending) return false;

  autoResolveTriggerEffect(trigger);

  var idx = gameState.triggerStack.findIndex(function(t) { return t.id === trigger.id; });
  if (idx !== -1) gameState.triggerStack.splice(idx, 1);
  updateTriggerBadge();

  if (gameState.rulesEngine.sbaChecks) checkStateBasedActions();

  var nextAuto = gameState.triggerStack.filter(function(t) { return !t.resolved && t.autoResolvable; });
  if (nextAuto.length > 0) {
    setTimeout(function() {
      autoResolveTrigger(nextAuto[0]);
      renderTriggerStack();
      updateUnifiedStack();
    }, 300);
  } else {
    renderTriggerStack();
    updateUnifiedStack();
    if (!gameState.triggerStack.filter(function(t) { return !t.resolved; }).length) {
      setTimeout(closeTriggerStack, 500);
    }
  }
  return true;
}


function resolveNextTrigger() {
  if (!gameState) return;
  const pending = gameState.triggerStack.filter(t => !t.resolved);
  if (!pending.length) return;

  const trigger = pending[0];

  // Try auto-resolve first (gated by setting)
  if (autoResolveTrigger(trigger)) {
    updateUnifiedStack();
    return;
  }

  const body = document.getElementById('trigger-stack-body');
  const item = body ? body.querySelector('[data-trigger-id="' + trigger.id + '"]') : null;

  // Manual resolution — apply effect for non-auto-resolve case
  autoResolveTriggerEffect(trigger);

  addLogEntry('✓ Resolved: <strong>' + trigger.cardName + '</strong> — ' + (TRIGGER_TYPE_LABELS[trigger.type] || trigger.type) + (trigger.effectHint ? ' (' + trigger.effectHint + ')' : ''));

  if (item) {
    item.classList.add('resolving');
    setTimeout(function() {
      const idx = gameState.triggerStack.findIndex(t => t.id === trigger.id);
      if (idx !== -1) gameState.triggerStack.splice(idx, 1);
      updateTriggerBadge();
      renderTriggerStack();
      updateUnifiedStack();
      if (gameState.rulesEngine && gameState.rulesEngine.sbaChecks) checkStateBasedActions();
      if (!gameState.triggerStack.filter(t => !t.resolved).length) {
        setTimeout(closeTriggerStack, 500);
      }
    }, 420);
  } else {
    const idx = gameState.triggerStack.findIndex(t => t.id === trigger.id);
    if (idx !== -1) gameState.triggerStack.splice(idx, 1);
    updateTriggerBadge();
    renderTriggerStack();
    updateUnifiedStack();
    if (gameState.rulesEngine && gameState.rulesEngine.sbaChecks) checkStateBasedActions();
    if (!gameState.triggerStack.filter(t => !t.resolved).length) {
      setTimeout(closeTriggerStack, 500);
    }
  }
}

function resolveAllTriggers() {
  if (!gameState) return;
  var pending = gameState.triggerStack.filter(t => !t.resolved);
  if (!pending.length) return;
  pending.forEach(function(t) { autoResolveTriggerEffect(t); });
  addLogEntry('✓ Resolved <strong>' + pending.length + '</strong> trigger' + (pending.length !== 1 ? 's' : ''));
  gameState.triggerStack = [];
  updateTriggerBadge();
  renderTriggerStack();
  updateUnifiedStack();
  if (gameState.rulesEngine && gameState.rulesEngine.sbaChecks) checkStateBasedActions();
  setTimeout(closeTriggerStack, 500);
}

function dismissTrigger(triggerId) {
  if (!gameState) return;
  const idx = gameState.triggerStack.findIndex(t => t.id === triggerId);
  if (idx === -1) return;
  const trigger = gameState.triggerStack[idx];
  gameState.triggerStack.splice(idx, 1);
  updateTriggerBadge();
  renderTriggerStack();
  updateUnifiedStack();
  addLogEntry('✕ Dismissed: <strong>' + trigger.cardName + '</strong>');
  if (!gameState.triggerStack.filter(t => !t.resolved).length) {
    setTimeout(closeTriggerStack, 500);
  }
}

// Drag-to-reorder trigger items
let dragTriggerSourceId = null;

function setupTriggerItemDrag(item, triggerId) {
  item.setAttribute('draggable', 'true');

  item.addEventListener('dragstart', function(e) {
    dragTriggerSourceId = triggerId;
    e.dataTransfer.effectAllowed = 'move';
    e.dataTransfer.setData('text/plain', String(triggerId));
    setTimeout(function() { item.style.opacity = '0.45'; }, 0);
  });

  item.addEventListener('dragend', function() {
    item.style.opacity = '';
    dragTriggerSourceId = null;
    document.querySelectorAll('.trigger-item').forEach(function(el) {
      el.style.outline = '';
    });
  });

  item.addEventListener('dragover', function(e) {
    e.preventDefault();
    e.dataTransfer.dropEffect = 'move';
    document.querySelectorAll('.trigger-item').forEach(function(el) { el.style.outline = ''; });
    if (triggerId !== dragTriggerSourceId) {
      item.style.outline = '2px solid var(--mtg-gold)';
    }
  });

  item.addEventListener('dragleave', function() {
    item.style.outline = '';
  });

  item.addEventListener('drop', function(e) {
    e.preventDefault();
    item.style.outline = '';
    if (!gameState || dragTriggerSourceId == null || dragTriggerSourceId === triggerId) return;

    const pending = gameState.triggerStack.filter(t => !t.resolved);
    const srcIdx  = pending.findIndex(t => t.id === dragTriggerSourceId);
    const dstIdx  = pending.findIndex(t => t.id === triggerId);
    if (srcIdx === -1 || dstIdx === -1) return;

    // Move srcIdx to dstIdx position
    const moved = pending.splice(srcIdx, 1)[0];
    pending.splice(dstIdx, 0, moved);
    gameState.triggerStack = pending;

    addLogEntry('⇅ Reordered trigger stack');
    renderTriggerStack();
  });
}

// ============================================================
// SCRYFALL API
// ============================================================

// searchDebounceTimer declared in ui.js
let lastSearchTime = 0;
const SEARCH_DEBOUNCE_MS = 300;
const RATE_LIMIT_MS = 100;

async function searchScryfall(query) {
  if (!query || query.trim().length < 2) {
    renderSearchResults([]);
    setSearchStatus('Type to search cards...');
    return;
  }

  clearTimeout(searchDebounceTimer);
  searchDebounceTimer = setTimeout(async () => {
    const now = Date.now();
    const waitMs = Math.max(0, lastSearchTime + RATE_LIMIT_MS - now);

    setTimeout(async () => {
      lastSearchTime = Date.now();
      setSearchStatus('');
      showSearchSpinner(true);

      try {
        const url = `${SCRYFALL_BASE}/cards/search?q=${encodeURIComponent(query)}&order=name&unique=cards`;
        const resp = await fetch(url);

        if (!resp.ok) {
          if (resp.status === 404) {
            renderSearchResults([]);
            setSearchStatus('No cards found.');
          } else {
            setSearchStatus('Search error. Try again.');
          }
          return;
        }

        const data = await resp.json();
        renderSearchResults(data.data || []);
        setSearchStatus(data.total_cards
          ? `${data.total_cards} result${data.total_cards === 1 ? '' : 's'}` + (data.total_cards > data.data.length ? ` (showing ${data.data.length})` : '')
          : 'No results.');
      } catch (err) {
        setSearchStatus('Network error. Check connection.');
      } finally {
        showSearchSpinner(false);
      }
    }, waitMs);
  }, SEARCH_DEBOUNCE_MS);
}

function getCardImage(card) {
  if (card.image_uris && card.image_uris.normal) {
    return card.image_uris.normal;
  }
  if (card.card_faces && card.card_faces[0] && card.card_faces[0].image_uris) {
    return card.card_faces[0].image_uris.normal;
  }
  return null;
}

function setSearchStatus(text) {
  const el = document.getElementById('search-status');
  if (el) el.textContent = text;
}

function showSearchSpinner(show) {
  const el = document.getElementById('search-status');
  if (!el) return;
  if (show) {
    el.innerHTML = '<div class="search-loading"><div class="spinner"></div></div>';
  }
}

function renderSearchResults(cards) {
  const container = document.getElementById('card-results');
  if (!container) return;

  if (!cards.length) {
    container.innerHTML = '<div class="zone-empty">No cards found.</div>';
    return;
  }

  container.innerHTML = '';
  cards.slice(0, 40).forEach(card => {
    const imgSrc = getCardImage(card);
    if (!imgSrc) return;

    const item = document.createElement('div');
    item.className = 'search-card-item';
    item.draggable = true;

    item.innerHTML = `
      <img src="${imgSrc}" alt="${card.name}" loading="lazy" onerror="this.style.display='none'"/>
      <div class="search-card-info">
        <div class="search-card-name">${card.name}</div>
        <div class="search-card-type">${card.type_line || ''}</div>
      </div>
      <div class="search-card-actions">
        <div class="search-card-add-btn" title="Add to Battlefield">+</div>
        <div class="search-card-lib-btn" title="Add to Library (top)">📚</div>
        <div class="search-card-hand-btn" title="Add to Hand">✋</div>
      </div>
    `;

    // Drag start
    item.addEventListener('dragstart', e => {
      e.dataTransfer.setData('application/json', JSON.stringify({
        type: 'search-card',
        card: {
          id: card.id || card.name,
          name: card.name,
          imageUrl: imgSrc,
          typeLine: card.type_line || '',
          manaCost: card.mana_cost || '',
          oracleText: card.oracle_text || '',
        }
      }));
      e.dataTransfer.effectAllowed = 'copy';
    });

    // Click to preview
    item.addEventListener('click', e => {
      if (e.target.classList.contains('search-card-add-btn')) {
        addCardToBattlefield(card.name, imgSrc, card.type_line || '', gameState.currentPlayerIndex, undefined, undefined, card.oracle_text || '', { manaCost: card.mana_cost || '', power: card.power || '', toughness: card.toughness || '', pt: (card.power && card.toughness) ? card.power + '/' + card.toughness : '', cmc: card.cmc || 0, loyalty: card.loyalty || '' });
      } else if (e.target.classList.contains('search-card-lib-btn')) {
        addCardToPlayerZone(card, imgSrc, 'library', 'top');
      } else if (e.target.classList.contains('search-card-hand-btn')) {
        addCardToPlayerZone(card, imgSrc, 'hand');
      } else {
        showCardPreviewModal(card.name, imgSrc, card.type_line, card.oracle_text, card.mana_cost);
      }
    });

    // Hover to preview
    item.addEventListener('mouseenter', e => {
      showFloatingCardPreview(imgSrc, e, {
        name: card.name,
        typeLine: card.type_line || '',
        oracleText: card.oracle_text || '',
        manaCost: card.mana_cost || '',
        power: card.power,
        toughness: card.toughness,
        loyalty: card.loyalty
      });
    });
    item.addEventListener('mousemove', e => {
      positionFloatingPreview(e);
    });
    item.addEventListener('mouseleave', () => {
      hideFloatingCardPreview();
    });

    container.appendChild(item);
  });
}

// ============================================================
// FLOATING CARD PREVIEW
// ============================================================

// Calculate effective Power/Toughness for a battlefield creature
// Includes: base P/T + counters + equipment buffs + anthem effects
function getEffectivePT(bfCard) {
  if (!bfCard) return null;
  var basePower = 0;
  var baseTough = 0;

  // Try power/toughness fields first, but only if they contain valid numbers
  var hasPower = bfCard.power !== undefined && bfCard.power !== '' && bfCard.power !== null;
  var hasTough = bfCard.toughness !== undefined && bfCard.toughness !== '' && bfCard.toughness !== null;

  if (hasPower) basePower = parseInt(bfCard.power, 10) || 0;
  if (hasTough) baseTough = parseInt(bfCard.toughness, 10) || 0;

  // If power/toughness not set (or 0/0 which could be parse failure), try pt string
  if ((!hasPower || !hasTough) && bfCard.pt) {
    var ptParts = bfCard.pt.split('/');
    if (ptParts.length === 2) {
      if (!hasPower) basePower = parseInt(ptParts[0], 10) || 0;
      if (!hasTough) baseTough = parseInt(ptParts[1], 10) || 0;
    }
  }

  var bonusPower = 0;
  var bonusTough = 0;

  // +1/+1 and -1/-1 counters
  if (bfCard.counters) {
    var plus = bfCard.counters['+1/+1'] || 0;
    var minus = bfCard.counters['-1/-1'] || 0;
    bonusPower += plus - minus;
    bonusTough += plus - minus;
  }

  // Equipment buffs: scan attached equipment oracle text for buff patterns
  if (bfCard.attachments && bfCard.attachments.length > 0 && gameState) {
    for (var i = 0; i < bfCard.attachments.length; i++) {
      var eq = gameState.battlefieldCards.find(function(c) { return c.id === bfCard.attachments[i]; });
      if (!eq || !eq.oracleText) continue;
      var buffMatches = eq.oracleText.match(/(?:gets?|has)\s+([+-]\d+)\/([+-]\d+)/gi);
      if (buffMatches) {
        for (var m = 0; m < buffMatches.length; m++) {
          var nums = buffMatches[m].match(/([+-]\d+)\/([+-]\d+)/);
          if (nums) {
            bonusPower += parseInt(nums[1]) || 0;
            bonusTough += parseInt(nums[2]) || 0;
          }
        }
      }
    }
  }

  // Anthem effects: scan all OTHER battlefield permanents for "creatures you control get +X/+X"
  if (gameState && gameState.battlefieldCards) {
    for (var j = 0; j < gameState.battlefieldCards.length; j++) {
      var other = gameState.battlefieldCards[j];
      if (other.id === bfCard.id) continue;
      if (other.ownerIndex !== bfCard.ownerIndex) continue;
      if (!other.oracleText) continue;
      // Match patterns like "creatures you control get +1/+1" or "other creatures you control get +2/+2"
      var anthemMatch = other.oracleText.match(/(?:other\s+)?creatures\s+you\s+control\s+get\s+([+-]\d+)\/([+-]\d+)/i);
      if (anthemMatch) {
        // "Other creatures" shouldn't buff itself — check if the anthem source IS the creature
        var isOther = /other\s+creatures/i.test(other.oracleText);
        if (!isOther || other.id !== bfCard.id) {
          bonusPower += parseInt(anthemMatch[1]) || 0;
          bonusTough += parseInt(anthemMatch[2]) || 0;
        }
      }
    }
  }

  return {
    power: basePower + bonusPower,
    toughness: baseTough + bonusTough,
    bonusPower: bonusPower,
    bonusTough: bonusTough
  };
}

function showFloatingCardPreview(imgSrc, e, cardInfo) {
  var preview = document.getElementById('card-preview');
  if (!preview) return;
  preview.style.display = 'block';
  preview.querySelector('img').src = imgSrc;

  // Effective P/T overlay for battlefield creatures
  var ptOverlay = preview.querySelector('.card-preview-pt-overlay');
  if (ptOverlay) {
    var bfCard = cardInfo && cardInfo._bfCard;
    if (bfCard && aiIsCreature(bfCard)) {
      var ept = getEffectivePT(bfCard);
      if (ept) {
        var basePower = parseInt(bfCard.power) || 0;
        var baseTough = parseInt(bfCard.toughness) || 0;
        var boosted = ept.power !== basePower || ept.toughness !== baseTough;
        ptOverlay.textContent = ept.power + ' / ' + ept.toughness;
        ptOverlay.style.display = 'flex';
        ptOverlay.className = 'card-preview-pt-overlay' + (boosted ? ' boosted' : '') +
          (ept.power > basePower ? ' power-up' : '') +
          (ept.toughness > baseTough ? ' tough-up' : '') +
          (ept.power < basePower ? ' power-down' : '') +
          (ept.toughness < baseTough ? ' tough-down' : '');
        // Position at bottom-left of the card image
        var imgEl = preview.querySelector('img');
        if (imgEl) {
          requestAnimationFrame(function() {
            ptOverlay.style.top = (imgEl.offsetHeight - ptOverlay.offsetHeight - 8) + 'px';
          });
        }
      } else {
        ptOverlay.style.display = 'none';
      }
    } else {
      ptOverlay.style.display = 'none';
    }
  }

  // Populate info panel if card data provided
  if (cardInfo && (cardInfo.name || cardInfo.typeLine || cardInfo.oracleText)) {
    preview.classList.add('has-info');
    var nameEl = preview.querySelector('.card-preview-name');
    var costEl = preview.querySelector('.card-preview-cost');
    var typeEl = preview.querySelector('.card-preview-type');
    var oracleEl = preview.querySelector('.card-preview-oracle');
    var ptEl = preview.querySelector('.card-preview-pt');

    if (nameEl) nameEl.textContent = cardInfo.name || '';
    if (costEl) costEl.innerHTML = cardInfo.manaCost ? renderManaCostHTML(cardInfo.manaCost) : '';
    if (typeEl) typeEl.textContent = cardInfo.typeLine || '';
    if (oracleEl) oracleEl.textContent = cardInfo.oracleText || '';
    if (ptEl) {
      // Show P/T for creatures, loyalty for planeswalkers
      if (cardInfo.power !== undefined && cardInfo.toughness !== undefined) {
        ptEl.textContent = cardInfo.power + '/' + cardInfo.toughness;
      } else if (cardInfo.pt) {
        ptEl.textContent = cardInfo.pt;
      } else if (cardInfo.loyalty) {
        ptEl.textContent = 'Loyalty: ' + cardInfo.loyalty;
      } else {
        ptEl.textContent = '';
      }
    }
  } else {
    preview.classList.remove('has-info');
  }

  positionFloatingPreview(e);
}

function positionFloatingPreview(e) {
  var preview = document.getElementById('card-preview');
  if (!preview || preview.style.display === 'none') return;
  var offset = 16;
  var pw = 290; // preview width + buffer
  var ph = preview.offsetHeight || 420;
  var x = e.clientX + offset;
  var y = e.clientY + offset;
  if (x + pw > window.innerWidth) x = e.clientX - pw - offset;
  if (y + ph > window.innerHeight) y = Math.max(8, window.innerHeight - ph - 8);
  if (x < 4) x = 4;
  if (y < 4) y = 4;
  preview.style.left = x + 'px';
  preview.style.top = y + 'px';
}

function hideFloatingCardPreview() {
  var preview = document.getElementById('card-preview');
  if (preview) {
    preview.style.display = 'none';
    preview.classList.remove('has-info');
  }
}

// Render mana cost string like "{2}{W}{U}" into colored circle HTML
function renderManaCostHTML(costStr) {
  if (!costStr) return '';
  var parts = costStr.match(/\{[^}]+\}/g);
  if (!parts) return costStr;
  return parts.map(function(p) {
    var sym = p.replace(/[{}]/g, '');
    var cls = 'mana-symbol';
    if (sym === 'W') cls += ' mana-W';
    else if (sym === 'U') cls += ' mana-U';
    else if (sym === 'B') cls += ' mana-B';
    else if (sym === 'R') cls += ' mana-R';
    else if (sym === 'G') cls += ' mana-G';
    else if (sym === 'C') cls += ' mana-C';
    else if (sym === 'X') cls += ' mana-X';
    else if (/^\d+$/.test(sym)) cls += ' mana-generic';
    else if (sym.indexOf('/') !== -1) {
      // Hybrid like W/U — use first color
      var first = sym.split('/')[0];
      if ('WUBRGC'.indexOf(first) !== -1) cls += ' mana-' + first;
      else cls += ' mana-generic';
    }
    else cls += ' mana-generic';
    return '<span class="' + cls + '">' + sym + '</span>';
  }).join('');
}

// ============================================================
// BATTLEFIELD
// ============================================================

let nextCardId = 1;
let draggedCardId = null;
let dragOffset = { x: 0, y: 0 };
let isDraggingBattlefieldCard = false;

// Determine battlefield zone for a card based on its type line
function getCardTypeZone(typeLine) {
  var t = (typeLine || '').toLowerCase();
  if (/instant|sorcery/.test(t)) return 'spell';
  if (/creature/.test(t)) return 'creature';
  if (/artifact|enchantment/.test(t)) return 'artifact';
  if (/land/.test(t)) return 'land';
  if (/planeswalker/.test(t)) return 'creature'; // planeswalkers with creatures top center
  return 'other';
}

// ============================================================
// EQUIPMENT ATTACH/DETACH SYSTEM
// ============================================================
var equipPickMode = false;
var equipPickSourceId = null;

function isEquipment(card) {
  if (!card || !card.typeLine) return false;
  return /equipment/i.test(card.typeLine);
}

function isAura(card) {
  if (!card || !card.typeLine) return false;
  return /aura/i.test(card.typeLine) && /enchantment/i.test(card.typeLine);
}

function isAttachable(card) {
  return isEquipment(card) || isAura(card);
}

function enterEquipPickMode(equipmentId) {
  equipPickMode = true;
  equipPickSourceId = equipmentId;
  document.body.classList.add('equip-pick-mode');
  var eqCard = gameState.battlefieldCards.find(function(c){return c.id===equipmentId});
  var eqIcon = eqCard && isAura(eqCard) ? '\u2728' : '\u2694';
  addLogEntry(eqIcon + ' Click a creature to attach <strong>' + (eqCard || {}).name + '</strong> to it.');
}

function cancelEquipPickMode() {
  equipPickMode = false;
  equipPickSourceId = null;
  document.body.classList.remove('equip-pick-mode');
}

function handleEquipPickClick(creatureId) {
  if (!equipPickMode || !equipPickSourceId) return;
  var equipment = gameState.battlefieldCards.find(function(c) { return c.id === equipPickSourceId; });
  var creature = gameState.battlefieldCards.find(function(c) { return c.id === creatureId; });
  if (!equipment || !creature) { cancelEquipPickMode(); return; }
  if (!aiIsCreature(creature)) {
    addLogEntry('\u26A0 <strong>' + creature.name + '</strong> is not a creature \u2014 cannot attach.');
    cancelEquipPickMode();
    return;
  }
  // If equipment is already on another creature, detach first
  if (equipment.attachedTo) {
    detachEquipment(equipment.id, true);
  }
  pushUndoState();
  // Attach
  equipment.attachedTo = creatureId;
  if (!creature.attachments) creature.attachments = [];
  if (creature.attachments.indexOf(equipment.id) === -1) {
    creature.attachments.push(equipment.id);
  }
  var attachIcon = isAura(equipment) ? '\u2728' : '\u2694';
  addLogEntry(attachIcon + ' <strong>' + equipment.name + '</strong> attached to <strong>' + creature.name + '</strong>');
  cancelEquipPickMode();
  repositionAttachments(creatureId);
}

function detachEquipment(equipmentId, silent) {
  var equipment = gameState.battlefieldCards.find(function(c) { return c.id === equipmentId; });
  if (!equipment || !equipment.attachedTo) return;
  var creatureId = equipment.attachedTo;
  var creature = gameState.battlefieldCards.find(function(c) { return c.id === creatureId; });
  if (creature && creature.attachments) {
    var idx = creature.attachments.indexOf(equipmentId);
    if (idx !== -1) creature.attachments.splice(idx, 1);
  }
  equipment.attachedTo = null;

  // Auras go to graveyard when detached (they can't exist unattached)
  if (isAura(equipment)) {
    var el = document.getElementById('bc-' + equipmentId);
    if (el) {
      el.classList.remove('attached-equipment', 'attached-aura');
      el.style.clipPath = '';
      el.style.zIndex = '';
    }
    if (!silent) {
      pushUndoState();
      addLogEntry('\u2728 <strong>' + equipment.name + '</strong> (Aura) lost its target and was moved to graveyard');
    }
    moveCardToZone(equipmentId, 'graveyard');
    // Reposition remaining attachments on the creature
    if (creature && creature.attachments && creature.attachments.length > 0) {
      repositionAttachments(creatureId);
    }
    return;
  }

  // Equipment: return to its type zone position
  var sectionArea = document.getElementById('bf-section-area-' + equipment.ownerIndex);
  var battlefield = document.getElementById('battlefield');
  var rect = sectionArea ? sectionArea.getBoundingClientRect() : battlefield.getBoundingClientRect();
  var zone = getCardTypeZone(equipment.typeLine || '');
  var zones = {
    creature: { x1: 0.25, x2: 0.65, y1: 0.05, y2: 0.42 },
    artifact: { x1: 0.68, x2: 0.95, y1: 0.05, y2: 0.42 },
    land:     { x1: 0.03, x2: 0.32, y1: 0.55, y2: 0.90 },
    spell:    { x1: 0.35, x2: 0.65, y1: 0.55, y2: 0.90 },
    other:    { x1: 0.25, x2: 0.70, y1: 0.25, y2: 0.75 }
  };
  var z = zones[zone] || zones.artifact;
  equipment.x = z.x1 * rect.width + Math.random() * ((z.x2 - z.x1) * rect.width - 110) + 4;
  equipment.y = z.y1 * rect.height + Math.random() * ((z.y2 - z.y1) * rect.height - 150) + 4;
  var el = document.getElementById('bc-' + equipmentId);
  if (el) {
    el.style.left = equipment.x + 'px';
    el.style.top = equipment.y + 'px';
    el.classList.remove('attached-equipment', 'attached-equip');
    el.style.clipPath = '';
    el.style.zIndex = '';
  }
  if (!silent) {
    pushUndoState();
    addLogEntry('\u2694 <strong>' + equipment.name + '</strong> unequipped');
  }
  // Reposition remaining attachments on the creature
  if (creature && creature.attachments && creature.attachments.length > 0) {
    repositionAttachments(creatureId);
  }
}

function repositionAttachments(creatureId) {
  var creature = gameState.battlefieldCards.find(function(c) { return c.id === creatureId; });
  if (!creature || !creature.attachments) return;
  var creatureEl = document.getElementById('bc-' + creatureId);
  if (!creatureEl) return;
  var cardH = creatureEl.offsetHeight || 140;
  var cardW = creatureEl.offsetWidth || 100;
  var attachOffset = 40; // how much of each attached card peeks out below

  for (var i = 0; i < creature.attachments.length; i++) {
    var eqId = creature.attachments[i];
    var eq = gameState.battlefieldCards.find(function(c) { return c.id === eqId; });
    if (!eq) continue;
    // Position attached card below the creature, offset for each attachment
    eq.x = creature.x;
    eq.y = creature.y + cardH + (i * attachOffset);
    var el = document.getElementById('bc-' + eqId);
    if (el) {
      el.style.left = eq.x + 'px';
      el.style.top = eq.y + 'px';
      el.classList.add('attached-equipment');
      el.classList.remove('attached-aura', 'attached-equip');
      // Distinguish aura vs equipment visually
      if (isAura(eq)) {
        el.classList.add('attached-aura');
      } else {
        el.classList.add('attached-equip');
      }
      // Show only the top portion (card name area) by clipping the bottom
      el.style.clipPath = 'inset(50% 0 0 0)';
      el.style.zIndex = '1';
    }
  }
}

// When a creature moves (drag), move its attachments too
function moveAttachmentsWithCreature(creatureId) {
  var creature = gameState.battlefieldCards.find(function(c) { return c.id === creatureId; });
  if (!creature || !creature.attachments || creature.attachments.length === 0) return;
  repositionAttachments(creatureId);
}

// When a creature leaves the battlefield, detach all equipment
function detachAllFromCreature(creatureId) {
  var creature = gameState.battlefieldCards.find(function(c) { return c.id === creatureId; });
  if (!creature || !creature.attachments) return;
  var attachmentsCopy = creature.attachments.slice();
  for (var i = 0; i < attachmentsCopy.length; i++) {
    detachEquipment(attachmentsCopy[i], true);
  }
}

/**
 * Apply static ETB effects to a card that just entered the battlefield.
 * Handles: enters tapped, enters with counters, defender, other static abilities.
 */
function applyStaticETBEffects(cardData) {
  if (!cardData || !gameState) return;
  var oracle = (cardData.oracleText || '').toLowerCase();
  var typeLine = (cardData.typeLine || '').toLowerCase();
  var ownerIdx = cardData.ownerIndex !== undefined ? cardData.ownerIndex : cardData.ownerId;
  var player = gameState.players[ownerIdx];
  var playerName = player ? player.name : 'Unknown';

  // ---- Enters the battlefield tapped ----
  if (/enters the battlefield tapped/i.test(oracle) ||
      /enters tapped/i.test(oracle) ||
      /this (?:land|creature|permanent|artifact) enters tapped/i.test(oracle)) {
    cardData.tapped = true;
    addLogEntry('\u27a1 <strong>' + cardData.name + '</strong> enters the battlefield tapped');
  }

  // ---- Enters with +1/+1 counters ----
  var plusMatch = oracle.match(/enters (?:the battlefield )?with (\w+|\d+) \+1\/\+1 counter/i);
  if (plusMatch) {
    var numStr = plusMatch[1];
    var num = parseInt(numStr, 10);
    if (isNaN(num)) {
      var wordMap = {one:1,two:2,three:3,four:4,five:5,six:6,seven:7,eight:8,nine:9,ten:10,eleven:11,twelve:12,thirteen:13};
      num = wordMap[numStr.toLowerCase()] || 0;
    }
    if (num > 0) {
      if (!cardData.counters) cardData.counters = {};
      cardData.counters['+1/+1'] = (cardData.counters['+1/+1'] || 0) + num;
      addLogEntry('\u2728 <strong>' + cardData.name + '</strong> enters with ' + num + ' +1/+1 counter' + (num > 1 ? 's' : ''));
    }
  }

  // ---- Enters with -1/-1 counters ----
  var minusMatch = oracle.match(/enters (?:the battlefield )?with (\w+|\d+) \-1\/\-1 counter/i);
  if (minusMatch) {
    var mNum = parseInt(minusMatch[1], 10);
    if (isNaN(mNum)) {
      var mWordMap = {one:1,two:2,three:3,four:4,five:5};
      mNum = mWordMap[minusMatch[1].toLowerCase()] || 0;
    }
    if (mNum > 0) {
      if (!cardData.counters) cardData.counters = {};
      cardData.counters['-1/-1'] = (cardData.counters['-1/-1'] || 0) + mNum;
      addLogEntry('\u2728 <strong>' + cardData.name + '</strong> enters with ' + mNum + ' -1/-1 counter' + (mNum > 1 ? 's' : ''));
    }
  }

  // ---- Enters with charge/lore/other named counters ----
  var namedCtrs = oracle.match(/enters (?:the battlefield )?with (\w+|\d+) (\w+) counter/i);
  if (namedCtrs && !/\+1|\-1/.test(namedCtrs[0])) {
    var nCnt = parseInt(namedCtrs[1], 10);
    if (isNaN(nCnt)) {
      var nWordMap = {one:1,two:2,three:3,four:4,five:5,six:6,seven:7,eight:8};
      nCnt = nWordMap[namedCtrs[1].toLowerCase()] || 0;
    }
    var ctrName = namedCtrs[2].toLowerCase();
    if (nCnt > 0 && ctrName !== 'loyalty') {
      if (!cardData.counters) cardData.counters = {};
      cardData.counters[ctrName] = (cardData.counters[ctrName] || 0) + nCnt;
      addLogEntry('\u2728 <strong>' + cardData.name + '</strong> enters with ' + nCnt + ' ' + ctrName + ' counter' + (nCnt > 1 ? 's' : ''));
    }
  }

  // ---- ETB draw a card (non-trigger static like cantrip creatures) ----
  // "When [this] enters, draw a card" is handled by triggers; this catches "enters...draw"

  // ---- ETB gain life ----
  var etbGainLife = oracle.match(/when .* enters.*gain (\d+) life/i);
  // Handled by trigger system, no need to duplicate here

  // ---- Creatures with Haste should not have summoning sickness regardless ----
  // (Already handled by hasKeyword check in hasSummoningSickness)

  // ---- Creatures that enter with specific abilities ----
  // "other creatures you control have haste" is an anthem, handled by hasKeyword

  // ---- Mana-producing lands auto-detect (tap abilities parsed elsewhere) ----
}

function addCardToBattlefield(name, imageUrl, typeLine, ownerIndex, x, y, oracleText, extraData) {
  pushUndoState("Play " + name);
  // New 4-quadrant layout: each player has battle-zone-N
  var pNum = (ownerIndex || 0) + 1;
  const battlefield = document.getElementById('battle-zone-' + pNum) || document.getElementById('battlefield');
  if (!battlefield) return;

  var sectionArea = document.getElementById('bf-section-area-' + ownerIndex);
  var rect = sectionArea ? sectionArea.getBoundingClientRect() : battlefield.getBoundingClientRect();

  var cardX, cardY;
  if (x !== undefined && y !== undefined) {
    cardX = x;
    cardY = y;
  } else {
    // Place cards by type in designated battlefield zones
    var zone = getCardTypeZone(typeLine || '');
    var cardW = 110, cardH = 150;
    // Zone regions (percentage of section area)
    // Creatures: top center (30%-70% x, 5%-45% y)
    // Artifacts/Enchantments: top right (70%-95% x, 5%-45% y)
    // Lands: bottom left (5%-35% x, 55%-90% y)
    // Instants/Sorceries: bottom center (35%-65% x, 55%-90% y)
    // Other: center (30%-70% x, 25%-75% y)
    var zones = {
      creature:    { x1: 0.25, x2: 0.65, y1: 0.05, y2: 0.42 },
      artifact:    { x1: 0.68, x2: 0.95, y1: 0.05, y2: 0.42 },
      land:        { x1: 0.03, x2: 0.32, y1: 0.55, y2: 0.90 },
      spell:       { x1: 0.35, x2: 0.65, y1: 0.55, y2: 0.90 },
      other:       { x1: 0.25, x2: 0.70, y1: 0.25, y2: 0.75 }
    };
    var z = zones[zone] || zones.other;
    var areaW = rect.width;
    var areaH = rect.height;
    // Count existing cards of same type to offset placement and avoid stacking
    var sameTypeCount = 0;
    if (gameState && gameState.battlefieldCards) {
      sameTypeCount = gameState.battlefieldCards.filter(function(c) {
        return c.ownerIndex === ownerIndex && getCardTypeZone(c.typeLine || '') === zone;
      }).length;
    }
    var zoneW = (z.x2 - z.x1) * areaW;
    var zoneH = (z.y2 - z.y1) * areaH;
    var cols = Math.max(1, Math.floor(zoneW / (cardW + 8)));
    var row = Math.floor(sameTypeCount / cols);
    var col = sameTypeCount % cols;
    cardX = z.x1 * areaW + col * (cardW + 8) + 4;
    cardY = z.y1 * areaH + row * (cardH + 8) + 4;
    // Wrap within zone bounds
    if (cardX + cardW > z.x2 * areaW) cardX = z.x1 * areaW + 4;
    if (cardY + cardH > z.y2 * areaH) cardY = z.y1 * areaH + 4;
  }

  const parsedTriggers = parseTriggers(name, oracleText || '');

  const cardData = {
    id: nextCardId++,
    name,
    imageUrl,
    typeLine,
    ownerIndex,
    ownerId: ownerIndex,
    x: cardX,
    y: cardY,
    tapped: false,
    faceDown: false,
    oracleText: oracleText || '',
    triggers: parsedTriggers,
    turnPlayed: gameState ? `${gameState.turnNumber}_${gameState.currentPlayerIndex}` : '0_0',
    damageMarked: 0,
    damageThisTurn: 0,
    ...(extraData || {}),
  };

  gameState.battlefieldCards.push(cardData);

  // Apply static ETB effects (enters tapped, enters with counters, etc.)
  applyStaticETBEffects(cardData);

  // Rescan replacement effects since a new permanent entered
  scanReplacementEffects();

  renderBattlefieldCard(cardData);
  animateCardEnter(cardData.id);
  addLogEntry(`<strong>${gameState.players[ownerIndex].name}</strong> played <strong>${name}</strong>`);
  // Feature 8: color identity check
  var _ciViolation = checkColorIdentityViolation(cardData, ownerIndex);
  if (_ciViolation) {
    showColorIdentityWarning(name, _ciViolation);
    addLogEntry('&#x26A0; <strong>' + name + '</strong> may violate color identity (' + _ciViolation.join(',') + ')');
  }
  gameState.stormCount++;
  updateStormCounter();

  // Fire ETB triggers: first check all existing battlefield permanents for
  // "whenever a creature/permanent enters" triggers, then the new card's own ETB.
  fireBattlefieldTriggers('etb', function(bfCard) {
    return bfCard.id !== cardData.id; // other permanents watching for ETBs
  });
  // Also fire the new card's own ETB trigger ("When [this card] enters...").
  fireCardTriggers(cardData, ['etb']);

  // Fire nontoken_etb if the entering card is NOT a token and IS a creature
  if (!cardData.isToken && cardData.typeLine && /creature/i.test(cardData.typeLine)) {
    fireBattlefieldTriggers('nontoken_etb', function(bfCard) {
      return bfCard.id !== cardData.id;
    });
  }

  if (cardData.typeLine && /land/i.test(cardData.typeLine)) {
    if (gameState.rulesEngine && gameState.rulesEngine.enforceLandLimit && gameState.landsPlayedThisTurn >= gameState.maxLandsPerTurn) {
      addLogEntry('⚠ <strong>' + cardData.name + '</strong> — land drop limit reached this turn! (Playing anyway)');
    }
    if (gameState.landsPlayedThisTurn !== undefined) gameState.landsPlayedThisTurn++;
    renderPhaseTracker();
  }

  // Fire landfall triggers if this is a land
  if (cardData.typeLine && /land/i.test(cardData.typeLine)) {
    fireBattlefieldTriggers('landfall');
  }

  // Fire cast triggers for all permanents watching spells being cast
  fireBattlefieldTriggers('cast');

  // Planeswalker ETB: auto-set loyalty counters from starting loyalty
  if (cardData.typeLine && /planeswalker/i.test(cardData.typeLine)) {
    var startingLoyalty = 0;
    if (cardData.loyalty) {
      startingLoyalty = parseInt(cardData.loyalty, 10) || 0;
    }
    if (startingLoyalty > 0) {
      if (!cardData.counters) cardData.counters = {};
      cardData.counters['loyalty'] = startingLoyalty;
      addLogEntry('\u25c6 <strong>' + name + '</strong> enters with ' + startingLoyalty + ' loyalty');
      // Re-render to show loyalty counter badge
      var bcEl = document.getElementById('bc-' + cardData.id);
      if (bcEl) bcEl.remove();
      renderBattlefieldCard(cardData);
    }
    // Track loyalty ability usage per turn
    cardData.loyaltyUsedThisTurn = false;
  }

  // Auto-attach: Auras prompt for target creature on ETB
  if (isAura(cardData)) {
    // Check if there are any creatures to attach to
    var ownerCreatures = gameState.battlefieldCards.filter(function(c) {
      return c.id !== cardData.id && aiIsCreature(c);
    });
    if (ownerCreatures.length > 0) {
      enterEquipPickMode(cardData.id);
    } else {
      addLogEntry('\u26A0 No creatures on the battlefield to enchant with <strong>' + cardData.name + '</strong>');
    }
  }
}

function getBattlefieldCardProtectionBadge(cardData) {
  var oracle = (cardData.oracleText || '').toLowerCase();
  if (/shroud/.test(oracle)) return '<div class="bf-protection-badge bf-shroud-badge" title="Shroud: cannot be targeted by any spells or abilities">🌫</div>';
  if (/hexproof/.test(oracle)) return '<div class="bf-protection-badge bf-hexproof-badge" title="Hexproof: cannot be targeted by opponents">🛡</div>';
  if (/protection from/.test(oracle)) return '<div class="bf-protection-badge bf-protection-badge-icon" title="Protection">🔒</div>';
  return '';
}

function renderBattlefieldCard(cardData) {
  const battlefield = document.getElementById('battlefield');
  if (!battlefield) return;

  // Target the player's section area; fall back to #battlefield if sections not built yet
  var sectionArea = document.getElementById('bf-section-area-' + cardData.ownerIndex);
  var cardContainer = sectionArea || battlefield;

  // Remove label if cards exist
  const label = battlefield.querySelector('.battlefield-label');
  if (label) label.style.opacity = '0';

  const card = document.createElement('div');
  card.className = 'battlefield-card';
  card.id = `bc-${cardData.id}`;
  card.style.left = cardData.x + 'px';
  card.style.top = cardData.y + 'px';
  card.style.borderColor = gameState.players[cardData.ownerIndex]?.color || 'transparent';

  if (cardData.tapped) card.classList.add('tapped');
  if (cardData.faceDown) card.classList.add('face-down');
  if (hasSummoningSickness(cardData)) card.classList.add('summoning-sick');
  if (cardData.isToken) card.classList.add('token-glow');

  // Build keyword badges
  const kwBadges = getKeywordBadges(cardData);
  let badgeHtml = '';
  if (kwBadges.length > 0) {
    badgeHtml = '<div class="kw-badge-strip">';
    for (const b of kwBadges) {
      badgeHtml += `<span class="kw-badge" style="background:${b.color}" title="${b.name}: ${b.description}">${b.icon}</span>`;
    }
    badgeHtml += '</div>';
  }

  // Check for activated/triggered abilities indicators
  const abilities = parseCardAbilities(cardData.oracleText || '', cardData.typeLine || '', cardData.name || '');
  let abilityIndicators = '';
  if (abilities.activated.length > 0) {
    abilityIndicators += `<span class="ability-indicator ability-ind-activated" title="${abilities.activated.length} activated abilit${abilities.activated.length > 1 ? 'ies' : 'y'}">⚡${abilities.activated.length > 1 ? abilities.activated.length : ''}</span>`;
  }
  if (abilities.triggered.length > 0) {
    abilityIndicators += `<span class="ability-indicator ability-ind-triggered" title="${abilities.triggered.length} triggered abilit${abilities.triggered.length > 1 ? 'ies' : 'y'}">⚙${abilities.triggered.length > 1 ? abilities.triggered.length : ''}</span>`;
  }
  if (abilities.mana.length > 0) {
    abilityIndicators += `<span class="ability-indicator ability-ind-mana" title="Mana ability">◆</span>`;
  }

  // Feature 6: Protection/hexproof/shroud badge
  const protectionBadge = getBattlefieldCardProtectionBadge(cardData);

  card.innerHTML = `
    ${protectionBadge}
    <img src="${cardData.imageUrl}" alt="${cardData.name}" draggable="false" loading="lazy"/>
    <div class="card-owner-bar" style="background:${gameState.players[cardData.ownerIndex]?.color || '#666'}"></div>

    ${badgeHtml}
    ${abilityIndicators ? '<div class="ability-indicators">' + abilityIndicators + '</div>' : ''}
  `;

  // Render counter badges (generic system)
  if (cardData.counters || cardData.plusCounters || cardData.minusCounters) {
    // Ensure counters map exists and migrate legacy
    if (!cardData.counters) cardData.counters = {};
    if (cardData.plusCounters > 0 && !cardData.counters['+1/+1']) cardData.counters['+1/+1'] = cardData.plusCounters;
    if (cardData.minusCounters > 0 && !cardData.counters['-1/-1']) cardData.counters['-1/-1'] = cardData.minusCounters;
    var cTypes = Object.keys(cardData.counters).filter(function(k) { return cardData.counters[k] > 0; });
    if (cTypes.length > 0) {
      var strip = document.createElement('div');
      strip.className = 'card-counters-strip';
      for (var ci = 0; ci < cTypes.length; ci++) {
        var cType = cTypes[ci];
        var cCount = cardData.counters[cType];
        var ct = COUNTER_TYPES[cType] || { icon: '●', color: '#9ca3af', label: cType, shortLabel: cType.substring(0, 3) };
        var badge = document.createElement('span');
        badge.className = 'card-counter-badge';
        badge.style.background = ct.color;
        badge.style.color = '#fff';
        badge.title = cCount + ' ' + ct.label + ' counter' + (cCount > 1 ? 's' : '');
        if (cType === '+1/+1') badge.textContent = '+' + cCount + '/+' + cCount;
        else if (cType === '-1/-1') badge.textContent = '-' + cCount + '/-' + cCount;
        else badge.textContent = ct.icon + cCount;
        strip.appendChild(badge);
      }
      card.appendChild(strip);
    }
  }

  // Damage badge
  if (cardData.damageMarked && cardData.damageMarked > 0) {
    var dmgBadge = document.createElement('div');
    dmgBadge.className = 'damage-badge';
    dmgBadge.textContent = cardData.damageMarked;
    dmgBadge.title = cardData.damageMarked + ' damage marked';
    card.appendChild(dmgBadge);
  }

  // Drag to move
  card.addEventListener('mousedown', e => {
    if (e.button !== 0) return;
    // Don't allow dragging attached equipment independently
    if (cardData.attachedTo) return;
    e.preventDefault();
    isDraggingBattlefieldCard = true;
    draggedCardId = cardData.id;
    const rect = card.getBoundingClientRect();
    dragOffset.x = e.clientX - rect.left;
    dragOffset.y = e.clientY - rect.top;
    card.style.zIndex = '100';
    card.style.transition = 'none';
  });

  // Right-click context menu
  card.addEventListener('contextmenu', e => {
    e.preventDefault();
    showContextMenu(e.clientX, e.clientY, cardData.id);
  });

  // Touch: long press for context menu
  let longPressTimer = null;
  card.addEventListener('touchstart', e => {
    longPressTimer = setTimeout(() => {
      const touch = e.touches[0];
      showContextMenu(touch.clientX, touch.clientY, cardData.id);
    }, 600);
  });
  card.addEventListener('touchend', () => clearTimeout(longPressTimer));
  card.addEventListener('touchmove', () => clearTimeout(longPressTimer));

  // Double-click to tap/untap
  card.addEventListener('dblclick', e => {
    e.preventDefault();
    toggleTap(cardData.id);
  });

  // Single-click for combat attacker/blocker toggle
  card.addEventListener('click', e => {
    if (!gameState) return;
    // Stack pick mode: clicking a card stacks it with the source
    if (stackPickMode) {
      handleStackPickClick(cardData.id);
      e.stopPropagation();
      return;
    }
    // Equip pick mode: clicking a creature attaches the equipment
    if (equipPickMode) {
      handleEquipPickClick(cardData.id);
      e.stopPropagation();
      return;
    }
    const combat = gameState.combat;
    if (combat.phase === 'declaring-attackers') {
      // Only the active player's untapped non-sick creatures
      if (cardData.ownerId === gameState.currentPlayerIndex && !cardData.tapped && aiIsCreature(cardData)) {
        toggleAttacker(cardData.id);
        e.stopPropagation();
      }
    } else if (combat.phase === 'declaring-blockers') {
      // Defending players assign their untapped creatures as blockers
      const isDefender = combat.attackers.some(a => a.targetPlayerId === cardData.ownerId);
      if (isDefender && !cardData.tapped && aiIsCreature(cardData)) {
        // If a pending attacker is set, assign this blocker to it
        if (combat.pendingBlockerFor !== null) {
          toggleBlocker(cardData.id, combat.pendingBlockerFor);
          e.stopPropagation();
        } else {
          // Click on an attacker card first to select it
          const asAttacker = combat.attackers.find(a => a.cardId === cardData.id);
          if (!asAttacker) {
            // Show pulse that user needs to pick an attacker first
            addLogEntry('Click an attacking creature first to assign a blocker to it.');
          }
        }
      }
      // Clicking an attacker card to select it as target for blocking
      const asAttacker = combat.attackers.find(a => a.cardId === cardData.id);
      if (asAttacker) {
        combat.pendingBlockerFor = cardData.id;
        refreshCombatOverlay();
        e.stopPropagation();
        // Highlight selected attacker
        document.querySelectorAll('.battlefield-card.attacker-selected').forEach(el => el.classList.remove('attacker-selected'));
        card.classList.add('attacker-selected');
      }
    }
  });

  // Hover preview + abilities panel
  card.addEventListener('mouseenter', e => {
    if (!isDraggingBattlefieldCard) {
      // Fan out stack if this is a stack leader
      if (cardData.stackGroupId && isStackLeader(cardData)) {
        fanOutStack(cardData.stackGroupId);
      }
      showFloatingCardPreview(cardData.imageUrl, e, {
        name: cardData.name,
        typeLine: cardData.typeLine,
        oracleText: cardData.oracleText,
        manaCost: cardData.manaCost || '',
        power: cardData.power,
        toughness: cardData.toughness,
        pt: cardData.pt,
        loyalty: cardData.loyalty,
        _bfCard: cardData
      });
    }
  });
  card.addEventListener('mousemove', e => {
    if (!isDraggingBattlefieldCard) positionFloatingPreview(e);
  });
  card.addEventListener('mouseleave', () => {
    hideFloatingCardPreview();
    // Schedule fan collapse — delay to avoid flicker when moving between stacked cards
    if (cardData.stackGroupId) {
      if (stackFanCollapseTimer) clearTimeout(stackFanCollapseTimer);
      stackFanCollapseTimer = setTimeout(() => {
        // Check if mouse is over any card in this stack
        const groupId = cardData.stackGroupId;
        if (!groupId) return;
        const cards = getStackCards(groupId);
        const anyHovered = cards.some(c => {
          const el = document.getElementById(`bc-${c.id}`);
          return el && el.matches(':hover');
        });
        if (!anyHovered) collapseStackFan(false);
      }, 150);
    }
  });

  cardContainer.appendChild(card);
  updateBattlefieldSectionCounts();
}

// Mouse drag for battlefield cards
document.addEventListener('mousemove', e => {
  if (!isDraggingBattlefieldCard || draggedCardId === null) return;
  hideFloatingCardPreview();

  const cardData = gameState?.battlefieldCards.find(c => c.id === draggedCardId);
  if (!cardData) return;

  // Use section area bounds if available, otherwise fall back to battlefield
  var dragSectionArea = document.getElementById('bf-section-area-' + cardData.ownerIndex);
  var dragBounds = dragSectionArea ? dragSectionArea : document.getElementById('battlefield');
  if (!dragBounds) return;

  const rect = dragBounds.getBoundingClientRect();
  let newX = e.clientX - rect.left - dragOffset.x;
  let newY = e.clientY - rect.top - dragOffset.y;

  // Clamp within section area
  newX = Math.max(0, Math.min(rect.width - 75, newX));
  newY = Math.max(0, Math.min(rect.height - 100, newY));

  cardData.x = newX;
  cardData.y = newY;

  const cardEl = document.getElementById(`bc-${draggedCardId}`);
  if (cardEl) {
    cardEl.style.left = newX + 'px';
    cardEl.style.top = newY + 'px';
  }

  // Move attached equipment/auras with the creature
  if (cardData.attachments && cardData.attachments.length > 0) {
    moveAttachmentsWithCreature(cardData.id);
  }
});

document.addEventListener('mouseup', e => {
  if (!isDraggingBattlefieldCard) return;
  isDraggingBattlefieldCard = false;
  const droppedId = draggedCardId;
  const cardEl = document.getElementById(`bc-${droppedId}`);
  if (cardEl) {
    cardEl.style.zIndex = '';
    cardEl.style.transition = '';
  }
  draggedCardId = null;

  // Shift+drop: check proximity to another card and stack them
  if (e.shiftKey && droppedId && gameState) {
    const droppedCard = gameState.battlefieldCards.find(c => c.id === droppedId);
    if (droppedCard) {
      const threshold = 40;
      let closestCard = null;
      let closestDist = Infinity;
      gameState.battlefieldCards.forEach(other => {
        if (other.id === droppedId) return;
        // Skip cards that are stacked-hidden (not leaders), unless it's a stacked card in same group
        if (other.stackGroupId && !isStackLeader(other)) return;
        const dx = (other.x || 0) - (droppedCard.x || 0);
        const dy = (other.y || 0) - (droppedCard.y || 0);
        const dist = Math.sqrt(dx * dx + dy * dy);
        if (dist < threshold && dist < closestDist) {
          closestDist = dist;
          closestCard = other;
        }
      });
      if (closestCard) {
        createStack(closestCard.id, droppedId);
      }
    }
  }
});

// ============================================================
// BATTLEFIELD FILTERS
// ============================================================

let bfTypeFilter = 'all';
let bfOwnerFilter = 'all'; // 'all' or player index

// ============================================================
// CARD STACKING SYSTEM
// ============================================================

let nextStackGroupId = 1;
let stackPickMode = false;      // true when "Stack With Next Click" is active
let stackPickSourceId = null;   // the card that initiated stack pick mode
let stackFanGroupId = null;     // which group is currently fanned out
let stackFanCollapseTimer = null;

function getStackCards(groupId) {
  if (!gameState || !groupId) return [];
  return gameState.battlefieldCards
    .filter(c => c.stackGroupId === groupId)
    .sort((a, b) => (a.stackOrder || 0) - (b.stackOrder || 0));
}

function getStackLeader(groupId) {
  const cards = getStackCards(groupId);
  return cards.length ? cards[cards.length - 1] : null;
}

function isStackLeader(cardData) {
  if (!cardData.stackGroupId) return false;
  const leader = getStackLeader(cardData.stackGroupId);
  return leader && leader.id === cardData.id;
}

function createStack(cardId1, cardId2) {
  if (!gameState) return;
  pushUndoState();
  const card1 = gameState.battlefieldCards.find(c => c.id === cardId1);
  const card2 = gameState.battlefieldCards.find(c => c.id === cardId2);
  if (!card1 || !card2) return;
  if (cardId1 === cardId2) return;

  // If either card is already in a stack, merge into that stack
  if (card1.stackGroupId && card2.stackGroupId) {
    // Merge card2's group into card1's group
    const gid = card1.stackGroupId;
    const otherCards = getStackCards(card2.stackGroupId);
    const existingMax = Math.max(...getStackCards(gid).map(c => c.stackOrder || 0));
    otherCards.forEach((c, i) => {
      c.stackGroupId = gid;
      c.stackOrder = existingMax + 1 + i;
    });
  } else if (card1.stackGroupId) {
    addToStack(cardId2, card1.stackGroupId);
    return;
  } else if (card2.stackGroupId) {
    addToStack(cardId1, card2.stackGroupId);
    return;
  } else {
    // Both ungrouped — create new stack
    const gid = nextStackGroupId++;
    card1.stackGroupId = gid;
    card1.stackOrder = 0;
    card2.stackGroupId = gid;
    card2.stackOrder = 1;
    // Move card2 to card1's position
    card2.x = card1.x;
    card2.y = card1.y;
    const el2 = document.getElementById(`bc-${cardId2}`);
    if (el2) { el2.style.left = card1.x + 'px'; el2.style.top = card1.y + 'px'; }
  }

  refreshStackVisuals();
  addLogEntry(`<strong>${card1.name}</strong> and <strong>${card2.name}</strong> stacked together`);
}

function addToStack(cardId, groupId) {
  if (!gameState) return;
  pushUndoState();
  const card = gameState.battlefieldCards.find(c => c.id === cardId);
  if (!card) return;

  // If card is already in another stack, remove it first
  if (card.stackGroupId && card.stackGroupId !== groupId) {
    removeFromStack(cardId);
  }

  const existing = getStackCards(groupId);
  const leaderCard = existing.length ? existing[existing.length - 1] : null;

  card.stackGroupId = groupId;
  card.stackOrder = existing.length ? (Math.max(...existing.map(c => c.stackOrder || 0)) + 1) : 0;

  // Move to leader's position
  if (leaderCard) {
    card.x = leaderCard.x;
    card.y = leaderCard.y;
    const el = document.getElementById(`bc-${cardId}`);
    if (el) { el.style.left = card.x + 'px'; el.style.top = card.y + 'px'; }
  }

  refreshStackVisuals();
}

function removeFromStack(cardId) {
  if (!gameState) return;
  pushUndoState();
  const card = gameState.battlefieldCards.find(c => c.id === cardId);
  if (!card || !card.stackGroupId) return;

  const groupId = card.stackGroupId;
  card.stackGroupId = null;
  card.stackOrder = 0;

  // Offset the card slightly so it's visible
  card.x = (card.x || 0) + 20;
  card.y = (card.y || 0) + 20;
  const el = document.getElementById(`bc-${cardId}`);
  if (el) {
    el.style.left = card.x + 'px';
    el.style.top = card.y + 'px';
  }

  // Re-number remaining stack cards
  const remaining = getStackCards(groupId);
  if (remaining.length === 1) {
    // Only one card left — dissolve the stack
    remaining[0].stackGroupId = null;
    remaining[0].stackOrder = 0;
  } else if (remaining.length === 0) {
    // Nothing left
  }

  refreshStackVisuals();
}

function unstackAll(groupId) {
  if (!gameState) return;
  pushUndoState();
  const cards = getStackCards(groupId);
  const baseCard = cards[0];
  const baseX = baseCard ? (baseCard.x || 0) : 0;
  const baseY = baseCard ? (baseCard.y || 0) : 0;

  cards.forEach((c, i) => {
    c.stackGroupId = null;
    c.stackOrder = 0;
    c.x = baseX + i * 20;
    c.y = baseY + i * 20;
    const el = document.getElementById(`bc-${c.id}`);
    if (el) {
      el.style.left = c.x + 'px';
      el.style.top = c.y + 'px';
      el.classList.remove('stacked-hidden', 'stack-leader', 'stack-fanned');
    }
  });

  refreshStackVisuals();
  addLogEntry(`Stack of ${cards.length} cards dissolved`);
}

function refreshStackVisuals() {
  if (!gameState) return;

  // Collapse any active fan first
  collapseStackFan(true);

  // Group all stacked cards by groupId
  const groups = {};
  gameState.battlefieldCards.forEach(c => {
    if (c.stackGroupId) {
      if (!groups[c.stackGroupId]) groups[c.stackGroupId] = [];
      groups[c.stackGroupId].push(c);
    }
  });

  // First: un-mark all cards
  gameState.battlefieldCards.forEach(c => {
    const el = document.getElementById(`bc-${c.id}`);
    if (!el) return;
    el.classList.remove('stacked-hidden', 'stack-leader');
    // Remove any existing stack badge
    const badge = el.querySelector('.stack-badge');
    if (badge) badge.remove();
  });

  // Then apply stack visuals per group
  Object.entries(groups).forEach(([gid, cards]) => {
    if (cards.length < 2) {
      // Degenerate single-card stack — clean up
      cards.forEach(c => { c.stackGroupId = null; c.stackOrder = 0; });
      return;
    }
    const sorted = cards.sort((a, b) => (a.stackOrder || 0) - (b.stackOrder || 0));
    const leader = sorted[sorted.length - 1];

    sorted.forEach(c => {
      const el = document.getElementById(`bc-${c.id}`);
      if (!el) return;
      if (c.id === leader.id) {
        el.classList.add('stack-leader');
        // Add count badge
        const badge = document.createElement('span');
        badge.className = 'stack-badge';
        badge.textContent = `\u00d7${sorted.length}`;
        el.appendChild(badge);
      } else {
        el.classList.add('stacked-hidden');
      }
    });
  });
}

function collapseStackFan(immediate) {
  if (stackFanCollapseTimer) clearTimeout(stackFanCollapseTimer);
  stackFanCollapseTimer = null;

  if (!stackFanGroupId) return;
  const groupId = stackFanGroupId;
  stackFanGroupId = null;

  const cards = getStackCards(groupId);
  const leader = cards.length ? cards[cards.length - 1] : null;
  if (!leader) return;

  cards.forEach(c => {
    const el = document.getElementById(`bc-${c.id}`);
    if (!el) return;
    el.classList.remove('stack-fanned');
    if (c.id !== leader.id) {
      if (!immediate) {
        // Animate back then hide
        el.style.left = leader.x + 'px';
        el.style.top = leader.y + 'px';
        setTimeout(() => {
          if (!el.classList.contains('stack-fanned')) {
            el.classList.add('stacked-hidden');
          }
        }, 220);
      } else {
        el.classList.add('stacked-hidden');
        el.style.left = leader.x + 'px';
        el.style.top = leader.y + 'px';
      }
    }
  });
}

function fanOutStack(groupId) {
  if (!gameState) return;
  if (stackFanGroupId === groupId) return; // already fanned

  // Collapse previous fan if any
  if (stackFanGroupId && stackFanGroupId !== groupId) {
    collapseStackFan(true);
  }

  stackFanGroupId = groupId;
  const cards = getStackCards(groupId);
  const leader = cards.length ? cards[cards.length - 1] : null;
  if (!leader) return;

  const baseX = leader.x || 0;
  const baseY = leader.y || 0;

  cards.forEach((c, i) => {
    const el = document.getElementById(`bc-${c.id}`);
    if (!el) return;
    el.classList.remove('stacked-hidden');
    el.classList.add('stack-fanned');
    const fanX = baseX + i * 18;
    const fanY = baseY + i * 5;
    el.style.left = fanX + 'px';
    el.style.top = fanY + 'px';
    // Update z-index so first cards are under later ones
    el.style.zIndex = String(50 + i);
  });
}

// Stack pick mode: activated via context menu
function enterStackPickMode(sourceCardId) {
  stackPickMode = true;
  stackPickSourceId = sourceCardId;
  document.body.classList.add('stack-pick-mode');
  addLogEntry('Click any other card to stack with it.');
}

function cancelStackPickMode() {
  stackPickMode = false;
  stackPickSourceId = null;
  document.body.classList.remove('stack-pick-mode');
}

// Handle stacking when a card is clicked in pick mode
function handleStackPickClick(targetCardId) {
  if (!stackPickMode) return false;
  if (targetCardId === stackPickSourceId) {
    cancelStackPickMode();
    return true;
  }
  const sourceId = stackPickSourceId;
  cancelStackPickMode();
  createStack(sourceId, targetCardId);
  return true;
}

function setBattlefieldTypeFilter(filter) {
  bfTypeFilter = filter;
  document.querySelectorAll('.bf-type-filters .bf-filter-btn').forEach(btn => {
    btn.classList.toggle('active', btn.dataset.bfFilter === filter);
  });
  applyBattlefieldFilter();
}

function setBattlefieldOwnerFilter(ownerIdx) {
  bfOwnerFilter = ownerIdx;
  document.querySelectorAll('.bf-owner-filters .bf-filter-btn').forEach(btn => {
    btn.classList.toggle('active', btn.dataset.bfOwner === String(ownerIdx));
  });
  applyBattlefieldFilter();
}

function buildOwnerFilterButtons() {
  const container = document.getElementById('bf-owner-filters');
  if (!container || !gameState) return;

  let html = '<button class="bf-filter-btn bf-owner-btn active" data-bf-owner="all" onclick="setBattlefieldOwnerFilter(\'all\')" title="All players">All</button>';
  gameState.players.forEach((p, idx) => {
    const short = p.name.length > 6 ? p.name.substring(0, 6) : p.name;
    html += `<button class="bf-filter-btn bf-owner-btn" data-bf-owner="${idx}" onclick="setBattlefieldOwnerFilter(${idx})" title="${p.name}" style="--owner-color:${p.color}">${short}</button>`;
  });
  container.innerHTML = html;
}

function buildBattlefieldSections() {
  var container = document.getElementById('bf-sections');
  if (!container || !gameState) return;
  container.innerHTML = '';
  // Order: other players top-to-bottom (furthest first), then Player 1 at very bottom
  // For 4 players: [3, 2, 1, 0] — P4 top, P3 next, P2 next, P1 bottom
  var order = [];
  for (var i = gameState.players.length - 1; i >= 1; i--) { order.push(i); }
  order.push(0); // Player 1 always last (bottom)
  order.forEach(function(idx) {
    var p = gameState.players[idx];
    var section = document.createElement('div');
    section.className = 'bf-player-section';
    section.id = 'bf-section-' + idx;
    section.style.borderColor = p.color;

    var header = document.createElement('div');
    header.className = 'bf-section-header';
    header.innerHTML = '<span class="bf-section-dot" style="background:' + p.color + '"></span>' +
      '<span class="bf-section-name">' + p.name + '</span>' +
      '<span class="bf-section-count" id="bf-section-count-' + idx + '">0</span>';
    section.appendChild(header);

    var area = document.createElement('div');
    area.className = 'bf-section-area';
    area.id = 'bf-section-area-' + idx;
    section.appendChild(area);

    container.appendChild(section);
  });
  // Re-render zone labels if active
  if (bfZonesVisible) {
    setTimeout(function() { renderBattlefieldZoneLabels(); }, 50);
  }
}

function updateBattlefieldSectionCounts() {
  if (!gameState) return;
  gameState.players.forEach(function(p, idx) {
    var countEl = document.getElementById('bf-section-count-' + idx);
    if (!countEl) return;
    var count = gameState.battlefieldCards.filter(function(c) { return c.ownerIndex === idx; }).length;
    countEl.textContent = count;
  });
}

function cardMatchesTypeFilter(cardData, filter) {
  if (filter === 'all') return true;
  const tl = (cardData.typeLine || '').toLowerCase();

  switch (filter) {
    case 'creature':      return tl.includes('creature');
    case 'artifact':       return tl.includes('artifact') && !tl.includes('creature');
    case 'enchantment':    return tl.includes('enchantment') && !tl.includes('creature');
    case 'land':           return tl.includes('land');
    case 'planeswalker':   return tl.includes('planeswalker');
    case 'instant_sorcery': return tl.includes('instant') || tl.includes('sorcery');
    case 'token':          return !!cardData.isToken;
    default: return true;
  }
}

function applyBattlefieldFilter() {
  if (!gameState) return;
  let shown = 0;
  let total = gameState.battlefieldCards.length;

  gameState.battlefieldCards.forEach(cardData => {
    const el = document.getElementById(`bc-${cardData.id}`);
    if (!el) return;

    const matchesType = cardMatchesTypeFilter(cardData, bfTypeFilter);
    const matchesOwner = bfOwnerFilter === 'all' || cardData.ownerIndex === bfOwnerFilter;
    const visible = matchesType && matchesOwner;

    // Don't toggle bf-dimmed on stacked-hidden cards (they stay display:none)
    if (!el.classList.contains('stacked-hidden')) {
      el.classList.toggle('bf-dimmed', !visible);
    }
    if (visible) shown++;
  });

  // Update count
  const countEl = document.getElementById('bf-filter-count');
  if (countEl) {
    if (bfTypeFilter === 'all' && bfOwnerFilter === 'all') {
      countEl.textContent = total > 0 ? `${total}` : '';
    } else {
      countEl.textContent = `${shown}/${total}`;
    }
  }
}

// ============================================================
// AUTO-ARRANGE BATTLEFIELD
// ============================================================

function autoArrangeBattlefield() {
  if (!gameState || gameState.battlefieldCards.length === 0) return;
  pushUndoState('Auto-arrange battlefield');

  const CARD_W = 100;
  const CARD_H = 140;
  const GAP_X = 6;
  const GAP_Y = 6;
  const PAD_LEFT = 10;
  const PAD_TOP = 4; // offset from section area top (header already accounts for 22px)
  const PAD_BOTTOM = 10;

  // Group cards by owner
  var playerCount = gameState.players.length;
  for (var pi = 0; pi < playerCount; pi++) {
    var sectionArea = document.getElementById('bf-section-area-' + pi);
    if (!sectionArea) continue;

    var rect = sectionArea.getBoundingClientRect();
    var bfW = rect.width;
    var bfH = rect.height;

    // Categorize this player's cards by type
    var categories = [
      { key: 'land',        cards: [] },
      { key: 'creature',    cards: [] },
      { key: 'artifact',    cards: [] },
      { key: 'enchantment', cards: [] },
      { key: 'planeswalker',cards: [] },
      { key: 'other',       cards: [] },
    ];

    var catMap = {};
    categories.forEach(function(c) { catMap[c.key] = c; });

    gameState.battlefieldCards.forEach(function(card) {
      if (card.ownerIndex !== pi) return;
      // Skip stacked non-leaders (they follow their leader)
      if (card.stackGroupId && !isStackLeader(card)) return;

      var tl = (card.typeLine || '').toLowerCase();
      if (tl.includes('land'))              catMap['land'].cards.push(card);
      else if (tl.includes('creature'))     catMap['creature'].cards.push(card);
      else if (tl.includes('planeswalker')) catMap['planeswalker'].cards.push(card);
      else if (tl.includes('artifact'))     catMap['artifact'].cards.push(card);
      else if (tl.includes('enchantment'))  catMap['enchantment'].cards.push(card);
      else                                  catMap['other'].cards.push(card);
    });

    // Sort within each category by name
    categories.forEach(function(cat) {
      cat.cards.sort(function(a, b) { return (a.name || '').localeCompare(b.name || ''); });
    });

    // Filter out empty categories
    var activeCats = categories.filter(function(c) { return c.cards.length > 0; });
    if (activeCats.length === 0) continue;

    // Reverse so lands end up at the bottom
    activeCats.reverse();

    var availH = bfH - PAD_TOP - PAD_BOTTOM;
    var rowH = CARD_H + GAP_Y;
    var availW = bfW - PAD_LEFT * 2;
    var cardsPerRow = Math.max(1, Math.floor((availW + GAP_X) / (CARD_W + GAP_X)));

    var totalRows = 0;
    activeCats.forEach(function(cat) {
      totalRows += Math.ceil(cat.cards.length / cardsPerRow);
    });

    var effectiveRowH = rowH;
    var neededH = totalRows * rowH;
    if (neededH > availH && totalRows > 0) {
      effectiveRowH = Math.max(30, availH / totalRows);
    }

    // Place cards bottom-up within this section
    var cursorY = bfH - PAD_BOTTOM - CARD_H;

    activeCats.forEach(function(cat) {
      var rows = Math.ceil(cat.cards.length / cardsPerRow);
      for (var r = rows - 1; r >= 0; r--) {
        var rowStart = r * cardsPerRow;
        var rowEnd = Math.min(rowStart + cardsPerRow, cat.cards.length);
        var rowCount = rowEnd - rowStart;

        for (var i = 0; i < rowCount; i++) {
          var card = cat.cards[rowStart + i];
          var newX = PAD_LEFT + i * (CARD_W + GAP_X);
          var newY = Math.max(PAD_TOP, cursorY);

          card.x = newX;
          card.y = newY;

          var el = document.getElementById('bc-' + card.id);
          if (el) {
            el.style.transition = 'left 0.4s cubic-bezier(0.16,1,0.3,1), top 0.4s cubic-bezier(0.16,1,0.3,1)';
            el.style.left = newX + 'px';
            el.style.top = newY + 'px';
            // Clear transition after animation
            setTimeout(function(e) { return function() { e.style.transition = ''; }; }(el), 450);
          }

          // Move stacked non-leaders to the same position
          if (card.stackGroupId) {
            var stackCards = getStackCards(card.stackGroupId);
            stackCards.forEach(function(sc) {
              if (sc.id !== card.id) {
                sc.x = newX;
                sc.y = newY;
              }
            });
          }
        }
        cursorY -= effectiveRowH;
      }
      // Small gap between categories
      cursorY -= 4;
    });
  }

  addLogEntry('🔧 Battlefield auto-arranged');
}

// Battlefield drag-and-drop from search sidebar
function setupBattlefieldDrop() {
  const battlefield = document.getElementById('battlefield');
  if (!battlefield) return;

  battlefield.addEventListener('dragover', e => {
    e.preventDefault();
    e.dataTransfer.dropEffect = 'copy';
    battlefield.classList.add('drag-over');
  });

  battlefield.addEventListener('dragleave', e => {
    if (!battlefield.contains(e.relatedTarget)) {
      battlefield.classList.remove('drag-over');
    }
  });

  battlefield.addEventListener('drop', e => {
    e.preventDefault();
    battlefield.classList.remove('drag-over');

    try {
      const raw = e.dataTransfer.getData('application/json');
      if (!raw) return;
      const data = JSON.parse(raw);

      if (data.type === 'search-card') {
        var dropOwnerIdx = gameState.currentPlayerIndex;
        var dropSectionArea = document.getElementById('bf-section-area-' + dropOwnerIdx);
        var dropRect = dropSectionArea ? dropSectionArea.getBoundingClientRect() : battlefield.getBoundingClientRect();
        const x = e.clientX - dropRect.left - 35;
        const y = e.clientY - dropRect.top - 49;
        addCardToBattlefield(
          data.card.name,
          data.card.imageUrl,
          data.card.typeLine,
          gameState.currentPlayerIndex,
          Math.max(0, x),
          Math.max(0, y),
          data.card.oracleText || '',
          { manaCost: data.card.manaCost || '' }
        );
      }
    } catch(err) { /* ignore */ }
  });
}

