// contextMenuTargetId declared in ui.js

function showContextMenu(x, y, cardId) {
  const menu = document.getElementById('context-menu');
  if (!menu) return;
  contextMenuTargetId = cardId;

  // Dynamically inject stack section based on card state
  const stackSection = menu.querySelector('.ctx-stack-section');
  if (stackSection && gameState) {
    const card = gameState.battlefieldCards.find(c => c.id === cardId);
    const isStacked = card && card.stackGroupId;
    stackSection.innerHTML = `
      <div class="context-menu-divider"></div>
      ${!isStacked
        ? `<button class="context-menu-item" onclick="(function(){var id=contextMenuTargetId;hideContextMenu();enterStackPickMode(id)})()">&#x1F4DA; Stack With Next Click</button>`
        : `<button class="context-menu-item" onclick="(function(){var id=contextMenuTargetId;hideContextMenu();enterStackPickMode(id)})()">&#x1F4DA; Add to Another Stack</button>`
      }
      ${isStacked
        ? `<button class="context-menu-item" onclick="(function(){var id=contextMenuTargetId;hideContextMenu();removeFromStack(id);addLogEntry('Card removed from stack')})()">&#x1F4E4; Unstack This Card</button>`
        : ''
      }
      ${isStacked
        ? `<button class="context-menu-item" onclick="(function(){var id=contextMenuTargetId;hideContextMenu();var cd=gameState.battlefieldCards.find(function(c){return c.id===id});if(cd&&cd.stackGroupId)unstackAll(cd.stackGroupId)})()">&#x1F4E4; Unstack All</button>`
        : ''
      }
    `;
  }

  // Dynamically inject equip section based on card type
  var equipSection = menu.querySelector('.ctx-equip-section');
  if (equipSection && gameState) {
    var eCard = gameState.battlefieldCards.find(function(c) { return c.id === cardId; });
    var equipHtml = '';
    if (eCard && isAttachable(eCard)) {
      var isAuraCard = isAura(eCard);
      var actionWord = isAuraCard ? 'Enchant' : 'Equip';
      var detachWord = isAuraCard ? 'Remove Aura' : 'Unequip';
      var icon = isAuraCard ? '\u2728' : '\u2694';
      equipHtml += '<div class="context-menu-divider"></div>';
      if (eCard.attachedTo) {
        var attachedCreature = gameState.battlefieldCards.find(function(c) { return c.id === eCard.attachedTo; });
        equipHtml += '<button class="context-menu-item" onclick="(function(){var id=contextMenuTargetId;hideContextMenu();detachEquipment(id)})()">' +
          icon + ' ' + detachWord + (attachedCreature ? ' from ' + attachedCreature.name : '') + '</button>';
        equipHtml += '<button class="context-menu-item" onclick="(function(){var id=contextMenuTargetId;hideContextMenu();enterEquipPickMode(id)})()">' +
          icon + ' Attach to Different Creature</button>';
      } else {
        equipHtml += '<button class="context-menu-item" onclick="(function(){var id=contextMenuTargetId;hideContextMenu();enterEquipPickMode(id)})()">' +
          icon + ' ' + actionWord + ' Creature</button>';
      }
    }
    // If card is a creature with attachments, show list
    if (eCard && eCard.attachments && eCard.attachments.length > 0) {
      equipHtml += '<div class="context-menu-divider"></div>';
      for (var ai = 0; ai < eCard.attachments.length; ai++) {
        var att = gameState.battlefieldCards.find(function(c) { return c.id === eCard.attachments[ai]; });
        if (att) {
          var attIcon = isAura(att) ? '\u2728' : '\u2694';
          var attLabel = isAura(att) ? 'Remove Aura ' : 'Unequip ';
          equipHtml += '<button class="context-menu-item" onclick="(function(){hideContextMenu();detachEquipment(' + att.id + ')})()">' +
            attIcon + ' ' + attLabel + att.name + '</button>';
        }
      }
    }
    equipSection.innerHTML = equipHtml;
  }

  // For tokens: replace zone buttons with "Destroy (cease to exist)" since tokens
  // cannot go to graveyard, hand, exile, or library per MTG rules
  if (gameState) {
    const card = gameState.battlefieldCards.find(c => c.id === cardId);
    if (card && card.isToken) {
      const gyBtn = menu.querySelector('[data-action="graveyard"]');
      const exBtn = menu.querySelector('[data-action="exile"]');
      const handBtn = menu.querySelector('[data-action="hand"]');
      const libTopBtn = menu.querySelector('[data-action="library-top"]');
      const libBotBtn = menu.querySelector('[data-action="library-bottom"]');
      if (gyBtn) gyBtn.innerHTML = '☠ Destroy (dies)';
      if (exBtn) exBtn.innerHTML = '⬡ Exile (cease to exist)';
      if (handBtn) handBtn.innerHTML = '✋ Bounce (cease to exist)';
      if (libTopBtn) libTopBtn.style.display = 'none';
      if (libBotBtn) libBotBtn.style.display = 'none';

      // Token batch operations section
      var existingTokenOps = menu.querySelector('.ctx-token-ops');
      if (existingTokenOps) existingTokenOps.remove();
      // Also remove non-token sections if present
      var existingCopySect = menu.querySelector('.ctx-token-copy-section');
      if (existingCopySect) existingCopySect.remove();
      var existingSmartSect = menu.querySelector('.ctx-smart-token-section');
      if (existingSmartSect) existingSmartSect.remove();
      var existingPwSect = menu.querySelector('.ctx-pw-section');
      if (existingPwSect) existingPwSect.remove();
      var tokenOpsDiv = document.createElement('div');
      tokenOpsDiv.className = 'ctx-token-ops context-menu-section';
      var tokenDispName = card.name.replace(/ Token$/, '');
      var ownerIdxForToken = card.ownerIndex;
      tokenOpsDiv.innerHTML =
        '<div class="context-menu-separator"></div>' +
        '<div class="context-menu-section-label">Token Actions</div>' +
        '<button class="context-menu-item token-quick-create" onclick="(function(){var id=contextMenuTargetId;hideContextMenu();createAnotherToken(id)})()">\u2728 Create Another ' + tokenDispName + '</button>' +
        '<button class="context-menu-item token-quick-create" onclick="(function(){var id=contextMenuTargetId;hideContextMenu();createXMoreTokens(id)})()">\u2728 Create X More...</button>' +
        '<button class="context-menu-item token-quick-create danger" onclick="(function(){var id=contextMenuTargetId;hideContextMenu();destroyAllTokensByNameFromCtx(id)})()">&#x1F5D1; Destroy All ' + tokenDispName + '</button>';
      menu.appendChild(tokenOpsDiv);
    } else {
      // Remove token ops if present
      var existingTokenOps2 = menu.querySelector('.ctx-token-ops');
      if (existingTokenOps2) existingTokenOps2.remove();
      // Restore defaults for non-tokens (since menu is reused)
      const gyBtn = menu.querySelector('[data-action="graveyard"]');
      const exBtn = menu.querySelector('[data-action="exile"]');
      const handBtn = menu.querySelector('[data-action="hand"]');
      const libTopBtn = menu.querySelector('[data-action="library-top"]');
      const libBotBtn = menu.querySelector('[data-action="library-bottom"]');
      if (gyBtn) gyBtn.innerHTML = '☠ Send to Graveyard';
      if (exBtn) exBtn.innerHTML = '⬡ Send to Exile';
      if (handBtn) handBtn.innerHTML = '✋ Return to Hand';
      if (libTopBtn) libTopBtn.style.display = '';
      if (libBotBtn) libBotBtn.style.display = '';

      // Non-token creature: add "Create Token Copy" for creatures
      var existingCopySection = menu.querySelector('.ctx-token-copy-section');
      if (existingCopySection) existingCopySection.remove();
      var existingSmartToken = menu.querySelector('.ctx-smart-token-section');
      if (existingSmartToken) existingSmartToken.remove();

      var ctCard = gameState && gameState.battlefieldCards.find(function(c) { return c.id === cardId; });
      if (ctCard) {
        // Planeswalker: Activate Loyalty Ability button
        if (ctCard.typeLine && /planeswalker/i.test(ctCard.typeLine)) {
          var existingPwSection = menu.querySelector('.ctx-pw-section');
          if (existingPwSection) existingPwSection.remove();
          var pwSection = document.createElement('div');
          pwSection.className = 'ctx-pw-section context-menu-section';
          var pwLoyalty = (ctCard.counters && ctCard.counters['loyalty']) || 0;
          var usedLabel = ctCard.loyaltyUsedThisTurn ? ' (used this turn)' : '';
          var usedClass = ctCard.loyaltyUsedThisTurn ? ' context-menu-item-disabled' : '';
          pwSection.innerHTML =
            '<div class="context-menu-separator"></div>' +
            '<div class="context-menu-section-label">Planeswalker (\u25c6' + pwLoyalty + ')' + usedLabel + '</div>' +
            '<button class="context-menu-item pw-activate-btn' + usedClass + '" onclick="(function(){var id=contextMenuTargetId;hideContextMenu();showPlaneswalkerAbilities(id)})()">\u25c6 Activate Loyalty Ability</button>';
          menu.appendChild(pwSection);
        } else {
          var existingPwSection2 = menu.querySelector('.ctx-pw-section');
          if (existingPwSection2) existingPwSection2.remove();
        }

        // Token copy button for creatures
        if (ctCard.typeLine && /creature/i.test(ctCard.typeLine)) {
          var copySection = document.createElement('div');
          copySection.className = 'ctx-token-copy-section context-menu-section';
          copySection.innerHTML =
            '<div class="context-menu-separator"></div>' +
            '<button class="context-menu-item token-quick-create" onclick="(function(){var id=contextMenuTargetId;hideContextMenu();createTokenCopy(id)})()">&#x1F4CB; Create Token Copy</button>';
          menu.appendChild(copySection);
        }

        // Smart token suggestions from oracle text
        var smartTokens = parseTokenCreationAbilities(ctCard.oracleText || '');
        if (smartTokens.length > 0) {
          var smartSection = document.createElement('div');
          smartSection.className = 'ctx-smart-token-section context-menu-section';
          var smartHtml = '<div class="context-menu-separator"></div><div class="context-menu-section-label">Create Tokens</div>';
          smartTokens.forEach(function(t) {
            var ownerIdx2 = ctCard.ownerIndex;
            var safeN = t.name.replace(/'/g, "\\'").replace(/"/g, '&quot;');
            var safeTl = t.typeLine.replace(/'/g, "\\'").replace(/"/g, '&quot;').replace(/\u2014/g, '-');
            var safeAb = (t.abilities || '').replace(/'/g, "\\'").replace(/"/g, '&quot;');
            smartHtml += '<button class="context-menu-item token-quick-create" onclick="(function(){hideContextMenu();createQuickToken(' + ownerIdx2 + ',\'' + safeN + '\',\'' + t.power + '\',\'' + t.toughness + '\',\'' + safeTl + '\',\'' + t.color + '\',\'' + safeAb + '\',' + t.count + ')})()">\u2728 Create: ' + t.displayLabel + '</button>';
          });
          smartSection.innerHTML = smartHtml;
          menu.appendChild(smartSection);
        }
      }
    }
  }

  // Feature 6: Show targeting restriction badge in context menu header
  if (gameState) {
    var tCard = gameState.battlefieldCards.find(function(c) { return c.id === cardId; });
    var existingTWarn = menu.querySelector('.ctx-targeting-warn');
    if (existingTWarn) existingTWarn.remove();
    if (tCard) {
      var protKws = getCardProtectionKeywords(tCard);
      if (protKws.length > 0) {
        var activeOwnerId = gameState.currentPlayerIndex;
        var tResult = canTarget(activeOwnerId, cardId);
        var warnDiv = document.createElement('div');
        warnDiv.className = 'ctx-targeting-warn';
        if (!tResult.allowed) {
          warnDiv.innerHTML = '🚫 <strong>Targeting restricted:</strong> ' + protKws.join(', ');
          warnDiv.classList.add('ctx-targeting-warn-blocked');
        } else {
          warnDiv.innerHTML = 'ℹ <strong>Keywords:</strong> ' + protKws.join(', ');
        }
        menu.insertBefore(warnDiv, menu.firstChild);
      }
    }
  }

  // Dim the Tap/Untap button when creature has summoning sickness
  if (gameState && gameState.rulesEngine && gameState.rulesEngine.enforceTurnStructure) {
    var sickCard = gameState.battlefieldCards.find(function(c) { return c.id === cardId; });
    var tapBtn = menu.querySelector('[data-action="tap"]');
    if (tapBtn && sickCard && !sickCard.tapped && hasSummoningSickness(sickCard)) {
      tapBtn.innerHTML = '\u26a0 Tap (Summoning Sickness)';
      tapBtn.style.opacity = '0.45';
      tapBtn.style.color = '#b388ff';
    } else if (tapBtn) {
      tapBtn.innerHTML = '\u27f3 Tap / Untap';
      tapBtn.style.opacity = '';
      tapBtn.style.color = '';
    }
  }

  // ---- Activated Abilities & Tap for Mana section ----
  if (gameState) {
    var abCard = gameState.battlefieldCards.find(function(c) { return c.id === cardId; });
    if (abCard) {
      var forgeSection = document.createElement('div');
      forgeSection.className = 'ctx-forge-section context-menu-section';
      var forgeHtml = '<div class="context-menu-separator"></div>';
      forgeHtml += '<div class="context-menu-section-label">Abilities & Mana</div>';

      // Check if card is a land for "Tap for Mana"
      var abTypeLine = (abCard.typeLine || '').toLowerCase();
      if (abTypeLine.indexOf('land') !== -1) {
        var tapDisabled = abCard.tapped ? ' context-menu-item-disabled' : '';
        forgeHtml += '<button class="context-menu-item' + tapDisabled + '" onclick="(function(){var id=contextMenuTargetId;hideContextMenu();tapLandForMana(id)})()">';
        forgeHtml += '\uD83D\uDCA7 Tap for Mana' + (abCard.tapped ? ' (tapped)' : '') + '</button>';
      }

      // Check if card has activated abilities
      var parsedAbs = parseActivatedAbilities(abCard);
      if (parsedAbs && parsedAbs.length > 0) {
        forgeHtml += '<button class="context-menu-item" onclick="(function(){var id=contextMenuTargetId;hideContextMenu();showActivatedAbilitiesPanel(id)})()">';
        forgeHtml += '\u26A1 Activate Ability (' + parsedAbs.length + ')</button>';
      }

      // Add mana manually button (for any card that might add mana)
      var oText = (abCard.oracleText || '').toLowerCase();
      if (oText.indexOf('add') !== -1 && /\{[wubrgc]\}/i.test(oText) && abTypeLine.indexOf('land') === -1) {
        var mTapDisabled = abCard.tapped ? ' context-menu-item-disabled' : '';
        forgeHtml += '<button class="context-menu-item' + mTapDisabled + '" onclick="(function(){var id=contextMenuTargetId;hideContextMenu();tapLandForMana(id)})()">';
        forgeHtml += '\uD83D\uDCA7 Tap for Mana (non-land)</button>';
      }

      // Show damage marked on creature
      if (abCard.damageMarked && abCard.damageMarked > 0) {
        forgeHtml += '<div class="context-menu-info-row">\uD83D\uDCA5 Damage marked: ' + abCard.damageMarked + '</div>';
      }

      forgeHtml += '</div>';
      forgeSection.innerHTML = forgeHtml;
      menu.appendChild(forgeSection);
    }
  }

  menu.style.left = Math.min(x, window.innerWidth - 220) + 'px';
  menu.style.top = Math.min(y, window.innerHeight - 350) + 'px';
  menu.classList.add('visible');
}

function hideContextMenu() {
  const menu = document.getElementById('context-menu');
  if (menu) menu.classList.remove('visible');
  contextMenuTargetId = null;
}

function toggleTap(cardId) {
  pushUndoState();
  const cardData = gameState.battlefieldCards.find(c => c.id === cardId);
  if (!cardData) return;
  // Block tapping creatures with summoning sickness (allow untapping)
  if (!cardData.tapped && hasSummoningSickness(cardData) && gameState.rulesEngine && gameState.rulesEngine.enforceTurnStructure) {
    addLogEntry('<span style="color:#b388ff">\u26a0 <strong>' + cardData.name + '</strong> has summoning sickness and cannot be tapped.</span>');
    return;
  }
  cardData.tapped = !cardData.tapped;
  const cardEl = document.getElementById(`bc-${cardId}`);
  if (cardEl) {
    cardEl.classList.toggle('tapped', cardData.tapped);
  }
  addLogEntry(`<strong>${cardData.name}</strong> ${cardData.tapped ? 'tapped' : 'untapped'}`);

  // Auto-tally mana when tapping a mana-producing permanent
  if (cardData.tapped) {
    handleManaOnTap(cardData);
  }
}

function toggleFaceDown(cardId) {
  pushUndoState();
  const cardData = gameState.battlefieldCards.find(c => c.id === cardId);
  if (!cardData) return;
  cardData.faceDown = !cardData.faceDown;
  const cardEl = document.getElementById(`bc-${cardId}`);
  if (cardEl) {
    cardEl.classList.toggle('face-down', cardData.faceDown);
  }
  addLogEntry(`A card was turned face ${cardData.faceDown ? 'down' : 'up'}`);
}

// ============================================================
// +1/+1 AND -1/-1 COUNTERS
// ============================================================

// ---- Generic Counter System ----

/** Add a counter of any type to a battlefield card */
function addCounter(cardId, counterType, amount) {
  const cardData = gameState.battlefieldCards.find(c => c.id === cardId);
  if (!cardData) return;
  if (!cardData.counters) cardData.counters = {};
  if (!cardData.counters[counterType]) cardData.counters[counterType] = 0;
  cardData.counters[counterType] += (amount || 1);
  // Sync legacy fields
  if (counterType === '+1/+1') cardData.plusCounters = cardData.counters['+1/+1'];
  if (counterType === '-1/-1') cardData.minusCounters = cardData.counters['-1/-1'];
  updateCardCounterBadge(cardId);
  const ct = COUNTER_TYPES[counterType] || { icon: '●', color: '#9ca3af', label: counterType };
  addLogEntry('<strong>' + cardData.name + '</strong> got a <span style="color:' + ct.color + '">' + ct.label + '</span> counter (' + cardData.counters[counterType] + ' total)');
}

/** Remove a counter of any type from a battlefield card */
function removeCounter(cardId, counterType, amount) {
  const cardData = gameState.battlefieldCards.find(c => c.id === cardId);
  if (!cardData || !cardData.counters || !cardData.counters[counterType] || cardData.counters[counterType] <= 0) return;
  cardData.counters[counterType] = Math.max(0, cardData.counters[counterType] - (amount || 1));
  if (cardData.counters[counterType] === 0) delete cardData.counters[counterType];
  // Sync legacy fields
  if (counterType === '+1/+1') cardData.plusCounters = cardData.counters['+1/+1'] || 0;
  if (counterType === '-1/-1') cardData.minusCounters = cardData.counters['-1/-1'] || 0;
  updateCardCounterBadge(cardId);
  const ct = COUNTER_TYPES[counterType] || { icon: '●', color: '#9ca3af', label: counterType };
  const remaining = (cardData.counters && cardData.counters[counterType]) || 0;
  addLogEntry('<strong>' + cardData.name + '</strong> lost a <span style="color:' + ct.color + '">' + ct.label + '</span> counter (' + remaining + ' remaining)');
}

/** Legacy wrappers for backward compatibility */
function addPlusCounter(cardId) { addCounter(cardId, '+1/+1'); }
function removePlusCounter(cardId) { removeCounter(cardId, '+1/+1'); }
function addMinusCounter(cardId) { addCounter(cardId, '-1/-1'); }
function removeMinusCounter(cardId) { removeCounter(cardId, '-1/-1'); }

/** Show the counter picker popover for a card */
function showCounterPicker(cardId) {
  hideContextMenu();
  const cardData = gameState.battlefieldCards.find(c => c.id === cardId);
  const cardEl = document.getElementById('bc-' + cardId);
  if (!cardData || !cardEl) return;

  // Remove any existing picker
  var old = document.getElementById('counter-picker');
  if (old) old.remove();

  var picker = document.createElement('div');
  picker.id = 'counter-picker';
  picker.className = 'counter-picker';

  // Position near the card
  var rect = cardEl.getBoundingClientRect();
  picker.style.left = Math.min(rect.right + 8, window.innerWidth - 260) + 'px';
  picker.style.top = Math.max(rect.top, 8) + 'px';

  // Header
  var header = '<div class="counter-picker-header">';
  header += '<span class="counter-picker-title">Counters: ' + cardData.name + '</span>';
  header += '<button class="counter-picker-close" onclick="closeCounterPicker()">✕</button>';
  header += '</div>';

  // Current counters on this card
  var currentHtml = '';
  if (cardData.counters && Object.keys(cardData.counters).length > 0) {
    currentHtml = '<div class="counter-picker-current">';
    for (var type in cardData.counters) {
      if (cardData.counters[type] <= 0) continue;
      var ct = COUNTER_TYPES[type] || { icon: '●', color: '#9ca3af', label: type, shortLabel: type };
      currentHtml += '<div class="counter-picker-row">';
      currentHtml += '<span class="counter-picker-row-label" style="color:' + ct.color + '">' + ct.icon + ' ' + ct.label + '</span>';
      currentHtml += '<div class="counter-picker-row-controls">';
      currentHtml += '<button class="counter-picker-btn minus" onclick="removeCounter(\'' + cardId + '\',\'' + type + '\');refreshCounterPicker(\'' + cardId + '\')">−</button>';
      currentHtml += '<span class="counter-picker-row-count">' + cardData.counters[type] + '</span>';
      currentHtml += '<button class="counter-picker-btn plus" onclick="addCounter(\'' + cardId + '\',\'' + type + '\');refreshCounterPicker(\'' + cardId + '\')">+</button>';
      currentHtml += '</div>';
      currentHtml += '</div>';
    }
    currentHtml += '</div>';
  }

  // Quick-add grid of common counters
  var gridHtml = '<div class="counter-picker-grid">';
  var commonTypes = ['+1/+1', '-1/-1', 'loyalty', 'charge', 'shield', 'time', 'lore', 'ki', 'quest', 'energy', 'experience', 'bounty'];
  for (var i = 0; i < commonTypes.length; i++) {
    var t = commonTypes[i];
    var ct = COUNTER_TYPES[t];
    var has = (cardData.counters && cardData.counters[t]) ? ' has' : '';
    gridHtml += '<button class="counter-picker-quick' + has + '" style="--cpc-color:' + ct.color + '" ';
    gridHtml += 'onclick="addCounter(\'' + cardId + '\',\'' + t + '\');refreshCounterPicker(\'' + cardId + '\')" ';
    gridHtml += 'title="Add ' + ct.label + ' counter">';
    gridHtml += '<span class="counter-picker-quick-icon">' + ct.icon + '</span>';
    gridHtml += '<span class="counter-picker-quick-label">' + ct.shortLabel + '</span>';
    gridHtml += '</button>';
  }
  gridHtml += '</div>';

  // Custom counter input
  var customHtml = '<div class="counter-picker-custom">';
  customHtml += '<input type="text" id="custom-counter-name" class="counter-picker-input" placeholder="Custom type..." maxlength="20" />';
  customHtml += '<button class="counter-picker-btn plus" onclick="var n=document.getElementById(\'custom-counter-name\');if(n&&n.value.trim()){addCounter(\'' + cardId + '\',n.value.trim().toLowerCase());refreshCounterPicker(\'' + cardId + '\');n.value=\'\';}">Add</button>';
  customHtml += '</div>';

  picker.innerHTML = header + currentHtml + '<div class="counter-picker-label">Add Counter</div>' + gridHtml + customHtml;

  document.body.appendChild(picker);

  // Close on outside click (delay to avoid immediate close)
  setTimeout(function() {
    document.addEventListener('mousedown', counterPickerOutsideClick);
  }, 50);
}

function counterPickerOutsideClick(e) {
  var picker = document.getElementById('counter-picker');
  if (picker && !picker.contains(e.target)) {
    closeCounterPicker();
  }
}

function closeCounterPicker() {
  var picker = document.getElementById('counter-picker');
  if (picker) picker.remove();
  document.removeEventListener('mousedown', counterPickerOutsideClick);
}

function refreshCounterPicker(cardId) {
  closeCounterPicker();
  showCounterPicker(cardId);
}

function updateCardCounterBadge(cardId) {
  const cardData = gameState.battlefieldCards.find(c => c.id === cardId);
  const cardEl = document.getElementById('bc-' + cardId);
  if (!cardData || !cardEl) return;

  // Remove existing counter badge container
  const existing = cardEl.querySelector('.card-counters-strip');
  if (existing) existing.remove();

  // Migrate legacy plusCounters/minusCounters into counters map if needed
  if (!cardData.counters) cardData.counters = {};
  if (cardData.plusCounters > 0 && !cardData.counters['+1/+1']) cardData.counters['+1/+1'] = cardData.plusCounters;
  if (cardData.minusCounters > 0 && !cardData.counters['-1/-1']) cardData.counters['-1/-1'] = cardData.minusCounters;

  var types = Object.keys(cardData.counters).filter(function(k) { return cardData.counters[k] > 0; });
  if (types.length === 0) return;

  var strip = document.createElement('div');
  strip.className = 'card-counters-strip';

  for (var i = 0; i < types.length; i++) {
    var type = types[i];
    var count = cardData.counters[type];
    var ct = COUNTER_TYPES[type] || { icon: '●', color: '#9ca3af', label: type, shortLabel: type.substring(0, 3) };
    var badge = document.createElement('span');
    badge.className = 'card-counter-badge';
    badge.style.background = ct.color;
    badge.style.color = '#fff';
    badge.title = count + ' ' + ct.label + ' counter' + (count > 1 ? 's' : '');
    if (type === '+1/+1') {
      badge.textContent = '+' + count + '/+' + count;
    } else if (type === '-1/-1') {
      badge.textContent = '-' + count + '/-' + count;
    } else {
      badge.textContent = ct.icon + count;
    }
    strip.appendChild(badge);
  }
  cardEl.appendChild(strip);
}

// Remove a card from its stack (if any) before it leaves the battlefield
function cleanupCardFromStack(cardId) {
  if (!gameState) return;
  const card = gameState.battlefieldCards.find(c => c.id === cardId);
  if (!card || !card.stackGroupId) return;
  const groupId = card.stackGroupId;
  card.stackGroupId = null;
  card.stackOrder = 0;
  // Clean up remaining stack
  const remaining = getStackCards(groupId);
  if (remaining.length === 1) {
    remaining[0].stackGroupId = null;
    remaining[0].stackOrder = 0;
  }
  // Refresh visuals for remaining stack members
  if (remaining.length >= 2) {
    // Reassign orders cleanly
    remaining.forEach((c, i) => { c.stackOrder = i; });
    refreshStackVisuals();
  } else {
    // Clean up the last card's visuals
    if (remaining.length === 1) {
      const el = document.getElementById(`bc-${remaining[0].id}`);
      if (el) {
        el.classList.remove('stacked-hidden', 'stack-leader', 'stack-fanned');
        const badge = el.querySelector('.stack-badge');
        if (badge) badge.remove();
      }
    }
  }
}

function moveCardToZone(cardId, zone) {
  pushUndoState("Move card to " + zone);
  const idx = gameState.battlefieldCards.findIndex(c => c.id === cardId);
  if (idx === -1) return;
  const cardData = gameState.battlefieldCards[idx];
  const owner = gameState.players[cardData.ownerIndex];
  if (!owner) return;

  // Apply replacement effects for death/graveyard
  if (zone === 'graveyard') {
    var dieEvent = applyReplacements('die', {
      cardId: cardId,
      cardName: cardData.name,
      ownerIndex: cardData.ownerIndex,
      isToken: !!cardData.isToken,
      destination: 'graveyard'
    });
    if (dieEvent && dieEvent.destination && dieEvent.destination !== 'graveyard') {
      zone = dieEvent.destination; // Redirect (e.g., exile instead of graveyard)
    }
  }

  // Remove replacement effects sourced from this card
  removeReplacementEffects(cardId);

  // Clean up stack membership before leaving battlefield
  cleanupCardFromStack(cardId);

  // Detach all equipment/auras from this creature, or detach this equipment from its creature
  if (cardData.attachments && cardData.attachments.length > 0) {
    detachAllFromCreature(cardId);
  }
  if (cardData.attachedTo) {
    detachEquipment(cardId, true);
  }

  // Commander zone replacement rule
  if (gameState.rulesEngine && gameState.rulesEngine.commanderZoneReplacement && isCommander(cardData) && (zone === 'graveyard' || zone === 'exile')) {
    // AI always sends commander back to command zone
    if (owner.isAI) {
      var prev = gameState.rulesEngine.commanderZoneReplacement;
      gameState.rulesEngine.commanderZoneReplacement = false;
      moveCardToZone(cardId, 'command');
      gameState.rulesEngine.commanderZoneReplacement = prev;
      addLogEntry('\u{1F916} \u{1F451} <strong>' + owner.name + '</strong> returns commander to command zone');
      return;
    }
    showCommanderZonePrompt(cardId, cardData, zone);
    return;
  }

  // Tokens cease to exist when they leave the battlefield (MTG rules)
  if (cardData.isToken) {
    // Still fire LTB/dies triggers
    fireBattlefieldTriggers('ltb', function(bfCard) {
      return bfCard.id !== cardData.id;
    });
    fireCardTriggers(cardData, ['ltb']);
    if (zone === 'graveyard') {
      fireBattlefieldTriggers('dies', function(bfCard) {
        return bfCard.id !== cardData.id;
      });
      fireCardTriggers(cardData, ['dies']);
    }

    gameState.battlefieldCards.splice(idx, 1);
    const cardEl = document.getElementById(`bc-${cardId}`);
    if (cardEl) {
      var exitDur = animateCardExit(cardEl, zone);
      setTimeout(function() { if (cardEl.parentNode) cardEl.remove(); }, exitDur || 350);
    }
    addLogEntry(`<strong>${cardData.name}</strong> ceased to exist (token)`);
    if (!gameState.battlefieldCards.length) {
      const label = document.querySelector('.battlefield-label');
      if (label) label.style.opacity = '';
    }
    updateBattlefieldSectionCounts();
    updatePlayerZones();
    updateTokenSummaryBar();
    return;
  }

  // Add to zone (preserve card data for tooltips and returning to battlefield)
  owner.zones[zone].push({
    name: cardData.name,
    imageUrl: cardData.imageUrl,
    typeLine: cardData.typeLine,
    oracleText: cardData.oracleText || '',
    manaCost: cardData.manaCost || '',
    power: cardData.power,
    toughness: cardData.toughness,
    loyalty: cardData.loyalty,
  });

  // Fire LTB triggers on ALL battlefield permanents watching for leaves
  fireBattlefieldTriggers('ltb', function(bfCard) {
    return bfCard.id !== cardData.id;
  });
  // Fire the leaving card's own LTB trigger
  fireCardTriggers(cardData, ['ltb']);

  // Fire dies triggers if going to graveyard
  if (zone === 'graveyard') {
    fireBattlefieldTriggers('dies', function(bfCard) {
      return bfCard.id !== cardData.id;
    });
    fireCardTriggers(cardData, ['dies']);
  }

  // Remove from battlefield
  gameState.battlefieldCards.splice(idx, 1);
  const cardEl = document.getElementById(`bc-${cardId}`);
  if (cardEl) {
    var exitDur2 = animateCardExit(cardEl, zone);
    setTimeout(function() { if (cardEl.parentNode) cardEl.remove(); }, exitDur2 || 350);
  }

  const zoneLabels = { graveyard: 'Graveyard', exile: 'Exile', hand: 'Hand', library: 'Library' };
  addLogEntry(`<strong>${cardData.name}</strong> sent to <strong>${owner.name}'s ${zoneLabels[zone] || zone}</strong>`);

  // Re-show label if battlefield is empty
  if (!gameState.battlefieldCards.length) {
    const label = document.querySelector('.battlefield-label');
    if (label) label.style.opacity = '';
  }

  updateBattlefieldSectionCounts();
  updatePlayerZones();

  // Check SBAs after zone change (token cleanup, toughness, etc.)
  if (gameState.rulesEngine && gameState.rulesEngine.sbaChecks) checkStateBasedActions();
}

function removeCardFromBattlefield(cardId) {
  pushUndoState('Remove card from battlefield');
  const idx = gameState.battlefieldCards.findIndex(c => c.id === cardId);
  if (idx === -1) return;
  const cardData = gameState.battlefieldCards[idx];
  // Clean up stack membership before removing
  cleanupCardFromStack(cardId);
  // Detach equipment
  if (cardData.attachments && cardData.attachments.length > 0) detachAllFromCreature(cardId);
  if (cardData.attachedTo) detachEquipment(cardId, true);
  gameState.battlefieldCards.splice(idx, 1);
  const cardEl = document.getElementById(`bc-${cardId}`);
  if (cardEl) cardEl.remove();
  addLogEntry(`<strong>${cardData.name}</strong> removed from battlefield`);
  if (!gameState.battlefieldCards.length) {
    const label = document.querySelector('.battlefield-label');
    if (label) label.style.opacity = '';
  }
  updateBattlefieldSectionCounts();
}

// ============================================================
// CONTEXT MENU SETUP
// ============================================================

function setupContextMenu() {
  const menu = document.getElementById('context-menu');
  if (!menu) return;

  menu.innerHTML = `
    <button class="context-menu-item" data-action="tap" onclick="(function(){var id=contextMenuTargetId;hideContextMenu();toggleTap(id)})()">⟳ Tap / Untap</button>
    <button class="context-menu-item" data-action="facedown" onclick="(function(){var id=contextMenuTargetId;hideContextMenu();toggleFaceDown(id)})()">◻ Flip Face Down/Up</button>
    <div class="context-menu-divider"></div>
    <div class="context-menu-counter-row">
      <button class="context-menu-counter-btn plus" onclick="(function(){var id=contextMenuTargetId;hideContextMenu();addCounter(id,'+1/+1')})()" title="Add +1/+1 counter">+1</button>
      <button class="context-menu-counter-btn minus" onclick="(function(){var id=contextMenuTargetId;hideContextMenu();addCounter(id,'-1/-1')})()" title="Add -1/-1 counter">-1</button>
      <button class="context-menu-item" style="flex:1" onclick="(function(){var id=contextMenuTargetId;hideContextMenu();showCounterPicker(id)})()">🔢 All Counters...</button>
    </div>
    <div class="context-menu-divider"></div>
    <button class="context-menu-item" data-action="view-abilities" onclick="(function(){var id=contextMenuTargetId;hideContextMenu();var cd=gameState.battlefieldCards.find(function(c){return c.id===id});var el=document.getElementById('bc-'+id);if(cd&&el)showAbilitiesPanel(cd,el)})()">📖 View Abilities</button>
    <button class="context-menu-item" data-action="declare-attacker" id="ctx-attacker" onclick="(function(){var id=contextMenuTargetId;hideContextMenu();toggleAttacker(id)})()">⚔ Toggle Attacker</button>
    <div class="context-menu-divider"></div>
    <button class="context-menu-item" data-action="graveyard" onclick="(function(){var id=contextMenuTargetId;hideContextMenu();moveCardToZone(id,'graveyard')})()">☠ Send to Graveyard</button>
    <button class="context-menu-item" data-action="exile" onclick="(function(){var id=contextMenuTargetId;hideContextMenu();moveCardToZone(id,'exile')})()">⬡ Send to Exile</button>
    <button class="context-menu-item" data-action="hand" onclick="(function(){var id=contextMenuTargetId;hideContextMenu();moveCardToZone(id,'hand')})()">✋ Return to Hand</button>
    <button class="context-menu-item" data-action="library-top" onclick="(function(){var id=contextMenuTargetId;hideContextMenu();moveCardToLibrary(id,'top')})()">📚 Put on Top of Library</button>
    <button class="context-menu-item" data-action="library-bottom" onclick="(function(){var id=contextMenuTargetId;hideContextMenu();moveCardToLibrary(id,'bottom')})()">📚 Put on Bottom of Library</button>
    <div class="ctx-stack-section"></div>
    <div class="ctx-equip-section"></div>
    <div class="context-menu-divider"></div>
    <button class="context-menu-item" onclick="(function(){var id=contextMenuTargetId;hideContextMenu();sacrificeCard(id)})()">💀 Sacrifice</button>
    <button class="context-menu-item danger" data-action="remove" onclick="(function(){var id=contextMenuTargetId;hideContextMenu();removeCardFromBattlefield(id)})()">✕ Remove</button>
  `;

  menu.querySelectorAll('[data-action]').forEach(btn => {
    btn.addEventListener('click', () => {
      const action = btn.dataset.action;
      const id = contextMenuTargetId;
      hideContextMenu();
      if (!id) return;
      switch(action) {
        case 'tap': toggleTap(id); break;
        case 'facedown': toggleFaceDown(id); break;
        case 'declare-attacker': toggleAttacker(id); break;
        case 'view-abilities': {
          const cd = gameState.battlefieldCards.find(c => c.id === id);
          const cardEl = document.getElementById(`bc-${id}`);
          if (cd && cardEl) showAbilitiesPanel(cd, cardEl);
          break;
        }
        case 'graveyard': moveCardToZone(id, 'graveyard'); break;
        case 'exile': moveCardToZone(id, 'exile'); break;
        case 'hand': moveCardToZone(id, 'hand'); break;
        case 'library-top': moveCardToLibrary(id, 'top'); break;
        case 'library-bottom': moveCardToLibrary(id, 'bottom'); break;
        case 'remove': removeCardFromBattlefield(id); break;
      }
    });
  });

  document.addEventListener('click', e => {
    if (!menu.contains(e.target)) hideContextMenu();
  });

  document.addEventListener('keydown', e => {
    if (e.key === 'Escape') { hideContextMenu(); cancelStackPickMode(); cancelEquipPickMode(); }
  });
}

// ============================================================
// PLAYER PANELS
// ============================================================

function renderPlayerPanels() {
  const { players, currentPlayerIndex } = gameState;
  const n = players.length;

  // Determine layout positions — all non-P1 players go to top bar
  let top = [], bottom = [], left = [], right = [];

  if (n === 2) {
    top = [1]; bottom = [0];
  } else if (n === 3) {
    top = [1, 2]; bottom = [0];
  } else if (n === 4) {
    top = [1, 2, 3]; bottom = [0];
  } else if (n === 5) {
    top = [1, 2, 3, 4]; bottom = [0];
  } else if (n === 6) {
    top = [1, 2, 3, 4, 5]; bottom = [0];
  }

  const containers = {
    top: document.getElementById('players-top'),
    bottom: document.getElementById('players-bottom'),
    left: document.getElementById('players-left'),
    right: document.getElementById('players-right'),
  };

  // Clear existing
  Object.values(containers).forEach(c => { if (c) c.innerHTML = ''; });

  // Also clear the fixed Player 1 panel
  const p1Fixed = document.getElementById('player1-fixed-panel');
  if (p1Fixed) { p1Fixed.innerHTML = ''; p1Fixed.classList.add('hidden'); }

  // Render each player in their position
  const allPositions = { top, bottom, left, right };
  Object.entries(allPositions).forEach(([pos, playerIds]) => {
    const container = containers[pos];
    if (!container) return;
    playerIds.forEach(pid => {
      // Player 1 (index 0) goes to fixed bottom-left panel
      if (pid === 0 && p1Fixed) {
        const panel = createPlayerPanel(players[pid], currentPlayerIndex === pid);
        p1Fixed.appendChild(panel);
        p1Fixed.classList.remove('hidden');
      } else {
        const panel = createPlayerPanel(players[pid], currentPlayerIndex === pid);
        container.appendChild(panel);
      }
    });
  });
}

function createPlayerPanel(player, isActive) {
  const panel = document.createElement('div');
  panel.className = `player-panel${isActive ? ' active-player' : ''}${player.eliminated ? ' eliminated' : ''}`;
  panel.id = `player-panel-${player.id}`;
  panel.style.setProperty('--player-color', player.color);
  if (isActive) {
    panel.style.boxShadow = '0 0 16px ' + hexToRgba(player.color, 0.3);
  }

  // Commander damage rows (vs other players)
  const otherPlayers = gameState.players.filter(p => p.id !== player.id);
  const cmdDamageHtml = otherPlayers.map(op => {
    const dmg = player.commanderDamage[op.id] || 0;
    const cls = dmg >= 18 ? 'danger' : dmg >= 10 ? 'warning' : '';
    return `
      <div class="cmd-dmg-item ${cls}" title="${op.name}'s commander damage">
        <div class="cmd-dmg-dot" style="background:${op.color}"></div>
        <span class="cmd-dmg-value" data-player="${player.id}" data-source="${op.id}" onclick="adjustCommanderDamage(${player.id}, ${op.id}, 1)">${dmg}</span>
        <span style="color:var(--color-text-faint);font-size:10px;cursor:pointer" onclick="adjustCommanderDamage(${player.id}, ${op.id}, -1)">−</span>
      </div>
    `;
  }).join('');

  // Zone counts
  const gravCount = player.zones.graveyard.length;
  const exileCount = player.zones.exile.length;
  const cmdCount = player.zones.command.length;
  const handCount = player.zones.hand.length;
  const libCount = player.zones.library.length;

  panel.innerHTML = `
    <div class="player-name">
      <div class="player-name-dot" style="background:${player.color}"></div>
      ${player.name}
      ${player.isAI ? '<span class="ai-badge">🤖 AI</span>' : ''}
    </div>

    <div class="life-total-display">
      <button class="life-btn" onclick="adjustLife(${player.id}, -1)" oncontextmenu="event.preventDefault();adjustLife(${player.id}, -5)" title="Left: −1 | Right: −5">−</button>
      <div class="life-total-value" id="life-${player.id}">${player.life}</div>
      <button class="life-btn" onclick="adjustLife(${player.id}, 1)" oncontextmenu="event.preventDefault();adjustLife(${player.id}, 5)" title="Left: +1 | Right: +5">+</button>
    </div>

    <div class="cmd-damage-section">
      <div class="cmd-damage-label">
        <span>CMD Damage</span>
        <span style="color:var(--color-text-faint)">21 = elim.</span>
      </div>
      <div class="cmd-damage-row">
        ${cmdDamageHtml || '<span style="color:var(--color-text-faint);font-size:var(--text-xs)">No opponents</span>'}
      </div>
    </div>

    <div class="counters-row">
      <div class="counter-item poison-counter ${player.poison >= 7 ? 'warning' : ''} ${player.poison >= 10 ? 'danger' : ''}"
           onclick="adjustPoison(${player.id}, 1)" title="Click to add poison (right-click to remove)">
        <span class="counter-label">☠</span>
        <span class="counter-value" id="poison-${player.id}">${player.poison}</span>
        <span style="font-size:10px;color:var(--color-text-faint)">poison</span>
      </div>
    </div>

    <div class="library-actions">
      <button class="library-action-btn draw-btn" onclick="drawCard(${player.id})" title="Draw a card">
        📤 Draw
      </button>
      <button class="library-action-btn scry-btn" onclick="showScryDialog(${player.id})" title="Scry — look at top cards">
        🔮 Scry
      </button>
      <button class="library-action-btn mill-btn" onclick="millCards(${player.id}, 1)" title="Mill 1 card (right-click for more)" oncontextmenu="event.preventDefault();showMillDialog(${player.id})">
        ⚰ Mill
      </button>
      <button class="library-action-btn shuffle-btn" onclick="shuffleLibrary(${player.id})" title="Shuffle library">
        🔀 Shuffle
      </button>
      <button class="library-action-btn browse-btn" onclick="openDeckView(${player.id})" title="Browse entire library — search and move cards">
        🔍 Browse
      </button>
    </div>

    <button class="deck-mgr-btn" onclick="openDeckModal(${player.id})" title="Import / Export Deck">
      📋 Deck Manager
    </button>

    <button class="deck-mgr-btn token-mgr-btn" onclick="openTokenModal(${player.id})" title="Create token creatures and artifacts">
      ✨ Create Token
    </button>

    <button class="deck-mgr-btn monarch-btn" onclick="becomeMonarch(${player.id})" title="Make this player the Monarch (draws extra card at end step)">
      ${gameState.monarchPlayerIndex === player.id ? '\ud83d\udc51 Monarch' : '\ud83d\udc51 Become Monarch'}
    </button>

    <button class="zones-btn" onclick="openZoneModal(${player.id})">
      ⚰ ${gravCount}  ⬡ ${exileCount}  ⚔ ${cmdCount}  ✋ ${handCount}  📚 ${libCount}
    </button>
    <div id="timer-display-${player.id}" class="player-timer-display" style="display:none"></div>
    <div class="partner-cmd-row">
      <button class="partner-cmd-btn" onclick="openSetPartnerModal(${player.id})" title="Set Partner Commander">
        ${player.commanderCardName2 ? '👑+👑 ' + player.commanderCardName2 : '+ Set Partner'}
      </button>
      ${player.commanderCardName2 ? '<button class="partner-cmd-clear-btn" onclick="clearPartnerCommander(' + player.id + ')" title="Clear partner">✕</button>' : ''}
    </div>
  `;

  // Right-click on life total to subtract more
  const lifeEl = panel.querySelector(`#life-${player.id}`);
  if (lifeEl) {
    lifeEl.addEventListener('contextmenu', e => {
      e.preventDefault();
      showSetLifeDialog(player.id);
    });
  }

  // Right-click on poison to remove
  panel.querySelectorAll('.poison-counter').forEach(el => {
    el.addEventListener('contextmenu', e => {
      e.preventDefault();
      adjustPoison(player.id, -1);
    });
  });

  return panel;
}

// ============================================================
// LIFE TOTAL MANAGEMENT
// ============================================================

function adjustLife(playerId, amount) {
  if (!gameState) return;
  const player = gameState.players[playerId];
  if (!player) return;

  // Apply replacement effects to life gain/loss
  if (amount > 0) {
    var gainEvent = applyReplacements('gain_life', { playerIdx: playerId, amount: amount });
    if (!gainEvent) return;
    amount = gainEvent.amount;
  }

  setLife(playerId, player.life + amount);
}

function setLife(playerId, newLife) {
  if (!gameState) return;
  pushUndoState();
  const player = gameState.players[playerId];
  if (!player) return;

  const oldLife = player.life;
  player.life = newLife;

  // Animate the value
  const lifeEl = document.getElementById(`life-${playerId}`);
  if (lifeEl) {
    lifeEl.textContent = newLife;
    lifeEl.classList.remove('life-gain', 'life-loss');
    lifeEl.offsetWidth; // Force reflow
    if (newLife > oldLife) lifeEl.classList.add('life-gain');
    else if (newLife < oldLife) lifeEl.classList.add('life-loss');
    setTimeout(() => lifeEl.classList.remove('life-gain', 'life-loss'), 500);
  }

  // Panel flash
  const panel = document.getElementById(`player-panel-${playerId}`);
  if (panel) {
    panel.classList.remove('life-gained', 'life-lost');
    panel.offsetWidth;
    if (newLife > oldLife) panel.classList.add('life-gained');
    else if (newLife < oldLife) panel.classList.add('life-lost');
    setTimeout(() => panel.classList.remove('life-gained', 'life-lost'), 700);
  }

  const diff = newLife - oldLife;
  const sign = diff > 0 ? '+' : '';
  addLogEntry(`<strong>${player.name}</strong> life: ${oldLife} → <strong>${newLife}</strong> (${sign}${diff})`);

  // Fire life gain/loss triggers
  if (diff > 0) {
    fireBattlefieldTriggers('life_gain');
  } else if (diff < 0) {
    fireBattlefieldTriggers('life_loss');
  }

  // Check for 0 or negative life
  if (newLife <= 0 && !player.eliminated) {
    eliminatePlayer(playerId, 'life total reached 0');
  }
  checkStateBasedActions();
  // Sync enhanced player panels
  if (typeof renderEnhancedPanels === 'function') renderEnhancedPanels();
}

// ============================================================
// COMMANDER DAMAGE
// ============================================================

function adjustCommanderDamage(targetPlayerId, sourcePlayerId, amount) {
  if (!gameState) return;
  pushUndoState();
  const player = gameState.players[targetPlayerId];
  if (!player) return;

  const oldDmg = player.commanderDamage[sourcePlayerId] || 0;
  const newDmg = Math.max(0, oldDmg + amount);
  player.commanderDamage[sourcePlayerId] = newDmg;

  const srcPlayer = gameState.players[sourcePlayerId];
  const srcName = srcPlayer ? srcPlayer.name : 'Unknown';

  if (amount > 0) {
    addLogEntry(`<strong>${player.name}</strong> took ${amount} commander damage from <strong>${srcName}</strong> (total: ${newDmg})`);
  }

  if (newDmg >= 21 && !player.eliminated) {
    eliminatePlayer(targetPlayerId, `21 commander damage from ${srcName}`);
  }

  // Re-render the panel
  const panelContainer = document.getElementById(`player-panel-${targetPlayerId}`);
  if (panelContainer) {
    const newPanel = createPlayerPanel(player, gameState.currentPlayerIndex === targetPlayerId);
    panelContainer.replaceWith(newPanel);
  }
  checkStateBasedActions();
  // Sync enhanced player panels
  if (typeof renderEnhancedPanels === 'function') renderEnhancedPanels();
}

// ============================================================
// POISON COUNTERS
// ============================================================

function adjustPoison(playerId, amount) {
  if (!gameState) return;
  pushUndoState();
  const player = gameState.players[playerId];
  if (!player) return;

  player.poison = Math.max(0, player.poison + amount);

  const poisonEl = document.getElementById(`poison-${playerId}`);
  if (poisonEl) poisonEl.textContent = player.poison;

  if (amount !== 0) {
    addLogEntry(`<strong>${player.name}</strong> has ${player.poison} poison counter${player.poison !== 1 ? 's' : ''}`);
  }

  if (player.poison >= 10 && !player.eliminated) {
    eliminatePlayer(playerId, '10 poison counters');
  }

  // Update the counter styling
  const panelContainer = document.getElementById(`player-panel-${playerId}`);
  if (panelContainer) {
    const newPanel = createPlayerPanel(player, gameState.currentPlayerIndex === playerId);
    panelContainer.replaceWith(newPanel);
  }
  if (gameState.rulesEngine && gameState.rulesEngine.sbaChecks) checkStateBasedActions();
  // Sync enhanced player panels
  if (typeof renderEnhancedPanels === 'function') renderEnhancedPanels();
}

