function showSetLifeDialog(playerId) {
  const player = gameState?.players[playerId];
  if (!player) return;

  // Remove any existing
  const existing = document.getElementById('set-life-dialog');
  if (existing) existing.remove();

  const dialog = document.createElement('div');
  dialog.id = 'set-life-dialog';
  dialog.style.cssText = `
    position: fixed; inset: 0; z-index: 800;
    display: flex; align-items: center; justify-content: center;
    background: rgba(0,0,0,0.7); backdrop-filter: blur(4px);
  `;
  dialog.innerHTML = `
    <div style="
      background: var(--color-surface-2);
      border: 1px solid var(--color-border-strong);
      border-radius: var(--radius-xl);
      padding: var(--space-8);
      min-width: 280px;
      box-shadow: var(--shadow-lg);
      text-align: center;
    ">
      <div style="font-family:var(--font-display); font-size:var(--text-lg); margin-bottom:var(--space-4); color:var(--color-text);">
        Set Life Total
      </div>
      <div style="color:var(--color-text-muted); font-size:var(--text-sm); margin-bottom:var(--space-4);">${player.name}</div>
      <input
        id="set-life-input"
        type="number"
        value="${player.life}"
        min="-999" max="999"
        style="
          width: 120px; font-family:var(--font-display);
          font-size: var(--text-2xl); font-weight:700;
          background: var(--color-surface-3); border: 1px solid var(--color-border-strong);
          border-radius: var(--radius-md); color: var(--color-text);
          text-align: center; padding: var(--space-2); margin-bottom: var(--space-6);
          outline: none;
        "
      />
      <div style="display:flex; gap: var(--space-3); justify-content: center;">
        <button onclick="document.getElementById('set-life-dialog').remove()" style="
          padding: var(--space-3) var(--space-6); background: var(--color-surface-3);
          border: 1px solid var(--color-border); border-radius: var(--radius-md);
          color: var(--color-text-muted); font-family: var(--font-body);
          font-weight: 600; cursor: pointer;
        ">Cancel</button>
        <button id="set-life-confirm" style="
          padding: var(--space-3) var(--space-6); background: rgba(91,141,217,0.15);
          border: 1px solid var(--color-primary); border-radius: var(--radius-md);
          color: var(--color-primary); font-family: var(--font-body);
          font-weight: 600; cursor: pointer;
        ">Set Life</button>
      </div>
    </div>
  `;

  document.body.appendChild(dialog);
  const input = document.getElementById('set-life-input');
  input.select();
  input.focus();

  const confirm = () => {
    const val = parseInt(input.value);
    if (!isNaN(val)) setLife(playerId, val);
    dialog.remove();
  };

  document.getElementById('set-life-confirm').addEventListener('click', confirm);
  input.addEventListener('keydown', e => {
    if (e.key === 'Enter') confirm();
    if (e.key === 'Escape') dialog.remove();
  });
  dialog.addEventListener('click', e => {
    if (e.target === dialog) dialog.remove();
  });
}



function eliminatePlayer(playerId, reason) {
  pushUndoState();
  const player = gameState.players[playerId];
  if (!player || player.eliminated) return;
  player.eliminated = true;
  addLogEntry(`⚠️ <strong>${player.name}</strong> has been eliminated! (${reason})`);
  renderPlayerPanels();
  // Fire player_eliminated triggers
  fireBattlefieldTriggers('player_eliminated');

  // Check for winner
  const activePlayers = gameState.players.filter(p => !p.eliminated);
  if (activePlayers.length === 1) {
    showWinner(activePlayers[0]);
  }
}

function showWinner(player) {
  addLogEntry(`🏆 <strong>${player.name}</strong> wins the game!`);
  // Show a nice in-app winner notification
  const banner = document.createElement('div');
  banner.style.cssText = `
    position: fixed; inset: 0; z-index: 2000;
    display: flex; align-items: center; justify-content: center;
    background: rgba(0,0,0,0.75); backdrop-filter: blur(8px);
    animation: fadeIn 0.5s ease;
  `;
  banner.innerHTML = `
    <div style="text-align:center; padding: 3rem;">
      <div style="font-family:var(--font-display); font-size:clamp(3rem,8vw,6rem); color:var(--mtg-gold); margin-bottom:1rem;">
        🏆
      </div>
      <div style="font-family:var(--font-display); font-size:clamp(1.5rem,4vw,3rem); font-weight:700; color:var(--mtg-gold); margin-bottom:0.5rem;">
        ${player.name}
      </div>
      <div style="font-family:var(--font-display); font-size:1.1rem; color:var(--color-text-muted); margin-bottom:2rem; letter-spacing:0.1em; text-transform:uppercase;">
        Wins the Game!
      </div>
      <button onclick="this.closest('[style]').remove()" style="
        font-family:var(--font-body); font-size:1rem; font-weight:600;
        padding: 0.75rem 2rem; border-radius: 0.5rem; cursor:pointer;
        background: rgba(200,168,67,0.15); border: 1px solid rgba(200,168,67,0.5);
        color: var(--mtg-gold); transition: background 0.2s;
      ">
        Continue Spectating
      </button>
    </div>
  `;
  document.body.appendChild(banner);
}

// ============================================================
// FEATURE 9: COMMANDER DAMAGE MATRIX
// ============================================================

function openCmdDmgMatrix() {
  if (!gameState) return;
  var existing = document.getElementById('cmd-dmg-matrix-modal');
  if (existing) { existing.classList.add('visible'); renderCmdDmgMatrix(); return; }
  renderCmdDmgMatrix();
  var modal = document.getElementById('cmd-dmg-matrix-modal');
  if (modal) modal.classList.add('visible');
}

function closeCmdDmgMatrix() {
  var modal = document.getElementById('cmd-dmg-matrix-modal');
  if (modal) modal.classList.remove('visible');
}

function renderCmdDmgMatrix() {
  var modal = document.getElementById('cmd-dmg-matrix-modal');
  if (!modal || !gameState) return;
  var players = gameState.players;
  var html = '<div class="cdm-header"><h3>📊 Commander Damage Matrix</h3>' +
    '<button class="btn-close" onclick="closeCmdDmgMatrix()">✕</button></div>';
  html += '<p class="cdm-hint">Row = damage from row commander. Column = player taking damage.<br>Click cell +1, right-click \u22121.</p>';
  html += '<div class="cdm-grid-wrap"><table class="cdm-table">';
  // Header row
  html += '<tr><th class="cdm-corner">From \ To</th>';
  players.forEach(function(p) {
    html += '<th class="cdm-col-header"><span class="cdm-dot" style="background:' + p.color + '"></span>' + p.name + '</th>';
  });
  html += '</tr>';
  // Data rows
  players.forEach(function(rowP) {
    html += '<tr>';
    html += '<td class="cdm-row-header"><span class="cdm-dot" style="background:' + rowP.color + '"></span>' + rowP.name + '</td>';
    players.forEach(function(colP) {
      if (rowP.id === colP.id) {
        html += '<td class="cdm-self">—</td>';
      } else {
        // damage that colP has taken FROM rowP's commander
        var dmg = colP.commanderDamage[rowP.id] || 0;
        var cls = 'cdm-cell';
        if (dmg >= 21) cls += ' cdm-red';
        else if (dmg >= 15) cls += ' cdm-orange';
        else if (dmg >= 8) cls += ' cdm-yellow';
        else cls += ' cdm-green';
        html += '<td class="' + cls + '" onclick="cdmAdjust(' + colP.id + ',' + rowP.id + ',1)" oncontextmenu="event.preventDefault();cdmAdjust(' + colP.id + ',' + rowP.id + ',-1)" title="Click +1 / Right-click -1">' + dmg + '</td>';
      }
    });
    html += '</tr>';
  });
  html += '</table></div>';
  modal.innerHTML = html;
}

function cdmAdjust(targetPlayerId, sourcePlayerId, amount) {
  if (!gameState) return;
  adjustCommanderDamage(targetPlayerId, sourcePlayerId, amount);
  renderCmdDmgMatrix();
}

