function getCommanderTax(playerIndex) {
  if (!gameState) return 0;
  var playerData = gameState.players[playerIndex];
  if (!playerData) return 0;
  return (playerData.commanderCastCount || 0) * 2;
}

function getCommanderTax2(playerIndex) {
  if (!gameState) return 0;
  var playerData = gameState.players[playerIndex];
  if (!playerData) return 0;
  return (playerData.commanderCastCount2 || 0) * 2;
}

// Feature 10: Partner Commanders
