function openDiceModal() {
  const modal = document.getElementById('dice-modal');
  if (modal) modal.classList.add('visible');
}

function closeDiceModal() {
  const modal = document.getElementById('dice-modal');
  if (modal) modal.classList.remove('visible');
}

function rollDice(sides) {
  const result = Math.floor(Math.random() * sides) + 1;
  const resultEl = document.getElementById('dice-result');
  const labelEl = document.getElementById('dice-label');

  if (resultEl) {
    resultEl.classList.remove('rolling');
    resultEl.offsetWidth;
    resultEl.textContent = result;
    resultEl.classList.add('rolling');
    resultEl.classList.remove('coin-result');
  }
  if (labelEl) labelEl.textContent = `d${sides}`;

  addLogEntry(`🎲 Rolled d${sides}: <strong>${result}</strong>`);
}

function flipCoin() {
  const result = Math.random() < 0.5 ? 'HEADS' : 'TAILS';
  const resultEl = document.getElementById('dice-result');
  const labelEl = document.getElementById('dice-label');

  if (resultEl) {
    resultEl.classList.remove('rolling');
    resultEl.offsetWidth;
    resultEl.textContent = result === 'HEADS' ? '🪙' : '☽';
    resultEl.classList.add('rolling', 'coin-result');
  }
  if (labelEl) labelEl.textContent = result;

  addLogEntry(`🪙 Coin flip: <strong>${result}</strong>`);
}

// ============================================================
// DECK IMPORT / EXPORT
// ============================================================

let deckModalPlayerId = null;
let deckImportAbortController = null;

/**
 * Parse a decklist text string into an array of { qty, name, section }.
 * Supports common formats from Moxfield, Archidekt, EDHREC, TappedOut, etc.
 */
function parseDeckList(text) {
  const lines = text.split(/\r?\n/);
  const cards = [];
  let currentSection = 'mainboard';

  for (let raw of lines) {
    let line = raw.trim();
    if (!line) continue;

    // Section headers — supports "// Commander", "Commander:", "[Commander]", "[Main]", "[metadata]"
    if (/^\/\/\s*/i.test(line) || /^\[?(COMMANDER|COMPANION|SIDEBOARD|MAYBEBOARD|MAINBOARD|MAIN|DECK|LAND|METADATA)\]?[:\s]*$/i.test(line)) {
      const cleaned = line.replace(/^\/\/\s*/, '').replace(/[\[\]:]/g, '').trim().toLowerCase();
      if (/commander/i.test(cleaned))    currentSection = 'commander';
      else if (/companion/i.test(cleaned)) currentSection = 'companion';
      else if (/sideboard/i.test(cleaned)) currentSection = 'sideboard';
      else if (/metadata/i.test(cleaned)) currentSection = 'metadata';
      else currentSection = 'mainboard';
      continue;
    }

    // Skip metadata lines like "Name=Elven Empire"
    if (currentSection === 'metadata') continue;

    // Skip comment lines
    if (/^#/.test(line) || /^\*/.test(line)) continue;

    // Strip set codes in parentheses/brackets
    line = line.replace(/\s*[\(\[][A-Z0-9]+[\)\]]\s*\d*\s*$/, '').trim();
    // Strip collector number at end
    line = line.replace(/\s+\d+\s*$/, '').trim();
    // Strip foil/etched tags
    line = line.replace(/\s*\*F\*\s*$/i, '').trim();

    // Match: optional quantity + card name
    const match = line.match(/^(?:(\d+)\s*[xX]?\s+)?(.+)$/);
    if (!match) continue;

    const qty = match[1] ? parseInt(match[1]) : 1;
    const name = match[2].trim();

    if (!name || name.length < 2) continue;

    cards.push({ qty: Math.min(qty, 99), name, section: currentSection });
  }

  return cards;
}

/**
 * Batch-fetch card data from Scryfall's /cards/collection endpoint.
 * Returns a Map<normalizedName, cardData>.
 */
async function batchFetchCards(cardNames, progressCallback) {
  const uniqueNames = [...new Set(cardNames.map(n => n.toLowerCase()))];
  const results = new Map();
  const BATCH_SIZE = 75;
  const RATE_LIMIT = 100;

  for (let i = 0; i < uniqueNames.length; i += BATCH_SIZE) {
    if (deckImportAbortController?.signal?.aborted) throw new Error('Import cancelled');

    const batch = uniqueNames.slice(i, i + BATCH_SIZE);
    const identifiers = batch.map(name => ({ name }));

    if (progressCallback) {
      progressCallback(Math.min(i + BATCH_SIZE, uniqueNames.length), uniqueNames.length);
    }

    try {
      const resp = await fetch(`${SCRYFALL_BASE}/cards/collection`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ identifiers }),
        signal: deckImportAbortController?.signal,
      });

      if (!resp.ok) {
        console.warn('[Deck Import] Batch request failed:', resp.status);
        continue;
      }

      const data = await resp.json();

      if (data.data) {
        for (const card of data.data) {
          results.set(card.name.toLowerCase(), card);
        }
      }
    } catch (err) {
      if (err.name === 'AbortError' || err.message === 'Import cancelled') throw err;
      console.warn('[Deck Import] Batch fetch error:', err);
    }

    if (i + BATCH_SIZE < uniqueNames.length) {
      await new Promise(r => setTimeout(r, RATE_LIMIT));
    }
  }

  return results;
}

function scryfallToZoneCard(card) {
  let imageUrl = '';
  if (card.image_uris && card.image_uris.normal) {
    imageUrl = card.image_uris.normal;
  } else if (card.card_faces && card.card_faces[0] && card.card_faces[0].image_uris) {
    imageUrl = card.card_faces[0].image_uris.normal;
  }
  // Build power/toughness string from Scryfall fields
  var pt = '';
  if (card.power !== undefined && card.toughness !== undefined) {
    pt = card.power + '/' + card.toughness;
  }
  return {
    name: card.name,
    imageUrl,
    typeLine: card.type_line || '',
    oracleText: card.oracle_text || (card.card_faces ? card.card_faces.map(f => f.oracle_text || '').join('\n') : ''),
    manaCost: card.mana_cost || '',
    cmc: card.cmc || 0,
    power: card.power || '',
    toughness: card.toughness || '',
    pt: pt,
    loyalty: card.loyalty || '',
    colorIdentity: card.color_identity || [],
    keywords: card.keywords || [],
  };
}

function openDeckModal(playerId) {
  if (!gameState) return;
  deckModalPlayerId = playerId;
  const player = gameState.players[playerId];
  if (!player) return;

  const modal = document.getElementById('deck-modal');
  if (!modal) return;

  const titleEl = document.getElementById('deck-modal-title');
  if (titleEl) titleEl.textContent = `${player.name}'s Deck Manager`;

  const textarea = document.getElementById('deck-import-text');
  if (textarea) textarea.value = '';

  updateDeckImportProgress(0, 0, '');
  const statusEl = document.getElementById('deck-import-status');
  if (statusEl) statusEl.textContent = '';

  updateDeckSummary(playerId);

  modal.classList.add('visible');
}

function closeDeckModal() {
  const modal = document.getElementById('deck-modal');
  if (modal) modal.classList.remove('visible');
  cancelDeckImport();
  deckModalPlayerId = null;
}

function updateDeckSummary(playerId) {
  const el = document.getElementById('deck-current-summary');
  if (!el || !gameState) return;
  const player = gameState.players[playerId];
  if (!player) return;

  const lib = player.zones.library.length;
  const hand = player.zones.hand.length;
  const cmd = player.zones.command.length;
  const total = lib + hand + cmd;

  el.innerHTML = `
    <div class="deck-summary-stat"><span class="deck-stat-val">${total}</span> total cards</div>
    <div class="deck-summary-stat"><span class="deck-stat-val">${lib}</span> in library</div>
    <div class="deck-summary-stat"><span class="deck-stat-val">${hand}</span> in hand</div>
    <div class="deck-summary-stat"><span class="deck-stat-val">${cmd}</span> in command zone</div>
  `;
}

function updateDeckImportProgress(loaded, total, message) {
  const bar = document.getElementById('deck-progress-bar');
  const text = document.getElementById('deck-progress-text');
  const container = document.getElementById('deck-progress');

  if (container) container.style.display = (total > 0) ? '' : 'none';
  if (bar && total > 0) bar.style.width = `${Math.round((loaded / total) * 100)}%`;
  if (text) text.textContent = message || `${loaded} / ${total} cards`;
}

function cancelDeckImport() {
  if (deckImportAbortController) {
    deckImportAbortController.abort();
    deckImportAbortController = null;
  }
}

async function importDeck() {
  if (!gameState || deckModalPlayerId === null) return;
  const player = gameState.players[deckModalPlayerId];
  if (!player) return;

  const textarea = document.getElementById('deck-import-text');
  const statusEl = document.getElementById('deck-import-status');
  const text = textarea?.value || '';

  if (!text.trim()) {
    if (statusEl) statusEl.textContent = 'Paste a deck list above first.';
    return;
  }

  const parsedCards = parseDeckList(text);
  if (!parsedCards.length) {
    if (statusEl) statusEl.textContent = 'Could not parse any cards from the list.';
    return;
  }

  const allCardNames = [];
  const commanderNames = [];
  for (const entry of parsedCards) {
    for (let q = 0; q < entry.qty; q++) {
      allCardNames.push(entry.name);
    }
    if (entry.section === 'commander') {
      commanderNames.push(entry.name);
    }
  }

  if (statusEl) statusEl.textContent = `Parsed ${allCardNames.length} cards. Fetching from Scryfall...`;

  deckImportAbortController = new AbortController();

  const importBtn = document.getElementById('deck-import-btn');
  const cancelBtn = document.getElementById('deck-cancel-btn');
  if (importBtn) { importBtn.disabled = true; importBtn.textContent = 'Importing...'; }
  if (cancelBtn) cancelBtn.style.display = '';

  try {
    const cardDataMap = await batchFetchCards(
      allCardNames,
      (loaded, total) => updateDeckImportProgress(loaded, total, `Fetching cards: ${loaded} / ${total}`)
    );

    const libraryCards = [];
    const commandCards = [];
    const notFound = [];

    for (const entry of parsedCards) {
      const scryfallCard = cardDataMap.get(entry.name.toLowerCase());

      if (!scryfallCard) {
        notFound.push(entry.name);
        continue;
      }

      const cardObj = scryfallToZoneCard(scryfallCard);

      for (let q = 0; q < entry.qty; q++) {
        if (entry.section === 'commander') {
          commandCards.push({ ...cardObj });
        } else {
          libraryCards.push({ ...cardObj });
        }
      }
    }

    const importMode = document.querySelector('input[name="deck-import-mode"]:checked')?.value || 'replace';

    if (importMode === 'replace') {
      player.zones.library = [];
      player.zones.hand = [];
      player.zones.command = [];
    }

    commandCards.forEach(card => player.zones.command.push(card));
    // Set commander name for zone replacement
    if (commandCards.length > 0 && !player.commanderCardName) {
      player.commanderCardName = commandCards[0].name || '';
    }

    // Shuffle library
    for (let i = libraryCards.length - 1; i > 0; i--) {
      const j = Math.floor(Math.random() * (i + 1));
      [libraryCards[i], libraryCards[j]] = [libraryCards[j], libraryCards[i]];
    }

    libraryCards.forEach(card => player.zones.library.push(card));

    // Draw opening hand (7 cards) if replacing
    if (importMode === 'replace' && player.zones.library.length >= 7) {
      for (let i = 0; i < 7; i++) {
        const card = player.zones.library.shift();
        player.zones.hand.push(card);
      }
    }

    updatePlayerZones();
    renderPlayerPanels();
    updateDeckSummary(deckModalPlayerId);

    let status = `\u2713 Imported ${libraryCards.length + commandCards.length} cards.`;
    if (commandCards.length) status += ` ${commandCards.length} commander(s).`;
    if (importMode === 'replace') status += ` Drew 7-card opening hand.`;
    if (notFound.length) {
      status += ` \u26a0 ${notFound.length} not found: ${notFound.slice(0, 5).join(', ')}${notFound.length > 5 ? '...' : ''}`;
    }
    if (statusEl) { statusEl.textContent = status; statusEl.className = 'deck-import-status success'; }

    addLogEntry(`\ud83d\udccb <strong>${player.name}</strong> imported a ${libraryCards.length + commandCards.length}-card deck`);

    // Enter mulligan phase for player 1
    if (importMode === 'replace' && deckModalPlayerId === 0) {
      enterMulliganPhase(0);
    }

    updateDeckImportProgress(0, 0, '');

  } catch (err) {
    if (err.name === 'AbortError' || err.message === 'Import cancelled') {
      if (statusEl) { statusEl.textContent = 'Import cancelled.'; statusEl.className = 'deck-import-status'; }
    } else {
      console.error('[Deck Import] Error:', err);
      if (statusEl) { statusEl.textContent = 'Error importing deck. Check console.'; statusEl.className = 'deck-import-status error'; }
    }
    updateDeckImportProgress(0, 0, '');
  } finally {
    deckImportAbortController = null;
    if (importBtn) { importBtn.disabled = false; importBtn.textContent = '\ud83d\udce5 Import Deck'; }
    if (cancelBtn) cancelBtn.style.display = 'none';
  }
}

function exportDeck() {
  if (!gameState || deckModalPlayerId === null) return;
  const player = gameState.players[deckModalPlayerId];
  if (!player) return;

  const lines = [];
  const cardCounts = new Map();
  const commanderCounts = new Map();

  const deckCards = [...player.zones.library, ...player.zones.hand];
  for (const card of deckCards) {
    cardCounts.set(card.name, (cardCounts.get(card.name) || 0) + 1);
  }

  for (const card of player.zones.command) {
    commanderCounts.set(card.name, (commanderCounts.get(card.name) || 0) + 1);
  }

  if (commanderCounts.size > 0) {
    lines.push('//Commander');
    for (const [name, qty] of commanderCounts) {
      lines.push(`${qty} ${name}`);
    }
    lines.push('');
  }

  lines.push('//Deck');
  const sorted = [...cardCounts.entries()].sort((a, b) => a[0].localeCompare(b[0]));
  for (const [name, qty] of sorted) {
    lines.push(`${qty} ${name}`);
  }

  const output = lines.join('\n');

  const textarea = document.getElementById('deck-import-text');
  if (textarea) {
    textarea.value = output;
    textarea.select();
  }

  navigator.clipboard?.writeText(output).then(() => {
    const statusEl = document.getElementById('deck-import-status');
    if (statusEl) { statusEl.textContent = `Exported ${deckCards.length + player.zones.command.length} cards \u2014 copied to clipboard.`; statusEl.className = 'deck-import-status success'; }
  }).catch(() => {
    const statusEl = document.getElementById('deck-import-status');
    if (statusEl) { statusEl.textContent = `Exported ${deckCards.length + player.zones.command.length} cards \u2014 select and copy from the text area.`; statusEl.className = 'deck-import-status'; }
  });
}

function downloadDeck() {
  if (!gameState || deckModalPlayerId === null) return;
  const player = gameState.players[deckModalPlayerId];
  if (!player) return;

  exportDeck();

  const textarea = document.getElementById('deck-import-text');
  const text = textarea?.value || '';
  if (!text.trim()) return;

  const blob = new Blob([text], { type: 'text/plain' });
  const url = URL.createObjectURL(blob);
  const a = document.createElement('a');
  a.href = url;
  a.download = `${player.name.replace(/[^a-zA-Z0-9]/g, '_')}_deck.txt`;
  a.click();
  URL.revokeObjectURL(url);
}

function loadDeckFile() {
  const input = document.createElement('input');
  input.type = 'file';
  input.accept = '.txt,.dec,.dek,.mwDeck,.csv';
  input.onchange = (e) => {
    const file = e.target.files[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (ev) => {
      const textarea = document.getElementById('deck-import-text');
      if (textarea) textarea.value = ev.target.result;
      const statusEl = document.getElementById('deck-import-status');
      if (statusEl) { statusEl.textContent = `Loaded "${file.name}". Click Import to fetch card data.`; statusEl.className = 'deck-import-status'; }
    };
    reader.readAsText(file);
  };
  input.click();
}

// ============================================================
// PRECON DECK BROWSER
// ============================================================

let preconColorFilter = 'all';
let selectedPreconId = null;

function switchDeckTab(tabName) {
  document.querySelectorAll('.deck-tab').forEach(t => t.classList.toggle('active', t.dataset.deckTab === tabName));
  document.querySelectorAll('.deck-tab-content').forEach(c => c.classList.remove('active'));
  const target = document.getElementById(`deck-tab-${tabName}`);
  if (target) target.classList.add('active');

  if (tabName === 'precons') {
    initPreconBrowser();
  }
}

function initPreconBrowser() {
  if (typeof PRECON_DATA === 'undefined') return;

  // Populate set filter
  const setSelect = document.getElementById('precon-filter-set');
  if (setSelect && setSelect.options.length <= 1) {
    const sets = [...new Set(PRECON_DATA.map(p => p.set))];
    // Sort by year descending
    sets.sort((a, b) => {
      const ya = PRECON_DATA.find(p => p.set === a)?.year || 0;
      const yb = PRECON_DATA.find(p => p.set === b)?.year || 0;
      return yb - ya;
    });
    sets.forEach(s => {
      const opt = document.createElement('option');
      opt.value = s;
      const yr = PRECON_DATA.find(p => p.set === s)?.year || '';
      opt.textContent = `${s} (${yr})`;
      setSelect.appendChild(opt);
    });
  }

  filterPrecons();
}

function setPreconColorFilter(color) {
  preconColorFilter = color;
  document.querySelectorAll('.precon-color-btn').forEach(b => b.classList.toggle('active', b.dataset.color === color));
  filterPrecons();
}

function filterPrecons() {
  if (typeof PRECON_DATA === 'undefined') return;

  const setFilter = document.getElementById('precon-filter-set')?.value || 'all';
  const grid = document.getElementById('precon-grid');
  const detail = document.getElementById('precon-detail');
  if (!grid) return;

  // Hide detail, show grid
  if (detail) detail.style.display = 'none';
  grid.style.display = '';
  selectedPreconId = null;

  let filtered = PRECON_DATA;
  if (setFilter !== 'all') {
    filtered = filtered.filter(p => p.set === setFilter);
  }
  if (preconColorFilter !== 'all') {
    filtered = filtered.filter(p => p.colors.includes(preconColorFilter));
  }

  if (!filtered.length) {
    grid.innerHTML = '<div class="precon-empty">No precons match these filters.</div>';
    return;
  }

  const COLOR_ICONS = { W: '\u2600', U: '\ud83d\udca7', B: '\ud83d\udc80', R: '\ud83d\udd25', G: '\ud83c\udf32', C: '\u25c7' };

  grid.innerHTML = filtered.map(p => {
    const colorPips = p.colors.split('').map(c => {
      const icon = COLOR_ICONS[c] || c;
      return `<span class="precon-pip precon-pip-${c.toLowerCase()}">${icon}</span>`;
    }).join('');

    return `
      <div class="precon-card" onclick="showPreconDetail('${p.id}')">
        <div class="precon-card-top">
          <div class="precon-card-name">${p.name}</div>
          <div class="precon-card-colors">${colorPips}</div>
        </div>
        <div class="precon-card-commander">${p.commander}</div>
        <div class="precon-card-meta">
          <span class="precon-card-set">${p.set}</span>
          <span class="precon-card-theme">${p.theme}</span>
        </div>
      </div>
    `;
  }).join('');
}

function showPreconDetail(preconId) {
  if (typeof PRECON_DATA === 'undefined') return;
  const precon = PRECON_DATA.find(p => p.id === preconId);
  if (!precon) return;

  selectedPreconId = preconId;

  const grid = document.getElementById('precon-grid');
  const detail = document.getElementById('precon-detail');
  if (grid) grid.style.display = 'none';
  if (detail) detail.style.display = '';

  // Clear any previous import status
  const statusEl = document.getElementById('precon-import-status');
  if (statusEl) { statusEl.textContent = ''; statusEl.className = 'precon-import-status'; }
  const progressWrap = document.getElementById('precon-import-progress');
  if (progressWrap) progressWrap.style.display = 'none';

  const nameEl = document.getElementById('precon-detail-name');
  const metaEl = document.getElementById('precon-detail-meta');
  const listEl = document.getElementById('precon-detail-list');

  if (nameEl) nameEl.textContent = precon.name;

  const COLOR_ICONS = { W: '\u2600', U: '\ud83d\udca7', B: '\ud83d\udc80', R: '\ud83d\udd25', G: '\ud83c\udf32', C: '\u25c7' };
  const colorPips = precon.colors.split('').map(c => {
    const icon = COLOR_ICONS[c] || c;
    return `<span class="precon-pip precon-pip-${c.toLowerCase()}">${icon}</span>`;
  }).join('');

  if (metaEl) metaEl.innerHTML = `
    <span>${precon.set} (${precon.year})</span>
    <span>${colorPips}</span>
    <span>${precon.theme}</span>
  `;

  if (listEl) {
    const lines = precon.decklist.split('\n').filter(l => l.trim());
    listEl.innerHTML = lines.map(line => {
      if (line.startsWith('//')) {
        return `<div class="precon-list-section">${line.replace('//', '').trim()}</div>`;
      }
      const m = line.match(/^(\d+)\s+(.+)$/);
      if (m) {
        return `<div class="precon-list-card"><span class="precon-list-qty">${m[1]}x</span> ${m[2]}</div>`;
      }
      return `<div class="precon-list-card">${line}</div>`;
    }).join('');
  }
}

function closePreconDetail() {
  const grid = document.getElementById('precon-grid');
  const detail = document.getElementById('precon-detail');
  if (grid) grid.style.display = '';
  if (detail) detail.style.display = 'none';
  selectedPreconId = null;
}

/** Copy the selected precon's decklist into the Import/Export textarea and switch tabs */
function sendPreconToImport() {
  if (!selectedPreconId || typeof PRECON_DATA === 'undefined') return;
  const precon = PRECON_DATA.find(p => p.id === selectedPreconId);
  if (!precon) return;

  const textarea = document.getElementById('deck-import-text');
  if (textarea) textarea.value = precon.decklist;

  // Switch to the Import/Export tab
  switchDeckTab('import');

  // Flash the textarea briefly to draw attention
  if (textarea) {
    textarea.style.outline = '2px solid rgba(92,184,92,0.7)';
    setTimeout(function() { textarea.style.outline = ''; }, 1200);
  }
}

let preconImportAbortController = null;

async function loadPreconIntoDeck() {
  if (!selectedPreconId || typeof PRECON_DATA === 'undefined') return;
  if (!gameState || deckModalPlayerId === null) return;

  const precon = PRECON_DATA.find(p => p.id === selectedPreconId);
  if (!precon) return;

  const player = gameState.players[deckModalPlayerId];
  if (!player) return;

  const loadBtn = document.getElementById('precon-load-btn');
  const cancelBtn = document.getElementById('precon-cancel-btn');
  const progressWrap = document.getElementById('precon-import-progress');
  const progressBar = document.getElementById('precon-progress-bar');
  const progressText = document.getElementById('precon-progress-text');
  const statusEl = document.getElementById('precon-import-status');

  // Parse the decklist
  const parsedCards = parseDeckList(precon.decklist);
  if (!parsedCards.length) {
    if (statusEl) { statusEl.textContent = 'Could not parse this precon decklist.'; statusEl.className = 'precon-import-status error'; }
    return;
  }

  const allCardNames = [];
  const commanderNames = [];
  for (const entry of parsedCards) {
    for (let q = 0; q < entry.qty; q++) {
      allCardNames.push(entry.name);
    }
    if (entry.section === 'commander') {
      commanderNames.push(entry.name);
    }
  }

  // UI: show progress, disable button
  if (loadBtn) { loadBtn.disabled = true; loadBtn.textContent = 'Importing...'; }
  if (cancelBtn) cancelBtn.style.display = '';
  if (progressWrap) progressWrap.style.display = '';
  if (statusEl) { statusEl.textContent = `Fetching ${allCardNames.length} cards from Scryfall...`; statusEl.className = 'precon-import-status'; }

  preconImportAbortController = new AbortController();
  // Temporarily replace the global abort controller for batchFetchCards
  const prevAbort = deckImportAbortController;
  deckImportAbortController = preconImportAbortController;

  try {
    const cardDataMap = await batchFetchCards(
      allCardNames,
      (loaded, total) => {
        if (progressBar) progressBar.style.width = `${Math.round((loaded / total) * 100)}%`;
        if (progressText) progressText.textContent = `Fetching cards: ${loaded} / ${total}`;
      }
    );

    const libraryCards = [];
    const commandCards = [];
    const notFound = [];

    for (const entry of parsedCards) {
      const scryfallCard = cardDataMap.get(entry.name.toLowerCase());
      if (!scryfallCard) {
        notFound.push(entry.name);
        continue;
      }
      const cardObj = scryfallToZoneCard(scryfallCard);
      for (let q = 0; q < entry.qty; q++) {
        if (entry.section === 'commander') {
          commandCards.push({ ...cardObj });
        } else {
          libraryCards.push({ ...cardObj });
        }
      }
    }

    // Replace player's deck
    player.zones.library = [];
    player.zones.hand = [];
    player.zones.command = [];

    commandCards.forEach(card => player.zones.command.push(card));

    // Shuffle library
    for (let i = libraryCards.length - 1; i > 0; i--) {
      const j = Math.floor(Math.random() * (i + 1));
      [libraryCards[i], libraryCards[j]] = [libraryCards[j], libraryCards[i]];
    }
    libraryCards.forEach(card => player.zones.library.push(card));

    // Draw opening hand (7 cards)
    if (player.zones.library.length >= 7) {
      for (let i = 0; i < 7; i++) {
        const card = player.zones.library.shift();
        player.zones.hand.push(card);
      }
    }

    updatePlayerZones();
    renderPlayerPanels();
    updateDeckSummary(deckModalPlayerId);

    let status = `\u2713 Loaded "${precon.name}" — ${libraryCards.length + commandCards.length} cards imported.`;
    if (commandCards.length) status += ` ${commandCards.length} commander(s).`;
    status += ` Drew 7-card opening hand.`;
    if (notFound.length) {
      status += ` \u26a0 ${notFound.length} not found: ${notFound.slice(0, 5).join(', ')}${notFound.length > 5 ? '...' : ''}`;
    }
    if (statusEl) { statusEl.textContent = status; statusEl.className = 'precon-import-status success'; }

    addLogEntry(`\ud83d\udccb <strong>${player.name}</strong> loaded precon "${precon.name}" (${libraryCards.length + commandCards.length} cards)`);

    // Enter mulligan phase for player 1
    if (deckModalPlayerId === 0) {
      enterMulliganPhase(0);
    }

  } catch (err) {
    if (err.name === 'AbortError' || err.message === 'Import cancelled') {
      if (statusEl) { statusEl.textContent = 'Import cancelled.'; statusEl.className = 'precon-import-status'; }
    } else {
      console.error('[Precon Import] Error:', err);
      if (statusEl) { statusEl.textContent = 'Error importing precon. Check console.'; statusEl.className = 'precon-import-status error'; }
    }
  } finally {
    deckImportAbortController = prevAbort;
    preconImportAbortController = null;
    if (loadBtn) { loadBtn.disabled = false; loadBtn.textContent = '\ud83d\udce5 Load This Deck'; }
    if (cancelBtn) cancelBtn.style.display = 'none';
    if (progressWrap) progressWrap.style.display = 'none';
    if (progressBar) progressBar.style.width = '0%';
  }
}

function cancelPreconImport() {
  if (preconImportAbortController) {
    preconImportAbortController.abort();
    preconImportAbortController = null;
  }
}

// ============================================================
// SETUP SCREEN
// ============================================================
// FLOATING MANA POOL
// ============================================================

const MANA_COLORS = ['W', 'U', 'B', 'R', 'G', 'C'];
const MANA_LABELS = { W: 'White', U: 'Blue', B: 'Black', R: 'Red', G: 'Green', C: 'Colorless' };

// Mana symbol to pool key mapping
const MANA_SYMBOL_MAP = {
  '{W}': 'W', '{U}': 'U', '{B}': 'B', '{R}': 'R', '{G}': 'G', '{C}': 'C',
};

/**
 * Parse oracle text to determine what mana a card produces when tapped.
 * Returns an object:
 *   { fixed: {W:0,U:0,B:0,R:0,G:0,C:0}, choices: number, anyColor: number }
 * - fixed: guaranteed mana added immediately
 * - choices: number of "pick one color" choices to prompt
 * - anyColor: number of "any color" picks to prompt
 */
function parseManaProduction(oracleText) {
  if (!oracleText) return null;

  const result = { fixed: { W:0, U:0, B:0, R:0, G:0, C:0 }, choices: [], anyColor: 0 };
  let found = false;

  // Normalize: handle parenthesized abilities like basic lands "({T}: Add {G}.)"
  const text = oracleText.replace(/\n/g, ' ');

  // Match all tap-for-mana abilities: optional cost + {T}: Add ...
  // Pattern: (optional cost, ){T}: Add <mana description>
  const tapAbilityRegex = /(?:^|\n|\(|(?:[^.]*,\s*)){T}:\s*[Aa]dd\s+([^.]+)\.?/g;
  let match;

  while ((match = tapAbilityRegex.exec(text)) !== null) {
    const manaDesc = match[1].trim();

    // Case 1: "one mana of any color" (with or without qualifier)
    if (/one mana of any color/i.test(manaDesc)) {
      result.anyColor += 1;
      found = true;
      continue;
    }

    // Case 2: "X mana in any combination of colors" — complex, treat as anyColor x1
    if (/mana in any combination/i.test(manaDesc)) {
      result.anyColor += 1;
      found = true;
      continue;
    }

    // Case 3: "one mana of any type" — treat as any color
    if (/one mana of any type/i.test(manaDesc)) {
      result.anyColor += 1;
      found = true;
      continue;
    }

    // Case 4: Fixed mana symbols like "{C}{C}" or "{B}{G}"
    // Also handles "{R} or {G}" choice patterns
    const symbols = manaDesc.match(/\{[WUBRGC]\}/g);
    if (symbols && symbols.length > 0) {
      // Check if it's an "or" choice: "{R} or {G}"
      if (/\bor\b/i.test(manaDesc)) {
        // This is a choice — collect the options
        const options = symbols.map(s => MANA_SYMBOL_MAP[s]).filter(Boolean);
        if (options.length > 0) {
          result.choices.push(options);
          found = true;
        }
      } else {
        // Fixed mana — add all symbols
        symbols.forEach(sym => {
          const key = MANA_SYMBOL_MAP[sym];
          if (key) {
            result.fixed[key]++;
            found = true;
          }
        });
      }
    }
  }

  return found ? result : null;
}

/**
 * Check if a card is a mana producer (land, artifact, or creature with tap-for-mana).
 */
function isManaProducer(cardData) {
  const type = (cardData.typeLine || '').toLowerCase();
  return type.includes('land') || type.includes('artifact') || parseManaProduction(cardData.oracleText) !== null;
}

// Pending mana pick state
let pendingManaPick = null;

/**
 * Called when a mana-producing card is tapped.
 * Auto-adds fixed mana, prompts for choices/any-color.
 */
function handleManaOnTap(cardData) {
  if (!gameState) return;
  const production = parseManaProduction(cardData.oracleText);
  if (!production) return;

  const player = gameState.players[cardData.ownerIndex];
  if (!player) return;

  // Switch mana pool view to the card's owner
  const manaSelect = document.getElementById('mana-pool-player-select');
  if (manaSelect) manaSelect.value = cardData.ownerIndex;

  // Add fixed mana immediately
  let addedAny = false;
  MANA_COLORS.forEach(c => {
    if (production.fixed[c] > 0) {
      player.manaPool[c] += production.fixed[c];
      addedAny = true;
    }
  });

  if (addedAny) {
    const parts = MANA_COLORS
      .filter(c => production.fixed[c] > 0)
      .map(c => `${production.fixed[c]} ${MANA_LABELS[c]}`);
    addLogEntry(`💎 <strong>${cardData.name}</strong> → +${parts.join(', ')}`);
  }

  renderManaPool();

  // Build list of pending picks
  const picks = [];
  production.choices.forEach(options => {
    picks.push({ type: 'choice', options });
  });
  for (let i = 0; i < production.anyColor; i++) {
    picks.push({ type: 'any', options: ['W','U','B','R','G'] });
  }

  if (picks.length > 0) {
    pendingManaPick = {
      cardName: cardData.name,
      ownerIndex: cardData.ownerIndex,
      picks,
      currentPick: 0,
    };
    showManaPickerModal();
  }
}

function showManaPickerModal() {
  if (!pendingManaPick) return;
  const pick = pendingManaPick.picks[pendingManaPick.currentPick];
  if (!pick) { closeManaPickerModal(); return; }

  const modal = document.getElementById('mana-picker-modal');
  if (!modal) return;

  const titleEl = document.getElementById('mana-picker-title');
  const bodyEl = document.getElementById('mana-picker-body');
  if (!titleEl || !bodyEl) return;

  const remaining = pendingManaPick.picks.length - pendingManaPick.currentPick;
  const label = pick.type === 'any' ? 'Choose a mana color' : 'Choose one';
  titleEl.textContent = `${pendingManaPick.cardName} — ${label}${remaining > 1 ? ` (${remaining} remaining)` : ''}`;

  const manaIcons = { W: '☀', U: '💧', B: '💀', R: '🔥', G: '🌲', C: '◇' };
  const manaClasses = { W: 'mana-white', U: 'mana-blue', B: 'mana-black', R: 'mana-red', G: 'mana-green', C: 'mana-colorless' };

  bodyEl.innerHTML = pick.options.map(color => `
    <button class="mana-pick-btn" onclick="pickManaColor('${color}')">
      <span class="mana-pip-icon ${manaClasses[color]}">${manaIcons[color]}</span>
      <span class="mana-pick-label">${MANA_LABELS[color]}</span>
    </button>
  `).join('');

  modal.classList.add('visible');
}

function pickManaColor(color) {
  if (!pendingManaPick || !gameState) return;
  const player = gameState.players[pendingManaPick.ownerIndex];
  if (!player) return;

  player.manaPool[color] = (player.manaPool[color] || 0) + 1;
  addLogEntry(`💎 <strong>${pendingManaPick.cardName}</strong> → +1 ${MANA_LABELS[color]}`);
  renderManaPool();

  pendingManaPick.currentPick++;
  if (pendingManaPick.currentPick < pendingManaPick.picks.length) {
    showManaPickerModal();
  } else {
    closeManaPickerModal();
  }
}

function closeManaPickerModal() {
  pendingManaPick = null;
  const modal = document.getElementById('mana-picker-modal');
  if (modal) modal.classList.remove('visible');
}

// ============================================================
// AUTO-TAP ENGINE — Smart land tapping for casting spells
// ============================================================

/**
 * Parse a mana cost string into structured requirements.
 * Returns { colored: {W:n, U:n, B:n, R:n, G:n}, colorless: n, generic: n, total: n, hasX: bool }
 */
function parseManaCostRequirements(manaCost) {
  if (!manaCost) return null;
  var req = { colored: { W:0, U:0, B:0, R:0, G:0 }, colorless: 0, generic: 0, total: 0, hasX: false };
  var tokens = manaCost.match(/\{[^}]+\}/g) || [];
  for (var i = 0; i < tokens.length; i++) {
    var sym = tokens[i].replace(/[{}]/g, '').toUpperCase();
    if (sym === 'W' || sym === 'U' || sym === 'B' || sym === 'R' || sym === 'G') {
      req.colored[sym]++;
      req.total++;
    } else if (sym === 'C') {
      req.colorless++;
      req.total++;
    } else if (/^\d+$/.test(sym)) {
      req.generic += parseInt(sym, 10);
      req.total += parseInt(sym, 10);
    } else if (sym === 'X') {
      req.hasX = true;
    } else if (sym.indexOf('/') !== -1) {
      // Hybrid mana like {W/U} — count as needing one of either
      req.generic++;
      req.total++;
    }
  }
  return req;
}

/**
 * Determine what mana colors a land can produce (without actually tapping it).
 * Returns array of color keys: ['W'], ['R','G'], ['W','U','B','R','G'], etc.
 */
function getLandManaProduction(cardData) {
  var colors = [];
  var type = (cardData.typeLine || '').toLowerCase();
  var name = (cardData.name || '').toLowerCase();

  // Basic land types — check both typeLine and name
  if (type.includes('plains') || name === 'plains') colors.push('W');
  if (type.includes('island') || name === 'island') colors.push('U');
  if (type.includes('swamp') || name === 'swamp') colors.push('B');
  if (type.includes('mountain') || name === 'mountain') colors.push('R');
  if (type.includes('forest') || name === 'forest') colors.push('G');

  // Parse oracle text for tap-add patterns
  var production = parseManaProduction(cardData.oracleText);
  if (production) {
    MANA_COLORS.forEach(function(c) {
      if (production.fixed[c] > 0 && colors.indexOf(c) === -1) colors.push(c);
    });
    // Choice lands: "{R} or {G}" etc.
    if (production.choices && production.choices.length > 0) {
      production.choices.forEach(function(opts) {
        opts.forEach(function(c) {
          if (colors.indexOf(c) === -1) colors.push(c);
        });
      });
    }
    // Any-color lands (Command Tower, City of Brass, etc.)
    if (production.anyColor > 0) {
      ['W','U','B','R','G'].forEach(function(c) {
        if (colors.indexOf(c) === -1) colors.push(c);
      });
    }
  }

  // Wastes / colorless-only lands
  if (colors.length === 0 && type.includes('land')) {
    colors.push('C');
  }

  return colors;
}

/**
 * Smart auto-tap algorithm.
 * Given a mana cost and a player index, determine which untapped lands to tap.
 * Prioritizes:
 *   1. Tap single-color lands that match ONLY the needed colors first
 *   2. Then tap dual lands where one color is needed
 *   3. Use "any color" / 5-color lands last (preserve flexibility)
 *   4. For generic costs, prefer tapping lands whose colors are NOT needed
 *
 * Returns { success: bool, landsToTap: [cardData...], manaProduced: {W:n,...}, shortfall: string|null }
 */
function calculateAutoTap(manaCost, playerIndex) {
  if (!gameState || !manaCost) return { success: false, landsToTap: [], manaProduced: {}, shortfall: 'No mana cost' };

  var req = parseManaCostRequirements(manaCost);
  if (!req) return { success: false, landsToTap: [], manaProduced: {}, shortfall: 'Cannot parse cost' };

  // If cost is 0 total and no X, no tapping needed
  if (req.total === 0 && !req.hasX) return { success: true, landsToTap: [], manaProduced: { W:0, U:0, B:0, R:0, G:0, C:0 }, shortfall: null };

  var player = gameState.players[playerIndex];
  if (!player) return { success: false, landsToTap: [], manaProduced: {}, shortfall: 'Invalid player' };

  // First check: can the pool already pay? If so, no tapping needed.
  if (canPayManaCost(manaCost, player.manaPool)) {
    return { success: true, landsToTap: [], manaProduced: { W:0, U:0, B:0, R:0, G:0, C:0 }, shortfall: null, poolSufficient: true };
  }

  // Account for existing mana in pool by reducing requirements
  var poolCopy = { W: player.manaPool.W||0, U: player.manaPool.U||0, B: player.manaPool.B||0, R: player.manaPool.R||0, G: player.manaPool.G||0, C: player.manaPool.C||0 };

  // Get all untapped lands and mana-producing permanents for this player
  var untappedLands = gameState.battlefieldCards.filter(function(c) {
    return c.ownerIndex === playerIndex && !c.tapped && isManaProducer(c);
  });

  // Build production info for each land
  var landInfo = untappedLands.map(function(land) {
    return {
      card: land,
      colors: getLandManaProduction(land),
      flexibility: 0
    };
  });

  // Calculate flexibility score (how many different colors it can produce)
  landInfo.forEach(function(li) {
    li.flexibility = li.colors.length;
  });

  // Figure out what we still need after using pool mana
  var needed = { W: req.colored.W, U: req.colored.U, B: req.colored.B, R: req.colored.R, G: req.colored.G };
  // Reduce needed by what the pool already has
  ['W','U','B','R','G'].forEach(function(c) {
    var fromPool = Math.min(needed[c], poolCopy[c]);
    needed[c] -= fromPool;
    poolCopy[c] -= fromPool;
  });
  var genericNeeded = req.generic + req.colorless;
  // Reduce generic by remaining pool
  var poolRemainder = poolCopy.W + poolCopy.U + poolCopy.B + poolCopy.R + poolCopy.G + poolCopy.C;
  var genericFromPool = Math.min(genericNeeded, poolRemainder);
  genericNeeded -= genericFromPool;

  var landsToTap = [];
  var manaProduced = { W:0, U:0, B:0, R:0, G:0, C:0 };
  var usedLands = {};

  // PASS 1: Tap single-color lands that produce EXACTLY a needed color
  var colorsNeeded = ['W','U','B','R','G'].filter(function(c) { return needed[c] > 0; });
  colorsNeeded.forEach(function(color) {
    var candidates = landInfo.filter(function(li) {
      return !usedLands[li.card.id] && li.colors.indexOf(color) !== -1;
    }).sort(function(a, b) {
      if (a.flexibility !== b.flexibility) return a.flexibility - b.flexibility;
      return 0;
    });

    for (var i = 0; i < candidates.length && needed[color] > 0; i++) {
      var li = candidates[i];
      usedLands[li.card.id] = true;
      landsToTap.push(li.card);
      manaProduced[color]++;
      needed[color]--;
    }
  });

  // PASS 2: For remaining colored needs, tap multi-color lands
  ['W','U','B','R','G'].forEach(function(color) {
    if (needed[color] <= 0) return;
    var candidates = landInfo.filter(function(li) {
      return !usedLands[li.card.id] && li.colors.indexOf(color) !== -1;
    }).sort(function(a, b) { return a.flexibility - b.flexibility; });

    for (var i = 0; i < candidates.length && needed[color] > 0; i++) {
      var li = candidates[i];
      usedLands[li.card.id] = true;
      landsToTap.push(li.card);
      manaProduced[color]++;
      needed[color]--;
    }
  });

  // Check if all colored requirements are met
  var colorShortfall = [];
  ['W','U','B','R','G'].forEach(function(c) {
    if (needed[c] > 0) colorShortfall.push(needed[c] + ' ' + MANA_LABELS[c]);
  });

  // PASS 3: Tap lands for generic/colorless costs
  if (genericNeeded > 0) {
    var genericCandidates = landInfo.filter(function(li) {
      return !usedLands[li.card.id];
    }).sort(function(a, b) {
      var aUseful = a.colors.filter(function(c) { return colorsNeeded.indexOf(c) !== -1; }).length;
      var bUseful = b.colors.filter(function(c) { return colorsNeeded.indexOf(c) !== -1; }).length;
      if (aUseful !== bUseful) return aUseful - bUseful;
      return a.flexibility - b.flexibility;
    });

    for (var i = 0; i < genericCandidates.length && genericNeeded > 0; i++) {
      var li = genericCandidates[i];
      usedLands[li.card.id] = true;
      landsToTap.push(li.card);
      var pickColor = 'C';
      if (li.colors.length > 0 && li.colors[0] !== 'C') {
        pickColor = li.colors[0];
        for (var j = 0; j < li.colors.length; j++) {
          if (colorsNeeded.indexOf(li.colors[j]) === -1) {
            pickColor = li.colors[j];
            break;
          }
        }
      }
      manaProduced[pickColor]++;
      genericNeeded--;
    }
  }

  var success = colorShortfall.length === 0 && genericNeeded <= 0;
  var shortfall = null;
  if (!success) {
    var parts = [];
    if (colorShortfall.length > 0) parts = parts.concat(colorShortfall);
    if (genericNeeded > 0) parts.push(genericNeeded + ' Generic');
    shortfall = 'Need ' + parts.join(', ');
  }

  return {
    success: success,
    landsToTap: landsToTap,
    manaProduced: manaProduced,
    shortfall: shortfall,
    poolSufficient: false
  };
}

/**
 * Execute auto-tap: tap the specified lands and add mana to pool.
 * Provides visual feedback with pulse animation on tapped lands.
 */
function executeAutoTap(landsToTap, playerIndex) {
  if (!gameState || !landsToTap || landsToTap.length === 0) return;
  var player = gameState.players[playerIndex];
  if (!player) return;

  // Switch mana pool view to the casting player
  var manaSelect = document.getElementById('mana-pool-player-select');
  if (manaSelect) manaSelect.value = playerIndex;

  landsToTap.forEach(function(cardData) {
    cardData.tapped = true;
    var cardEl = document.getElementById('bc-' + cardData.id);
    if (cardEl) {
      cardEl.classList.add('tapped');
      cardEl.classList.add('auto-tap-pulse');
      setTimeout(function() {
        cardEl.classList.remove('auto-tap-pulse');
      }, 1200);
    }
    handleManaOnTap(cardData);
  });

  addLogEntry('⚡ Auto-tapped <strong>' + landsToTap.length + '</strong> land' + (landsToTap.length > 1 ? 's' : '') + ' for <strong>' + player.name + '</strong>');
}

/**
 * Spend mana from pool to pay a cost.
 * Deducts colored mana first, then generic from whatever is available.
 * Returns true if successful, false if insufficient.
 */
function spendManaFromPool(manaCost, playerIndex) {
  if (!gameState || !manaCost) return true;
  var player = gameState.players[playerIndex];
  if (!player) return false;

  var req = parseManaCostRequirements(manaCost);
  if (!req || req.total === 0) return true;

  // Check first
  if (!canPayManaCost(manaCost, player.manaPool)) return false;

  // Deduct colored costs
  ['W','U','B','R','G'].forEach(function(c) {
    var amt = req.colored[c] || 0;
    player.manaPool[c] = Math.max(0, (player.manaPool[c] || 0) - amt);
  });

  // Deduct colorless costs (from C pool first)
  var clNeeded = req.colorless;
  if (clNeeded > 0 && player.manaPool.C >= clNeeded) {
    player.manaPool.C -= clNeeded;
    clNeeded = 0;
  } else if (clNeeded > 0) {
    clNeeded -= player.manaPool.C;
    player.manaPool.C = 0;
  }

  // Deduct generic costs (from least valuable mana first)
  var genNeeded = req.generic + clNeeded;
  var spendOrder = MANA_COLORS.slice().sort(function(a, b) {
    return (player.manaPool[b] || 0) - (player.manaPool[a] || 0);
  });
  spendOrder.forEach(function(c) {
    if (genNeeded <= 0) return;
    var spend = Math.min(genNeeded, player.manaPool[c] || 0);
    player.manaPool[c] -= spend;
    genNeeded -= spend;
  });

  addLogEntry('💸 <strong>' + player.name + '</strong> spent ' + (manaCost || '0') + ' mana');

  renderManaPool();
  renderHandArea();
  return true;
}

/**
 * Show mana shortfall warning popup.
 */
function showManaShortfallWarning(cardName, shortfall, playerIndex) {
  var modal = document.getElementById('mana-shortfall-modal');
  if (!modal) return;
  var titleEl = document.getElementById('mana-shortfall-title');
  var bodyEl = document.getElementById('mana-shortfall-body');
  if (titleEl) titleEl.textContent = 'Insufficient Mana';
  if (bodyEl) {
    bodyEl.innerHTML = '<div class="mana-shortfall-card-name">' + cardName + '</div>' +
      '<div class="mana-shortfall-detail">' + shortfall + '</div>' +
      '<div class="mana-shortfall-hint">Tap more lands or use mana abilities, then try again.</div>';
  }
  modal.classList.add('visible');
  setTimeout(function() { closeManaShortfallModal(); }, 4000);
}

function closeManaShortfallModal() {
  var modal = document.getElementById('mana-shortfall-modal');
  if (modal) modal.classList.remove('visible');
}

/**
 * Master function: attempt to cast a card by auto-tapping lands and spending mana.
 * Returns true always (simulator allows play even with shortfall).
 */
function attemptManaPay(manaCost, playerIndex, cardName) {
  if (!gameState) return true;
  var re = gameState.rulesEngine || {};

  if (!re.autoTapLands && !re.autoSpendMana) return true;

  if (!manaCost) return true;
  var req = parseManaCostRequirements(manaCost);
  if (!req || req.total === 0) return true;

  var player = gameState.players[playerIndex];
  if (!player) return true;

  // Check if the pool can already pay
  if (canPayManaCost(manaCost, player.manaPool)) {
    if (re.autoSpendMana) {
      spendManaFromPool(manaCost, playerIndex);
    }
    return true;
  }

  // Auto-tap lands to generate mana
  if (re.autoTapLands) {
    var tapResult = calculateAutoTap(manaCost, playerIndex);

    if (tapResult.poolSufficient) {
      if (re.autoSpendMana) {
        spendManaFromPool(manaCost, playerIndex);
      }
      return true;
    }

    if (tapResult.success) {
      executeAutoTap(tapResult.landsToTap, playerIndex);
      if (re.autoSpendMana) {
        spendManaFromPool(manaCost, playerIndex);
      }
      return true;
    } else {
      showManaShortfallWarning(cardName || 'Unknown Card', tapResult.shortfall, playerIndex);
      if (tapResult.landsToTap.length > 0) {
        executeAutoTap(tapResult.landsToTap, playerIndex);
      }
      return true; // Allow play anyway — simulator flexibility
    }
  }

  return true;
}

/**
 * Tap all untapped lands for a player — quick mana generation.
 */
function tapAllLands(playerIndex) {
  if (!gameState) return;
  var pid = (playerIndex !== undefined) ? playerIndex : gameState.currentPlayerIndex;
  var player = gameState.players[pid];
  if (!player) return;
  pushUndoState();

  var untappedLands = gameState.battlefieldCards.filter(function(c) {
    return c.ownerIndex === pid && !c.tapped && isManaProducer(c) &&
           (c.typeLine || '').toLowerCase().indexOf('land') !== -1;
  });

  if (untappedLands.length === 0) {
    addLogEntry('No untapped lands to tap');
    return;
  }

  untappedLands.forEach(function(cardData) {
    cardData.tapped = true;
    var cardEl = document.getElementById('bc-' + cardData.id);
    if (cardEl) {
      cardEl.classList.add('tapped');
      cardEl.classList.add('auto-tap-pulse');
      setTimeout(function() { cardEl.classList.remove('auto-tap-pulse'); }, 1200);
    }
    handleManaOnTap(cardData);
  });

  addLogEntry('⚡ Tapped all <strong>' + untappedLands.length + '</strong> lands for <strong>' + player.name + '</strong>');
}

/**
 * Get floating mana summary text for a player.
 */
function getManaFloatingSummary(playerIndex) {
  if (!gameState) return '';
  var p = gameState.players[playerIndex];
  if (!p || !p.manaPool) return '';
  var parts = [];
  var icons = { W: '☀', U: '💧', B: '💀', R: '🔥', G: '🌲', C: '◇' };
  MANA_COLORS.forEach(function(c) {
    if (p.manaPool[c] > 0) parts.push(icons[c] + p.manaPool[c]);
  });
  return parts.join(' ');
}


function getSelectedManaPlayerId() {
  const sel = document.getElementById('mana-pool-player-select');
  return sel ? parseInt(sel.value) : 0;
}

function adjustMana(color, amount) {
  if (!gameState) return;
  const pid = getSelectedManaPlayerId();
  const player = gameState.players[pid];
  if (!player) return;
  player.manaPool[color] = Math.max(0, player.manaPool[color] + amount);
  renderManaPool();
}

function emptyManaPool() {
  if (!gameState) return;
  pushUndoState();
  const pid = getSelectedManaPlayerId();
  const player = gameState.players[pid];
  if (!player) return;
  MANA_COLORS.forEach(c => { player.manaPool[c] = 0; });
  renderManaPool();
  addLogEntry(`\u2205 ${player.name} emptied their mana pool`);
}

function emptyAllManaPools() {
  if (!gameState) return;
  // Respect the auto-clear toggle
  if (!gameState.manaAutoClear) return;
  const hadMana = gameState.players.some(p => MANA_COLORS.some(c => p.manaPool[c] > 0));
  gameState.players.forEach(p => {
    MANA_COLORS.forEach(c => { p.manaPool[c] = 0; });
  });
  renderManaPool();
  if (hadMana) {
    addLogEntry('\u2205 Mana pools emptied (phase change)');
  }
}

function toggleManaAutoClear() {
  if (!gameState) return;
  const cb = document.getElementById('mana-autoclear-toggle');
  gameState.manaAutoClear = cb ? cb.checked : true;
}

function renderManaPool() {
  // Mana pool display removed — internal tracking only.
  // No visual update needed.
}

// Legacy renderManaPool body preserved for reference (removed from UI)
function _renderManaPoolLegacy() {
  if (!gameState) return;
  const pid = getSelectedManaPlayerId();
  const player = gameState.players[pid];
  if (!player) return;

  let total = 0;
  MANA_COLORS.forEach(c => {
    const val = player.manaPool[c] || 0;
    total += val;
    const el = document.getElementById(`mana-${c}`);
    if (el) {
      el.textContent = val;
      el.classList.toggle('has-mana', val > 0);
    }
  });

  const totalEl = document.getElementById('mana-total');
  if (totalEl) totalEl.textContent = total;

  // Refresh hand castability badges when mana changes
  if (typeof renderHandArea === 'function') {
    // Debounce to avoid excessive rerenders
    if (renderManaPool._handTimer) clearTimeout(renderManaPool._handTimer);
    renderManaPool._handTimer = setTimeout(function() { renderHandArea(); }, 100);
  }
}

function populateManaPlayerSelect() {
  const sel = document.getElementById('mana-pool-player-select');
  if (!sel || !gameState) return;
  sel.innerHTML = '';
  gameState.players.forEach((p, i) => {
    const opt = document.createElement('option');
    opt.value = i;
    opt.textContent = p.name;
    if (i === gameState.currentPlayerIndex) opt.selected = true;
    sel.appendChild(opt);
  });
}

function showManaPool() {
  // Mana pool display removed.
}

function toggleManaPoolCollapse() {
  const widget = document.getElementById('mana-pool-widget');
  const btn = document.getElementById('mana-pool-collapse');
  if (widget) {
    widget.classList.toggle('collapsed');
    if (btn) btn.textContent = widget.classList.contains('collapsed') ? '\u25b8' : '\u25be';
  }
}

function setupManaPoolDrag() {
  // Mana pool display removed — no drag setup needed.
}

// ============================================================

let setupPlayerCount = 4;
let setupStartingLife = 40;
let setupAiPlayers = new Set(); // indices of AI-controlled players
let setupAiDifficulty = 'easy';
// aiTurnActive declared in ui.js
var _aiBlockerPauseState = null; // { resumeFn, playerIdx } — set when AI turn pauses for human blockers
var setupDeckChoices = {}; // playerIdx -> { type: 'precon'|'import', preconId/text }

// Global inline-handler functions for setup screen (fallback for embedded browsers)
function selectPlayerCount(count) {
  setupPlayerCount = count;
  document.querySelectorAll('.player-count-btn').forEach(function(b) { b.classList.remove('active'); });
  var btn = document.querySelector('[data-count="' + count + '"]');
  if (btn) btn.classList.add('active');
  setupAiPlayers.clear();
  updatePlayerNameFields();
  updateAiToggleGrid();
}

function adjustSetupLife(delta) {
  setupStartingLife = Math.max(1, Math.min(999, setupStartingLife + delta));
  var el = document.getElementById('starting-life-display');
  if (el) el.textContent = setupStartingLife;
}

function selectAiDifficulty(el, diff) {
  setupAiDifficulty = diff;
  document.querySelectorAll('.ai-diff-btn').forEach(function(b) { b.classList.remove('active'); });
  el.classList.add('active');
}

function initSetupScreen() {
  // Player count buttons
  document.querySelectorAll('.player-count-btn').forEach(btn => {
    btn.addEventListener('click', () => {
      setupPlayerCount = parseInt(btn.dataset.count);
      document.querySelectorAll('.player-count-btn').forEach(b => b.classList.remove('active'));
      btn.classList.add('active');
      setupAiPlayers.clear();
      updatePlayerNameFields();
      updateAiToggleGrid();
    });
  });

  // AI difficulty buttons
  document.querySelectorAll('.ai-diff-btn').forEach(btn => {
    btn.addEventListener('click', () => {
      setupAiDifficulty = btn.dataset.diff;
      document.querySelectorAll('.ai-diff-btn').forEach(b => b.classList.remove('active'));
      btn.classList.add('active');
    });
  });

  // Life adjust buttons use inline onclick handlers (Comet compatibility)
  // Do NOT add addEventListener here — would double-step the value

  // Start game button now goes to Step 2 (deck selection) via inline onclick
  // Do NOT add addEventListener here — would bypass deck selection

  // Initial render
  document.querySelector(`[data-count="${setupPlayerCount}"]`)?.classList.add('active');
  updatePlayerNameFields();
  updateAiToggleGrid();
}

function updatePlayerNameFields() {
  const grid = document.getElementById('player-names-grid');
  if (!grid) return;
  grid.innerHTML = '';

  for (let i = 0; i < setupPlayerCount; i++) {
    const field = document.createElement('div');
    field.className = 'player-name-field';
    field.innerHTML = `
      <div class="player-color-dot" style="background:${PLAYER_COLORS[i]}"></div>
      <input
        class="player-name-input"
        type="text"
        placeholder="Player ${i + 1}"
        maxlength="20"
        id="player-name-${i}"
        autocomplete="off"
      />
    `;
    grid.appendChild(field);
  }
}

function updateAiToggleGrid() {
  const grid = document.getElementById('ai-toggle-grid');
  if (!grid) return;
  grid.innerHTML = '';

  for (let i = 0; i < setupPlayerCount; i++) {
    const isAi = setupAiPlayers.has(i);
    const btn = document.createElement('button');
    btn.className = 'ai-toggle-btn' + (isAi ? ' ai-active' : '');
    btn.innerHTML = `
      <div class="ai-toggle-dot" style="background:${PLAYER_COLORS[i]}"></div>
      <span class="ai-toggle-label">${isAi ? '🤖 AI' : '👤 Human'}</span>
      <span class="ai-toggle-name">P${i + 1}</span>
    `;
    btn.addEventListener('click', () => {
      // Don't allow all players to be AI
      if (!setupAiPlayers.has(i)) {
        const humanCount = setupPlayerCount - setupAiPlayers.size;
        if (humanCount <= 1) return; // need at least 1 human
        setupAiPlayers.add(i);
      } else {
        setupAiPlayers.delete(i);
      }
      updateAiToggleGrid();
      // Auto-set AI names
      const nameInput = document.getElementById(`player-name-${i}`);
      if (nameInput) {
        if (setupAiPlayers.has(i) && (!nameInput.value.trim() || nameInput.value.startsWith('Player '))) {
          nameInput.value = `AI Bot ${i + 1}`;
        } else if (!setupAiPlayers.has(i) && nameInput.value.startsWith('AI Bot')) {
          nameInput.value = '';
        }
      }
    });
    grid.appendChild(btn);
  }

  // Show/hide difficulty row
  const diffRow = document.getElementById('ai-difficulty-row');
  if (diffRow) diffRow.style.display = setupAiPlayers.size > 0 ? 'flex' : 'none';
}

// ============================================================
// SETUP STEP 2: DECK SELECTION
// ============================================================

function goToStep2() {
  var step1 = document.getElementById('setup-step-1');
  var step2 = document.getElementById('setup-step-2');
  if (step1) step1.classList.add('hidden');
  if (step2) step2.classList.remove('hidden');
  renderDeckSelectionGrid();
}

function goBackToStep1() {
  var step2 = document.getElementById('setup-step-2');
  var step1 = document.getElementById('setup-step-1');
  if (step2) step2.classList.add('hidden');
  if (step1) step1.classList.remove('hidden');
  // Clear pending choices when going back
  setupDeckChoices = {};
}

function renderDeckSelectionGrid() {
  var grid = document.getElementById('deck-selection-grid');
  if (!grid) return;
  grid.innerHTML = '';

  for (var i = 0; i < setupPlayerCount; i++) {
    var isAi = setupAiPlayers.has(i);
    var nameInput = document.getElementById('player-name-' + i);
    var playerName = (nameInput && nameInput.value.trim()) ||
      (isAi ? ('AI Bot ' + (i + 1)) : ('Player ' + (i + 1)));
    var color = (typeof PLAYER_COLORS !== 'undefined' && PLAYER_COLORS[i]) ? PLAYER_COLORS[i] : '#888';

    var panel = document.createElement('div');
    panel.className = 'deck-select-panel';
    panel.id = 'setup-deck-panel-' + i;

    // Build precon select options grouped by set
    var preconOptionsHtml = '<option value="">-- Select a precon --</option>';
    if (typeof PRECON_DATA !== 'undefined' && PRECON_DATA.length) {
      var sets = {};
      PRECON_DATA.forEach(function(p) {
        if (!sets[p.set]) sets[p.set] = [];
        sets[p.set].push(p);
      });
      Object.keys(sets).forEach(function(setName) {
        preconOptionsHtml += '<optgroup label="' + setName.replace(/"/g, '&quot;') + '">';
        sets[setName].forEach(function(p) {
          preconOptionsHtml += '<option value="' + p.id + '">' + p.name.replace(/"/g, '&quot;') + '</option>';
        });
        preconOptionsHtml += '</optgroup>';
      });
    }

    if (isAi) {
      panel.innerHTML =
        '<div class="deck-select-panel-header">' +
          '<div class="player-color-dot" style="background:' + color + '"></div>' +
          '<span class="deck-select-player-name">' + playerName + '</span>' +
          '<span class="deck-select-ai-badge">AI</span>' +
        '</div>' +
        '<div style="color:var(--color-text-secondary);font-size:var(--text-sm);">AI Deck (auto-generated)</div>';
    } else {
      var idx = i;
      // Build saved decks options
      var savedDecks = (typeof getDecks === 'function') ? getDecks() : [];
      var savedDecksHtml = '';
      if (savedDecks.length === 0) {
        savedDecksHtml = '<div style="color:var(--color-text-faint);font-size:var(--text-sm);padding:var(--space-3);">No saved decks. Build one in Deck Builder first.</div>';
      } else {
        savedDecksHtml = '<div class="setup-custom-deck-list" id="setup-custom-deck-list-' + idx + '">';
        for (var di = 0; di < savedDecks.length; di++) {
          var sd = savedDecks[di];
          var cardCount = 0;
          if (sd.cards) sd.cards.forEach(function(c) { cardCount += (c.quantity || 1); });
          if (sd.commander) cardCount++;
          var deckColors = '';
          if (sd.commander && sd.commander.colorIdentity && sd.commander.colorIdentity.length) {
            var manaSymbols = { W: '\u2600', U: '\uD83D\uDCA7', B: '\uD83D\uDC80', R: '\uD83D\uDD25', G: '\uD83C\uDF33' };
            sd.commander.colorIdentity.forEach(function(c) { deckColors += (manaSymbols[c] || c) + ' '; });
          }
          savedDecksHtml += '<button class="setup-custom-deck-btn" id="setup-custom-deck-btn-' + idx + '-' + di + '"' +
            ' onclick="selectSetupCustomDeck(' + idx + ',\'' + sd.id.replace(/'/g, "\\'") + '\')">' +
            '<span class="setup-custom-deck-name">' + (sd.name || 'Untitled').replace(/</g, '&lt;') + '</span>' +
            '<span class="setup-custom-deck-meta">' + deckColors + cardCount + ' cards</span>' +
          '</button>';
        }
        savedDecksHtml += '</div>';
      }

      panel.innerHTML =
        '<div class="deck-select-panel-header">' +
          '<div class="player-color-dot" style="background:' + color + '"></div>' +
          '<span class="deck-select-player-name">' + playerName + '</span>' +
          '<span class="deck-select-status" id="setup-deck-status-' + idx + '">No deck selected</span>' +
        '</div>' +
        '<div class="deck-select-tabs">' +
          '<button class="deck-select-tab active" id="setup-deck-tab-precon-' + idx + '" onclick="switchSetupDeckTab(' + idx + ',\'precon\')">Precon</button>' +
          '<button class="deck-select-tab" id="setup-deck-tab-mydecks-' + idx + '" onclick="switchSetupDeckTab(' + idx + ',\'mydecks\')">My Decks</button>' +
          '<button class="deck-select-tab" id="setup-deck-tab-import-' + idx + '" onclick="switchSetupDeckTab(' + idx + ',\'import\')">Import</button>' +
        '</div>' +
        '<div class="deck-select-tab-content active" id="setup-deck-content-precon-' + idx + '">' +
          '<select class="deck-select-precon-select" id="setup-deck-precon-select-' + idx + '" onchange="selectSetupPrecon(' + idx + ')">' +
            preconOptionsHtml +
          '</select>' +
        '</div>' +
        '<div class="deck-select-tab-content" id="setup-deck-content-mydecks-' + idx + '">' +
          savedDecksHtml +
        '</div>' +
        '<div class="deck-select-tab-content" id="setup-deck-content-import-' + idx + '">' +
          '<textarea class="deck-select-import-text" id="setup-deck-import-text-' + idx + '" placeholder="Paste deck list here...&#10;&#10;// Commander&#10;1 Atraxa, Praetors\' Voice&#10;&#10;// Deck&#10;1 Sol Ring&#10;..."></textarea>' +
          '<button class="deck-select-import-btn" onclick="importSetupDeck(' + idx + ')">\uD83D\uDCE5 Validate &amp; Use This List</button>' +
        '</div>';
    }

    grid.appendChild(panel);
  }
}

function switchSetupDeckTab(playerIdx, tab) {
  var tabs = ['precon', 'mydecks', 'import'];
  tabs.forEach(function(t) {
    var tabBtn = document.getElementById('setup-deck-tab-' + t + '-' + playerIdx);
    var content = document.getElementById('setup-deck-content-' + t + '-' + playerIdx);
    if (tabBtn) tabBtn.classList.remove('active');
    if (content) content.classList.remove('active');
  });
  var activeTab = document.getElementById('setup-deck-tab-' + tab + '-' + playerIdx);
  var activeContent = document.getElementById('setup-deck-content-' + tab + '-' + playerIdx);
  if (activeTab) activeTab.classList.add('active');
  if (activeContent) activeContent.classList.add('active');
}

function selectSetupPrecon(playerIdx) {
  var sel = document.getElementById('setup-deck-precon-select-' + playerIdx);
  var statusEl = document.getElementById('setup-deck-status-' + playerIdx);
  if (!sel) return;
  var preconId = sel.value;
  if (!preconId) {
    delete setupDeckChoices[playerIdx];
    if (statusEl) { statusEl.textContent = 'No deck selected'; statusEl.className = 'deck-select-status'; }
    return;
  }
  var precon = (typeof PRECON_DATA !== 'undefined') ? PRECON_DATA.find(function(p) { return p.id === preconId; }) : null;
  var preconName = precon ? precon.name : preconId;
  setupDeckChoices[playerIdx] = { type: 'precon', preconId: preconId };
  if (statusEl) { statusEl.textContent = 'Precon: ' + preconName; statusEl.className = 'deck-select-status loaded'; }
}

function importSetupDeck(playerIdx) {
  var textarea = document.getElementById('setup-deck-import-text-' + playerIdx);
  var statusEl = document.getElementById('setup-deck-status-' + playerIdx);
  if (!textarea) return;
  var text = textarea.value.trim();
  if (!text) {
    if (statusEl) { statusEl.textContent = 'Paste a deck list first.'; statusEl.className = 'deck-select-status'; }
    return;
  }
  var parsed = parseDeckList(text);
  if (!parsed.length) {
    if (statusEl) { statusEl.textContent = 'Could not parse cards from list.'; statusEl.className = 'deck-select-status'; }
    return;
  }
  var total = parsed.reduce(function(sum, e) { return sum + e.qty; }, 0);
  setupDeckChoices[playerIdx] = { type: 'import', text: text };
  if (statusEl) { statusEl.textContent = 'Deck ready (' + total + ' cards)'; statusEl.className = 'deck-select-status loaded'; }
}

function selectSetupCustomDeck(playerIdx, deckId) {
  var decks = (typeof getDecks === 'function') ? getDecks() : [];
  var deck = decks.find(function(d) { return d.id === deckId; });
  if (!deck) return;
  var statusEl = document.getElementById('setup-deck-status-' + playerIdx);

  // Highlight selected button, unhighlight others
  var listEl = document.getElementById('setup-custom-deck-list-' + playerIdx);
  if (listEl) {
    listEl.querySelectorAll('.setup-custom-deck-btn').forEach(function(b) { b.classList.remove('selected'); });
  }
  var btns = document.querySelectorAll('[id^="setup-custom-deck-btn-' + playerIdx + '-"]');
  btns.forEach(function(b) { b.classList.remove('selected'); });
  // Find the right button by matching deckId in onclick
  btns.forEach(function(b) {
    if (b.getAttribute('onclick') && b.getAttribute('onclick').indexOf(deckId) !== -1) {
      b.classList.add('selected');
    }
  });

  setupDeckChoices[playerIdx] = { type: 'custom', deckId: deckId };
  var cardCount = 0;
  if (deck.cards) deck.cards.forEach(function(c) { cardCount += (c.quantity || 1); });
  if (deck.commander) cardCount++;
  if (statusEl) { statusEl.textContent = deck.name + ' (' + cardCount + ' cards)'; statusEl.className = 'deck-select-status loaded'; }
}

async function loadCustomDeckForPlayer(playerIdx, deckId) {
  var decks = (typeof getDecks === 'function') ? getDecks() : [];
  var deck = decks.find(function(d) { return d.id === deckId; });
  if (!deck) return;
  var player = gameState.players[playerIdx];
  if (!player) return;

  // Convert deck builder format to a text decklist, then use importDeckForPlayer
  var lines = [];
  if (deck.commander) {
    lines.push('// Commander');
    lines.push('1 ' + deck.commander.name);
    lines.push('');
    lines.push('// Deck');
  }
  if (deck.cards && deck.cards.length) {
    deck.cards.forEach(function(c) {
      lines.push((c.quantity || 1) + ' ' + c.name);
    });
  }
  var deckText = lines.join('\n');
  await importDeckForPlayer(playerIdx, deckText);
  addLogEntry('\uD83D\uDCCB <strong>' + player.name + '</strong> loaded custom deck "' + deck.name + '"');
}

async function loadPreconForPlayer(playerIdx, preconId) {
  if (typeof PRECON_DATA === 'undefined') return;
  var precon = PRECON_DATA.find(function(p) { return p.id === preconId; });
  if (!precon) return;
  var player = gameState.players[playerIdx];
  if (!player) return;

  // Try to get decklist text: embedded first, then fetch from backend .dck file
  var decklistText = precon.decklist || '';
  if (!decklistText && precon.fileName) {
    // Fetch .dck file from backend if available
    if (typeof AIBridge !== 'undefined' && AIBridge.connector.connected) {
      try {
        var deckData = await AIBridge.deckSource.fetchPreconDeck(precon.fileName);
        if (deckData && deckData.decklist) {
          decklistText = deckData.decklist;
        } else if (deckData && typeof deckData === 'string') {
          decklistText = deckData;
        }
      } catch (e) {
        console.warn('[loadPreconForPlayer] Backend deck fetch failed:', e);
      }
    }
    // Fallback: try to fetch .dck file directly from precon-decks/ (same origin)
    if (!decklistText) {
      try {
        var resp = await fetch('precon-decks/' + precon.fileName);
        if (resp.ok) {
          decklistText = await resp.text();
        }
      } catch (e) {
        // Fallback: try relative to backend
        try {
          var resp2 = await fetch('/precon-decks/' + precon.fileName);
          if (resp2.ok) {
            decklistText = await resp2.text();
          }
        } catch (e2) {
          console.warn('[loadPreconForPlayer] Could not fetch .dck file:', precon.fileName);
        }
      }
    }
  }

  var parsedCards = parseDeckList(decklistText);
  if (!parsedCards.length) return;

  var allCardNames = [];
  for (var ei = 0; ei < parsedCards.length; ei++) {
    for (var q = 0; q < parsedCards[ei].qty; q++) {
      allCardNames.push(parsedCards[ei].name);
    }
  }

  var cardDataMap = await batchFetchCards(allCardNames, null);

  var libraryCards = [];
  var commandCards = [];
  for (var ci = 0; ci < parsedCards.length; ci++) {
    var entry = parsedCards[ci];
    var scryfallCard = cardDataMap.get(entry.name.toLowerCase());
    if (!scryfallCard) continue;
    var cardObj = scryfallToZoneCard(scryfallCard);
    for (var cq = 0; cq < entry.qty; cq++) {
      if (entry.section === 'commander') {
        commandCards.push(Object.assign({}, cardObj));
      } else {
        libraryCards.push(Object.assign({}, cardObj));
      }
    }
  }

  player.zones.library = [];
  player.zones.hand = [];
  player.zones.command = [];

  commandCards.forEach(function(card) { player.zones.command.push(card); });
  if (commandCards.length > 0) {
    player.commanderCardName = commandCards[0].name || '';
  }

  // Shuffle library
  for (var si = libraryCards.length - 1; si > 0; si--) {
    var sj = Math.floor(Math.random() * (si + 1));
    var tmp = libraryCards[si]; libraryCards[si] = libraryCards[sj]; libraryCards[sj] = tmp;
  }
  libraryCards.forEach(function(card) { player.zones.library.push(card); });

  // Draw opening hand of 7
  if (player.zones.library.length >= 7) {
    for (var di = 0; di < 7; di++) {
      player.zones.hand.push(player.zones.library.shift());
    }
  }

  addLogEntry('\uD83D\uDCCB <strong>' + player.name + '</strong> loaded precon "' + precon.name + '" (' + (libraryCards.length + commandCards.length) + ' cards)');
}

async function importDeckForPlayer(playerIdx, deckText) {
  var player = gameState.players[playerIdx];
  if (!player || !deckText.trim()) return;

  var parsedCards = parseDeckList(deckText);
  if (!parsedCards.length) return;

  var allCardNames = [];
  for (var ei = 0; ei < parsedCards.length; ei++) {
    for (var q = 0; q < parsedCards[ei].qty; q++) {
      allCardNames.push(parsedCards[ei].name);
    }
  }

  var cardDataMap = await batchFetchCards(allCardNames, null);

  var libraryCards = [];
  var commandCards = [];
  for (var ci = 0; ci < parsedCards.length; ci++) {
    var entry = parsedCards[ci];
    var scryfallCard = cardDataMap.get(entry.name.toLowerCase());
    if (!scryfallCard) continue;
    var cardObj = scryfallToZoneCard(scryfallCard);
    for (var cq = 0; cq < entry.qty; cq++) {
      if (entry.section === 'commander') {
        commandCards.push(Object.assign({}, cardObj));
      } else {
        libraryCards.push(Object.assign({}, cardObj));
      }
    }
  }

  player.zones.library = [];
  player.zones.hand = [];
  player.zones.command = [];

  commandCards.forEach(function(card) { player.zones.command.push(card); });
  if (commandCards.length > 0 && !player.commanderCardName) {
    player.commanderCardName = commandCards[0].name || '';
  }

  // Shuffle library
  for (var si = libraryCards.length - 1; si > 0; si--) {
    var sj = Math.floor(Math.random() * (si + 1));
    var tmp = libraryCards[si]; libraryCards[si] = libraryCards[sj]; libraryCards[sj] = tmp;
  }
  libraryCards.forEach(function(card) { player.zones.library.push(card); });

  // Draw opening hand of 7
  if (player.zones.library.length >= 7) {
    for (var di = 0; di < 7; di++) {
      player.zones.hand.push(player.zones.library.shift());
    }
  }

  addLogEntry('\uD83D\uDCCB <strong>' + player.name + '</strong> imported a deck (' + (libraryCards.length + commandCards.length) + ' cards)');
}

async function startGameWithDecks() {
  // 1. Call existing startGame() — creates gameState, sets up AI, shows board
  startGame();

  // 2. Collect human players with deck choices
  var humanDecks = [];
  for (var i = 0; i < setupPlayerCount; i++) {
    if (setupAiPlayers.has(i)) continue;
    if (setupDeckChoices[i]) humanDecks.push({ idx: i, choice: setupDeckChoices[i] });
  }

  if (humanDecks.length === 0) {
    // No decks to load — if player 0 has cards already, enter mulligan
    if (gameState.players[0] && gameState.players[0].zones.hand.length > 0) {
      enterMulliganPhase(0);
    }
    setupDeckChoices = {};
    return;
  }

  // 3. Show loading overlay
  var overlay = document.createElement('div');
  overlay.id = 'deck-loading-overlay';
  overlay.className = 'deck-loading-overlay';
  overlay.innerHTML =
    '<div class="deck-loading-text">Loading Decks...</div>' +
    '<div class="deck-loading-subtext" id="deck-loading-subtext">Fetching cards from Scryfall</div>';
  document.body.appendChild(overlay);

  try {
    // 4. Process each human deck choice sequentially
    for (var d = 0; d < humanDecks.length; d++) {
      var hd = humanDecks[d];
      var sub = document.getElementById('deck-loading-subtext');
      var pName = gameState.players[hd.idx] ? gameState.players[hd.idx].name : ('Player ' + (hd.idx + 1));
      if (sub) sub.textContent = 'Loading deck for ' + pName + '...';

      if (hd.choice.type === 'precon') {
        await loadPreconForPlayer(hd.idx, hd.choice.preconId);
      } else if (hd.choice.type === 'custom') {
        await loadCustomDeckForPlayer(hd.idx, hd.choice.deckId);
      } else if (hd.choice.type === 'import') {
        await importDeckForPlayer(hd.idx, hd.choice.text);
      }
    }
  } catch (err) {
    console.error('[startGameWithDecks] Error loading decks:', err);
  }

  // 5. Remove overlay
  if (overlay.parentNode) overlay.parentNode.removeChild(overlay);

  // 6. Clear choices, re-render, enter mulligan
  setupDeckChoices = {};
  if (typeof updatePlayerZones === 'function') updatePlayerZones();
  renderPlayerPanels();
  renderHandArea();

  if (gameState.players[0] && gameState.players[0].zones.hand.length > 0) {
    enterMulliganPhase(0);
  }
}

function startGame() {
  const names = [];
  for (let i = 0; i < setupPlayerCount; i++) {
    const input = document.getElementById(`player-name-${i}`);
    names.push(input?.value.trim() || (setupAiPlayers.has(i) ? `AI Bot ${i + 1}` : `Player ${i + 1}`));
  }

  gameState = createInitialState(setupPlayerCount, names, setupStartingLife);

  // Clear undo/redo stacks for new game
  undoStack = [];
  redoStack = [];
  updateUndoRedoButtons();

  // Clear token history for new game
  tokenHistory = [];
  // Clear AI thought history for new game
  aiThoughts = [];
  // Hide token summary bar on new game
  var tsb = document.getElementById('token-summary-bar');
  if (tsb) tsb.style.display = 'none';

  // Initialize turn history with first turn
  const firstPlayer = gameState.players[0];
  gameState.turnHistory = [{
    turnNumber: 1,
    playerIndex: 0,
    playerName: firstPlayer?.name || 'Player 1',
    playerColor: firstPlayer?.color || PLAYER_COLORS[0] || '#666',
  }];

  // Mark AI players
  setupAiPlayers.forEach(idx => {
    if (gameState.players[idx]) {
      gameState.players[idx].isAI = true;
    }
  });
  gameState.aiDifficulty = setupAiDifficulty;

  // ========================================
  // Commander-AI-Lab: Initialize backend session
  // ========================================
  if (typeof AIBridge !== 'undefined' && AIBridge.connector.connected) {
    AIBridge.gameState.initSession(gameState).then(function(session) {
      if (session) {
        addLogEntry('\u{1F9E0} Connected to Commander-AI-Lab (session: ' +
          session.game_id.substring(0, 8) + '...)');
      }
    }).catch(function(err) {
      console.warn('[startGame] AI Bridge session init failed:', err);
    });
  }

  // Forge Engine: If enabled, start a Forge game session
  if (typeof ForgeBridge !== 'undefined' && ForgeBridge.enabled && ForgeBridge.connected) {
    gameState.forgeEnabled = true;
    forgeStartGame({
      players: gameState.players,
      startingLife: setupStartingLife,
      aiDifficulty: setupAiDifficulty,
    });
    // Show eval button
    var evalBtn = document.getElementById('btn-forge-eval');
    if (evalBtn) evalBtn.style.display = '';
  } else {
    gameState.forgeEnabled = false;
    var evalBtn2 = document.getElementById('btn-forge-eval');
    if (evalBtn2) evalBtn2.style.display = 'none';
  }

  // Setup AI decks (generates library, draws opening hand)
  setupAiDecks();

  // Fetch real Scryfall images for AI cards in background (non-blocking)
  fetchAiCardImages();

  // Hide setup, show board
  document.getElementById('setup-screen').classList.add('hidden');
  const board = document.getElementById('game-board');
  board.classList.add('visible');

  // Show game log sidebar
  var logSidebar = document.getElementById('game-log-sidebar');
  if (logSidebar) logSidebar.classList.remove('collapsed');

  // Show zone panel
  var zp = document.getElementById('zone-panel');
  if (zp) zp.classList.remove('hidden');

  initGameBoard();
  // showManaPool() removed — mana pool display removed
  // Set commanderCardName for each player from their command zone
  gameState.players.forEach(function(p) {
    if (p.zones.command && p.zones.command.length > 0) {
      p.commanderCardName = p.zones.command[0].name || '';
    }
  });
  addLogEntry(`🎮 Game started with ${setupPlayerCount} players, ${setupStartingLife} starting life`);
  renderPlayerPanels();
  renderHandArea();
  renderPhaseTracker();
  updateTurnDisplay();

  // Set default search focus
  setTimeout(() => {
    document.getElementById('card-search-input')?.focus();
  }, 600);

  // If first player is AI, start their turn
  if (gameState.players[0]?.isAI) {
    setTimeout(() => runAiTurn(), 1200);
  }
}

// ============================================================
// GAME BOARD INIT
// ============================================================

function initGameBoard() {
  setupBattlefieldDrop();
  setupContextMenu();
  setupKeyboardShortcuts();
  setupHandCardPreview();
  setupManaPoolDrag();
  updateStormCounter();
  initCombatOverlay();
  initZonePanel();
  buildOwnerFilterButtons();
  buildBattlefieldSections();

  // Next phase / next turn buttons use inline onclick handlers (Comet compatibility)
  // Do NOT add addEventListener here — would double-fire with onclick

  // Card search
  const searchInput = document.getElementById('card-search-input');
  if (searchInput) {
    searchInput.addEventListener('input', e => {
      searchScryfall(e.target.value);
    });
    searchInput.addEventListener('keydown', e => {
      if (e.key === 'Enter') {
        clearTimeout(searchDebounceTimer);
        searchScryfall(e.target.value);
      }
    });
    setSearchStatus('Type to search cards...');
  }

  // Sidebar toggles
  document.getElementById('toggle-search-sidebar')?.addEventListener('click', () => {
    document.getElementById('card-search-sidebar')?.classList.toggle('collapsed');
  });

  // Dice modal
  document.getElementById('btn-dice')?.addEventListener('click', openDiceModal);
  document.getElementById('close-dice-modal')?.addEventListener('click', closeDiceModal);
  document.getElementById('dice-modal')?.addEventListener('click', e => {
    if (e.target === document.getElementById('dice-modal')) closeDiceModal();
  });

  // Dice buttons
  document.getElementById('btn-roll-d6')?.addEventListener('click', () => rollDice(6));
  document.getElementById('btn-roll-d20')?.addEventListener('click', () => rollDice(20));
  document.getElementById('btn-roll-d12')?.addEventListener('click', () => rollDice(12));
  document.getElementById('btn-roll-d10')?.addEventListener('click', () => rollDice(10));
  document.getElementById('btn-roll-d8')?.addEventListener('click', () => rollDice(8));
  document.getElementById('btn-roll-d4')?.addEventListener('click', () => rollDice(4));
  document.getElementById('btn-flip-coin')?.addEventListener('click', flipCoin);

  // Zone modal
  document.getElementById('close-zone-modal')?.addEventListener('click', closeZoneModal);
  document.getElementById('zone-modal')?.addEventListener('click', e => {
    if (e.target === document.getElementById('zone-modal')) closeZoneModal();
  });

  // Scry modal
  document.getElementById('close-scry-modal')?.addEventListener('click', closeScryModal);
  document.getElementById('scry-modal')?.addEventListener('click', e => {
    if (e.target === document.getElementById('scry-modal')) closeScryModal();
  });
  document.getElementById('btn-scry-confirm')?.addEventListener('click', confirmScry);
  document.getElementById('btn-scry-all-top')?.addEventListener('click', scryAllTop);
  document.getElementById('btn-scry-all-bottom')?.addEventListener('click', scryAllBottom);

  // Zone tabs
  document.querySelectorAll('.zone-tab').forEach(tab => {
    tab.addEventListener('click', () => {
      activeZoneTab = tab.dataset.zone;
      renderZoneModal();
    });
  });

  // Trigger stack
  document.getElementById('btn-trigger-stack')?.addEventListener('click', toggleTriggerStack);
  document.getElementById('close-trigger-stack')?.addEventListener('click', closeTriggerStack);
  document.getElementById('btn-resolve-next')?.addEventListener('click', resolveNextTrigger);
  document.getElementById('btn-resolve-all')?.addEventListener('click', resolveAllTriggers);
  document.getElementById('btn-add-response')?.addEventListener('click', () => {
    // Open the card search sidebar for instant-speed responses
    const sidebar = document.getElementById('card-search-sidebar');
    if (sidebar) sidebar.classList.remove('collapsed');
    document.getElementById('card-search-input')?.focus();
    addLogEntry('⚡ Adding response — search for a card to respond with');
  });

  // Reset game
  document.getElementById('btn-reset')?.addEventListener('click', confirmReset);

  // Storm counter decrement
  document.getElementById('storm-counter')?.addEventListener('click', () => {
    gameState.stormCount = Math.max(0, gameState.stormCount - 1);
    updateStormCounter();
  });

  // Storm counter increment via FAB
  document.getElementById('btn-storm')?.addEventListener('click', () => {
    gameState.stormCount++;
    updateStormCounter();
    addLogEntry(`⛈ Storm count: <strong>${gameState.stormCount}</strong>`);
  });

  // Untap all
  document.getElementById('btn-untap-all')?.addEventListener('click', untapAllCards);

  // Theme toggle
  const themeToggle = document.querySelector('[data-theme-toggle]');
  if (themeToggle) {
    themeToggle.addEventListener('click', toggleTheme);
  }
}

// ============================================================
// UNTAP ALL
// ============================================================

function untapAllCards() {
  if (!gameState) return;
  pushUndoState();
  let count = 0;
  gameState.battlefieldCards.forEach(card => {
    if (card.tapped) {
      card.tapped = false;
      count++;
      const cardEl = document.getElementById(`bc-${card.id}`);
      if (cardEl) cardEl.classList.remove('tapped');
    }
  });
  if (count > 0) addLogEntry(`✨ Untapped <strong>${count}</strong> card${count > 1 ? 's' : ''}`);
}

// ============================================================
// RESET GAME
// ============================================================

function confirmReset() {
  const dialog = document.getElementById('confirm-dialog');
  if (dialog) dialog.classList.add('visible');
}

function executeReset() {
  const dialog = document.getElementById('confirm-dialog');
  if (dialog) dialog.classList.remove('visible');

  // Go back to setup
  document.getElementById('game-board').classList.remove('visible');
  document.getElementById('setup-screen').classList.remove('hidden');
  document.getElementById('setup-screen').style.display = '';

  // Hide game log sidebar
  var logSidebar = document.getElementById('game-log-sidebar');
  if (logSidebar) logSidebar.classList.add('collapsed');

  // Clear game state
  gameState = null;
  nextTriggerId = 1;

  // Close trigger stack if open
  closeTriggerStack();

  // Hide mana pool
  const manaWidget = document.getElementById('mana-pool-widget');
  if (manaWidget) manaWidget.classList.remove('visible');

  // Clear battlefield
  const battlefield = document.getElementById('battlefield');
  if (battlefield) {
    battlefield.querySelectorAll('.battlefield-card').forEach(c => c.remove());
    const label = battlefield.querySelector('.battlefield-label');
    if (label) label.style.opacity = '';
  }
  // Hide combat overlay
  hideCombatOverlay();

  // Hide player 1 fixed panel
  const p1Fixed = document.getElementById('player1-fixed-panel');
  if (p1Fixed) { p1Fixed.innerHTML = ''; p1Fixed.classList.add('hidden'); }

  // Clear log
  const logContainer = document.getElementById('log-entries');
  if (logContainer) logContainer.innerHTML = '';
}

// ============================================================
// KEYBOARD SHORTCUTS
// ============================================================

let shortcutHintTimer = null;

function showShortcutHint() {
  const hint = document.getElementById('shortcut-hint');
  if (!hint) return;
  hint.classList.add('show');
  clearTimeout(shortcutHintTimer);
  shortcutHintTimer = setTimeout(() => hint.classList.remove('show'), 2500);
}

function setupKeyboardShortcuts() {
  document.addEventListener('keydown', e => {
    // Undo/Redo — Ctrl+Z / Ctrl+Shift+Z (works everywhere including inputs)
    if ((e.ctrlKey || e.metaKey) && e.key === 'z' && !e.shiftKey) {
      e.preventDefault();
      undo();
      return;
    }
    if ((e.ctrlKey || e.metaKey) && e.key === 'z' && e.shiftKey) {
      e.preventDefault();
      redo();
      return;
    }
    if ((e.ctrlKey || e.metaKey) && e.key === 'y') {
      e.preventDefault();
      redo();
      return;
    }

    // Don't fire when typing in inputs
    if (e.target.matches('input, textarea, select')) return;

    switch(e.key) {
      case ' ':
        e.preventDefault();
        // If priority window is open, Space passes priority
        if (isPriorityBlocking()) {
          passPriority();
        } else {
          nextPhase();
        }
        break;
      case 'n':
      case 'N':
        nextTurn();
        break;
      case 'u':
      case 'U':
        untapAllCards();
        break;
      case 'd':
      case 'D':
        openDiceModal();
        break;
      case 't':
      case 'T':
        toggleTriggerStack();
        break;
      case 'm':
      case 'M':
        toggleManaPoolCollapse();
        break;
      case 'Escape':
        closeZoneModal();
        closeDiceModal();
        closeTriggerStack();
        hideContextMenu();
        closeScryModal();
        closeManaPickerModal();
        closeDeckModal();
        closeDeckView();
        closeTokenModal();
        hideAbilitiesPanel();
        closeSaveLoadModal();
        closeShortcutsModal();
        closeUndoHistory();
        // Close keyword reference
        {
          const kref = document.getElementById('keyword-reference-panel');
          if (kref) kref.style.display = 'none';
        }
        break;
      case 'k':
      case 'K':
        toggleKeywordReference();
        break;
      case 's':
      case 'S':
        openSaveLoadModal();
        break;
      case '?':
        openShortcutsModal();
        break;
      case 'h':
      case 'H':
        toggleUndoHistory();
        break;
    }
  });
}

// ============================================================
// THEME TOGGLE
// ============================================================

let currentTheme = 'dark';

function toggleTheme() {
  currentTheme = currentTheme === 'dark' ? 'light' : 'dark';
  document.documentElement.setAttribute('data-theme', currentTheme);

  const toggle = document.querySelector('[data-theme-toggle]');
  if (toggle) {
    toggle.title = currentTheme === 'dark' ? 'Switch to light mode' : 'Switch to dark mode';
    toggle.innerHTML = currentTheme === 'dark'
      ? `<svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><circle cx="12" cy="12" r="5"/><path d="M12 1v2M12 21v2M4.22 4.22l1.42 1.42M18.36 18.36l1.42 1.42M1 12h2M21 12h2M4.22 19.78l1.42-1.42M18.36 5.64l1.42-1.42"/></svg>`
      : `<svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><path d="M21 12.79A9 9 0 1 1 11.21 3 7 7 0 0 0 21 12.79z"/></svg>`;
  }
}

// ============================================================
// SHORTCUT HINT
// ============================================================

function initShortcutHint() {
  const hint = document.getElementById('shortcut-hint');
  if (hint) {
    hint.innerHTML = `<kbd>Space</kbd> Next Phase &nbsp; <kbd>N</kbd> Next Turn &nbsp; <kbd>U</kbd> Untap All &nbsp; <kbd>D</kbd> Dice &nbsp; <kbd>T</kbd> Triggers &nbsp; <kbd>S</kbd> Save/Load &nbsp; <kbd>?</kbd> Shortcuts &nbsp; <kbd>H</kbd> Undo History`;
  }
}

// ============================================================
// LIFE ADJUST VIA KEYBOARD (click + hold)
// ============================================================

let lifeHoldTimer = null;
let lifeHoldInterval = null;

function setupLifeHold() {
  document.addEventListener('pointerdown', e => {
    const btn = e.target.closest('.life-btn');
    if (!btn) return;

    const panel = btn.closest('.player-panel');
    if (!panel) return;

    const panelId = panel.id;
    const playerId = parseInt(panelId.replace('player-panel-', ''));
    const isPlus = btn.textContent.trim() === '+';

    lifeHoldTimer = setTimeout(() => {
      lifeHoldInterval = setInterval(() => {
        adjustLife(playerId, isPlus ? 1 : -1);
      }, 80);
    }, 400);
  });

  document.addEventListener('pointerup', () => {
    clearTimeout(lifeHoldTimer);
    clearInterval(lifeHoldInterval);
  });
}

