const AI_COLOR_KEYS = ['mono_white', 'mono_blue', 'mono_black', 'mono_red', 'mono_green'];

function generateAiDeck() {
  // Pick a random color
  const colorKey = AI_COLOR_KEYS[Math.floor(Math.random() * AI_COLOR_KEYS.length)];
  const template = AI_DECK_TEMPLATES[colorKey];
  const deck = [];

  // 36 lands (reduced from 38 to make room for equipment/enchantments)
  for (let i = 0; i < 36; i++) {
    const land = { ...template.lands[0] };
    deck.push(land);
  }

  // Fill creatures - randomly sample from pool to get ~35 (with some duplicates allowed)
  const creatures = template.creatures;
  for (let i = 0; i < 35; i++) {
    const c = creatures[i % creatures.length];
    deck.push({ ...c });
  }

  // Fill spells - randomly sample to get ~18
  const spells = template.spells;
  for (let i = 0; i < 18; i++) {
    const s = spells[i % spells.length];
    deck.push({ ...s });
  }

  // Equipment (4 copies spread from pool)
  const equip = template.equipment || [];
  for (let i = 0; i < 4 && equip.length > 0; i++) {
    const e = equip[i % equip.length];
    deck.push({ ...e });
  }

  // Enchantments (4 copies spread from pool)
  const ench = template.enchantments || [];
  for (let i = 0; i < 4 && ench.length > 0; i++) {
    const e = ench[i % ench.length];
    deck.push({ ...e });
  }

  // Ramp spells get the isRamp flag preserved (green especially)
  // Commander (last creature in pool, bumped to slot 0)
  const commander = { ...creatures[creatures.length - 1], isCommander: true };
  deck.push(commander);

  // Shuffle (Fisher-Yates)
  for (let i = deck.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [deck[i], deck[j]] = [deck[j], deck[i]];
  }

  return { deck, colorKey };
}

function setupAiDecks() {
  if (!gameState) return;
  gameState.players.forEach((player, idx) => {
    if (!player.isAI) return;
    const { deck, colorKey } = generateAiDeck();
    player.aiColorKey = colorKey;
    player.aiLandPlayedThisTurn = false;

    // Put commander in command zone, rest in library
    deck.forEach(card => {
      const cardObj = {
        name: card.name,
        imageUrl: '', // AI uses text-based rendering
        typeLine: card.typeLine,
        oracleText: card.oracleText || '',
        cmc: card.cmc || 0,
        pt: card.pt || '',
        mana: card.mana || '',
        manaCost: card.manaCost || '',
        isRemoval: card.isRemoval || false,
        isBoardWipe: card.isBoardWipe || false,
        isManaProducer: card.isManaProducer || false,
        manaAbility: card.manaAbility || '',
        isRamp: card.isRamp || false,
      };
      if (card.isCommander) {
        player.zones.command.push(cardObj);
        if (!player.commanderCardName) player.commanderCardName = cardObj.name || '';
      } else {
        player.zones.library.push(cardObj);
      }
    });

    // Draw opening hand of 7 with mulligan logic
    // AI mulligans until it has at least 2 lands, up to 3 times
    var mulliganCount = 0;
    var maxMulligans = 3;
    var handOk = false;

    while (!handOk && mulliganCount <= maxMulligans) {
      // Draw 7
      player.zones.hand = [];
      for (let i = 0; i < 7 && player.zones.library.length > 0; i++) {
        player.zones.hand.push(player.zones.library.shift());
      }

      // Count lands in hand
      var landsInHand = player.zones.hand.filter(function(c) {
        return c.typeLine && c.typeLine.toLowerCase().includes('land');
      }).length;

      if (landsInHand >= 2) {
        handOk = true;
        if (mulliganCount > 0) {
          addLogEntry('\u{1F916} <strong>' + player.name + '</strong> mulliganed ' + mulliganCount + ' time' + (mulliganCount > 1 ? 's' : '') + ' (found ' + landsInHand + ' lands)');
        }
      } else if (mulliganCount < maxMulligans) {
        // Put hand back into library and reshuffle
        while (player.zones.hand.length > 0) {
          player.zones.library.push(player.zones.hand.pop());
        }
        // Fisher-Yates shuffle
        for (let i = player.zones.library.length - 1; i > 0; i--) {
          const j = Math.floor(Math.random() * (i + 1));
          [player.zones.library[i], player.zones.library[j]] = [player.zones.library[j], player.zones.library[i]];
        }
        mulliganCount++;
      } else {
        // Max mulligans reached, keep whatever we have
        addLogEntry('\u{1F916} <strong>' + player.name + '</strong> kept hand after ' + mulliganCount + ' mulligan' + (mulliganCount > 1 ? 's' : '') + ' (' + landsInHand + ' lands)');
        handOk = true;
      }
    }

    // Commander mulligan penalty: for each mulligan past the free one, put 1 card on bottom
    var cardsToPutBack = Math.max(0, mulliganCount - 1);
    for (let i = 0; i < cardsToPutBack && player.zones.hand.length > 1; i++) {
      // Put the highest CMC non-land card on bottom (expensive cards hurt most when down cards)
      var worstIdx = 0;
      var worstScore = -1;
      player.zones.hand.forEach(function(c, ci) {
        var isLand = c.typeLine && c.typeLine.toLowerCase().includes('land');
        // Never bottom lands; pick highest CMC spell to bottom
        var score = isLand ? -1 : (c.cmc || 0);
        if (score > worstScore) {
          worstScore = score;
          worstIdx = ci;
        }
      });
      var bottomCard = player.zones.hand.splice(worstIdx, 1)[0];
      player.zones.library.push(bottomCard);
    }
  });
}

async function fetchAiCardImages() {
  if (!gameState) return;
  // Collect all unique card names from AI players
  var allNames = [];
  gameState.players.forEach(function(player) {
    if (!player.isAI) return;
    var zones = ['library', 'hand', 'command'];
    zones.forEach(function(z) {
      if (player.zones[z]) {
        player.zones[z].forEach(function(card) {
          if (card.name && allNames.indexOf(card.name) === -1) {
            allNames.push(card.name);
          }
        });
      }
    });
  });
  if (allNames.length === 0) return;

  try {
    var cardDataMap = await batchFetchCards(allNames, null);

    // Update imageUrl on all AI cards in all zones
    gameState.players.forEach(function(player) {
      if (!player.isAI) return;
      var zones = ['library', 'hand', 'command'];
      zones.forEach(function(z) {
        if (player.zones[z]) {
          player.zones[z].forEach(function(card) {
            var data = cardDataMap.get(card.name.toLowerCase());
            if (data) {
              var imgUrl = '';
              if (data.image_uris && data.image_uris.normal) {
                imgUrl = data.image_uris.normal;
              } else if (data.card_faces && data.card_faces[0] && data.card_faces[0].image_uris) {
                imgUrl = data.card_faces[0].image_uris.normal;
              }
              if (imgUrl) card.imageUrl = imgUrl;
            }
          });
        }
      });
    });

    // Also update any AI cards already on the battlefield
    gameState.battlefieldCards.forEach(function(card) {
      var owner = gameState.players[card.ownerId];
      if (!owner || !owner.isAI) return;
      var data = cardDataMap.get(card.name.toLowerCase());
      if (data) {
        var imgUrl = '';
        if (data.image_uris && data.image_uris.normal) {
          imgUrl = data.image_uris.normal;
        } else if (data.card_faces && data.card_faces[0] && data.card_faces[0].image_uris) {
          imgUrl = data.card_faces[0].image_uris.normal;
        }
        if (imgUrl) {
          card.imageUrl = imgUrl;
          var el = document.getElementById('bc-' + card.id);
          if (el) {
            var img = el.querySelector('img');
            if (img) img.src = imgUrl;
          }
        }
      }
    });

    // Re-render hand if current player has AI cards visible
    if (typeof renderHandArea === 'function') renderHandArea();
    if (typeof renderPlayerPanels === 'function') renderPlayerPanels();
  } catch(e) {
    console.warn('[AI Images] Failed to fetch card images:', e);
  }
}

// Determine how many lands the AI has on the battlefield (untapped)
function aiCountLands(playerId) {
  return gameState.battlefieldCards.filter(c =>
    c.ownerId === playerId && c.typeLine && c.typeLine.toLowerCase().includes('land')
  );
}

function aiCountUntappedLands(playerId) {
  return aiCountLands(playerId).filter(c => !c.tapped).length;
}

function aiCountCreatures(playerId) {
  return gameState.battlefieldCards.filter(c =>
    c.ownerId === playerId && c.typeLine && c.typeLine.toLowerCase().includes('creature') && !c.typeLine.toLowerCase().includes('land')
  );
}

function aiGetUntappedCreatures(playerId) {
  return aiCountCreatures(playerId).filter(c => !c.tapped);
}

function aiIsLand(card) {
  return card.typeLine && card.typeLine.toLowerCase().includes('land');
}
function aiIsCreature(card) {
  return card.typeLine && card.typeLine.toLowerCase().includes('creature');
}

function aiGetCmc(card) {
  return card.cmc || 0;
}

// ============================================================
// FORGE-INSPIRED CARD SCRIPT API
// Declarative card scripting with SpellAbility objects
// ============================================================

// --- SpellAbility Class ---
// Each ability on a card is decomposed into a SpellAbility object
// with cost, effect, targeting, and a resolve() method.
// Inspired by Forge's SpellAbility.java architecture.

function SpellAbility(config) {
  this.id = 'sa_' + Date.now() + '_' + Math.random().toString(36).slice(2, 8);
  this.abilityType = config.abilityType || 'activated'; // activated | triggered | static | mana | spell | keyword
  this.api = config.api || '';           // e.g. 'DealDamage', 'GainLife', 'DrawCard', 'DestroyPermanent'
  this.cost = config.cost || null;       // { mana: '{2}{B}', tap: true, sacrifice: false, discard: 0, payLife: 0, custom: '' }
  this.effect = config.effect || {};     // { amount: 3, target: 'creature', scope: 'opponent', ... }
  this.trigger = config.trigger || null; // { event: 'etb', filter: 'self' } for triggered abilities
  this.keyword = config.keyword || null; // 'flying', 'deathtouch', etc. for keyword abilities
  this.zone = config.zone || 'battlefield'; // where this ability functions
  this.oracleSnippet = config.oracleSnippet || '';
  this.cardName = config.cardName || '';
  this.ownerIndex = config.ownerIndex !== undefined ? config.ownerIndex : -1;
  this.sourceCardId = config.sourceCardId || null;
  this.restrictions = config.restrictions || {}; // { sorcerySpeed: true, oncePerTurn: false }
  this.usedThisTurn = false;

  // AI evaluation hints (Forge-inspired)
  this.aiHints = config.aiHints || {};
  // e.g. { priority: 'high', timing: 'mainPhase', targetPriority: 'threateningCreature' }
}

SpellAbility.prototype.canActivate = function(gameState, playerIdx) {
  if (this.restrictions.oncePerTurn && this.usedThisTurn) return false;
  if (this.restrictions.sorcerySpeed) {
    var phase = PHASES[gameState.currentPhaseIndex];
    var isMain = phase && (phase.id === 'main1' || phase.id === 'main2');
    if (!isMain) return false;
    if (gameState.currentPlayerIndex !== playerIdx) return false;
  }
  if (this.cost) {
    if (this.cost.tap && this.sourceCardId) {
      var src = gameState.battlefieldCards.find(function(c) { return c.id === this.sourceCardId; }.bind(this));
      if (src && src.tapped) return false;
    }
    if (this.cost.mana) {
      var cmc = parseCMCFromManaCost(this.cost.mana);
      if (aiCountUntappedLands(playerIdx) < cmc) return false;
    }
    if (this.cost.payLife) {
      var p = gameState.players[playerIdx];
      if (!p || p.life <= this.cost.payLife) return false;
    }
  }
  return true;
};

SpellAbility.prototype.resolve = function(gameState, context) {
  // context: { caster: playerIdx, targets: [], sourceCard: cardData }
  var api = this.api;
  var eff = this.effect;
  var caster = context.caster;
  var targets = context.targets || [];
  var source = context.sourceCard;

  // Mark used
  this.usedThisTurn = true;

  // Dispatch to the appropriate CardScript API resolver
  if (CardScriptResolvers[api]) {
    return CardScriptResolvers[api](gameState, eff, caster, targets, source, this);
  }

  // Fallback: log that it resolved but has no automated effect
  if (typeof addLogEntry === 'function') {
    addLogEntry('&#9881; <strong>' + this.cardName + '</strong> ability resolved (manual: ' + (this.oracleSnippet || api) + ')');
  }
  return { resolved: true, automated: false };
};

SpellAbility.prototype.resetTurn = function() {
  this.usedThisTurn = false;
};

// Helper to parse CMC from a mana cost string like '{2}{B}{B}'
function parseCMCFromManaCost(manaCost) {
  if (!manaCost) return 0;
  var total = 0;
  var matches = manaCost.match(/\{([^}]+)\}/g);
  if (!matches) return 0;
  for (var i = 0; i < matches.length; i++) {
    var inner = matches[i].replace(/[{}]/g, '');
    var num = parseInt(inner);
    if (!isNaN(num)) {
      total += num;
    } else if (/^[WUBRGC]$/i.test(inner)) {
      total += 1;
    } else if (/^[WUBRG]\/[WUBRG]$/i.test(inner)) {
      total += 1; // hybrid
    } else if (inner === 'X') {
      total += 0; // X = variable
    }
  }
  return total;
}


// ============================================================
// CARD SCRIPT RESOLVERS — Automated effects for each API type
// ============================================================

var CardScriptResolvers = {

  // --- Damage ---
  DealDamage: function(gs, eff, caster, targets, source, sa) {
    var amount = eff.amount || 1;
    var resolved = [];
    for (var i = 0; i < targets.length; i++) {
      var t = targets[i];
      if (t.type === 'player') {
        var player = gs.players[t.index];
        if (player && !player.eliminated) {
          player.life -= amount;
          if (typeof addLogEntry === 'function') {
            addLogEntry('&#9889; <strong>' + (source ? source.name : sa.cardName) + '</strong> deals ' + amount + ' damage to <strong>' + player.name + '</strong>');
          }
          resolved.push({ type: 'player', index: t.index, damage: amount });
        }
      } else if (t.type === 'creature') {
        var card = gs.battlefieldCards.find(function(c) { return c.id === t.id; });
        if (card) {
          card.damageMarked = (card.damageMarked || 0) + amount;
          if (typeof addLogEntry === 'function') {
            addLogEntry('&#9889; <strong>' + (source ? source.name : sa.cardName) + '</strong> deals ' + amount + ' damage to <strong>' + card.name + '</strong>');
          }
          resolved.push({ type: 'creature', id: t.id, damage: amount });
        }
      }
    }
    return { resolved: true, automated: true, results: resolved };
  },

  // --- Life Gain ---
  GainLife: function(gs, eff, caster, targets, source, sa) {
    var amount = eff.amount || 1;
    var player = gs.players[caster];
    if (player) {
      player.life += amount;
      if (typeof addLogEntry === 'function') {
        addLogEntry('&#10084; <strong>' + player.name + '</strong> gains ' + amount + ' life from <strong>' + (source ? source.name : sa.cardName) + '</strong>');
      }
      if (typeof fireBattlefieldTriggers === 'function') {
        fireBattlefieldTriggers('life_gain');
      }
    }
    return { resolved: true, automated: true };
  },

  // --- Life Loss ---
  LoseLife: function(gs, eff, caster, targets, source, sa) {
    var amount = eff.amount || 1;
    for (var i = 0; i < targets.length; i++) {
      var t = targets[i];
      if (t.type === 'player') {
        var player = gs.players[t.index];
        if (player) {
          player.life -= amount;
          if (typeof addLogEntry === 'function') {
            addLogEntry('&#128128; <strong>' + player.name + '</strong> loses ' + amount + ' life');
          }
        }
      }
    }
    return { resolved: true, automated: true };
  },

  // --- Draw Cards ---
  DrawCard: function(gs, eff, caster, targets, source, sa) {
    var amount = eff.amount || 1;
    var playerIdx = (eff.targetSelf !== false) ? caster : (targets.length > 0 ? targets[0].index : caster);
    var player = gs.players[playerIdx];
    if (player) {
      var drawn = 0;
      for (var d = 0; d < amount; d++) {
        if (player.zones.library.length > 0) {
          var drawnCard = player.zones.library.shift();
          player.zones.hand.push(drawnCard);
          drawn++;
        }
      }
      if (typeof addLogEntry === 'function') {
        addLogEntry('&#128195; <strong>' + player.name + '</strong> draws ' + drawn + ' card' + (drawn !== 1 ? 's' : '') + ' from <strong>' + (source ? source.name : sa.cardName) + '</strong>');
      }
      if (typeof fireBattlefieldTriggers === 'function') {
        for (var dd = 0; dd < drawn; dd++) {
          fireBattlefieldTriggers('draw');
        }
      }
    }
    return { resolved: true, automated: true, drawn: drawn };
  },

  // --- Discard ---
  Discard: function(gs, eff, caster, targets, source, sa) {
    var amount = eff.amount || 1;
    var playerIdx = (eff.scope === 'opponent' && targets.length > 0) ? targets[0].index : caster;
    var player = gs.players[playerIdx];
    if (player) {
      var discarded = 0;
      for (var d = 0; d < amount; d++) {
        if (player.zones.hand.length > 0) {
          // AI: discard worst card; Human: random for now
          var idx = player.isAI ? player.zones.hand.length - 1 : Math.floor(Math.random() * player.zones.hand.length);
          var card = player.zones.hand.splice(idx, 1)[0];
          player.zones.graveyard.push(card);
          discarded++;
        }
      }
      if (typeof addLogEntry === 'function') {
        addLogEntry('&#9760; <strong>' + player.name + '</strong> discards ' + discarded + ' card' + (discarded !== 1 ? 's' : ''));
      }
    }
    return { resolved: true, automated: true };
  },

  // --- Destroy Permanent ---
  DestroyPermanent: function(gs, eff, caster, targets, source, sa) {
    var destroyed = [];
    for (var i = 0; i < targets.length; i++) {
      var t = targets[i];
      if (t.type === 'creature' || t.type === 'permanent') {
        var idx = gs.battlefieldCards.findIndex(function(c) { return c.id === t.id; });
        if (idx !== -1) {
          var card = gs.battlefieldCards[idx];
          // Check indestructible
          if (typeof hasKeyword === 'function' && hasKeyword(card, 'indestructible')) {
            if (typeof addLogEntry === 'function') {
              addLogEntry('&#128737; <strong>' + card.name + '</strong> is indestructible!');
            }
            continue;
          }
          gs.battlefieldCards.splice(idx, 1);
          var owner = gs.players[card.ownerIndex || card.ownerId];
          if (owner) {
            owner.zones.graveyard.push(card);
          }
          // Fire dies triggers
          if (typeof fireBattlefieldTriggers === 'function') {
            fireBattlefieldTriggers('dies');
          }
          if (typeof fireCardTriggers === 'function') {
            fireCardTriggers(card, ['dies']);
          }
          if (typeof addLogEntry === 'function') {
            addLogEntry('&#9760; <strong>' + card.name + '</strong> was destroyed by <strong>' + (source ? source.name : sa.cardName) + '</strong>');
          }
          destroyed.push(card);
        }
      }
    }
    return { resolved: true, automated: true, destroyed: destroyed };
  },

  // --- Exile Permanent ---
  ExilePermanent: function(gs, eff, caster, targets, source, sa) {
    var exiled = [];
    for (var i = 0; i < targets.length; i++) {
      var t = targets[i];
      var idx = gs.battlefieldCards.findIndex(function(c) { return c.id === t.id; });
      if (idx !== -1) {
        var card = gs.battlefieldCards.splice(idx, 1)[0];
        var owner = gs.players[card.ownerIndex || card.ownerId];
        if (owner) {
          owner.zones.exile.push(card);
        }
        if (typeof addLogEntry === 'function') {
          addLogEntry('&#11041; <strong>' + card.name + '</strong> was exiled by <strong>' + (source ? source.name : sa.cardName) + '</strong>');
        }
        exiled.push(card);
      }
    }
    return { resolved: true, automated: true, exiled: exiled };
  },

  // --- Create Token ---
  CreateToken: function(gs, eff, caster, targets, source, sa) {
    var count = eff.amount || 1;
    var tokenName = eff.tokenName || 'Token';
    var tokenPower = eff.power || 1;
    var tokenTough = eff.toughness || 1;
    var tokenType = eff.tokenType || 'Creature Token';
    var tokenKeywords = eff.keywords || [];

    for (var i = 0; i < count; i++) {
      var tokenData = {
        name: tokenName,
        typeLine: tokenType,
        oracleText: tokenKeywords.join(', '),
        power: String(tokenPower),
        toughness: String(tokenTough),
        pt: tokenPower + '/' + tokenTough,
        imageUrl: '',
        isToken: true,
        keywords: tokenKeywords
      };
      if (typeof generateAiCardSVG === 'function') {
        tokenData.imageUrl = generateAiCardSVG(tokenData);
      }
      if (typeof addCardToBattlefield === 'function') {
        addCardToBattlefield(tokenName, tokenData.imageUrl, tokenType, caster, undefined, undefined, tokenData.oracleText, tokenData);
      }
    }
    if (typeof addLogEntry === 'function') {
      addLogEntry('&#9878; <strong>' + gs.players[caster].name + '</strong> creates ' + count + ' ' + tokenPower + '/' + tokenTough + ' ' + tokenName + ' token' + (count !== 1 ? 's' : ''));
    }
    return { resolved: true, automated: true };
  },

  // --- Mana Production ---
  ManaAdd: function(gs, eff, caster, targets, source, sa) {
    // Visual log only; mana pool is handled by existing adjustMana system
    var colors = eff.colors || ['C']; // colorless by default
    if (typeof addLogEntry === 'function') {
      addLogEntry('&#9883; <strong>' + (source ? source.name : sa.cardName) + '</strong> adds {' + colors.join('}{') + '} to mana pool');
    }
    return { resolved: true, automated: true };
  },

  // --- Pump Creature (+X/+X until end of turn) ---
  PumpCreature: function(gs, eff, caster, targets, source, sa) {
    var pw = eff.power || 0;
    var tw = eff.toughness || 0;
    for (var i = 0; i < targets.length; i++) {
      var t = targets[i];
      var card = gs.battlefieldCards.find(function(c) { return c.id === t.id; });
      if (card) {
        card.powerMod = (card.powerMod || 0) + pw;
        card.toughnessMod = (card.toughnessMod || 0) + tw;
        if (typeof addLogEntry === 'function') {
          var sign = function(n) { return n >= 0 ? '+' + n : '' + n; };
          addLogEntry('&#9876; <strong>' + card.name + '</strong> gets ' + sign(pw) + '/' + sign(tw) + ' from <strong>' + (source ? source.name : sa.cardName) + '</strong>');
        }
      }
    }
    return { resolved: true, automated: true };
  },

  // --- Counter Spell ---
  CounterSpell: function(gs, eff, caster, targets, source, sa) {
    if (gs.theStack && gs.theStack.length > 0) {
      // Counter the top spell on the stack (or targeted)
      var targetIdx = targets.length > 0 ? targets[0].stackIndex : gs.theStack.length - 1;
      if (targetIdx >= 0 && targetIdx < gs.theStack.length) {
        var countered = gs.theStack.splice(targetIdx, 1)[0];
        var owner = gs.players[countered.ownerIndex];
        if (owner) {
          owner.zones.graveyard.push(countered);
        }
        if (typeof addLogEntry === 'function') {
          addLogEntry('&#10060; <strong>' + (source ? source.name : sa.cardName) + '</strong> counters <strong>' + countered.name + '</strong>!');
        }
        return { resolved: true, automated: true, countered: countered };
      }
    }
    return { resolved: true, automated: false };
  },

  // --- Search Library ---
  SearchLibrary: function(gs, eff, caster, targets, source, sa) {
    // Log only; actual search requires human interaction
    if (typeof addLogEntry === 'function') {
      addLogEntry('&#128218; <strong>' + gs.players[caster].name + '</strong> searches their library (' + (source ? source.name : sa.cardName) + ')');
    }
    return { resolved: true, automated: false };
  },

  // --- Board Wipe ---
  DestroyAll: function(gs, eff, caster, targets, source, sa) {
    var filter = eff.filter || 'creature'; // 'creature', 'nonland', 'all'
    var destroyed = [];
    var toRemove = [];
    for (var i = gs.battlefieldCards.length - 1; i >= 0; i--) {
      var card = gs.battlefieldCards[i];
      var matches = false;
      if (filter === 'creature' && card.typeLine && /creature/i.test(card.typeLine)) matches = true;
      if (filter === 'nonland' && card.typeLine && !/land/i.test(card.typeLine)) matches = true;
      if (filter === 'all') matches = true;
      if (filter === 'artifact' && card.typeLine && /artifact/i.test(card.typeLine)) matches = true;
      if (filter === 'enchantment' && card.typeLine && /enchantment/i.test(card.typeLine)) matches = true;

      if (matches) {
        if (typeof hasKeyword === 'function' && hasKeyword(card, 'indestructible')) continue;
        toRemove.push(i);
      }
    }
    for (var r = 0; r < toRemove.length; r++) {
      var card = gs.battlefieldCards.splice(toRemove[r], 1)[0];
      var owner = gs.players[card.ownerIndex || card.ownerId];
      if (owner) owner.zones.graveyard.push(card);
      destroyed.push(card);
    }
    if (typeof addLogEntry === 'function') {
      addLogEntry('&#128165; <strong>' + (source ? source.name : sa.cardName) + '</strong> destroys ' + destroyed.length + ' permanents!');
    }
    return { resolved: true, automated: true, destroyed: destroyed };
  },

  // --- Bounce (Return to Hand) ---
  ReturnToHand: function(gs, eff, caster, targets, source, sa) {
    var bounced = [];
    for (var i = 0; i < targets.length; i++) {
      var t = targets[i];
      var idx = gs.battlefieldCards.findIndex(function(c) { return c.id === t.id; });
      if (idx !== -1) {
        var card = gs.battlefieldCards.splice(idx, 1)[0];
        var owner = gs.players[card.ownerIndex || card.ownerId];
        if (owner) owner.zones.hand.push(card);
        if (typeof addLogEntry === 'function') {
          addLogEntry('&#128260; <strong>' + card.name + '</strong> returned to hand by <strong>' + (source ? source.name : sa.cardName) + '</strong>');
        }
        bounced.push(card);
      }
    }
    return { resolved: true, automated: true, bounced: bounced };
  },

  // --- Tap/Untap ---
  TapPermanent: function(gs, eff, caster, targets, source, sa) {
    for (var i = 0; i < targets.length; i++) {
      var card = gs.battlefieldCards.find(function(c) { return c.id === targets[i].id; });
      if (card) {
        card.tapped = eff.untap ? false : true;
      }
    }
    return { resolved: true, automated: true };
  },

  // --- Mill ---
  Mill: function(gs, eff, caster, targets, source, sa) {
    var amount = eff.amount || 1;
    var playerIdx = targets.length > 0 ? targets[0].index : caster;
    var player = gs.players[playerIdx];
    if (player) {
      var milled = 0;
      for (var m = 0; m < amount; m++) {
        if (player.zones.library.length > 0) {
          var card = player.zones.library.shift();
          player.zones.graveyard.push(card);
          milled++;
        }
      }
      if (typeof addLogEntry === 'function') {
        addLogEntry('&#127744; <strong>' + player.name + '</strong> mills ' + milled + ' card' + (milled !== 1 ? 's' : ''));
      }
    }
    return { resolved: true, automated: true };
  },

  // --- Scry ---
  Scry: function(gs, eff, caster, targets, source, sa) {
    var amount = eff.amount || 1;
    if (typeof addLogEntry === 'function') {
      addLogEntry('&#128065; <strong>' + gs.players[caster].name + '</strong> scries ' + amount + ' (' + (source ? source.name : sa.cardName) + ')');
    }
    return { resolved: true, automated: false }; // Requires manual reordering
  },

  // --- Gain Keyword (until end of turn) ---
  GainKeyword: function(gs, eff, caster, targets, source, sa) {
    var keyword = eff.keyword || '';
    for (var i = 0; i < targets.length; i++) {
      var card = gs.battlefieldCards.find(function(c) { return c.id === targets[i].id; });
      if (card) {
        if (!card.tempKeywords) card.tempKeywords = [];
        card.tempKeywords.push(keyword);
        if (typeof addLogEntry === 'function') {
          addLogEntry('&#10024; <strong>' + card.name + '</strong> gains ' + keyword + ' until end of turn');
        }
      }
    }
    return { resolved: true, automated: true };
  },

  // --- Put Counters ---
  PutCounters: function(gs, eff, caster, targets, source, sa) {
    var counterType = eff.counterType || '+1/+1';
    var amount = eff.amount || 1;
    for (var i = 0; i < targets.length; i++) {
      var card = gs.battlefieldCards.find(function(c) { return c.id === targets[i].id; });
      if (card) {
        if (!card.counters) card.counters = {};
        card.counters[counterType] = (card.counters[counterType] || 0) + amount;
        // Apply stat mods for +1/+1 and -1/-1 counters
        if (counterType === '+1/+1') {
          card.powerMod = (card.powerMod || 0) + amount;
          card.toughnessMod = (card.toughnessMod || 0) + amount;
        } else if (counterType === '-1/-1') {
          card.powerMod = (card.powerMod || 0) - amount;
          card.toughnessMod = (card.toughnessMod || 0) - amount;
        }
        if (typeof addLogEntry === 'function') {
          addLogEntry('&#11044; ' + amount + ' ' + counterType + ' counter' + (amount !== 1 ? 's' : '') + ' on <strong>' + card.name + '</strong>');
        }
      }
    }
    return { resolved: true, automated: true };
  },

  // --- Ramp (Put land from library onto battlefield) ---
  Ramp: function(gs, eff, caster, targets, source, sa) {
    var amount = eff.amount || 1;
    var player = gs.players[caster];
    if (player) {
      var ramped = 0;
      for (var r = 0; r < amount; r++) {
        // Find a basic land in library
        var landIdx = player.zones.library.findIndex(function(c) {
          return c.typeLine && /basic.*land/i.test(c.typeLine);
        });
        if (landIdx === -1) {
          landIdx = player.zones.library.findIndex(function(c) {
            return c.typeLine && /land/i.test(c.typeLine);
          });
        }
        if (landIdx !== -1) {
          var land = player.zones.library.splice(landIdx, 1)[0];
          if (typeof addCardToBattlefield === 'function') {
            addCardToBattlefield(land.name, land.imageUrl || '', land.typeLine || 'Land', caster, undefined, undefined, land.oracleText || '', land);
          }
          ramped++;
        }
      }
      if (typeof addLogEntry === 'function' && ramped > 0) {
        addLogEntry('&#127793; <strong>' + player.name + '</strong> ramps ' + ramped + ' land' + (ramped !== 1 ? 's' : '') + ' (' + (source ? source.name : sa.cardName) + ')');
      }
    }
    return { resolved: true, automated: true };
  }
};


// ============================================================
// CARD SCRIPT PARSER — Forge-style declarative text format
// ============================================================
// Format: "A:AB$ <API> | Cost$ <cost> | Defined$ <target> | <params>"
// Also parses: "T:Mode$ <trigger> | Execute$ <API> | ..."
// And: "K:<keyword>"
// And: "S:Mode$ <static_type> | Affected$ <filter> | AddKeyword$ <kw>"

var CardScriptParser = {

  // Parse a Forge-style script string into an array of SpellAbility objects
  parse: function(scriptText, cardName, ownerIndex, sourceCardId) {
    if (!scriptText) return [];
    var abilities = [];
    var lines = scriptText.split('\n');

    for (var i = 0; i < lines.length; i++) {
      var line = lines[i].trim();
      if (!line || line.charAt(0) === '#') continue; // Skip comments and empty lines

      var sa = null;
      if (line.indexOf('A:AB$') === 0) {
        sa = this.parseActivated(line, cardName, ownerIndex, sourceCardId);
      } else if (line.indexOf('T:Mode$') === 0) {
        sa = this.parseTriggered(line, cardName, ownerIndex, sourceCardId);
      } else if (line.indexOf('K:') === 0) {
        sa = this.parseKeyword(line, cardName, ownerIndex, sourceCardId);
      } else if (line.indexOf('S:Mode$') === 0) {
        sa = this.parseStatic(line, cardName, ownerIndex, sourceCardId);
      } else if (line.indexOf('SP:AB$') === 0) {
        sa = this.parseSpell(line, cardName, ownerIndex, sourceCardId);
      }

      if (sa) abilities.push(sa);
    }

    return abilities;
  },

  // Parse pipe-separated parameters: "Key$ Value | Key2$ Value2"
  parseParams: function(text) {
    var params = {};
    var parts = text.split('|');
    for (var i = 0; i < parts.length; i++) {
      var part = parts[i].trim();
      var dollarIdx = part.indexOf('$');
      if (dollarIdx !== -1) {
        var key = part.substring(0, dollarIdx).trim();
        var val = part.substring(dollarIdx + 1).trim();
        params[key] = val;
      }
    }
    return params;
  },

  // Parse cost string: "{2}{B}, {T}" -> { mana: '{2}{B}', tap: true }
  parseCost: function(costStr) {
    if (!costStr) return null;
    var cost = { mana: '', tap: false, sacrifice: false, discard: 0, payLife: 0, custom: '' };
    if (/\{T\}/i.test(costStr)) cost.tap = true;
    if (/sacrifice/i.test(costStr)) cost.sacrifice = true;
    var lifeMatch = costStr.match(/pay (\d+) life/i);
    if (lifeMatch) cost.payLife = parseInt(lifeMatch[1]);
    var discardMatch = costStr.match(/discard (\d+)/i);
    if (discardMatch) cost.discard = parseInt(discardMatch[1]);
    // Extract mana symbols
    var manaParts = costStr.match(/\{[WUBRGCX0-9/]+\}/gi);
    if (manaParts) {
      cost.mana = manaParts.filter(function(m) { return m !== '{T}'; }).join('');
    }
    return cost;
  },

  // A:AB$ DealDamage | Cost$ {R} | NumDmg$ 3 | ValidTgts$ Creature,Player
  parseActivated: function(line, cardName, ownerIndex, sourceCardId) {
    var body = line.substring(5); // strip "A:AB$"
    var params = this.parseParams(body);
    var api = (body.split('|')[0] || '').trim();
    var cost = this.parseCost(params['Cost'] || '');
    var effect = this.buildEffect(api, params);

    return new SpellAbility({
      abilityType: 'activated',
      api: api,
      cost: cost,
      effect: effect,
      cardName: cardName,
      ownerIndex: ownerIndex,
      sourceCardId: sourceCardId,
      oracleSnippet: params['SpellDescription'] || '',
      restrictions: {
        sorcerySpeed: params['SorcerySpeed'] === 'True',
        oncePerTurn: params['OncePerTurn'] === 'True'
      },
      aiHints: {
        priority: params['AILogic'] || 'normal',
        timing: cost && cost.tap ? 'beforeCombat' : 'mainPhase'
      }
    });
  },

  // T:Mode$ ChangesZone | Origin$ Any | Destination$ Battlefield | Execute$ DrawCard | ...
  parseTriggered: function(line, cardName, ownerIndex, sourceCardId) {
    var body = line.substring(7); // strip "T:Mode$"
    var params = this.parseParams(body);
    var mode = (body.split('|')[0] || '').trim();
    var api = params['Execute'] || '';
    var effect = this.buildEffect(api, params);

    var trigger = this.buildTrigger(mode, params);

    return new SpellAbility({
      abilityType: 'triggered',
      api: api,
      effect: effect,
      trigger: trigger,
      cardName: cardName,
      ownerIndex: ownerIndex,
      sourceCardId: sourceCardId,
      oracleSnippet: params['TriggerDescription'] || '',
      aiHints: {
        priority: params['AILogic'] || 'normal'
      }
    });
  },

  // K:Flying or K:Deathtouch or K:Lifelink
  parseKeyword: function(line, cardName, ownerIndex, sourceCardId) {
    var kw = line.substring(2).trim();
    return new SpellAbility({
      abilityType: 'keyword',
      api: 'Keyword',
      keyword: kw.toLowerCase(),
      cardName: cardName,
      ownerIndex: ownerIndex,
      sourceCardId: sourceCardId,
      oracleSnippet: kw,
      aiHints: {
        priority: 'passive'
      }
    });
  },

  // S:Mode$ Continuous | Affected$ Creature.YouCtrl | AddPower$ 1 | AddToughness$ 1
  parseStatic: function(line, cardName, ownerIndex, sourceCardId) {
    var body = line.substring(7); // strip "S:Mode$"
    var params = this.parseParams(body);
    var mode = (body.split('|')[0] || '').trim();

    return new SpellAbility({
      abilityType: 'static',
      api: 'StaticAbility',
      effect: {
        mode: mode,
        affected: params['Affected'] || '',
        addPower: parseInt(params['AddPower'] || '0'),
        addToughness: parseInt(params['AddToughness'] || '0'),
        addKeyword: params['AddKeyword'] || '',
        addAbility: params['AddAbility'] || ''
      },
      cardName: cardName,
      ownerIndex: ownerIndex,
      sourceCardId: sourceCardId,
      oracleSnippet: params['StaticDescription'] || '',
      aiHints: {
        priority: 'passive'
      }
    });
  },

  // SP:AB$ DealDamage | Cost$ {1}{R} | NumDmg$ 3 | ValidTgts$ Creature,Player
  parseSpell: function(line, cardName, ownerIndex, sourceCardId) {
    var body = line.substring(5); // strip "SP:AB"
    var params = this.parseParams(body);
    var api = (body.split('|')[0] || '').trim().replace(/^\$\s*/, '');
    var cost = this.parseCost(params['Cost'] || '');
    var effect = this.buildEffect(api, params);

    return new SpellAbility({
      abilityType: 'spell',
      api: api,
      cost: cost,
      effect: effect,
      cardName: cardName,
      ownerIndex: ownerIndex,
      sourceCardId: sourceCardId,
      oracleSnippet: params['SpellDescription'] || '',
      aiHints: {
        priority: params['AILogic'] || 'normal'
      }
    });
  },

  // Build effect object from API name + params
  buildEffect: function(api, params) {
    var eff = {};
    switch (api) {
      case 'DealDamage':
        eff.amount = parseInt(params['NumDmg'] || '1');
        eff.target = params['ValidTgts'] || 'Any';
        break;
      case 'GainLife':
        eff.amount = parseInt(params['LifeAmount'] || '1');
        break;
      case 'LoseLife':
        eff.amount = parseInt(params['LifeAmount'] || '1');
        eff.scope = params['Scope'] || 'opponent';
        break;
      case 'DrawCard':
        eff.amount = parseInt(params['NumCards'] || '1');
        eff.targetSelf = params['Defined'] !== 'Opponent';
        break;
      case 'Discard':
        eff.amount = parseInt(params['NumCards'] || '1');
        eff.scope = params['Defined'] === 'Opponent' ? 'opponent' : 'self';
        break;
      case 'DestroyPermanent':
        eff.target = params['ValidTgts'] || 'Creature';
        break;
      case 'ExilePermanent':
        eff.target = params['ValidTgts'] || 'Permanent';
        break;
      case 'CreateToken':
        eff.amount = parseInt(params['TokenAmount'] || '1');
        eff.tokenName = params['TokenName'] || 'Token';
        eff.power = parseInt(params['TokenPower'] || '1');
        eff.toughness = parseInt(params['TokenToughness'] || '1');
        eff.tokenType = params['TokenType'] || 'Creature Token';
        eff.keywords = (params['TokenKeywords'] || '').split(',').map(function(k) { return k.trim(); }).filter(Boolean);
        break;
      case 'ManaAdd':
        eff.colors = (params['Produced'] || 'C').split(',').map(function(c) { return c.trim(); });
        break;
      case 'PumpCreature':
        eff.power = parseInt(params['NumAtt'] || '0');
        eff.toughness = parseInt(params['NumDef'] || '0');
        break;
      case 'CounterSpell':
        eff.target = 'spell';
        break;
      case 'SearchLibrary':
        eff.searchType = params['SearchType'] || 'Any';
        break;
      case 'DestroyAll':
        eff.filter = (params['ValidCards'] || 'creature').toLowerCase();
        break;
      case 'ReturnToHand':
        eff.target = params['ValidTgts'] || 'Permanent';
        break;
      case 'TapPermanent':
        eff.untap = params['Untap'] === 'True';
        break;
      case 'Mill':
        eff.amount = parseInt(params['NumCards'] || '1');
        break;
      case 'Scry':
        eff.amount = parseInt(params['ScryNum'] || '1');
        break;
      case 'GainKeyword':
        eff.keyword = params['KW'] || '';
        break;
      case 'PutCounters':
        eff.counterType = params['CounterType'] || '+1/+1';
        eff.amount = parseInt(params['CounterNum'] || '1');
        break;
      case 'Ramp':
        eff.amount = parseInt(params['Amount'] || '1');
        break;
    }
    return eff;
  },

  // Build trigger descriptor from mode + params
  buildTrigger: function(mode, params) {
    var trigger = { event: '', filter: 'any' };
    switch (mode) {
      case 'ChangesZone':
        if (params['Destination'] === 'Battlefield') trigger.event = 'etb';
        else if (params['Origin'] === 'Battlefield') trigger.event = 'ltb';
        break;
      case 'ChangesZoneAll':
        trigger.event = 'etb';
        trigger.filter = params['ValidCards'] || 'Creature';
        break;
      case 'Attacks':
        trigger.event = 'attack';
        break;
      case 'Blocks':
        trigger.event = 'block';
        break;
      case 'DamageDone':
        trigger.event = 'damage';
        break;
      case 'SpellCast':
        trigger.event = 'cast';
        trigger.filter = params['ValidActivatingPlayer'] || 'You';
        break;
      case 'Phase':
        if (/upkeep/i.test(params['Phase'] || '')) trigger.event = 'upkeep';
        else if (/end/i.test(params['Phase'] || '')) trigger.event = 'end_step';
        else if (/combat/i.test(params['Phase'] || '')) trigger.event = 'combat_begin';
        break;
      case 'LifeGained':
        trigger.event = 'life_gain';
        break;
      case 'LifeLost':
        trigger.event = 'life_loss';
        break;
      case 'Drawn':
        trigger.event = 'draw';
        break;
      case 'Discarded':
        trigger.event = 'discard';
        break;
      case 'Landfall':
        trigger.event = 'landfall';
        break;
      default:
        trigger.event = mode.toLowerCase();
    }
    return trigger;
  }
};


// ============================================================
// CARD SCRIPT REGISTRY — Common card patterns
// ============================================================
// Maps oracle text patterns to Forge-style CardScript definitions.
// When a card's oracle text matches, the corresponding SpellAbilities
// are automatically generated, enabling the AI to understand and
// potentially automate common card effects.

var CardScriptRegistry = {

  // Each entry: { pattern: RegExp, script: function(match, cardName) -> scriptString }
  patterns: [],

  register: function(pattern, scriptFn) {
    this.patterns.push({ pattern: pattern, scriptFn: scriptFn });
  },

  // Try to match a card's oracle text and generate CardScript
  match: function(oracleText, typeLine, cardName) {
    if (!oracleText) return '';
    var scripts = [];
    var text = oracleText;

    for (var i = 0; i < this.patterns.length; i++) {
      var entry = this.patterns[i];
      var m = text.match(entry.pattern);
      if (m) {
        var script = entry.scriptFn(m, cardName);
        if (script) scripts.push(script);
      }
    }

    // Also generate keyword scripts
    var kwText = text.toLowerCase();
    var commonKeywords = ['flying', 'deathtouch', 'lifelink', 'first strike', 'double strike',
      'trample', 'haste', 'vigilance', 'menace', 'hexproof', 'indestructible',
      'reach', 'flash', 'infect', 'toxic', 'ward', 'defender', 'shroud',
      'prowess', 'cascade', 'undying', 'persist', 'annihilator'];
    for (var k = 0; k < commonKeywords.length; k++) {
      var kw = commonKeywords[k];
      var kwRe = new RegExp('(?:^|[,;.\\n\\s])' + kw.replace(/[.*+?^${}()|[\]\\]/g, '\\$&') + '(?:\\b|\\s|,|\\.|$)', 'i');
      if (kwRe.test(kwText) || kwRe.test(',' + kwText)) {
        scripts.push('K:' + kw.charAt(0).toUpperCase() + kw.slice(1));
      }
    }

    return scripts.join('\n');
  }
};

// --- Register common Oracle text patterns ---

// ETB: "When [cardname/this creature] enters the battlefield, [effect]"
CardScriptRegistry.register(
  /when (?:this creature|~|it) enters(?: the battlefield)?,?\s*(.+?)(?:\.|$)/i,
  function(m, cardName) {
    var effect = m[1].toLowerCase();
    // ETB draw
    if (/draw (\w+|\d+) cards?/.test(effect)) {
      var num = effect.match(/draw (\w+|\d+)/);
      var amount = num ? (parseInt(num[1]) || ({'a':1,'one':1,'two':2,'three':3,'four':4,'five':5}[num[1]] || 1)) : 1;
      return 'T:Mode$ ChangesZone | Origin$ Any | Destination$ Battlefield | Execute$ DrawCard | NumCards$ ' + amount + ' | TriggerDescription$ ETB: Draw ' + amount;
    }
    // ETB gain life
    if (/gain (\d+) life/.test(effect)) {
      var life = effect.match(/gain (\d+)/);
      return 'T:Mode$ ChangesZone | Origin$ Any | Destination$ Battlefield | Execute$ GainLife | LifeAmount$ ' + (life ? life[1] : '1') + ' | TriggerDescription$ ETB: Gain life';
    }
    // ETB deal damage
    if (/deals? (\d+) damage/.test(effect)) {
      var dmg = effect.match(/deals? (\d+)/);
      return 'T:Mode$ ChangesZone | Origin$ Any | Destination$ Battlefield | Execute$ DealDamage | NumDmg$ ' + (dmg ? dmg[1] : '1') + ' | TriggerDescription$ ETB: Deal damage';
    }
    // ETB create token
    if (/create (\w+|\d+)\s+(\d+)\/(\d+)/.test(effect)) {
      var tok = effect.match(/create (\w+|\d+)\s+(\d+)\/(\d+)\s*([\w\s]*?)(?:creature)?\s*token/i);
      if (tok) {
        var cnt = parseInt(tok[1]) || ({'a':1,'one':1,'two':2,'three':3}[tok[1]] || 1);
        return 'T:Mode$ ChangesZone | Origin$ Any | Destination$ Battlefield | Execute$ CreateToken | TokenAmount$ ' + cnt +
               ' | TokenPower$ ' + tok[2] + ' | TokenToughness$ ' + tok[3] + ' | TriggerDescription$ ETB: Create tokens';
      }
    }
    // ETB destroy
    if (/destroy target/.test(effect)) {
      return 'T:Mode$ ChangesZone | Origin$ Any | Destination$ Battlefield | Execute$ DestroyPermanent | TriggerDescription$ ETB: Destroy';
    }
    // ETB exile
    if (/exile target/.test(effect)) {
      return 'T:Mode$ ChangesZone | Origin$ Any | Destination$ Battlefield | Execute$ ExilePermanent | TriggerDescription$ ETB: Exile';
    }
    // ETB +1/+1 counters
    if (/(\d+) \+1\/\+1 counter/.test(effect)) {
      var cnt = effect.match(/(\d+) \+1\/\+1/);
      return 'T:Mode$ ChangesZone | Origin$ Any | Destination$ Battlefield | Execute$ PutCounters | CounterType$ +1/+1 | CounterNum$ ' + (cnt ? cnt[1] : '1') + ' | TriggerDescription$ ETB: +1/+1 counters';
    }
    // Generic ETB (not automated)
    return 'T:Mode$ ChangesZone | Origin$ Any | Destination$ Battlefield | Execute$ Generic | TriggerDescription$ ETB: ' + effect.substring(0, 50);
  }
);

// Activated: "{cost}: Draw a card"
CardScriptRegistry.register(
  /(\{[^}]+\}(?:\s*,?\s*\{[^}]*\})*)\s*:\s*draw (\w+|\d+) cards?/i,
  function(m) {
    var num = parseInt(m[2]) || ({'a':1,'one':1,'two':2,'three':3}[m[2].toLowerCase()] || 1);
    return 'A:AB$ DrawCard | Cost$ ' + m[1] + ' | NumCards$ ' + num + ' | SpellDescription$ Draw ' + num;
  }
);

// Activated: "{cost}: Deal N damage"
CardScriptRegistry.register(
  /(\{[^}]+\}(?:\s*,?\s*\{[^}]*\})*)\s*:\s*(?:it |~\s+)?deals? (\d+) damage/i,
  function(m) {
    return 'A:AB$ DealDamage | Cost$ ' + m[1] + ' | NumDmg$ ' + m[2] + ' | ValidTgts$ Any | SpellDescription$ Deal ' + m[2] + ' damage';
  }
);

// Activated: "{cost}: Gain N life"
CardScriptRegistry.register(
  /(\{[^}]+\}(?:\s*,?\s*\{[^}]*\})*)\s*:\s*(?:you )?gain (\d+) life/i,
  function(m) {
    return 'A:AB$ GainLife | Cost$ ' + m[1] + ' | LifeAmount$ ' + m[2] + ' | SpellDescription$ Gain ' + m[2] + ' life';
  }
);

// Mana ability: "{T}: Add {X}"
CardScriptRegistry.register(
  /\{T\}\s*:\s*add\s+(\{[WUBRGC]\}(?:\s*(?:or\s*)?\{[WUBRGC]\})*)/i,
  function(m) {
    var colors = [];
    var colorMatches = m[1].match(/\{([WUBRGC])\}/gi);
    if (colorMatches) {
      colors = colorMatches.map(function(c) { return c.replace(/[{}]/g, ''); });
    }
    return 'A:AB$ ManaAdd | Cost$ {T} | Produced$ ' + colors.join(',') + ' | SpellDescription$ Tap for mana';
  }
);

// Sorcery/Instant: "Destroy target creature"
CardScriptRegistry.register(
  /destroy (?:target|all) (creature|permanent|artifact|enchantment|planeswalker)s?/i,
  function(m) {
    if (/all/i.test(m[0])) {
      return 'SP:AB$ DestroyAll | ValidCards$ ' + m[1] + ' | SpellDescription$ Destroy all ' + m[1] + 's';
    }
    return 'SP:AB$ DestroyPermanent | ValidTgts$ ' + m[1].charAt(0).toUpperCase() + m[1].slice(1) + ' | SpellDescription$ Destroy target ' + m[1];
  }
);

// Sorcery/Instant: "Exile target creature/permanent"
CardScriptRegistry.register(
  /exile target (creature|permanent|artifact|enchantment|nonland permanent)/i,
  function(m) {
    return 'SP:AB$ ExilePermanent | ValidTgts$ ' + m[1].charAt(0).toUpperCase() + m[1].slice(1) + ' | SpellDescription$ Exile target ' + m[1];
  }
);

// Sorcery/Instant: "Counter target spell"
CardScriptRegistry.register(
  /counter target (\w+ )?spell/i,
  function(m) {
    return 'SP:AB$ CounterSpell | SpellDescription$ Counter target spell';
  }
);

// Draw: "Draw N cards"
CardScriptRegistry.register(
  /^draw (\w+|\d+) cards?/im,
  function(m) {
    var num = parseInt(m[1]) || ({'a':1,'one':1,'two':2,'three':3,'four':4,'five':5}[m[1].toLowerCase()] || 1);
    return 'SP:AB$ DrawCard | NumCards$ ' + num + ' | SpellDescription$ Draw ' + num;
  }
);

// Ramp: "Search your library for a basic land"
CardScriptRegistry.register(
  /search your library for (?:up to )?(\w+|\d+)? ?(?:basic )?land cards?/i,
  function(m) {
    var num = m[1] ? (parseInt(m[1]) || ({'a':1,'one':1,'two':2,'three':3}[m[1].toLowerCase()] || 1)) : 1;
    return 'SP:AB$ Ramp | Amount$ ' + num + ' | SpellDescription$ Search for ' + num + ' land(s)';
  }
);

// Mill: "Mill N cards" or "put the top N cards of your library into your graveyard"
CardScriptRegistry.register(
  /(?:mill (\d+)|put the top (\d+) cards? of (?:your|their|target player's) library into (?:your|their|that player's) graveyard)/i,
  function(m) {
    var num = parseInt(m[1] || m[2] || '1');
    return 'SP:AB$ Mill | NumCards$ ' + num + ' | SpellDescription$ Mill ' + num;
  }
);

// Scry: "Scry N"
CardScriptRegistry.register(
  /scry (\d+)/i,
  function(m) {
    return 'SP:AB$ Scry | ScryNum$ ' + m[1] + ' | SpellDescription$ Scry ' + m[1];
  }
);

// Dies trigger: "When [name/this creature] dies, [effect]"
CardScriptRegistry.register(
  /when (?:this creature|~|it) dies,?\s*(.+?)(?:\.|$)/i,
  function(m, cardName) {
    var effect = m[1].toLowerCase();
    if (/draw (\w+|\d+) cards?/.test(effect)) {
      var num = effect.match(/draw (\w+|\d+)/);
      var amount = num ? (parseInt(num[1]) || 1) : 1;
      return 'T:Mode$ ChangesZone | Origin$ Battlefield | Destination$ Graveyard | Execute$ DrawCard | NumCards$ ' + amount + ' | TriggerDescription$ Dies: Draw';
    }
    if (/create/.test(effect)) {
      return 'T:Mode$ ChangesZone | Origin$ Battlefield | Destination$ Graveyard | Execute$ CreateToken | TriggerDescription$ Dies: Create token';
    }
    return 'T:Mode$ ChangesZone | Origin$ Battlefield | Destination$ Graveyard | Execute$ Generic | TriggerDescription$ Dies: ' + effect.substring(0, 50);
  }
);

// Attack trigger: "Whenever [name/this creature] attacks, [effect]"
CardScriptRegistry.register(
  /whenever (?:this creature|~|it) attacks,?\s*(.+?)(?:\.|$)/i,
  function(m, cardName) {
    var effect = m[1].toLowerCase();
    if (/draw/.test(effect)) {
      return 'T:Mode$ Attacks | Execute$ DrawCard | NumCards$ 1 | TriggerDescription$ Attack: Draw';
    }
    if (/deal/.test(effect)) {
      var dmg = effect.match(/deals? (\d+)/);
      return 'T:Mode$ Attacks | Execute$ DealDamage | NumDmg$ ' + (dmg ? dmg[1] : '1') + ' | TriggerDescription$ Attack: Damage';
    }
    if (/create/.test(effect)) {
      return 'T:Mode$ Attacks | Execute$ CreateToken | TriggerDescription$ Attack: Create token';
    }
    return 'T:Mode$ Attacks | Execute$ Generic | TriggerDescription$ Attack: ' + effect.substring(0, 50);
  }
);

// Upkeep trigger: "At the beginning of your upkeep, [effect]"
CardScriptRegistry.register(
  /at the beginning of (?:your |each (?:player's )?)?upkeep,?\s*(.+?)(?:\.|$)/i,
  function(m, cardName) {
    var effect = m[1].toLowerCase();
    if (/draw/.test(effect)) {
      return 'T:Mode$ Phase | Phase$ Upkeep | Execute$ DrawCard | NumCards$ 1 | TriggerDescription$ Upkeep: Draw';
    }
    if (/gain (\d+) life/.test(effect)) {
      var life = effect.match(/gain (\d+)/);
      return 'T:Mode$ Phase | Phase$ Upkeep | Execute$ GainLife | LifeAmount$ ' + (life ? life[1] : '1') + ' | TriggerDescription$ Upkeep: Gain life';
    }
    if (/lose (\d+) life/.test(effect)) {
      var life2 = effect.match(/lose (\d+)/);
      return 'T:Mode$ Phase | Phase$ Upkeep | Execute$ LoseLife | LifeAmount$ ' + (life2 ? life2[1] : '1') + ' | TriggerDescription$ Upkeep: Lose life';
    }
    return 'T:Mode$ Phase | Phase$ Upkeep | Execute$ Generic | TriggerDescription$ Upkeep: ' + effect.substring(0, 50);
  }
);

// Static: "Other creatures you control get +N/+N"
CardScriptRegistry.register(
  /(?:other )?creatures you control (?:get|have) \+(\d+)\/\+(\d+)/i,
  function(m) {
    return 'S:Mode$ Continuous | Affected$ Creature.YouCtrl | AddPower$ ' + m[1] + ' | AddToughness$ ' + m[2] + ' | StaticDescription$ Anthem +' + m[1] + '/+' + m[2];
  }
);

// Static: "Creatures you control have [keyword]"
CardScriptRegistry.register(
  /creatures you control (?:have|gain) (\w[\w\s]*?)(?:\.|,|$)/i,
  function(m) {
    return 'S:Mode$ Continuous | Affected$ Creature.YouCtrl | AddKeyword$ ' + m[1].trim() + ' | StaticDescription$ Grant ' + m[1].trim();
  }
);


// ============================================================
// CARD SCRIPT MANAGER — Bridges CardScript with game engine
// ============================================================

var CardScriptManager = {

  // Cache: cardName -> SpellAbility[]
  _cache: {},

  // Get SpellAbility objects for a card (auto-generates from oracle text if no manual script)
  getAbilities: function(cardData) {
    var key = cardData.name;
    if (this._cache[key]) return this._cache[key];

    // First try the registry (auto-match oracle text)
    var script = CardScriptRegistry.match(
      cardData.oracleText || '',
      cardData.typeLine || '',
      cardData.name || ''
    );

    var abilities = [];
    if (script) {
      abilities = CardScriptParser.parse(
        script,
        cardData.name,
        cardData.ownerIndex !== undefined ? cardData.ownerIndex : (cardData.ownerId || 0),
        cardData.id
      );
    }

    this._cache[key] = abilities;
    return abilities;
  },

  // Clear cache (call when cards change)
  clearCache: function() {
    this._cache = {};
  },

  // Get just the keyword abilities
  getKeywords: function(cardData) {
    return this.getAbilities(cardData).filter(function(sa) {
      return sa.abilityType === 'keyword';
    }).map(function(sa) {
      return sa.keyword;
    });
  },

  // Get triggered abilities matching an event type
  getTriggersForEvent: function(cardData, eventType) {
    return this.getAbilities(cardData).filter(function(sa) {
      return sa.abilityType === 'triggered' && sa.trigger && sa.trigger.event === eventType;
    });
  },

  // Get all activated abilities
  getActivatedAbilities: function(cardData) {
    return this.getAbilities(cardData).filter(function(sa) {
      return sa.abilityType === 'activated';
    });
  },

  // Get the spell effect (for instants/sorceries)
  getSpellAbility: function(cardData) {
    var spells = this.getAbilities(cardData).filter(function(sa) {
      return sa.abilityType === 'spell';
    });
    return spells.length > 0 ? spells[0] : null;
  },

  // Get static abilities
  getStaticAbilities: function(cardData) {
    return this.getAbilities(cardData).filter(function(sa) {
      return sa.abilityType === 'static';
    });
  },

  // Count total abilities (for AI scoring)
  countAbilities: function(cardData) {
    var abs = this.getAbilities(cardData);
    return {
      total: abs.length,
      keywords: abs.filter(function(a) { return a.abilityType === 'keyword'; }).length,
      activated: abs.filter(function(a) { return a.abilityType === 'activated'; }).length,
      triggered: abs.filter(function(a) { return a.abilityType === 'triggered'; }).length,
      static: abs.filter(function(a) { return a.abilityType === 'static'; }).length,
      mana: abs.filter(function(a) { return a.api === 'ManaAdd'; }).length
    };
  },

  // AI: Score a card's abilities for strategic evaluation
  scoreAbilities: function(cardData, weights) {
    var w = weights || (typeof aiWeights !== 'undefined' ? aiWeights : {});
    var abs = this.getAbilities(cardData);
    var score = 0;

    for (var i = 0; i < abs.length; i++) {
      var sa = abs[i];
      switch (sa.abilityType) {
        case 'keyword':
          var kwMap = {
            'flying': w.kw_flying || 2.5, 'haste': w.kw_haste || 2.5,
            'deathtouch': w.kw_deathtouch || 2.5, 'double strike': w.kw_doubleStrike || 3,
            'first strike': w.kw_firstStrike || 1.5, 'lifelink': w.kw_lifelink || 1.5,
            'trample': w.kw_trample || 1.5, 'hexproof': w.kw_hexproof || 2,
            'indestructible': w.kw_indestructible || 3, 'menace': w.kw_menace || 1.5,
            'vigilance': w.kw_vigilance || 1, 'reach': w.kw_reach || 0.5,
            'infect': w.kw_infect || 3, 'flash': w.kw_flash || 1,
            'defender': w.kw_defender || -2, 'cascade': w.kw_cascade || 3,
          };
          score += kwMap[sa.keyword] || (w.kw_default || 0.5);
          break;
        case 'triggered':
          if (sa.trigger) {
            if (sa.trigger.event === 'etb') score += w.trig_etb || 2;
            else if (sa.trigger.event === 'attack') score += w.trig_attack || 1.5;
            else if (sa.trigger.event === 'dies') score += w.trig_dies || 1;
            else score += w.trig_other || 0.5;
          }
          // Bonus for automated effects
          if (sa.api && CardScriptResolvers[sa.api]) score += 0.5;
          break;
        case 'activated':
          score += w.activated_bonus || 1;
          if (sa.api === 'DrawCard') score += 1.5; // Card advantage is premium
          if (sa.api === 'DealDamage') score += 1;
          break;
        case 'static':
          score += 2; // Static abilities are always active
          if (sa.effect.addPower > 0 || sa.effect.addToughness > 0) score += 1;
          if (sa.effect.addKeyword) score += 1;
          break;
        case 'spell':
          if (sa.api === 'DestroyPermanent' || sa.api === 'ExilePermanent') score += w.spell_destroy || 5;
          if (sa.api === 'DrawCard') score += w.spell_draw || 3;
          if (sa.api === 'CounterSpell') score += w.spell_counter || 4;
          if (sa.api === 'DestroyAll') score += 7; // Board wipes are high value
          if (sa.api === 'Ramp') score += w.spell_ramp || 6;
          if (sa.api === 'CreateToken') score += 2;
          break;
      }
    }

    return score;
  }
};


// ============================================================
// AI GAME STATE EVALUATOR — Forge-Inspired Board Analysis
// ============================================================

var AIBoardAnalyzer = {

  // Comprehensive board state evaluation
  // Returns a numeric score: positive = favorable, negative = unfavorable
  evaluateBoardState: function(playerIdx) {
    if (!gameState) return 0;
    var w = (typeof aiWeights !== 'undefined') ? aiWeights : {};
    var me = gameState.players[playerIdx];
    if (!me || me.eliminated) return -1000;

    var score = 0;

    // 1. Material advantage (card count on board)
    var myCards = gameState.battlefieldCards.filter(function(c) { return c.ownerId === playerIdx; });
    var enemyCards = gameState.battlefieldCards.filter(function(c) { return c.ownerId !== playerIdx; });
    var myCreatures = myCards.filter(function(c) { return c.typeLine && /creature/i.test(c.typeLine); });
    var enemyCreatures = enemyCards.filter(function(c) { return c.typeLine && /creature/i.test(c.typeLine); });

    score += myCreatures.length * 3;
    score -= enemyCreatures.length * 2;
    score += (myCards.length - myCreatures.length) * 1.5; // non-creature permanents

    // 2. Power projection (total power on board)
    var myPower = 0, myToughness = 0;
    myCreatures.forEach(function(c) {
      var p = (typeof getCreaturePower === 'function') ? getCreaturePower(c) : (parseInt(c.power) || 0);
      var t = (typeof getCreatureToughness === 'function') ? getCreatureToughness(c) : (parseInt(c.toughness) || 0);
      myPower += p;
      myToughness += t;
    });
    var enemyPower = 0, enemyToughness = 0;
    enemyCreatures.forEach(function(c) {
      var p = (typeof getCreaturePower === 'function') ? getCreaturePower(c) : (parseInt(c.power) || 0);
      var t = (typeof getCreatureToughness === 'function') ? getCreatureToughness(c) : (parseInt(c.toughness) || 0);
      enemyPower += p;
      enemyToughness += t;
    });

    score += (myPower - enemyPower) * 1.5;
    score += (myToughness - enemyToughness) * 0.5;

    // 3. Evasion advantage
    var myFlyers = myCreatures.filter(function(c) { return typeof hasKeyword === 'function' && hasKeyword(c, 'flying'); });
    var enemyFlyers = enemyCreatures.filter(function(c) { return typeof hasKeyword === 'function' && hasKeyword(c, 'flying'); });
    score += myFlyers.length * 2;
    score -= enemyFlyers.length * 1.5;

    // 4. Card advantage (hand size)
    var myHand = me.zones.hand ? me.zones.hand.length : 0;
    var avgEnemyHand = 0;
    var enemyCount = 0;
    gameState.players.forEach(function(p, i) {
      if (i !== playerIdx && !p.eliminated) {
        avgEnemyHand += (p.zones.hand ? p.zones.hand.length : 0);
        enemyCount++;
      }
    });
    avgEnemyHand = enemyCount > 0 ? avgEnemyHand / enemyCount : 0;
    score += (myHand - avgEnemyHand) * 2;

    // 5. Life advantage
    var startLife = gameState.startingLife || 40;
    score += (me.life / startLife) * 5;
    gameState.players.forEach(function(p, i) {
      if (i !== playerIdx && !p.eliminated) {
        score -= (p.life / startLife) * 2;
      }
    });

    // 6. Mana advantage (land count)
    var myLands = myCards.filter(function(c) { return c.typeLine && /land/i.test(c.typeLine); });
    var maxEnemyLands = 0;
    gameState.players.forEach(function(p, i) {
      if (i !== playerIdx && !p.eliminated) {
        var their = gameState.battlefieldCards.filter(function(c) {
          return c.ownerId === i && c.typeLine && /land/i.test(c.typeLine);
        });
        if (their.length > maxEnemyLands) maxEnemyLands = their.length;
      }
    });
    score += (myLands.length - maxEnemyLands) * 1;

    // 7. Ability quality bonus (using CardScript system)
    myCards.forEach(function(c) {
      score += CardScriptManager.scoreAbilities(c) * 0.3;
    });

    // 8. Commander threat
    var cmdOnField = myCards.some(function(c) { return c.isCommander; });
    if (cmdOnField) score += 4;

    return Math.round(score * 10) / 10;
  },

  // Detect synergies between cards on the battlefield
  detectSynergies: function(playerIdx) {
    if (!gameState) return [];
    var synergies = [];
    var myCards = gameState.battlefieldCards.filter(function(c) { return c.ownerId === playerIdx; });

    // Anthem detection: static abilities that buff other creatures
    var anthems = [];
    myCards.forEach(function(c) {
      var statics = CardScriptManager.getStaticAbilities(c);
      statics.forEach(function(sa) {
        if (sa.effect.addPower > 0 || sa.effect.addToughness > 0 || sa.effect.addKeyword) {
          anthems.push({ source: c, ability: sa });
        }
      });
    });
    if (anthems.length > 0) {
      var creatureCount = myCards.filter(function(c) { return c.typeLine && /creature/i.test(c.typeLine); }).length;
      synergies.push({
        type: 'anthem',
        value: anthems.length * creatureCount * 2,
        description: anthems.length + ' anthem effect' + (anthems.length !== 1 ? 's' : '') + ' buffing ' + creatureCount + ' creatures'
      });
    }

    // Token synergy: token generators + anthem/lords
    var hasTokenGen = myCards.some(function(c) {
      var triggers = CardScriptManager.getTriggersForEvent(c, 'etb');
      return triggers.some(function(t) { return t.api === 'CreateToken'; });
    });
    if (hasTokenGen && anthems.length > 0) {
      synergies.push({
        type: 'token_anthem',
        value: 5,
        description: 'Token generation + anthem synergy'
      });
    }

    // Sacrifice synergy: dies triggers + sacrifice outlets
    var hasDiesTrigger = myCards.some(function(c) {
      return CardScriptManager.getTriggersForEvent(c, 'dies').length > 0 ||
             (c.triggers && c.triggers.some(function(t) { return t.type === 'dies'; }));
    });
    var hasSacOutlet = myCards.some(function(c) {
      var activated = CardScriptManager.getActivatedAbilities(c);
      return activated.some(function(a) { return a.cost && a.cost.sacrifice; });
    });
    if (hasDiesTrigger && hasSacOutlet) {
      synergies.push({
        type: 'sacrifice',
        value: 4,
        description: 'Dies triggers + sacrifice outlet synergy'
      });
    }

    // Card draw engine: multiple draw triggers
    var drawEngines = myCards.filter(function(c) {
      var triggers = CardScriptManager.getTriggersForEvent(c, 'draw');
      return triggers.length > 0;
    });
    if (drawEngines.length >= 2) {
      synergies.push({
        type: 'draw_engine',
        value: 6,
        description: 'Card draw engine: ' + drawEngines.length + ' draw triggers'
      });
    }

    // Evasion suite: flying + pump/buff
    var flyerCount = myCards.filter(function(c) {
      return typeof hasKeyword === 'function' && hasKeyword(c, 'flying');
    }).length;
    if (flyerCount >= 3) {
      synergies.push({
        type: 'evasion_swarm',
        value: flyerCount * 1.5,
        description: 'Evasion swarm: ' + flyerCount + ' flyers'
      });
    }

    // Lifegain synergy: life gain triggers + life gain sources
    var hasLifegainTrigger = myCards.some(function(c) {
      return CardScriptManager.getTriggersForEvent(c, 'life_gain').length > 0;
    });
    var hasLifelink = myCards.some(function(c) {
      return typeof hasKeyword === 'function' && hasKeyword(c, 'lifelink');
    });
    if (hasLifegainTrigger && hasLifelink) {
      synergies.push({
        type: 'lifegain',
        value: 3,
        description: 'Lifegain synergy: life gain triggers + lifelink'
      });
    }

    return synergies;
  },

  // Detect the archetype a player's board most closely represents
  detectArchetype: function(playerIdx) {
    if (!gameState) return { archetype: 'unknown', confidence: 0 };
    var myCards = gameState.battlefieldCards.filter(function(c) { return c.ownerId === playerIdx; });
    var player = gameState.players[playerIdx];
    if (!player) return { archetype: 'unknown', confidence: 0 };

    var scores = {
      aggro: 0,
      midrange: 0,
      control: 0,
      combo: 0,
      ramp: 0,
      tokens: 0
    };

    var creatureCount = 0;
    var lowCmcCreatures = 0;
    var removalCount = 0;
    var drawCount = 0;
    var landCount = 0;
    var tokenCount = 0;
    var totalPower = 0;

    myCards.forEach(function(c) {
      var cmc = c.cmc || 0;
      var isCreature = c.typeLine && /creature/i.test(c.typeLine);
      var isLand = c.typeLine && /land/i.test(c.typeLine);

      if (isCreature) {
        creatureCount++;
        if (cmc <= 3) lowCmcCreatures++;
        var pow = (typeof getCreaturePower === 'function') ? getCreaturePower(c) : (parseInt(c.power) || 0);
        totalPower += pow;
        if (typeof hasKeyword === 'function') {
          if (hasKeyword(c, 'haste')) scores.aggro += 2;
          if (hasKeyword(c, 'flying') || hasKeyword(c, 'menace')) scores.aggro += 1;
        }
      }
      if (isLand) landCount++;
      if (c.isToken) tokenCount++;

      // Check card oracle for role
      var text = (c.oracleText || '').toLowerCase();
      if (/destroy|exile/.test(text) && /target/.test(text)) removalCount++;
      if (/draw/.test(text)) drawCount++;
      if (/counter target spell/.test(text)) scores.control += 3;
      if (/search your library for.*land/.test(text)) scores.ramp += 3;
      if (/create.*token/.test(text)) scores.tokens += 2;
    });

    // Hand analysis
    var hand = player.zones.hand || [];
    hand.forEach(function(c) {
      var text = (c.oracleText || '').toLowerCase();
      if (/counter target spell/.test(text)) scores.control += 2;
      if (/destroy|exile/.test(text)) removalCount++;
    });

    // Aggro: many cheap creatures, high total power, few lands
    scores.aggro += lowCmcCreatures * 2;
    scores.aggro += Math.min(totalPower / 3, 8);
    if (creatureCount >= 4) scores.aggro += 3;

    // Control: removal, draw, few creatures
    scores.control += removalCount * 2;
    scores.control += drawCount * 1.5;
    if (creatureCount <= 2) scores.control += 3;

    // Midrange: balanced mix
    if (creatureCount >= 2 && creatureCount <= 4 && removalCount >= 1) scores.midrange += 4;
    if (drawCount >= 1 && totalPower >= 6) scores.midrange += 3;

    // Ramp: many lands
    if (landCount >= 6) scores.ramp += 3;
    if (landCount >= 8) scores.ramp += 3;

    // Tokens: many tokens
    scores.tokens += tokenCount * 2;

    // Combo: synergy-based (detected separately)
    var synergies = this.detectSynergies(playerIdx);
    var synergyValue = 0;
    synergies.forEach(function(s) { synergyValue += s.value; });
    if (synergyValue >= 8) scores.combo += 5;
    if (synergyValue >= 12) scores.combo += 5;

    // Find highest score
    var bestArch = 'midrange';
    var bestScore = 0;
    for (var arch in scores) {
      if (scores[arch] > bestScore) {
        bestScore = scores[arch];
        bestArch = arch;
      }
    }

    return {
      archetype: bestArch,
      confidence: Math.min(Math.round(bestScore / 15 * 100), 100),
      scores: scores,
      synergies: synergies
    };
  },

  // Get strategic recommendations for the AI
  getStrategicAdvice: function(playerIdx) {
    if (!gameState) return [];
    var advice = [];
    var boardScore = this.evaluateBoardState(playerIdx);
    var archetype = this.detectArchetype(playerIdx);
    var synergies = archetype.synergies || [];
    var player = gameState.players[playerIdx];
    if (!player) return advice;

    // Board position advice
    if (boardScore > 15) {
      advice.push({ type: 'position', priority: 'high', text: 'Strong board position. Press advantage, protect key pieces.' });
    } else if (boardScore < -10) {
      advice.push({ type: 'position', priority: 'high', text: 'Behind on board. Prioritize removal and board wipes.' });
    } else {
      advice.push({ type: 'position', priority: 'medium', text: 'Board is roughly even. Play for incremental advantage.' });
    }

    // Archetype-specific advice
    switch (archetype.archetype) {
      case 'aggro':
        advice.push({ type: 'strategy', priority: 'high', text: 'Aggro: Maximize damage, attack every turn, finish off weak players.' });
        break;
      case 'control':
        advice.push({ type: 'strategy', priority: 'high', text: 'Control: Hold removal for biggest threats, draw cards, avoid overextending.' });
        break;
      case 'ramp':
        advice.push({ type: 'strategy', priority: 'high', text: 'Ramp: Prioritize land drops and mana rocks, play expensive threats ASAP.' });
        break;
      case 'tokens':
        advice.push({ type: 'strategy', priority: 'high', text: 'Tokens: Protect anthem effects, go wide, beware board wipes.' });
        break;
      case 'combo':
        advice.push({ type: 'strategy', priority: 'high', text: 'Combo potential detected. Protect key synergy pieces.' });
        break;
    }

    // Synergy advice
    if (synergies.length > 0) {
      var synText = synergies.map(function(s) { return s.description; }).join('; ');
      advice.push({ type: 'synergy', priority: 'medium', text: 'Active synergies: ' + synText });
    }

    // Threat assessment
    if (typeof aiEvaluatePlayerThreats === 'function') {
      var threats = aiEvaluatePlayerThreats(playerIdx);
      if (threats.length > 0 && threats[0].threatScore > 20) {
        advice.push({ type: 'threat', priority: 'high', text: 'High threat: ' + threats[0].name + ' (score: ' + Math.round(threats[0].threatScore) + '). Focus removal/attacks there.' });
      }
    }

    // Life total advice
    if (player.life <= 15) {
      advice.push({ type: 'survival', priority: 'high', text: 'Low life total (' + player.life + '). Prioritize defense and lifegain.' });
    }

    return advice;
  }
};


// ============================================================
// INTEGRATION: Connect CardScript system to AI scoring
// ============================================================

// Enhanced AI card scorer that uses CardScript system
function aiScoreCardEnhanced(card, difficulty, w) {
  w = w || (typeof aiWeights !== 'undefined' ? aiWeights : {});

  // Start with the base score from the original system
  var score = (typeof aiScoreCard === 'function') ? aiScoreCard(card, difficulty, w) : 10;

  // Add CardScript-based scoring
  var csScore = CardScriptManager.scoreAbilities(card, w);
  score += csScore * 0.25; // Weighted blend

  // Synergy bonus: if this card synergizes with what's already on board
  if (gameState) {
    var playerIdx = card.ownerId !== undefined ? card.ownerId : gameState.currentPlayerIndex;
    var currentSynergies = AIBoardAnalyzer.detectSynergies(playerIdx);
    var currentSynergyValue = 0;
    currentSynergies.forEach(function(s) { currentSynergyValue += s.value; });

    // Check if playing this card would improve synergies
    var cardAbilities = CardScriptManager.getAbilities(card);
    var hasAnthem = cardAbilities.some(function(a) { return a.abilityType === 'static' && (a.effect.addPower > 0 || a.effect.addKeyword); });
    var hasTokenGen = cardAbilities.some(function(a) { return a.api === 'CreateToken'; });
    var hasDiesTrigger = cardAbilities.some(function(a) { return a.abilityType === 'triggered' && a.trigger && a.trigger.event === 'dies'; });

    if (hasAnthem) {
      var creaturesOnBoard = gameState.battlefieldCards.filter(function(c) {
        return c.ownerId === playerIdx && c.typeLine && /creature/i.test(c.typeLine);
      }).length;
      score += creaturesOnBoard * 0.5; // Anthem is worth more with more creatures
    }
    if (hasTokenGen && currentSynergies.some(function(s) { return s.type === 'anthem'; })) {
      score += 3; // Token gen + existing anthem = synergy
    }
    if (hasDiesTrigger) {
      var hasSacOnBoard = gameState.battlefieldCards.some(function(c) {
        if (c.ownerId !== playerIdx) return false;
        var activated = CardScriptManager.getActivatedAbilities(c);
        return activated.some(function(a) { return a.cost && a.cost.sacrifice; });
      });
      if (hasSacOnBoard) score += 3; // Dies trigger + sac outlet = synergy
    }
  }

  // Difficulty adjustment
  if (difficulty === 'hard') {
    // Hard mode: additional strategic adjustments
    if (card.isRamp && gameState && gameState.turnNumber <= 4) score += 3; // Early game ramp premium
    if (card.isRemoval && gameState) {
      var threats = (typeof aiEvaluateBoardThreats === 'function') ? aiEvaluateBoardThreats(gameState.currentPlayerIndex) : [];
      if (threats.length > 0 && threats[0].score > 8) score += 4; // Removal premium when threats exist
    }
  }

  return score;
}


