// Active AI weights (can be overridden by training)
var aiWeights = JSON.parse(JSON.stringify(AI_DEFAULT_WEIGHTS));

// Load saved weights from local storage
(function() {
  try {
    var saved = window['local' + 'Storage'].getItem('mtg_ai_weights');
    if (saved) {
      var parsed = JSON.parse(saved);
      for (var k in parsed) {
        if (parsed.hasOwnProperty(k) && aiWeights.hasOwnProperty(k)) {
          aiWeights[k] = parsed[k];
        }
      }
    }
  } catch(e) { /* ignore */ }
})();

function saveAiWeights() {
  try {
    window['local' + 'Storage'].setItem('mtg_ai_weights', JSON.stringify(aiWeights));
  } catch(e) { /* ignore */ }
}

function resetAiWeights() {
  aiWeights = JSON.parse(JSON.stringify(AI_DEFAULT_WEIGHTS));
  try { window['local' + 'Storage'].removeItem('mtg_ai_weights'); } catch(e) {}
}

// Score a card for AI priority
function aiScoreCard(card, difficulty, w) {
  w = w || aiWeights;
  var cmc = aiGetCmc(card);
  var score = 10 - cmc * w.card_baseCmcPenalty;

  var abilities = parseCardAbilities(card.oracleText || '', card.typeLine || '', card.name || '');

  if (aiIsCreature(card)) {
    if (card.pt) {
      var parts = card.pt.split('/');
      var power = parseInt(parts[0]) || 0;
      var tough = parseInt(parts[1]) || 0;
      score += (power + tough) * w.card_ptBonus;
    }
    var kwMap = {
      'flying': w.kw_flying, 'haste': w.kw_haste, 'deathtouch': w.kw_deathtouch,
      'double strike': w.kw_doubleStrike, 'first strike': w.kw_firstStrike,
      'lifelink': w.kw_lifelink, 'trample': w.kw_trample, 'hexproof': w.kw_hexproof,
      'indestructible': w.kw_indestructible, 'menace': w.kw_menace, 'vigilance': w.kw_vigilance,
      'reach': w.kw_reach, 'infect': w.kw_infect, 'toxic': w.kw_toxic,
      'annihilator': w.kw_annihilator, 'cascade': w.kw_cascade, 'undying': w.kw_undying,
      'persist': w.kw_persist, 'prowess': w.kw_prowess, 'ward': w.kw_ward,
      'flash': w.kw_flash, 'defender': w.kw_defender,
    };
    for (var ki = 0; ki < abilities.keywords.length; ki++) {
      score += kwMap[abilities.keywords[ki].name] || w.kw_default;
    }
    for (var ti = 0; ti < abilities.triggered.length; ti++) {
      var st = abilities.triggered[ti].subType;
      if (st === 'etb') score += w.trig_etb;
      else if (st === 'attack') score += w.trig_attack;
      else if (st === 'dies') score += w.trig_dies;
      else score += w.trig_other;
    }
    score += abilities.activated.length * w.activated_bonus;
  } else {
    var text = (card.oracleText || '').toLowerCase();
    var tl = (card.typeLine || '').toLowerCase();
    if (text.includes('destroy') || text.includes('exile')) score += w.spell_destroy;
    if (text.includes('draw')) score += w.spell_draw;
    if (text.includes('counter target')) score += w.spell_counter;
    if (text.includes('return') && text.includes('graveyard')) score += w.spell_graveyard;
    if (text.includes('search your library')) score += w.spell_search;
    if (card.isRamp) score += w.spell_ramp;
    if (tl.includes('equipment')) score += w.spell_equipment;
    if (tl.includes('enchantment') && !tl.includes('creature')) score += w.spell_enchantment;
    for (var ki2 = 0; ki2 < abilities.keywords.length; ki2++) {
      if (abilities.keywords[ki2].name === 'flash') score += w.spell_flash;
      if (abilities.keywords[ki2].name === 'cascade') score += w.spell_cascade;
    }
  }

  if (difficulty === 'easy') score += Math.random() * w.diff_easyNoise;
  if (difficulty === 'normal') score += Math.random() * w.diff_normalNoise;

  return score;
}

// Generate a simple SVG card image for AI cards
function generateAiCardSVG(card) {
  const colors = {
    mono_white: { bg: '#F9FAF4', border: '#F0E68C', text: '#333' },
    mono_blue: { bg: '#E8F0FE', border: '#4A90D9', text: '#1a3a5c' },
    mono_black: { bg: '#2A2A2A', border: '#555', text: '#ddd' },
    mono_red: { bg: '#FDE8E8', border: '#D32F2F', text: '#5a1a1a' },
    mono_green: { bg: '#E8F5E9', border: '#388E3C', text: '#1a3a1a' },
  };
  const style = colors.mono_white; // Default
  const isCreature = card.typeLine?.toLowerCase().includes('creature');
  const isLand = card.typeLine?.toLowerCase().includes('land');

  const name = (card.name || 'Unknown').substring(0, 24);
  const type = (card.typeLine || '').substring(0, 30);
  const pt = card.pt || '';

  const svg = `<svg xmlns="http://www.w3.org/2000/svg" width="200" height="280" viewBox="0 0 200 280">
    <rect x="2" y="2" width="196" height="276" rx="12" fill="${isLand ? '#2d5016' : style.bg}" stroke="${isLand ? '#4a8c28' : style.border}" stroke-width="2"/>
    <rect x="10" y="10" width="180" height="30" rx="4" fill="rgba(0,0,0,0.08)"/>
    <text x="16" y="30" font-family="serif" font-size="12" font-weight="bold" fill="${isLand ? '#c5e1a5' : style.text}">${name}</text>
    ${card.cmc ? `<text x="184" y="30" font-family="sans-serif" font-size="11" fill="${style.text}" text-anchor="end">{${card.cmc}}</text>` : ''}
    <rect x="10" y="48" width="180" height="100" rx="4" fill="rgba(0,0,0,0.04)"/>
    <text x="16" y="66" font-family="sans-serif" font-size="9" fill="${isLand ? '#a5d6a7' : '#666'}">${type}</text>
    <foreignObject x="12" y="160" width="176" height="80">
      <div xmlns="http://www.w3.org/1999/xhtml" style="font:9px sans-serif;color:${isLand ? '#c5e1a5' : '#555'};overflow:hidden;word-wrap:break-word">${(card.oracleText || '').substring(0, 120)}</div>
    </foreignObject>
    ${isCreature && pt ? `<rect x="150" y="248" width="40" height="22" rx="4" fill="rgba(0,0,0,0.15)"/><text x="170" y="264" font-family="sans-serif" font-size="12" font-weight="bold" fill="${isLand ? '#fff' : style.text}" text-anchor="middle">${pt}</text>` : ''}
    <text x="100" y="150" font-size="10" fill="rgba(0,0,0,0.06)" text-anchor="middle" font-family="sans-serif">AI</text>
  </svg>`;

  return 'data:image/svg+xml;base64,' + btoa(unescape(encodeURIComponent(svg)));
}

// ============================================================
// AI STRATEGY & DECISION-MAKING HELPERS
// ============================================================

// ---- AI Helper: Evaluate board threat level (per-card) ----
function aiEvaluateBoardThreats(playerIdx, w) {
  w = w || aiWeights;
  var threats = [];
  if (!gameState) return threats;
  gameState.battlefieldCards.forEach(function(c) {
    if (c.ownerId === playerIdx) return;
    if (!aiIsCreature(c)) return;
    var pow = getCreaturePower(c);
    var tou = getCreatureToughness(c);
    var score = pow + tou;
    if (hasKeyword(c, 'flying')) score += w.bt_flying;
    if (hasKeyword(c, 'deathtouch')) score += w.bt_deathtouch;
    if (hasKeyword(c, 'lifelink')) score += w.bt_lifelink;
    if (hasKeyword(c, 'double strike')) score += pow;
    if (hasKeyword(c, 'first strike')) score += w.bt_firstStrike;
    if (hasKeyword(c, 'trample')) score += w.bt_trample;
    if (hasKeyword(c, 'hexproof')) score += w.bt_hexproof;
    if (hasKeyword(c, 'indestructible')) score += w.bt_indestructible;
    if (c.isCommander) score += w.bt_commander;
    threats.push({ card: c, score: score });
  });
  threats.sort(function(a, b) { return b.score - a.score; });
  return threats;
}

// ---- AI Helper: Evaluate per-PLAYER threat level (political awareness) ----
// Returns sorted array: [{ idx, name, threatScore, breakdown }] highest threat first
function aiEvaluatePlayerThreats(playerIdx, w) {
  w = w || aiWeights;
  if (!gameState) return [];
  var playerScores = [];

  gameState.players.forEach(function(p, i) {
    if (i === playerIdx || p.eliminated) return;

    var breakdown = {
      boardPresence: 0,
      creaturePower: 0,
      cardAdvantage: 0,
      lifeDelta: 0,
      commanderThreat: 0,
      momentum: 0
    };

    // --- Board presence: count permanents, weight creatures more ---
    var theirCards = gameState.battlefieldCards.filter(function(c) { return c.ownerId === i; });
    var theirCreatures = theirCards.filter(function(c) { return aiIsCreature(c); });
    var theirNonCreatures = theirCards.length - theirCreatures.length;
    breakdown.boardPresence = theirCreatures.length * w.pt_creatureWeight + theirNonCreatures * w.pt_nonCreatureWeight;

    // --- Creature power: sum total power on board ---
    var totalPower = 0;
    theirCreatures.forEach(function(c) {
      var pow = getCreaturePower(c);
      totalPower += pow;
      // Extra danger for evasive creatures
      if (hasKeyword(c, 'flying')) totalPower += w.pt_flyingBonus;
      if (hasKeyword(c, 'trample')) totalPower += w.pt_trampleBonus;
      if (hasKeyword(c, 'double strike')) totalPower += pow;
      if (hasKeyword(c, 'indestructible')) totalPower += w.pt_indestructBonus;
      if (hasKeyword(c, 'hexproof')) totalPower += w.pt_hexproofBonus;
    });
    breakdown.creaturePower = totalPower;

    // --- Card advantage: hand size relative to average ---
    var handSize = p.zones.hand ? p.zones.hand.length : 0;
    var avgHand = 0;
    var activeCount = 0;
    gameState.players.forEach(function(pp, pi) {
      if (pi === playerIdx || pp.eliminated) return;
      avgHand += pp.zones.hand ? pp.zones.hand.length : 0;
      activeCount++;
    });
    avgHand = activeCount > 0 ? avgHand / activeCount : 3;
    breakdown.cardAdvantage = (handSize - avgHand) * w.pt_cardAdvMultiplier;

    // --- Life delta: higher life = more threat (they can afford risky plays) ---
    // Also factor in how close to killing opponents they are
    var startLife = gameState.startingLife || 40;
    var lifeRatio = p.life / startLife;
    breakdown.lifeDelta = (lifeRatio - 0.5) * w.pt_lifeDeltaScale; // 0 at half life, +4 at full, -4 at 0

    // --- Commander threat: commander on battlefield is dangerous ---
    var cmdOnField = theirCards.some(function(c) { return c.isCommander; });
    var cmdDamage = 0;
    // Check if this player has dealt commander damage to us
    if (p.commanderDamageDealt) {
      cmdDamage = p.commanderDamageDealt[playerIdx] || 0;
    }
    breakdown.commanderThreat = (cmdOnField ? w.pt_cmdOnField : 0) + (cmdDamage > 10 ? w.pt_cmdDmgHigh : cmdDamage > 5 ? w.pt_cmdDmgMid : 0);

    // --- Momentum: recently-cast spells suggest active turn ---
    // Use graveyard size as a proxy for spells cast
    var gySize = p.zones.graveyard ? p.zones.graveyard.length : 0;
    breakdown.momentum = Math.min(gySize, w.pt_momentumCap); // Cap at 5

    var totalThreat = breakdown.boardPresence + breakdown.creaturePower +
      breakdown.cardAdvantage + breakdown.lifeDelta +
      breakdown.commanderThreat + breakdown.momentum;

    playerScores.push({
      idx: i,
      name: p.name,
      threatScore: totalThreat,
      breakdown: breakdown
    });
  });

  // Sort highest threat first
  playerScores.sort(function(a, b) { return b.threatScore - a.threatScore; });
  return playerScores;
}

// ---- AI Helper: Check if AI can afford a card (CMC vs untapped lands) ----
function aiCanAfford(card, playerIdx) {
  var cmc = aiGetCmc(card);
  var untapped = aiCountUntappedLands(playerIdx);
  return untapped >= cmc;
}

// ---- AI Helper: Pick best attack target (political — attack the leader) ----
function aiPickAttackTarget(playerIdx) {
  var difficulty = gameState ? (gameState.aiDifficulty || 'easy') : 'easy';

  // Easy mode: pick lowest life (old behavior)
  if (difficulty === 'easy') {
    var bestIdx = -1;
    var lowestLife = Infinity;
    gameState.players.forEach(function(p, i) {
      if (i === playerIdx || p.eliminated) return;
      if (p.life < lowestLife) {
        lowestLife = p.life;
        bestIdx = i;
      }
    });
    return bestIdx;
  }

  // Normal/Hard: use threat assessment to attack the leader
  var playerThreats = aiEvaluatePlayerThreats(playerIdx);
  if (playerThreats.length === 0) return -1;

  var leader = playerThreats[0]; // Highest threat player

  // Hard mode: consider if a low-life player is close to dying (finish them off)
  if (difficulty === 'hard') {
    var nearDeath = playerThreats.find(function(pt) {
      var p = gameState.players[pt.idx];
      if (!p) return false;
      // Can we lethal them this turn?
      var ourPower = 0;
      gameState.battlefieldCards.forEach(function(c) {
        if (c.ownerId === playerIdx && aiIsCreature(c) && !c.tapped && !hasSummoningSickness(c)) {
          ourPower += getCreaturePower(c);
        }
      });
      return p.life <= ourPower && p.life <= 15;
    });
    if (nearDeath) {
      aiAddThought(playerIdx, 'Going for the kill on ' + nearDeath.name + ' (' + gameState.players[nearDeath.idx].life + ' life)');
      return nearDeath.idx;
    }
  }

  // Log the political decision
  if (leader.threatScore > 0) {
    var bd = leader.breakdown;
    var reasons = [];
    if (bd.creaturePower >= 8) reasons.push('big board');
    if (bd.commanderThreat >= 6) reasons.push('commander out');
    if (bd.cardAdvantage >= 3) reasons.push('card advantage');
    if (bd.lifeDelta >= 3) reasons.push('high life');
    if (reasons.length > 0) {
      aiAddThought(playerIdx, 'Targeting ' + leader.name + ' (leader: ' + reasons.join(', ') + ')');
    }
  }

  return leader.idx;
}

// ---- AI Helper: Evaluate if an attack is favorable ----
function aiEvaluateAttack(attacker, defenderIdx) {
  var pow = getCreaturePower(attacker);
  var tou = getCreatureToughness(attacker);
  // Count potential blockers
  var blockers = gameState.battlefieldCards.filter(function(c) {
    return c.ownerId === defenderIdx && aiIsCreature(c) && !c.tapped;
  });
  // If no blockers, always good to attack
  if (blockers.length === 0) return { shouldAttack: true, risk: 'none' };
  // If attacker has flying and no defender has flying/reach, safe
  if (hasKeyword(attacker, 'flying')) {
    var canBlockFlying = blockers.some(function(b) { return hasKeyword(b, 'flying') || hasKeyword(b, 'reach'); });
    if (!canBlockFlying) return { shouldAttack: true, risk: 'none' };
  }
  // If attacker has menace and <2 untapped creatures, safe
  if (hasKeyword(attacker, 'menace') && blockers.length < 2) {
    return { shouldAttack: true, risk: 'none' };
  }
  // Check if any blocker can kill us
  var canDie = blockers.some(function(b) {
    var bPow = getCreaturePower(b);
    return (bPow >= tou) || hasKeyword(b, 'deathtouch');
  });
  // Check if we can kill any blocker
  var canKill = blockers.some(function(b) {
    var bTou = getCreatureToughness(b);
    return pow >= bTou || hasKeyword(attacker, 'deathtouch');
  });
  if (!canDie) return { shouldAttack: true, risk: 'low' };
  if (canDie && canKill) return { shouldAttack: true, risk: 'trade' };
  if (canDie && !canKill) return { shouldAttack: false, risk: 'bad-trade' };
  return { shouldAttack: true, risk: 'medium' };
}

// ---- AI Helper: Find best removal target (threat-aware, prioritize leader's cards) ----
function aiFindRemovalTarget(playerIdx, w) {
  w = w || aiWeights;
  var difficulty = gameState ? (gameState.aiDifficulty || 'easy') : 'easy';
  var threats = aiEvaluateBoardThreats(playerIdx);
  if (threats.length === 0) return null;

  // Easy mode: just pick highest-threat card regardless of owner
  if (difficulty === 'easy') {
    for (var i = 0; i < threats.length; i++) {
      var t = threats[i];
      if (hasKeyword(t.card, 'hexproof') || hasKeyword(t.card, 'shroud')) continue;
      return t.card;
    }
    return null;
  }

  // Normal/Hard: weight removal toward the biggest threat PLAYER's cards
  var playerThreats = aiEvaluatePlayerThreats(playerIdx);
  if (playerThreats.length === 0) {
    // Fallback: just pick highest individual threat
    for (var j = 0; j < threats.length; j++) {
      if (hasKeyword(threats[j].card, 'hexproof') || hasKeyword(threats[j].card, 'shroud')) continue;
      return threats[j].card;
    }
    return null;
  }

  var leaderIdx = playerThreats[0].idx;

  // Score each threat card, boosting cards owned by the table leader
  var scoredThreats = threats.map(function(t) {
    var adjustedScore = t.score;
    // Boost cards from the leading player
    if (t.card.ownerId === leaderIdx) adjustedScore += w.rem_leaderBoost;
    // Extra boost for commanders (removing commander is huge tempo swing)
    if (t.card.isCommander) adjustedScore += w.rem_commanderBoost;
    // Penalty for hexproof/shroud (untargetable)
    if (hasKeyword(t.card, 'hexproof') || hasKeyword(t.card, 'shroud')) adjustedScore = -100;
    // Hard mode: also consider if removing this creature prevents lethal
    if (difficulty === 'hard') {
      var ownerPow = getCreaturePower(t.card);
      var myLife = gameState.players[playerIdx] ? gameState.players[playerIdx].life : 40;
      if (ownerPow >= myLife * w.rem_lifeThreatFactor) adjustedScore += w.rem_lifeThreatBonus; // Threatens significant life
    }
    return { card: t.card, score: adjustedScore };
  });

  scoredThreats.sort(function(a, b) { return b.score - a.score; });

  for (var k = 0; k < scoredThreats.length; k++) {
    if (scoredThreats[k].score > 0) {
      var target = scoredThreats[k].card;
      aiAddThought(playerIdx, 'Removal target: ' + target.name + ' (' + (gameState.players[target.ownerId] ? gameState.players[target.ownerId].name : '?') + ')');
      return target;
    }
  }
  return null;
}

// ---- AI Helper: Should the AI use a board wipe? ----
function aiShouldBoardWipe(playerIdx, w) {
  w = w || aiWeights;
  var myCreatures = gameState.battlefieldCards.filter(function(c) {
    return c.ownerId === playerIdx && aiIsCreature(c);
  });
  var enemyCreatures = gameState.battlefieldCards.filter(function(c) {
    return c.ownerId !== playerIdx && aiIsCreature(c);
  });
  // Wipe if enemies have significantly more creatures than us
  if (enemyCreatures.length >= myCreatures.length + w.bw_creatureAdvantage) return true;
  // Or if any single enemy creature is very threatening
  var bigThreat = enemyCreatures.some(function(c) {
    return getCreaturePower(c) >= w.bw_bigThreatPower || hasKeyword(c, 'indestructible');
  });
  if (bigThreat && enemyCreatures.length > myCreatures.length) return true;
  return false;
}

// ---- AI Helper: Cast commander from command zone ----
function aiTryCastCommander(playerIdx) {
  if (!gameState) return false;
  var player = gameState.players[playerIdx];
  if (!player || !player.isAI) return false;
  var cmdZone = player.zones.command;
  if (!cmdZone || cmdZone.length === 0) return false;

  var cmdName = player.commanderCardName || '';
  if (!cmdName) return false;

  var cmdIdx = -1;
  for (var i = 0; i < cmdZone.length; i++) {
    if (cmdZone[i].name === cmdName) { cmdIdx = i; break; }
  }
  if (cmdIdx === -1) return false;

  var cardData = cmdZone[cmdIdx];
  var baseCmc = cardData.cmc || 0;
  var tax = getCommanderTax(playerIdx);
  var totalCost = baseCmc + tax;
  var available = aiCountUntappedLands(playerIdx);

  if (available < totalCost) return false;

  // Generate image if needed
  if (!cardData.imageUrl) cardData.imageUrl = generateAiCardSVG(cardData);

  // Use confirmCastCommander logic but adapted for AI
  player.commanderCastCount = (player.commanderCastCount || 0) + 1;
  var castCard = cmdZone.splice(cmdIdx, 1)[0];

  // Tap lands to pay total cost (base + tax)
  var manaToPay = totalCost;
  var lands = aiCountLands(playerIdx).filter(function(c) { return !c.tapped; });
  for (var li = 0; li < lands.length; li++) {
    if (manaToPay <= 0) break;
    toggleTap(lands[li].id);
    manaToPay--;
  }

  addCardToBattlefield(castCard.name, castCard.imageUrl || '',
    castCard.typeLine || '', playerIdx, undefined, undefined,
    castCard.oracleText || '',
    { manaCost: castCard.manaCost || '', pt: castCard.pt, cmc: castCard.cmc, isCommander: true });

  addLogEntry('\u{1F916} \u{1F451} <strong>' + player.name + '</strong> cast <strong>' + cmdName + '</strong> from command zone (tax: +' + tax + ')');
  fireBattlefieldTriggers('commander_cast');
  fireBattlefieldTriggers('cast');
  updatePlayerZones();
  renderPlayerPanels();
  return true;
}

// ---- AI Helper: Pick multiple attack targets for multiplayer ----
function aiPickMultiTargetAttacks(playerIdx, creatures, difficulty) {
  if (!gameState) return [];
  var opponents = [];
  gameState.players.forEach(function(p, i) {
    if (i === playerIdx || p.eliminated) return;
    var theirCreatures = gameState.battlefieldCards.filter(function(c) {
      return c.ownerId === i && aiIsCreature(c) && !c.tapped;
    });
    opponents.push({
      idx: i,
      life: p.life,
      blockerCount: theirCreatures.length,
      hasFlyers: theirCreatures.some(function(c) { return hasKeyword(c, 'flying') || hasKeyword(c, 'reach'); }),
      name: p.name
    });
  });

  if (opponents.length === 0) return [];

  // Use threat assessment for Normal/Hard to determine primary target
  var primaryTarget;
  if (difficulty === 'easy') {
    // Easy: lowest life
    opponents.sort(function(a, b) { return a.life - b.life; });
    primaryTarget = opponents[0].idx;
  } else {
    // Normal/Hard: highest-threat player from political assessment
    var playerThreats = aiEvaluatePlayerThreats(playerIdx);
    if (playerThreats.length > 0) {
      primaryTarget = playerThreats[0].idx;
    } else {
      opponents.sort(function(a, b) { return a.life - b.life; });
      primaryTarget = opponents[0].idx;
    }
  }

  var assignments = []; // { card, targetIdx }

  if (difficulty === 'easy' || opponents.length === 1) {
    // Easy/single opponent: everything at one target
    creatures.forEach(function(c) {
      assignments.push({ card: c, targetIdx: primaryTarget });
    });
    return assignments;
  }

  // Normal/Hard: smart multi-target allocation
  // Sort opponents by threat for secondary targeting
  var opponentsByThreat = opponents.slice();
  var ptMap = {};
  var pt2 = aiEvaluatePlayerThreats(playerIdx);
  pt2.forEach(function(p) { ptMap[p.idx] = p.threatScore; });
  opponentsByThreat.sort(function(a, b) { return (ptMap[b.idx] || 0) - (ptMap[a.idx] || 0); });

  creatures.forEach(function(c) {
    var assigned = false;

    // Flying creatures -> target player with no flying/reach blockers
    if (hasKeyword(c, 'flying')) {
      var noFlyerDefender = opponentsByThreat.find(function(op) { return !op.hasFlyers && op.blockerCount > 0; });
      if (noFlyerDefender) {
        assignments.push({ card: c, targetIdx: noFlyerDefender.idx });
        assigned = true;
      }
    }

    if (!assigned) {
      // Hard: if primary target is well-defended, spread to unblocked opponents
      if (difficulty === 'hard' && opponents.length >= 3) {
        var unblocked = opponentsByThreat.find(function(op) {
          return op.idx !== primaryTarget && op.blockerCount === 0;
        });
        if (unblocked) {
          assignments.push({ card: c, targetIdx: unblocked.idx });
          assigned = true;
        }
      }
      if (!assigned) {
        assignments.push({ card: c, targetIdx: primaryTarget });
      }
    }
  });

  return assignments;
}

// ---- AI Helper: Check if AI has a counterspell and should use it ----
function aiCheckForCounterspell(playerIdx) {
  if (!gameState) return null;
  var player = gameState.players[playerIdx];
  if (!player || !player.isAI) return null;

  for (var i = 0; i < player.zones.hand.length; i++) {
    var card = player.zones.hand[i];
    var text = (card.oracleText || '').toLowerCase();
    if (text.indexOf('counter target') !== -1) {
      // Check if can afford it
      var cmc = aiGetCmc(card);
      var available = aiCountUntappedLands(playerIdx);
      if (available >= cmc) {
        return { card: card, handIndex: i };
      }
    }
  }
  return null;
}

// ---- AI Stack Response: AI reacts to spells on the stack ----
function aiRespondToStack() {
  if (!gameState || !gameState.theStack || gameState.theStack.length === 0) return;
  if (!gameState.rulesEngine || !gameState.rulesEngine.useStack) return;

  var topSpell = gameState.theStack[gameState.theStack.length - 1];
  if (!topSpell) return;

  // Check each AI player for responses
  gameState.players.forEach(function(player, idx) {
    if (!player.isAI || player.eliminated) return;
    if (idx === topSpell.ownerIndex) return; // Don't counter own spells

    var difficulty = gameState.aiDifficulty || 'easy';
    // Easy AI doesn't respond to stack
    if (difficulty === 'easy') return;

    var counterInfo = aiCheckForCounterspell(idx);
    if (!counterInfo) return;

    // Evaluate if the spell is worth countering
    var spellText = (topSpell.oracleText || '').toLowerCase();
    var spellType = (topSpell.typeLine || '').toLowerCase();
    var shouldCounter = false;

    // Always counter board wipes
    if (spellText.indexOf('destroy all') !== -1 || spellText.indexOf('each creature') !== -1) {
      shouldCounter = true;
    }
    // Counter big threats (CMC >= 5)
    if (topSpell.cmc >= 5 || (spellType.indexOf('creature') !== -1 && topSpell.cmc >= 4)) {
      shouldCounter = true;
    }
    // Counter removal targeting AI's stuff (heuristic)
    if (spellText.indexOf('destroy target') !== -1 || spellText.indexOf('exile target') !== -1) {
      if (difficulty === 'hard') shouldCounter = true;
      else shouldCounter = Math.random() > 0.4;
    }
    // Threat-aware: more likely to counter spells from the leading player
    var playerThreats = aiEvaluatePlayerThreats(idx);
    var casterIsLeader = playerThreats.length > 0 && playerThreats[0].idx === topSpell.ownerIndex;
    if (casterIsLeader && topSpell.cmc >= 2) {
      shouldCounter = true; // Counter leader's spells more aggressively
    }
    // Hard mode: counter anything that costs 3+ from any player
    if (difficulty === 'hard' && topSpell.cmc >= 3) shouldCounter = true;

    if (!shouldCounter) return;

    // Cast the counterspell
    var card = counterInfo.card;
    if (!card.imageUrl) card.imageUrl = generateAiCardSVG(card);

    // Tap lands to pay
    var manaToPay = aiGetCmc(card);
    var lands = aiCountLands(idx).filter(function(c) { return !c.tapped; });
    for (var li = 0; li < lands.length; li++) {
      if (manaToPay <= 0) break;
      toggleTap(lands[li].id);
      manaToPay--;
    }

    // Remove from hand
    player.zones.hand.splice(counterInfo.handIndex, 1);

    // Counter the spell (remove from stack)
    var countered = gameState.theStack.pop();
    // Put countered spell in owner's graveyard
    var spellOwner = gameState.players[countered.ownerIndex];
    if (spellOwner) {
      spellOwner.zones.graveyard.push({
        name: countered.name,
        imageUrl: countered.imageUrl || '',
        typeLine: countered.typeLine || '',
        oracleText: countered.oracleText || '',
        manaCost: countered.manaCost || ''
      });
    }
    // Put counterspell in AI's graveyard
    player.zones.graveyard.push(card);

    addLogEntry('\u{1F916} \u{1F6AB} <strong>' + player.name + '</strong> counters <strong>' + countered.name + '</strong> with <strong>' + card.name + '</strong>!');
    aiAddThought(idx, 'Countered ' + countered.name + ' (threat level: high)');
    renderStackPanel();
    renderHandArea();
    renderPlayerPanels();
  });
}

// ---- AI Thinking Log: visible decision tracking ----
var aiThoughts = []; // Array of { playerIdx, playerName, thought, timestamp }

function aiAddThought(playerIdx, thought) {
  if (!gameState) return;
  var player = gameState.players[playerIdx];
  if (!player) return;
  aiThoughts.push({
    playerIdx: playerIdx,
    playerName: player.name,
    thought: thought,
    timestamp: Date.now()
  });
  // Keep max 50
  if (aiThoughts.length > 50) aiThoughts.shift();
  renderAiThoughtBubble(playerIdx, thought);
}

function renderAiThoughtBubble(playerIdx, thought) {
  // Show a floating thought bubble near the player's panel
  var panelEl = document.getElementById('player-panel-' + playerIdx);
  if (!panelEl) return;

  var existing = panelEl.querySelector('.ai-thought-bubble');
  if (existing) existing.remove();

  var bubble = document.createElement('div');
  bubble.className = 'ai-thought-bubble';
  bubble.innerHTML = '\u{1F4AD} ' + thought;
  panelEl.appendChild(bubble);

  // Auto-remove after 3 seconds
  setTimeout(function() {
    if (bubble.parentNode) bubble.remove();
  }, 3500);
}

// ============================================================
// AI BATTLEFIELD ABILITIES - Mana dorks, equipment usage
// ============================================================

/**
 * AI taps mana-producing creatures (mana dorks) to generate extra mana.
 * Called at the start of Main Phase 1 before casting spells.
 * Returns the number of extra mana produced.
 */
function aiTapManaDorks(playerIdx) {
  var player = gameState.players[playerIdx];
  if (!player) return 0;
  var produced = 0;
  var dorks = gameState.battlefieldCards.filter(function(c) {
    return c.ownerId === playerIdx &&
           c.typeLine && c.typeLine.toLowerCase().includes('creature') &&
           !c.tapped &&
           !hasSummoningSickness(c) &&
           (c.isManaProducer || (c.oracleText && /\{T\}:.*[Aa]dd \{[WUBRGC]\}/i.test(c.oracleText)));
  });
  if (dorks.length === 0) return 0;

  dorks.forEach(function(dork) {
    // Determine what color of mana to produce
    var manaColor = dork.manaAbility || 'G';
    // Try to detect from oracle text
    if (!dork.manaAbility && dork.oracleText) {
      var manaMatch = dork.oracleText.match(/[Aa]dd \{([WUBRGC])\}/);
      if (manaMatch) manaColor = manaMatch[1];
    }
    // Tap the dork
    dork.tapped = true;
    var el = document.getElementById('bc-' + dork.id);
    if (el) el.classList.add('tapped');
    // Add mana to pool directly
    var p = gameState.players[playerIdx];
    if (p && p.manaPool) {
      p.manaPool[manaColor] = (p.manaPool[manaColor] || 0) + 1;
    }
    produced++;
  });

  if (produced > 0) {
    addLogEntry('\u{1F916} <strong>' + player.name + '</strong> tapped ' + produced + ' mana dork' + (produced > 1 ? 's' : '') + ' for mana');
    aiAddThought(playerIdx, 'Tapped ' + produced + ' mana dork' + (produced > 1 ? 's' : ''));
  }
  return produced;
}

/**
 * AI equips equipment to its best unequipped creature.
 * Looks for equipment on the battlefield and attaches to best candidate.
 */
function aiEquipCreatures(playerIdx) {
  var player = gameState.players[playerIdx];
  if (!player) return;

  // Find unattached equipment the AI controls
  var equipment = gameState.battlefieldCards.filter(function(c) {
    return c.ownerId === playerIdx &&
           c.typeLine && c.typeLine.toLowerCase().includes('equipment') &&
           !c.attachedTo;
  });
  if (equipment.length === 0) return;

  // Find best creature to equip (prefer attackers, biggest creatures)
  var creatures = gameState.battlefieldCards.filter(function(c) {
    return c.ownerId === playerIdx &&
           c.typeLine && c.typeLine.toLowerCase().includes('creature') &&
           !c.typeLine.toLowerCase().includes('land');
  });
  if (creatures.length === 0) return;

  // Sort by power descending - equip the biggest threats
  creatures.sort(function(a, b) {
    return getCreaturePower(b) - getCreaturePower(a);
  });

  equipment.forEach(function(equip) {
    // Find equip cost from oracle text
    var equipCostMatch = equip.oracleText ? equip.oracleText.match(/[Ee]quip \{(\d+)\}/) : null;
    var equipCost = equipCostMatch ? parseInt(equipCostMatch[1]) : 2;
    // Special case: Equip {0}
    if (equip.oracleText && /[Ee]quip \{0\}/.test(equip.oracleText)) equipCost = 0;

    var available = aiCountUntappedLands(playerIdx);
    if (available < equipCost) return;

    // Pick the best creature that doesn't already have this equipment
    var target = creatures.find(function(c) {
      var attachments = c.attachments || [];
      return !attachments.includes(equip.id);
    });
    if (!target) return;

    // Pay equip cost by tapping lands
    if (equipCost > 0) {
      var lands = gameState.battlefieldCards.filter(function(c) {
        return c.ownerId === playerIdx && c.typeLine && c.typeLine.toLowerCase().includes('land') && !c.tapped;
      });
      for (var li = 0; li < equipCost && li < lands.length; li++) {
        lands[li].tapped = true;
        var landEl = document.getElementById('bc-' + lands[li].id);
        if (landEl) landEl.classList.add('tapped');
      }
    }

    // Attach equipment
    equip.attachedTo = target.id;
    if (!target.attachments) target.attachments = [];
    target.attachments.push(equip.id);

    addLogEntry('\u{1F916} <strong>' + player.name + '</strong> equipped <strong>' + equip.name + '</strong> to <strong>' + target.name + '</strong>');
    aiAddThought(playerIdx, 'Equipped ' + equip.name + ' to ' + target.name);
    renderBattlefield();
  });
}

// ============================================================
// AI SPELL TIMING & SEQUENCING
// ============================================================

/**
 * Sort and categorize the AI's hand into play sequencing buckets.
 * Returns { ramp: [], removal: [], threats: [], utility: [], instants: [] }
 * Each entry has { card, index, score, cmc }
 */
function aiCategorizeHand(playerIdx, difficulty) {
  var player = gameState.players[playerIdx];
  if (!player) return { ramp: [], removal: [], threats: [], utility: [], instants: [] };

  var result = { ramp: [], removal: [], threats: [], utility: [], instants: [] };

  player.zones.hand.forEach(function(c, i) {
    if (aiIsLand(c)) return;
    var entry = { card: c, index: i, score: (typeof aiScoreCardEnhanced === 'function' ? aiScoreCardEnhanced(c, difficulty) : aiScoreCard(c, difficulty)), cmc: aiGetCmc(c) };
    var tl = (c.typeLine || '').toLowerCase();
    var isInstant = tl.includes('instant');

    if (c.isRamp) {
      result.ramp.push(entry);
    } else if (c.isRemoval) {
      if (isInstant) result.instants.push(entry);
      else result.removal.push(entry);
    } else if (c.isBoardWipe) {
      result.removal.push(entry);
    } else if (isInstant) {
      result.instants.push(entry);
    } else if (tl.includes('creature')) {
      result.threats.push(entry);
    } else {
      result.utility.push(entry);
    }
  });

  // Sort each bucket by score descending
  var sortFn = function(a, b) { return b.score - a.score; };
  result.ramp.sort(sortFn);
  result.removal.sort(sortFn);
  result.threats.sort(sortFn);
  result.utility.sort(sortFn);
  result.instants.sort(sortFn);

  return result;
}

/**
 * Build the AI's play sequence for Main Phase 1.
 * Hard mode: ramp first, then threats. Hold removal + instants for post-combat.
 * Normal mode: ramp first, then best cards by score.
 * Easy mode: random order.
 */
function aiBuildPlaySequence(playerIdx, difficulty) {
  var categories = aiCategorizeHand(playerIdx, difficulty);
  var sequence = [];

  if (difficulty === 'easy') {
    // Easy: just play whatever, no sequencing intelligence
    var all = [].concat(categories.ramp, categories.removal, categories.threats, categories.utility, categories.instants);
    // Shuffle
    for (var i = all.length - 1; i > 0; i--) {
      var j = Math.floor(Math.random() * (i + 1));
      var tmp = all[i]; all[i] = all[j]; all[j] = tmp;
    }
    return { mainPhase1: all, holdForPostCombat: [] };
  }

  if (difficulty === 'normal') {
    // Normal: ramp first, then everything else by score
    sequence = [].concat(categories.ramp);
    var rest = [].concat(categories.threats, categories.removal, categories.utility, categories.instants);
    rest.sort(function(a, b) { return b.score - a.score; });
    sequence = sequence.concat(rest);
    return { mainPhase1: sequence, holdForPostCombat: [] };
  }

  // Hard mode: sophisticated sequencing
  // Phase 1: Ramp spells first, then equipment/enchantments, then threats
  var phase1 = [].concat(categories.ramp);
  // Add utility (equipment, enchantments) early
  phase1 = phase1.concat(categories.utility);
  // Add threats
  phase1 = phase1.concat(categories.threats);

  // Hold back: sorcery-speed removal (play post-combat to see if combat solves the problem)
  // Hold back: instants (save for opponent's turn if stack is enabled)
  var held = [];
  // In hard mode, hold instant-speed removal and counterspells for post-combat or responses
  held = held.concat(categories.instants);
  // Sorcery removal goes post-combat in hard mode
  held = held.concat(categories.removal);

  return { mainPhase1: phase1, holdForPostCombat: held };
}

// --- AI post-combat continuation (used after human blocker pause) ---
function _aiRunPostCombat(playerIdx, player, difficulty, heldCards) {
  var postActions = [];
  var postDelay = 600;

  // MAIN PHASE 2 (same logic as inline version)
  if (difficulty !== 'easy') {
    postActions.push({ delay: postDelay, fn: function() {
      var bluffReserve = 0;
      var bluffCardName = '';
      if (difficulty === 'hard' || difficulty === 'normal') {
        var instantsInHand = player.zones.hand.filter(function(c) {
          var tl = (c.typeLine || '').toLowerCase();
          return tl.indexOf('instant') !== -1;
        });
        var flashCards = player.zones.hand.filter(function(c) {
          var text = (c.oracleText || '').toLowerCase();
          return text.indexOf('flash') !== -1;
        });
        var bluffCandidates = instantsInHand.concat(flashCards);
        if (bluffCandidates.length > 0) {
          var cheapestInstant = bluffCandidates.reduce(function(best, c) {
            var cmc = aiGetCmc(c);
            return cmc < aiGetCmc(best) ? c : best;
          }, bluffCandidates[0]);
          bluffReserve = aiGetCmc(cheapestInstant);
          bluffCardName = cheapestInstant.name;
          if (difficulty === 'normal' && Math.random() > 0.5) bluffReserve = 0;
        }
        if (bluffReserve === 0 && difficulty === 'hard' && Math.random() > 0.6) {
          bluffReserve = 2;
          bluffCardName = '';
        }
      }

      if (heldCards && heldCards.length > 0) {
        var heldPlayed = 0;
        for (var hi = 0; hi < heldCards.length && heldPlayed < 3; hi++) {
          var he = heldCards[hi];
          if (bluffReserve > 0 && he.card.name === bluffCardName) continue;
          var hci = player.zones.hand.indexOf(he.card);
          if (hci === -1) continue;
          var havailable = aiCountUntappedLands(playerIdx);
          var hcmc = aiGetCmc(he.card);
          if (havailable - hcmc < bluffReserve) continue;
          if (havailable < hcmc) continue;
          if (!he.card.imageUrl) he.card.imageUrl = generateAiCardSVG(he.card);
          playCardFromHand(playerIdx, hci);
          addLogEntry('\u{1F916} <strong>' + player.name + '</strong> cast <strong>' + he.card.name + '</strong> (post-combat)');
          heldPlayed++;
        }
      }

      var remainingHand = player.zones.hand
        .map(function(c, i) { return { card: c, index: i, score: (typeof aiScoreCardEnhanced === 'function' ? aiScoreCardEnhanced(c, difficulty) : aiScoreCard(c, difficulty)) }; })
        .filter(function(e) { return !aiIsLand(e.card); })
        .sort(function(a, b) { return b.score - a.score; });

      for (var ri = 0; ri < remainingHand.length && ri < 2; ri++) {
        var re = remainingHand[ri];
        if (bluffReserve > 0 && re.card.name === bluffCardName) continue;
        var ci = player.zones.hand.indexOf(re.card);
        if (ci === -1) continue;
        var available = aiCountUntappedLands(playerIdx);
        var cardCmc = aiGetCmc(re.card);
        if (available - cardCmc < bluffReserve) continue;
        if (available < cardCmc) continue;
        if (!re.card.imageUrl) re.card.imageUrl = generateAiCardSVG(re.card);
        playCardFromHand(playerIdx, ci);
        addLogEntry('\u{1F916} <strong>' + player.name + '</strong> cast <strong>' + re.card.name + '</strong> (post-combat)');
      }

      if (bluffReserve > 0) {
        var untappedAfter = aiCountUntappedLands(playerIdx);
        if (untappedAfter >= bluffReserve) {
          if (bluffCardName) {
            aiAddThought(playerIdx, 'Holding ' + untappedAfter + ' mana open (has ' + bluffCardName + ')');
          } else {
            aiAddThought(playerIdx, 'Holding ' + untappedAfter + ' mana open (bluffing)');
          }
          addLogEntry('\u{1F916} <strong>' + player.name + '</strong> passes with ' + untappedAfter + ' mana open...');
        }
      }
    }});
    postDelay += 800;
  }

  // END TURN
  postActions.push({ delay: postDelay, fn: function() {
    addLogEntry('\u{1F916} <strong>' + player.name + '</strong> passes the turn');
    aiTurnActive = false;
    nextTurn();
  }});

  postActions.forEach(function(action) {
    setTimeout(function() {
      try { action.fn(); } catch(e) { console.error('[AI Post-Combat Error]', e); }
    }, action.delay);
  });
}

function runAiTurn() {
  if (!gameState) return;
  var playerIdx = gameState.currentPlayerIndex;
  var player = gameState.players[playerIdx];
  if (!player || !player.isAI) return;

  // ========================================
  // PRIORITY 1: Commander-AI-Lab ML Pipeline
  // ========================================
  if (typeof AIBridge !== 'undefined' &&
      AIBridge.connector.connected &&
      AIBridge.connector.modelLoaded) {

    aiTurnActive = true;
    player.aiLandPlayedThisTurn = false;
    addLogEntry('\u{1F9E0} <strong>' + player.name + '</strong> is thinking... [ML Policy]');
    aiAddThought(playerIdx, 'ML pipeline mode \u2014 consulting neural network...');

    _runMlAiTurn(playerIdx).then(function(success) {
      if (!success) {
        addLogEntry('\u{1F916} [ML] Falling back to local AI for ' + player.name);
        aiTurnActive = false;
        _runLocalAiTurn();
      }
    }).catch(function(err) {
      console.error('[runAiTurn] ML pipeline error:', err);
      aiTurnActive = false;
      _runLocalAiTurn();
    });
    return;
  }

  // ========================================
  // PRIORITY 2: Forge Engine Hybrid
  // ========================================
  if (typeof ForgeBridge !== 'undefined' && ForgeBridge.enabled &&
      ForgeBridge.connected && ForgeBridge.gameActive) {
    aiTurnActive = true;
    player.aiLandPlayedThisTurn = false;
    addLogEntry('\u{1F916} <strong>' + player.name + '</strong> is thinking... [Forge AI]');
    aiAddThought(playerIdx, 'Forge engine mode \u2014 consulting advanced AI...');

    forgeRunAiTurn(playerIdx, function(success) {
      if (success) {
        addLogEntry('\u{1F916} <strong>' + player.name + '</strong> passes the turn [Forge AI]');
        aiTurnActive = false;
        renderPlayerPanels();
        renderHandArea();
        nextTurn();
      } else {
        addLogEntry('\u{1F916} [Forge] Falling back to local AI for ' + player.name);
        aiTurnActive = false;
        _runLocalAiTurn();
      }
    });
    return;
  }

  // ========================================
  // PRIORITY 3: Local Heuristic AI
  // ========================================
  _runLocalAiTurn();
}

/**
 * Run an AI turn using the Commander-AI-Lab ML policy pipeline.
 * Makes multiple decision requests per turn (one per phase).
 * Returns true if the ML pipeline completed the turn successfully.
 */
async function _runMlAiTurn(playerIdx) {
  if (!gameState) return false;
  var player = gameState.players[playerIdx];
  if (!player || !player.isAI) return false;

  aiTurnActive = true;
  player.aiLandPlayedThisTurn = false;
  var difficulty = gameState.aiDifficulty || 'easy';
  var turnDelay = gameState.aiSettings?.turnDelay || 800;

  try {
    // ── PHASE 1: Play a land (local, immediate) ──────────
    var landInHand = player.zones.hand.findIndex(function(c) {
      return typeof aiIsLand === 'function' && aiIsLand(c);
    });
    if (landInHand !== -1) {
      var landCard = player.zones.hand[landInHand];
      if (landCard && !landCard.imageUrl && typeof generateAiCardSVG === 'function') {
        landCard.imageUrl = generateAiCardSVG(landCard);
      }
      playCardFromHand(playerIdx, landInHand);
      player.aiLandPlayedThisTurn = true;
      addLogEntry('\u{1F9E0} <strong>' + player.name + '</strong> played a land [ML]');
      await _mlDelay(turnDelay * 0.5);
    }

    // ── PHASE 2: Main Phase 1 decisions ──────────────────
    var maxActions = difficulty === 'easy' ? 1 : difficulty === 'normal' ? 3 : 5;
    var actionsPlayed = 0;

    for (var i = 0; i < maxActions; i++) {
      var decision = await AIBridge.gameState.requestAiDecision(gameState, playerIdx);
      if (!decision) break;

      aiAddThought(playerIdx,
        'ML decision: ' + decision.action +
        ' (' + Math.round(decision.confidence * 100) + '% conf, ' +
        decision.inference_ms.toFixed(1) + 'ms)');

      // Display probability distribution
      if (decision.probabilities) {
        var topActions = Object.entries(decision.probabilities)
          .sort(function(a, b) { return b[1] - a[1]; })
          .slice(0, 3)
          .map(function(e) { return e[0] + ':' + Math.round(e[1] * 100) + '%'; })
          .join(', ');
        aiAddThought(playerIdx, 'Top actions: ' + topActions);
      }

      // Skip if action is pass/hold
      if (decision.action === 'pass' || decision.action === 'hold_mana') {
        aiAddThought(playerIdx, 'ML chose to ' +
          (decision.action === 'pass' ? 'pass' : 'hold mana open'));
        break;
      }

      // Skip combat action in main phase — save for combat
      if (decision.action === 'attack_opponent') {
        aiAddThought(playerIdx, 'ML wants to attack \u2014 saving for combat phase');
        break;
      }

      var executed = AIBridge.MacroActionMapper.execute(
        decision.action, playerIdx, gameState, decision
      );

      if (executed) {
        actionsPlayed++;
        // Push state update to backend
        AIBridge.gameState.pushState(gameState);
        AIBridge.gameState.pushDecision(decision);
        await _mlDelay(turnDelay);
      } else {
        // Action couldn't execute — likely no valid targets
        aiAddThought(playerIdx,
          'Could not execute ' + decision.action + ' \u2014 moving on');
        break;
      }
    }

    // ── PHASE 3: Combat ──────────────────────────────────
    var combatDecision = await AIBridge.gameState.requestAiDecision(gameState, playerIdx);
    if (combatDecision && combatDecision.action === 'attack_opponent') {
      AIBridge.MacroActionMapper.execute(
        'attack_opponent', playerIdx, gameState, combatDecision
      );
      await _mlDelay(turnDelay);
    }

    // ── PHASE 4: Post-combat main phase 2 ────────────────
    var postDecision = await AIBridge.gameState.requestAiDecision(gameState, playerIdx);
    if (postDecision &&
        postDecision.action !== 'pass' &&
        postDecision.action !== 'hold_mana' &&
        postDecision.action !== 'attack_opponent') {
      AIBridge.MacroActionMapper.execute(
        postDecision.action, playerIdx, gameState, postDecision
      );
      await _mlDelay(turnDelay * 0.5);
    }

    // ── PHASE 5: End turn ────────────────────────────────
    addLogEntry('\u{1F9E0} <strong>' + player.name + '</strong> ends their turn [ML]');
    aiTurnActive = false;
    renderPlayerPanels();
    renderHandArea();
    nextTurn();
    return true;

  } catch (err) {
    console.error('[_runMlAiTurn] Error:', err);
    aiTurnActive = false;
    return false;
  }
}

function _mlDelay(ms) {
  return new Promise(function(resolve) { setTimeout(resolve, ms); });
}

function _runLocalAiTurn() {
  if (!gameState) return;
  var playerIdx = gameState.currentPlayerIndex;
  var player = gameState.players[playerIdx];
  if (!player || !player.isAI) return;

  aiTurnActive = true;
  player.aiLandPlayedThisTurn = false;
  var difficulty = gameState.aiDifficulty || 'easy';

  addLogEntry('\u{1F916} <strong>' + player.name + '</strong> is thinking...');
  aiAddThought(playerIdx, difficulty.charAt(0).toUpperCase() + difficulty.slice(1) + ' mode \u2014 evaluating options...');

  // Log threat assessment for Normal/Hard
  if (difficulty !== 'easy') {
    var threatReport = aiEvaluatePlayerThreats(playerIdx);
    if (threatReport.length > 0) {
      var topThreat = threatReport[0];
      var threatSummary = 'Threat assessment: ' + threatReport.map(function(t) {
        return t.name + ' (' + Math.round(t.threatScore) + ')';
      }).join(' > ');
      aiAddThought(playerIdx, threatSummary);
    }

    // Forge-inspired board analysis
    if (typeof AIBoardAnalyzer !== 'undefined') {
      var boardScore = AIBoardAnalyzer.evaluateBoardState(playerIdx);
      var archInfo = AIBoardAnalyzer.detectArchetype(playerIdx);
      aiAddThought(playerIdx, 'Board eval: ' + boardScore + ' | Archetype: ' + archInfo.archetype + ' (' + archInfo.confidence + '% conf)');

      // Log active synergies
      var synergies = archInfo.synergies || [];
      if (synergies.length > 0) {
        aiAddThought(playerIdx, 'Synergies: ' + synergies.map(function(s) { return s.description; }).join(', '));
      }

      // Strategic advice for hard mode
      if (difficulty === 'hard') {
        var advice = AIBoardAnalyzer.getStrategicAdvice(playerIdx);
        var highPriority = advice.filter(function(a) { return a.priority === 'high'; });
        if (highPriority.length > 0) {
          aiAddThought(playerIdx, 'Strategy: ' + highPriority[0].text);
        }
      }
    }
  }

  var actions = []; // queue of { delay, fn }
  var delay = 600;

  // ========================================
  // MAIN PHASE 1: Play a land via playCardFromHand()
  // ========================================
  var landInHand = player.zones.hand.findIndex(function(c) { return aiIsLand(c); });
  if (landInHand !== -1) {
    actions.push({ delay: delay, fn: function() {
      // Ensure card has imageUrl for battlefield rendering
      var landCard = player.zones.hand[landInHand];
      if (landCard && !landCard.imageUrl) landCard.imageUrl = generateAiCardSVG(landCard);
      // Use playCardFromHand to integrate with mana system, triggers, land-drop tracking
      playCardFromHand(playerIdx, landInHand);
      addLogEntry('\u{1F916} <strong>' + player.name + '</strong> played a land');
    }});
    delay += 800;
  }

  // ========================================
  // MAIN PHASE 1: Try to cast commander from command zone
  // ========================================
  var cmdZone = player.zones.command || [];
  if (cmdZone.length > 0) {
    actions.push({ delay: delay, fn: function() {
      var result = aiTryCastCommander(playerIdx);
      if (result) {
        var tax = getCommanderTax(playerIdx);
        aiAddThought(playerIdx, 'Cast commander! (tax: ' + (tax > 0 ? '+' + (tax - 2) : '0') + ')');
      } else {
        var needed = (cmdZone[0] ? cmdZone[0].cmc || 0 : 0) + getCommanderTax(playerIdx);
        var have = aiCountUntappedLands(playerIdx);
        if (have < needed) {
          aiAddThought(playerIdx, 'Need ' + needed + ' mana for commander, have ' + have);
        }
      }
    }});
    delay += 800;
  }

  // ========================================
  // MAIN PHASE 1: Tap mana dorks for extra mana (before casting)
  // ========================================
  actions.push({ delay: delay, fn: function() {
    aiTapManaDorks(playerIdx);
  }});
  delay += 400;

  // ========================================
  // MAIN PHASE 1: Cast spells from hand using playCardFromHand()
  // Uses smart sequencing: ramp > threats > hold removal for post-combat
  // ========================================
  var playSequence = aiBuildPlaySequence(playerIdx, difficulty);
  var phase1Cards = playSequence.mainPhase1;
  var heldCards = playSequence.holdForPostCombat;

  // Also check board threats for emergency overrides
  var boardThreats = aiEvaluateBoardThreats(playerIdx);
  var biggestThreat = boardThreats.length > 0 ? boardThreats[0] : null;

  // If there's a massive threat, override and play removal in Main Phase 1
  if (biggestThreat && biggestThreat.score >= 10 && difficulty === 'hard') {
    // Move removal from held back to phase1
    phase1Cards = phase1Cards.concat(heldCards.filter(function(e) { return e.card.isRemoval || e.card.isBoardWipe; }));
    heldCards = heldCards.filter(function(e) { return !e.card.isRemoval && !e.card.isBoardWipe; });
    aiAddThought(playerIdx, 'Critical threat detected - using removal now!');
  }

  // Boost board wipe scores if significantly behind
  if (aiShouldBoardWipe(playerIdx)) {
    phase1Cards.forEach(function(e) { if (e.card.isBoardWipe) e.score += 30; });
    phase1Cards.sort(function(a, b) { return b.score - a.score; });
  }

  // Decide how many spells to play based on difficulty
  var maxSpells = difficulty === 'easy' ? 1 : difficulty === 'normal' ? 3 : 5;
  var spellsQueued = 0;

  for (var si = 0; si < phase1Cards.length; si++) {
    if (spellsQueued >= maxSpells) break;
    var entry = phase1Cards[si];
    var cardRef = entry.card;
    var cmc = aiGetCmc(cardRef);

    (function(theCardRef, theCmc) {
      actions.push({ delay: delay, fn: function() {
        // Re-find card in hand at action time (indices shift as cards are played)
        var ci = player.zones.hand.indexOf(theCardRef);
        if (ci === -1) return;
        var available = aiCountUntappedLands(playerIdx);
        if (available < theCmc) return;

        // Ensure card has imageUrl and manaCost for rendering and mana payment
        if (!theCardRef.imageUrl) theCardRef.imageUrl = generateAiCardSVG(theCardRef);

        // Use playCardFromHand() which integrates with:
        // - attemptManaPay() (auto-tap + mana spend)
        // - Stack system (if useStack is enabled)
        // - Triggers and battlefield placement
        playCardFromHand(playerIdx, ci);
        addLogEntry('\u{1F916} <strong>' + player.name + '</strong> cast <strong>' + theCardRef.name + '</strong>');
        aiAddThought(playerIdx, 'Casting ' + theCardRef.name + (theCardRef.isRemoval ? ' (removal!)' : theCardRef.isBoardWipe ? ' (board wipe!)' : ''));
      }});
    })(cardRef, cmc);

    delay += 1000;
    spellsQueued++;
  }

  // ========================================
  // MAIN PHASE 1: Equip equipment to creatures
  // ========================================
  if (difficulty !== 'easy') {
    actions.push({ delay: delay, fn: function() {
      aiEquipCreatures(playerIdx);
    }});
    delay += 600;
  }

  // ========================================
  // COMBAT PHASE: Smart attack decisions with multi-target
  // ========================================
  var shouldAttack = difficulty === 'easy' ? Math.random() > 0.3 : true;
  if (shouldAttack) {
    actions.push({ delay: delay, fn: function() {
      var creatures = aiGetUntappedCreatures(playerIdx).filter(function(c) {
        return !hasSummoningSickness(c);
      });
      if (creatures.length === 0) {
        aiAddThought(playerIdx, 'No creatures ready to attack');
        return;
      }

      // Smart attacker selection based on difficulty
      var attackerCards = [];

      if (difficulty === 'easy') {
        // Easy: random subset
        attackerCards = creatures.filter(function() { return Math.random() > 0.5; });
        if (attackerCards.length === 0 && creatures.length > 0) attackerCards = [creatures[0]];
      } else {
        // For evaluation, pick a primary target first
        var primaryTarget = aiPickAttackTarget(playerIdx);
        if (primaryTarget === -1) return;

        // Normal/Hard: evaluate each attack
        creatures.forEach(function(c) {
          var eval_ = aiEvaluateAttack(c, primaryTarget);
          if (difficulty === 'normal') {
            if (eval_.shouldAttack || eval_.risk === 'trade') attackerCards.push(c);
          } else {
            if (eval_.shouldAttack) attackerCards.push(c);
            else if (creatures.length >= 4 && eval_.risk === 'bad-trade') attackerCards.push(c);
          }
        });

        // Hard mode: hold back 1-2 creatures as blockers
        if (difficulty === 'hard' && attackerCards.length > 2) {
          var sortedByToughness = attackerCards.slice().sort(function(a, b) {
            return getCreatureToughness(b) - getCreatureToughness(a);
          });
          var holdBack = sortedByToughness.find(function(c) {
            return !hasKeyword(c, 'vigilance') && getCreatureToughness(c) >= 3;
          });
          if (holdBack) {
            attackerCards = attackerCards.filter(function(c) { return c.id !== holdBack.id; });
            aiAddThought(playerIdx, 'Holding back ' + holdBack.name + ' to block');
          }
        }
      }

      if (attackerCards.length === 0) {
        aiAddThought(playerIdx, 'No favorable attacks available');
        return;
      }

      // Use multi-target attack allocation in multiplayer
      var assignments = aiPickMultiTargetAttacks(playerIdx, attackerCards, difficulty);
      if (assignments.length === 0) return;

      // Set up combat state with potentially multiple targets
      gameState.combat.attackers = assignments.map(function(a) {
        return { cardId: a.card.id, targetPlayerId: a.targetIdx };
      });

      // Tap attackers (unless vigilance)
      attackerCards.forEach(function(c) {
        if (!hasKeyword(c, 'vigilance')) {
          c.tapped = true;
          var el = document.getElementById('bc-' + c.id);
          if (el) el.classList.add('tapped');
        }
        var el2 = document.getElementById('bc-' + c.id);
        if (el2) el2.classList.add('attacking');
      });

      // Log attacks grouped by target
      var targetGroups = {};
      assignments.forEach(function(a) {
        if (!targetGroups[a.targetIdx]) targetGroups[a.targetIdx] = [];
        targetGroups[a.targetIdx].push(a.card.name);
      });
      var targetCount = Object.keys(targetGroups).length;
      for (var tIdx in targetGroups) {
        var targetName = gameState.players[tIdx] ? gameState.players[tIdx].name : '?';
        var names = targetGroups[tIdx].join(', ');
        addLogEntry('\u{1F916} \u2694 <strong>' + player.name + '</strong> attacks <strong>' + targetName + '</strong> with: ' + names);
      }
      if (targetCount > 1) {
        aiAddThought(playerIdx, 'Splitting attacks across ' + targetCount + ' opponents');
      } else {
        aiAddThought(playerIdx, 'Attacking with ' + attackerCards.length + ' creature' + (attackerCards.length > 1 ? 's' : ''));
      }
      fireBattlefieldTriggers('attack');
    }});
    delay += 800;

    // Let any AI defenders assign blockers, then check for human defenders
    actions.push({ delay: delay, fn: function() {
      if (gameState.combat.attackers.length === 0) return;

      // AI defenders assign blockers first
      aiAssignBlockers();

      // Check if any human player is being attacked
      var defenderSet = {};
      gameState.combat.attackers.forEach(function(a) { defenderSet[a.targetPlayerId] = true; });
      var humanDefended = false;
      for (var dIdx in defenderSet) {
        var def = gameState.players[dIdx];
        if (def && !def.isAI && !def.eliminated) { humanDefended = true; break; }
      }

      if (humanDefended) {
        // PAUSE: Show blocker UI for human player, store resume callback
        gameState.combat.phase = 'declaring-blockers';
        gameState.combat.pendingBlockerFor = null;
        showCombatOverlay();
        refreshCombatOverlay();
        addLogEntry('\u{1F6E1} Declare your blockers!');

        // Store the resume function — confirmBlockers will call it
        _aiBlockerPauseState = {
          playerIdx: playerIdx,
          resumeFn: function() {
            _aiBlockerPauseState = null;
            // Continue with damage resolution
            if (gameState.combat.attackers.length > 0) {
              resolveCombatDamage();
              setTimeout(function() {
                endCombat();
                renderPlayerPanels();
                // Continue with Main Phase 2 and End Turn
                _aiRunPostCombat(playerIdx, player, difficulty, heldCards);
              }, 600);
            } else {
              _aiRunPostCombat(playerIdx, player, difficulty, heldCards);
            }
          }
        };
        // STOP the action queue here — remaining actions are handled by resumeFn
        return '__PAUSE_AI_TURN__';
      }
    }});
    delay += 600;

    // Resolve combat damage (only runs if not paused for human blockers)
    actions.push({ delay: delay, fn: function() {
      if (_aiBlockerPauseState) return; // Skip — human blocker flow handles this
      if (gameState.combat.attackers.length > 0) {
        resolveCombatDamage();
        setTimeout(function() {
          endCombat();
          renderPlayerPanels();
        }, 600);
      }
    }});
    delay += 1000;
  }

  // ========================================
  // MAIN PHASE 2: Post-combat spell casting (normal & hard)
  // Hard: play held-back removal + instants + any remaining affordable spells
  // Normal: try to play any remaining affordable spells
  // BLUFFING: On Normal/Hard, hold back mana if we have instant-speed answers
  // ========================================
  if (difficulty !== 'easy') {
    actions.push({ delay: delay, fn: function() {
      if (_aiBlockerPauseState) return; // Skip — human blocker flow handles this
      var bluffReserve = 0;
      var bluffCardName = '';
      if (difficulty === 'hard' || difficulty === 'normal') {
        // Check for instant-speed cards in hand we want to bluff with
        var instantsInHand = player.zones.hand.filter(function(c) {
          var tl = (c.typeLine || '').toLowerCase();
          return tl.indexOf('instant') !== -1;
        });
        // Also check for cards with flash
        var flashCards = player.zones.hand.filter(function(c) {
          var text = (c.oracleText || '').toLowerCase();
          return text.indexOf('flash') !== -1;
        });
        var bluffCandidates = instantsInHand.concat(flashCards);
        if (bluffCandidates.length > 0) {
          // Pick the cheapest instant to bluff with
          var cheapestInstant = bluffCandidates.reduce(function(best, c) {
            var cmc = aiGetCmc(c);
            return cmc < aiGetCmc(best) ? c : best;
          }, bluffCandidates[0]);
          bluffReserve = aiGetCmc(cheapestInstant);
          bluffCardName = cheapestInstant.name;
          // Hard mode: always bluff if possible. Normal: 50% chance
          if (difficulty === 'normal' && Math.random() > 0.5) {
            bluffReserve = 0;
          }
        }
        // Even without instants in hand, hard mode sometimes bluffs with 2 open mana
        if (bluffReserve === 0 && difficulty === 'hard' && Math.random() > 0.6) {
          bluffReserve = 2;
          bluffCardName = ''; // Pure bluff, no actual card
        }
      }

      // First: play held-back cards (hard mode sequencing)
      if (heldCards && heldCards.length > 0) {
        var heldPlayed = 0;
        for (var hi = 0; hi < heldCards.length && heldPlayed < 3; hi++) {
          var he = heldCards[hi];
          // Don't play the card we're bluffing with
          if (bluffReserve > 0 && he.card.name === bluffCardName) continue;
          var hci = player.zones.hand.indexOf(he.card);
          if (hci === -1) continue;
          var havailable = aiCountUntappedLands(playerIdx);
          var hcmc = aiGetCmc(he.card);
          // Reserve mana for bluff
          if (havailable - hcmc < bluffReserve) continue;
          if (havailable < hcmc) continue;
          if (!he.card.imageUrl) he.card.imageUrl = generateAiCardSVG(he.card);
          playCardFromHand(playerIdx, hci);
          addLogEntry('\u{1F916} <strong>' + player.name + '</strong> cast <strong>' + he.card.name + '</strong> (post-combat)');
          if (he.card.isRemoval) {
            aiAddThought(playerIdx, 'Using held removal: ' + he.card.name);
          }
          heldPlayed++;
        }
      }

      // Then: play any remaining affordable spells from hand (respecting bluff reserve)
      var remainingHand = player.zones.hand
        .map(function(c, i) { return { card: c, index: i, score: (typeof aiScoreCardEnhanced === 'function' ? aiScoreCardEnhanced(c, difficulty) : aiScoreCard(c, difficulty)) }; })
        .filter(function(e) { return !aiIsLand(e.card); })
        .sort(function(a, b) { return b.score - a.score; });

      for (var ri = 0; ri < remainingHand.length && ri < 2; ri++) {
        var re = remainingHand[ri];
        // Don't play bluff card
        if (bluffReserve > 0 && re.card.name === bluffCardName) continue;
        var ci = player.zones.hand.indexOf(re.card);
        if (ci === -1) continue;
        var available = aiCountUntappedLands(playerIdx);
        var cardCmc = aiGetCmc(re.card);
        // Reserve mana for bluff
        if (available - cardCmc < bluffReserve) continue;
        if (available < cardCmc) continue;
        if (!re.card.imageUrl) re.card.imageUrl = generateAiCardSVG(re.card);
        playCardFromHand(playerIdx, ci);
        addLogEntry('\u{1F916} <strong>' + player.name + '</strong> cast <strong>' + re.card.name + '</strong> (post-combat)');
      }

      // Log bluff status
      if (bluffReserve > 0) {
        var untappedAfter = aiCountUntappedLands(playerIdx);
        if (untappedAfter >= bluffReserve) {
          if (bluffCardName) {
            aiAddThought(playerIdx, 'Holding ' + untappedAfter + ' mana open (has ' + bluffCardName + ')');
          } else {
            aiAddThought(playerIdx, 'Holding ' + untappedAfter + ' mana open (bluffing)');
          }
          addLogEntry('\u{1F916} <strong>' + player.name + '</strong> passes with ' + untappedAfter + ' mana open...');
        }
      }
    }});
    delay += 800;
  }

  // ========================================
  // END TURN
  // ========================================
  actions.push({ delay: delay, fn: function() {
    if (_aiBlockerPauseState) return; // Skip — human blocker flow handles this
    addLogEntry('\u{1F916} <strong>' + player.name + '</strong> passes the turn');
    aiTurnActive = false;
    nextTurn();
  }});

  // Execute queued actions with delays (wrapped in try/catch so aiTurnActive resets on error)
  actions.forEach(function(action) {
    setTimeout(function() {
      try { action.fn(); } catch(e) { console.error('[AI Turn Error]', e); }
    }, action.delay);
  });

  // Safety timeout: if aiTurnActive is still true after all actions should be done, force-reset it
  var safetyDelay = delay + 5000;
  setTimeout(function() {
    if (aiTurnActive && !_aiBlockerPauseState) {
      console.warn('[AI] Safety timeout - resetting aiTurnActive');
      aiTurnActive = false;
    }
  }, safetyDelay);
}

// ============================================================
// ============================================================
// CARD ABILITIES & RULES TEXT PARSING ENGINE
// ============================================================

/**
 * Parse all abilities from a card's oracle text.
 * Returns a structured object with keyword, activated, triggered, static, and mana abilities.
 */
function parseCardAbilities(oracleText, typeLine, cardName) {
  if (!oracleText && !typeLine) return { keywords: [], activated: [], triggered: [], static: [], mana: [], loyalty: [], replacement: [] };
  const text = oracleText || '';
  const type = (typeLine || '').toLowerCase();
  const result = {
    keywords: [],
    activated: [],
    triggered: [],
    static: [],
    mana: [],
    loyalty: [],
    replacement: [],
  };

  // --- 1. KEYWORD ABILITIES ---
  const textLower = text.toLowerCase();
  for (const [keyword, data] of Object.entries(KEYWORD_ABILITIES)) {
    const kw = keyword.toLowerCase();
    // Match keyword as standalone word or at start of a sentence
    const re = new RegExp(`(?:^|[,;.\\n\\s])${kw.replace(/[.*+?^${}()|[\]\\]/g, '\\$&')}(?:\\b|\\s|,|\\.|$)`, 'i');
    if (re.test(textLower) || re.test(',' + textLower)) {
      result.keywords.push({
        name: keyword,
        icon: data.icon,
        color: data.color,
        description: data.desc,
      });
    }
  }

  // --- 2. ACTIVATED ABILITIES ---
  // Pattern: "[cost]: [effect]" where cost contains mana symbols or {T}
  const lines = text.split('\n');
  for (const line of lines) {
    // Activated abilities have a colon separating cost from effect
    // Match patterns like "{2}{B}, {T}: Do something" or "{T}: Add {G}"
    const activatedMatch = line.match(/^([^:"]+(?:\{[^}]+\})[^:]*?):\s*(.+)$/i);
    if (activatedMatch) {
      const costPart = activatedMatch[1].trim();
      const effectPart = activatedMatch[2].trim();
      // Verify it has a mana symbol or tap symbol in cost
      if (/\{[WUBRGCTX0-9]+\}/.test(costPart) || /sacrifice|discard|pay|exile|remove|tap an untapped/i.test(costPart)) {
        // Check if it's a mana ability (produces mana)
        if (/add \{[WUBRGC]\}/i.test(effectPart) || /add one mana/i.test(effectPart)) {
          result.mana.push({
            cost: costPart,
            effect: effectPart,
            type: 'mana',
          });
        } else {
          result.activated.push({
            cost: costPart,
            effect: effectPart,
            type: 'activated',
          });
        }
      }
    }
  }

  // --- 3. TRIGGERED ABILITIES ---
  const triggerPatterns = [
    { re: /\b(when(?:ever)?\s+(?:this|~|[^,]+?)\s+enters(?:\s+the\s+battlefield)?)/gi, sub: 'etb' },
    { re: /\b(when(?:ever)?\s+(?:this|~|[^,]+?)\s+leaves\s+the\s+battlefield)/gi, sub: 'ltb' },
    { re: /\b(when(?:ever)?\s+(?:this|~|[^,]+?)\s+dies)/gi, sub: 'dies' },
    { re: /\b(when(?:ever)?\s+(?:this|~|[^,]+?)\s+attacks)/gi, sub: 'attack' },
    { re: /\b(when(?:ever)?\s+(?:this|~|[^,]+?)\s+blocks)/gi, sub: 'block' },
    { re: /\b(when(?:ever)?\s+(?:this|~|[^,]+?)\s+becomes?\s+(?:the\s+)?target)/gi, sub: 'targeted' },
    { re: /\b(when(?:ever)?\s+(?:you|a player)\s+(?:cast|draw|discard|gain|lose|pay))/gi, sub: 'action' },
    { re: /\b(at the beginning of (?:your|each|the)\s+(?:upkeep|end step|draw step|combat|main phase|untap step))/gi, sub: 'upkeep' },
    { re: /\b(when(?:ever)?\s+(?:a|another|one or more)\s+(?:creature|permanent|artifact|enchantment|land|nontoken))/gi, sub: 'permanent' },
    { re: /\b(when(?:ever)?\s+(?:this|~|[^,]+?)\s+deals\s+(?:combat\s+)?damage)/gi, sub: 'damage' },
    { re: /\b(when(?:ever)?\s+(?:this|~|[^,]+?)\s+becomes\s+(?:tapped|untapped))/gi, sub: 'tap' },
  ];

  for (const { re, sub } of triggerPatterns) {
    let match;
    re.lastIndex = 0;
    while ((match = re.exec(text)) !== null) {
      // Grab the rest of the sentence for context
      const startIdx = match.index;
      let endIdx = text.indexOf('.', startIdx + match[0].length);
      if (endIdx === -1) endIdx = text.indexOf('\n', startIdx + match[0].length);
      if (endIdx === -1) endIdx = text.length;
      const fullAbilityText = text.substring(startIdx, endIdx + 1).trim();
      result.triggered.push({
        trigger: match[1].trim(),
        effect: fullAbilityText,
        subType: sub,
        type: 'triggered',
      });
    }
  }

  // --- 4. STATIC ABILITIES ---
  const staticPatterns = [
    { re: /\b(other\s+(?:creatures?|permanents?)\s+you\s+control\s+(?:get|have|gain)[^.]+)/gi, sub: 'anthem' },
    { re: /\b(creatures?\s+you\s+control\s+(?:get|have|gain)[^.]+)/gi, sub: 'anthem' },
    { re: /\b((?:creatures?|spells?)\s+(?:you\s+cast\s+)?cost\s+\{?\d+\}?\s+(?:less|more))/gi, sub: 'cost-mod' },
    { re: /\b(you\s+(?:can't|cannot)\s+[^.]+)/gi, sub: 'restriction' },
    { re: /\b(players?\s+(?:can't|cannot)\s+[^.]+)/gi, sub: 'restriction' },
    { re: /\b((?:this|~|enchanted|equipped)\s+(?:creature|permanent)\s+(?:gets?|has|gains)\s+[^.]+)/gi, sub: 'buff' },
    { re: /\b((?:each|all)\s+(?:creatures?|opponents?|players?)\s+[^.]*(?:get|have|gain|lose|deal|take)[^.]+)/gi, sub: 'global' },
    { re: /\b((?:as long as|while)\s+[^,]+,\s+[^.]+)/gi, sub: 'conditional' },
  ];

  for (const { re, sub } of staticPatterns) {
    let match;
    re.lastIndex = 0;
    while ((match = re.exec(text)) !== null) {
      result.static.push({
        text: match[1].trim(),
        subType: sub,
        type: 'static',
      });
    }
  }

  // --- 5. LOYALTY ABILITIES (Planeswalkers) ---
  if (type.includes('planeswalker')) {
    const loyaltyRe = /([+\-\u2212]\d+|0):\s*([^\n]+)/g;
    let lm;
    while ((lm = loyaltyRe.exec(text)) !== null) {
      result.loyalty.push({
        cost: lm[1].replace('\u2212', '-'),
        effect: lm[2].trim(),
        type: 'loyalty',
      });
    }
  }

  // --- 6. REPLACEMENT EFFECTS ---
  const replacementPatterns = [
    /\b(if .+ would .+, .+ instead[^.]*)/gi,
    /\b(as .+ enters the battlefield[^.]*)/gi,
    /\b(.+ enters the battlefield (?:tapped|with)[^.]*)/gi,
  ];
  for (const re of replacementPatterns) {
    let match;
    re.lastIndex = 0;
    while ((match = re.exec(text)) !== null) {
      result.replacement.push({
        text: match[1].trim(),
        type: 'replacement',
      });
    }
  }

  return result;
}

/**
 * Get a compact badge set for battlefield card display.
 * Returns max 4 most important keyword icons.
 */
function getKeywordBadges(cardData) {
  if (!cardData || !cardData.oracleText) return [];
  const abilities = parseCardAbilities(cardData.oracleText, cardData.typeLine, cardData.name);
  // Priority order for display (combat-relevant first)
  const priorityOrder = [
    'flying', 'deathtouch', 'lifelink', 'first strike', 'double strike',
    'trample', 'haste', 'vigilance', 'menace', 'hexproof', 'indestructible',
    'reach', 'flash', 'infect', 'toxic', 'ward', 'defender', 'shroud',
    'prowess', 'annihilator', 'cascade', 'undying', 'persist',
  ];
  const badges = [];
  for (const kw of priorityOrder) {
    const found = abilities.keywords.find(k => k.name === kw);
    if (found) badges.push(found);
    if (badges.length >= 4) break;
  }
  // If less than 4, add remaining keywords not in priority list
  if (badges.length < 4) {
    for (const kw of abilities.keywords) {
      if (!badges.find(b => b.name === kw.name)) {
        badges.push(kw);
        if (badges.length >= 4) break;
      }
    }
  }
  return badges;
}

/**
 * Convert mana symbols in text to styled HTML spans.
 */
function formatManaSymbols(text) {
  if (!text) return '';
  return text.replace(/\{([^}]+)\}/g, (match) => {
    const sym = MANA_DISPLAY_MAP[match];
    if (sym) {
      return `<span class="mana-sym" style="background:${sym.bg};color:${sym.color}">${sym.text}</span>`;
    }
    return `<span class="mana-sym mana-generic">${match.replace(/[{}]/g, '')}</span>`;
  });
}

/**
 * Format oracle text with mana symbols, line breaks, and ability highlighting.
 */
function formatOracleText(text) {
  if (!text) return '<em class="no-abilities">Vanilla (no abilities)</em>';
  const escaped = text.replace(/</g, '&lt;').replace(/>/g, '&gt;');
  let formatted = formatManaSymbols(escaped);
  // Add line breaks
  formatted = formatted.replace(/\n/g, '<br>');
  // Highlight keyword abilities in bold
  for (const kw of Object.keys(KEYWORD_ABILITIES)) {
    const re = new RegExp(`\\b(${kw.replace(/[.*+?^${}()|[\]\\]/g, '\\$&')})\\b`, 'gi');
    formatted = formatted.replace(re, '<strong class="kw-highlight">$1</strong>');
  }
  return formatted;
}

/**
 * Build the full abilities detail panel HTML for a card.
 */
function buildAbilitiesPanel(cardData) {
  const abilities = parseCardAbilities(cardData.oracleText || '', cardData.typeLine || '', cardData.name || '');
  const sections = [];

  // Card identity header
  const isCreature = (cardData.typeLine || '').toLowerCase().includes('creature');
  const pt = cardData.pt || (cardData.extraData && cardData.extraData.pt) || '';
  let headerInfo = `<div class="ap-header">`;
  headerInfo += `<div class="ap-name">${cardData.name || 'Unknown Card'}</div>`;
  headerInfo += `<div class="ap-type">${cardData.typeLine || 'Unknown Type'}</div>`;
  if (isCreature && pt) headerInfo += `<div class="ap-pt">${pt}</div>`;
  headerInfo += `</div>`;
  sections.push(headerInfo);

  // Oracle text with formatted mana symbols
  sections.push(`<div class="ap-section"><div class="ap-section-label">Rules Text</div><div class="ap-oracle">${formatOracleText(cardData.oracleText)}</div></div>`);

  // Keywords
  if (abilities.keywords.length > 0) {
    let kwHtml = '<div class="ap-section"><div class="ap-section-label">Keyword Abilities</div><div class="ap-keywords">';
    for (const kw of abilities.keywords) {
      kwHtml += `<div class="ap-keyword-item" title="${kw.description}"><span class="ap-kw-icon" style="color:${kw.color}">${kw.icon}</span><span class="ap-kw-name">${kw.name}</span>`;
      if (kw.description) kwHtml += `<span class="ap-kw-desc">${kw.description}</span>`;
      kwHtml += `</div>`;
    }
    kwHtml += '</div></div>';
    sections.push(kwHtml);
  }

  // Activated abilities
  if (abilities.activated.length > 0) {
    let actHtml = '<div class="ap-section"><div class="ap-section-label">Activated Abilities</div>';
    for (const ab of abilities.activated) {
      actHtml += `<div class="ap-ability-item ap-activated"><span class="ap-cost">${formatManaSymbols(ab.cost)}</span><span class="ap-colon">:</span><span class="ap-effect">${formatManaSymbols(ab.effect)}</span></div>`;
    }
    actHtml += '</div>';
    sections.push(actHtml);
  }

  // Mana abilities
  if (abilities.mana.length > 0) {
    let manaHtml = '<div class="ap-section"><div class="ap-section-label">Mana Abilities</div>';
    for (const ab of abilities.mana) {
      manaHtml += `<div class="ap-ability-item ap-mana"><span class="ap-cost">${formatManaSymbols(ab.cost)}</span><span class="ap-colon">:</span><span class="ap-effect">${formatManaSymbols(ab.effect)}</span></div>`;
    }
    manaHtml += '</div>';
    sections.push(manaHtml);
  }

  // Triggered abilities
  if (abilities.triggered.length > 0) {
    let trigHtml = '<div class="ap-section"><div class="ap-section-label">Triggered Abilities</div>';
    for (const ab of abilities.triggered) {
      const subLabel = ab.subType === 'etb' ? 'ETB' : ab.subType === 'ltb' ? 'LTB' : ab.subType === 'dies' ? 'Dies' : ab.subType === 'attack' ? 'Attack' : ab.subType === 'block' ? 'Block' : ab.subType === 'upkeep' ? 'Upkeep' : ab.subType === 'damage' ? 'Damage' : ab.subType === 'action' ? 'Action' : ab.subType === 'targeted' ? 'Target' : 'Trigger';
      trigHtml += `<div class="ap-ability-item ap-triggered"><span class="ap-trigger-badge">${subLabel}</span><span class="ap-effect">${formatManaSymbols(ab.effect)}</span></div>`;
    }
    trigHtml += '</div>';
    sections.push(trigHtml);
  }

  // Static abilities
  if (abilities.static.length > 0) {
    let statHtml = '<div class="ap-section"><div class="ap-section-label">Static Abilities</div>';
    for (const ab of abilities.static) {
      const subLabel = ab.subType === 'anthem' ? 'Anthem' : ab.subType === 'cost-mod' ? 'Cost' : ab.subType === 'restriction' ? 'Rule' : ab.subType === 'buff' ? 'Buff' : ab.subType === 'global' ? 'Global' : ab.subType === 'conditional' ? 'Cond.' : 'Static';
      statHtml += `<div class="ap-ability-item ap-static"><span class="ap-trigger-badge ap-static-badge">${subLabel}</span><span class="ap-effect">${formatManaSymbols(ab.text)}</span></div>`;
    }
    statHtml += '</div>';
    sections.push(statHtml);
  }

  // Loyalty abilities (planeswalkers)
  if (abilities.loyalty.length > 0) {
    let loyHtml = '<div class="ap-section"><div class="ap-section-label">Loyalty Abilities</div>';
    for (const ab of abilities.loyalty) {
      const isPlus = ab.cost.startsWith('+');
      const isZero = ab.cost === '0';
      const badgeClass = isPlus ? 'ap-loyalty-plus' : isZero ? 'ap-loyalty-zero' : 'ap-loyalty-minus';
      loyHtml += `<div class="ap-ability-item ap-loyalty"><span class="ap-loyalty-badge ${badgeClass}">${ab.cost}</span><span class="ap-effect">${formatManaSymbols(ab.effect)}</span></div>`;
    }
    loyHtml += '</div>';
    sections.push(loyHtml);
  }

  // Replacement effects
  if (abilities.replacement.length > 0) {
    let repHtml = '<div class="ap-section"><div class="ap-section-label">Replacement Effects</div>';
    for (const ab of abilities.replacement) {
      repHtml += `<div class="ap-ability-item ap-replacement"><span class="ap-effect">${formatManaSymbols(ab.text)}</span></div>`;
    }
    repHtml += '</div>';
    sections.push(repHtml);
  }

  return sections.join('');
}

/**
 * Show the abilities detail panel positioned near a battlefield card.
 */
function showAbilitiesPanel(cardData, anchorEl) {
  let panel = document.getElementById('abilities-panel');
  if (!panel) {
    panel = document.createElement('div');
    panel.id = 'abilities-panel';
    panel.className = 'abilities-panel';
    document.body.appendChild(panel);
  }
  panel.innerHTML = '<button class="abilities-panel-close" onclick="hideAbilitiesPanel()">&times;</button>' + buildAbilitiesPanel(cardData);
  panel.style.display = 'block';

  // Position near the card
  const rect = anchorEl.getBoundingClientRect();
  let x = rect.right + 12;
  let y = rect.top;
  // Keep within viewport
  if (x + 320 > window.innerWidth) x = rect.left - 332;
  if (y + 400 > window.innerHeight) y = Math.max(8, window.innerHeight - 408);
  if (x < 8) x = 8;
  if (y < 8) y = 8;
  panel.style.left = x + 'px';
  panel.style.top = y + 'px';

  // Dismiss on click outside
  setTimeout(function() {
    document.addEventListener('click', _abilitiesPanelOutsideClick);
  }, 0);
}

function _abilitiesPanelOutsideClick(e) {
  var panel = document.getElementById('abilities-panel');
  if (panel && !panel.contains(e.target)) {
    hideAbilitiesPanel();
  }
}

function hideAbilitiesPanel() {
  const panel = document.getElementById('abilities-panel');
  if (panel) panel.style.display = 'none';
  document.removeEventListener('click', _abilitiesPanelOutsideClick);
}

/**
 * Toggle the keyword reference panel.
 */
function toggleKeywordReference() {
  let panel = document.getElementById('keyword-reference-panel');
  if (!panel) {
    panel = document.createElement('div');
    panel.id = 'keyword-reference-panel';
    panel.className = 'keyword-ref-panel';
    document.body.appendChild(panel);
  }

  if (panel.style.display === 'block') {
    panel.style.display = 'none';
    return;
  }

  // Build keyword reference content
  let html = '<div class="kref-header"><h3>Keyword Reference</h3><input type="text" id="kref-search" placeholder="Search keywords..." class="kref-search"></div>';
  html += '<div class="kref-list" id="kref-list">';

  // Sort alphabetically
  const sortedKeywords = Object.entries(KEYWORD_ABILITIES).sort((a, b) => a[0].localeCompare(b[0]));
  for (const [name, data] of sortedKeywords) {
    if (!data.desc) continue; // Skip empty descriptions
    html += `<div class="kref-item" data-kw="${name}">`;
    html += `<span class="kref-icon" style="color:${data.color}">${data.icon}</span>`;
    html += `<span class="kref-name">${name.charAt(0).toUpperCase() + name.slice(1)}</span>`;
    html += `<span class="kref-desc">${data.desc}</span>`;
    html += `</div>`;
  }
  html += '</div>';

  panel.innerHTML = html;
  panel.style.display = 'block';

  // Search filter
  const searchInput = document.getElementById('kref-search');
  if (searchInput) {
    searchInput.addEventListener('input', (e) => {
      const q = e.target.value.toLowerCase();
      document.querySelectorAll('.kref-item').forEach(item => {
        const kw = item.dataset.kw || '';
        const desc = item.querySelector('.kref-desc')?.textContent || '';
        item.style.display = (kw.includes(q) || desc.toLowerCase().includes(q)) ? '' : 'none';
      });
    });
    searchInput.focus();
  }
}

// ============================================================
// COMBAT SYSTEM
// ============================================================

/**
 * Checks if a card's oracleText contains a given MTG keyword.
 * Case-insensitive, matches whole words.
 */
function hasKeyword(cardData, keyword) {
  if (!cardData) return false;
  var kw = keyword.toLowerCase();
  // Check temporary keywords from CardScript system
  if (cardData.tempKeywords && cardData.tempKeywords.length > 0) {
    for (var i = 0; i < cardData.tempKeywords.length; i++) {
      if (cardData.tempKeywords[i].toLowerCase() === kw) return true;
    }
  }
  if (!cardData.oracleText) return false;
  const text = cardData.oracleText.toLowerCase();
  // Match keyword as a standalone word (not substring of another word)
  const re = new RegExp(`\\b${kw.replace(/[.*+?^${}()|[\]\\]/g, '\\$&')}\\b`);
  return re.test(text);
}

/** Parse power as integer from a pt string like "3/4" */
function getCreaturePower(cardData) {
  if (!cardData) return 1;
  // Use getEffectivePT for full calculation including counters, equipment, anthems
  var ept = getEffectivePT(cardData);
  if (ept) return Math.max(0, ept.power);
  // Fallback if getEffectivePT returns null
  var base = 0;
  if (cardData.pt) {
    var parts = cardData.pt.split('/');
    var val = parseInt(parts[0], 10);
    if (!isNaN(val)) base = val;
  } else if (cardData.power !== undefined && cardData.power !== '') {
    var val2 = parseInt(cardData.power, 10);
    if (!isNaN(val2)) base = val2;
  }
  if (cardData.powerMod) base += cardData.powerMod;
  return Math.max(0, base);
}

/** Parse toughness as integer from a pt string like "3/4" */
function getCreatureToughness(cardData) {
  if (!cardData) return 1;
  // Use getEffectivePT for full calculation including counters, equipment, anthems
  var ept = getEffectivePT(cardData);
  if (ept) {
    // If modifiers reduced toughness below base, allow 0 or negative (for SBA)
    // But if no modifiers at all, floor at 1 to avoid false positives from bad data
    if (ept.bonusTough < 0) {
      return ept.toughness; // Allow negative — SBA should catch this
    }
    return Math.max(1, ept.toughness);
  }
  // Fallback if getEffectivePT returns null
  var base = 1;
  if (cardData.pt) {
    var parts = cardData.pt.split('/');
    var val = parseInt(parts[1], 10);
    if (!isNaN(val)) base = val;
  } else if (cardData.toughness !== undefined && cardData.toughness !== '') {
    var val2 = parseInt(cardData.toughness, 10);
    if (!isNaN(val2)) base = val2;
  }
  if (cardData.toughnessMod) base += cardData.toughnessMod;
  return Math.max(1, base);
}

/**
 * Summoning sickness: creature that entered this turn cannot attack
 * unless it has haste. Only applies to creatures.
 */
function hasSummoningSickness(cardData) {
  if (!cardData || !cardData.typeLine) return false;
  if (!cardData.typeLine.toLowerCase().includes('creature')) return false;
  if (!gameState) return false;
  const currentKey = `${gameState.turnNumber}_${gameState.currentPlayerIndex}`;
  if (cardData.turnPlayed !== currentKey) return false;
  return !hasKeyword(cardData, 'haste');
}

// ---- Combat Overlay UI ----

function showCombatOverlay() {
  const overlay = document.getElementById('combat-overlay');
  if (overlay) overlay.style.display = 'flex';
}

function hideCombatOverlay() {
  const overlay = document.getElementById('combat-overlay');
  if (overlay) overlay.style.display = 'none';
}

/**
 * Refresh the combat overlay display with current state.
 */
function refreshCombatOverlay() {
  if (!gameState) return;
  const combat = gameState.combat;
  const phase = combat.phase;

  const phaseLabel = document.getElementById('combat-phase-label');
  const instructions = document.getElementById('combat-instructions');
  const attackersList = document.getElementById('combat-attackers-list');
  const targetSelector = document.getElementById('combat-target-selector');
  const blockersSection = document.getElementById('combat-blockers-section');
  const blockingPairs = document.getElementById('combat-blocking-pairs');
  const dmgPreview = document.getElementById('combat-damage-preview');
  const confirmBtn = document.getElementById('combat-confirm');
  const skipBtn = document.getElementById('combat-skip');

  if (!phaseLabel) return;

  if (phase === 'declaring-attackers') {
    phaseLabel.textContent = '⚔ Declare Attackers';
    instructions.textContent = 'Click your untapped creatures to declare them as attackers. Creatures with summoning sickness cannot attack.';
    blockersSection.style.display = 'none';
    dmgPreview.style.display = 'none';
    confirmBtn.textContent = '✓ Confirm Attackers';

    // Build attackers list
    if (combat.attackers.length === 0) {
      attackersList.innerHTML = '<span class="combat-list-empty">No attackers declared yet.</span>';
      targetSelector.innerHTML = '';
    } else {
      // Each attacker gets a target selector for multiplayer
      attackersList.innerHTML = combat.attackers.map(a => {
        const card = gameState.battlefieldCards.find(c => c.id === a.cardId);
        const cardName = card ? card.name : `Card #${a.cardId}`;
        const targetName = gameState.players[a.targetPlayerId]?.name || '?';
        const pt = card ? (card.pt || '?/?' ) : '?/?';
        return `<div class="combat-attacker-item" data-card-id="${a.cardId}">
          <span class="combat-attacker-icon">⚔</span>
          <span class="combat-attacker-name">${cardName}</span>
          <span class="combat-attacker-pt">${pt}</span>
          <span class="combat-arrow">→</span>
          <select class="combat-target-select" onchange="setCombatAttackerTargetFromSelect(${a.cardId}, this.value)">
            ${gameState.players.map((p, i) => {
              if (i === gameState.currentPlayerIndex || p.eliminated) return '';
              return `<option value="p_${i}" ${!a.targetPlaneswalkerCardId && i === a.targetPlayerId ? 'selected' : ''}>${p.name} (${p.life}❤)</option>`;
            }).join('')}
            ${getOpponentPlaneswalkers().map(pw => {
              const loyalty = pw.counters && pw.counters['loyalty'] != null ? pw.counters['loyalty'] : '?';
              return `<option value="pw_${pw.id}" ${a.targetPlaneswalkerCardId === pw.id ? 'selected' : ''}>${escapeHtml(pw.name)} [♦${loyalty}]</option>`;
            }).join('')}
          </select>
          <button class="combat-remove-attacker" onclick="toggleAttacker(${a.cardId})" title="Remove attacker">✕</button>
        </div>`;
      }).join('');
      targetSelector.innerHTML = '';
    }

  } else if (phase === 'declaring-blockers') {
    phaseLabel.textContent = '🛡 Declare Blockers';
    blockersSection.style.display = 'block';
    dmgPreview.style.display = 'none';
    confirmBtn.textContent = '✓ Confirm Blockers';
    if (skipBtn) skipBtn.textContent = _aiBlockerPauseState ? "\u23e9 No Blockers" : "\u23e9 Skip Combat";

    // Show all attackers and their current blockers
    const attackerGroups = {};
    combat.attackers.forEach(a => {
      if (!attackerGroups[a.cardId]) attackerGroups[a.cardId] = { attacker: a, blockers: [] };
    });
    combat.blockers.forEach(b => {
      if (attackerGroups[b.blockingCardId]) {
        attackerGroups[b.blockingCardId].blockers.push(b.cardId);
      }
    });

    const pendingId = combat.pendingBlockerFor;
    const groups = Object.values(attackerGroups);

    if (groups.length === 0) {
      attackersList.innerHTML = '<span class="combat-list-empty">No attackers — proceed to damage.</span>';
      blockingPairs.innerHTML = '';
      instructions.textContent = 'No creatures are attacking. Click Confirm to proceed.';
      targetSelector.innerHTML = '';
    } else {
      const defenders = new Set(combat.attackers.map(a => a.targetPlayerId));
      const humanDefenders = [...defenders].filter(pid => !gameState.players[pid].isAI);

      if (humanDefenders.length === 0) {
        instructions.textContent = 'No human players are being attacked. Click Confirm to proceed to damage.';
      } else {
        instructions.textContent = `Defending players: Click an attacking creature (to select target), then click your untapped creatures to assign as blockers.`;
      }

      // Summary of attackers
      attackersList.innerHTML = groups.map(group => {
        const atkCard = gameState.battlefieldCards.find(c => c.id === group.attacker.cardId);
        const atkName = atkCard ? atkCard.name : `Attacker #${group.attacker.cardId}`;
        const atkPt = atkCard ? (atkCard.pt || '?/?') : '?/?';
        const targetName = gameState.players[group.attacker.targetPlayerId]?.name || '?';
        const isPending = pendingId === group.attacker.cardId;
        const blockerNames = group.blockers.map(bid => {
          const bc = gameState.battlefieldCards.find(c => c.id === bid);
          return bc ? bc.name : `#${bid}`;
        }).join(', ');
        return `<div class="combat-attacker-item ${isPending ? 'combat-pending-target' : ''}" onclick="selectPendingBlockerTarget(${group.attacker.cardId})" style="cursor:pointer">
          <span class="combat-attacker-icon">⚔</span>
          <span class="combat-attacker-name">${atkName}</span>
          <span class="combat-attacker-pt">${atkPt}</span>
          <span class="combat-arrow">→ ${targetName}</span>
          ${blockerNames ? `<span class="combat-blocker-list">🛡 ${blockerNames}</span>` : '<span class="combat-blocker-list unblocked">Unblocked</span>'}
        </div>`;
      }).join('');

      // Pending blocker selection hint
      if (pendingId !== null) {
        const atkCard = gameState.battlefieldCards.find(c => c.id === pendingId);
        blockingPairs.innerHTML = `<div class="combat-blocker-hint">Now click one of your untapped creatures on the battlefield to block <strong>${atkCard ? atkCard.name : 'attacker'}</strong>. Click the attacker again to deselect.</div>`;
      } else {
        blockingPairs.innerHTML = `<div class="combat-blocker-hint">Click an attacking creature above to select it as the target for blocking.</div>`;
      }
      targetSelector.innerHTML = '';
    }
  }
  // Update SVG combat arrows
  updateCombatArrows();
}

/** Set a specific target player for an attacker */
function setCombatAttackerTarget(cardId, targetPlayerId) {
  if (!gameState) return;
  const atk = gameState.combat.attackers.find(a => a.cardId === cardId);
  if (atk) atk.targetPlayerId = targetPlayerId;
  refreshCombatOverlay();
}

/** Set attacker target from select value (supports both players and planeswalkers) */
function setCombatAttackerTargetFromSelect(cardId, value) {
  if (!gameState) return;
  const atk = gameState.combat.attackers.find(a => a.cardId === cardId);
  if (!atk) return;
  if (value && value.startsWith('pw_')) {
    // Planeswalker target
    var pwId = parseInt(value.replace('pw_', ''), 10);
    atk.targetPlaneswalkerCardId = pwId;
    // Find which player owns that planeswalker to assign targetPlayerId
    var pw = gameState.battlefieldCards.find(function(c) { return c.id === pwId; });
    if (pw) atk.targetPlayerId = pw.ownerId;
  } else if (value && value.startsWith('p_')) {
    // Player target
    atk.targetPlaneswalkerCardId = null;
    atk.targetPlayerId = parseInt(value.replace('p_', ''), 10);
  } else {
    // Legacy fallback
    atk.targetPlaneswalkerCardId = null;
    atk.targetPlayerId = parseInt(value, 10);
  }
  refreshCombatOverlay();
  updateCombatArrows();
}

/** Select an attacker as target for pending blocker assignment */
function selectPendingBlockerTarget(atkCardId) {
  if (!gameState) return;
  const combat = gameState.combat;
  if (combat.phase !== 'declaring-blockers') return;

  if (combat.pendingBlockerFor === atkCardId) {
    // Deselect
    combat.pendingBlockerFor = null;
    document.querySelectorAll('.battlefield-card.attacker-selected').forEach(el => el.classList.remove('attacker-selected'));
  } else {
    combat.pendingBlockerFor = atkCardId;
    // Highlight the selected attacker card on the battlefield
    document.querySelectorAll('.battlefield-card.attacker-selected').forEach(el => el.classList.remove('attacker-selected'));
    const atkEl = document.getElementById(`bc-${atkCardId}`);
    if (atkEl) atkEl.classList.add('attacker-selected');
  }
  refreshCombatOverlay();
}

// ---- Attacker Declaration ----

/**
 * Enter the Declare Attackers phase — show overlay, set state.
 */
function startAttackerDeclaration() {
  if (!gameState) return;
  gameState.combat.phase = 'declaring-attackers';
  gameState.combat.attackers = [];
  gameState.combat.blockers = [];
  gameState.combat.damageAssignments = [];
  gameState.combat.pendingBlockerFor = null;
  gameState.combat.damagePreview = null;

  // Update the battlefield — mark/unmark cards visually
  clearCombatVisuals();

  // Prevent tapped creatures from being toggled as attacker
  showCombatOverlay();
  refreshCombatOverlay();
  addLogEntry(`⚔ <strong>${gameState.players[gameState.currentPlayerIndex].name}</strong> may now declare attackers.`);
}

/**
 * Toggle a creature as an attacker. Handles flying/menace enforcement,
 * summoning sickness check, and vigliiance.
 */
function toggleAttacker(cardId) {
  if (!gameState) return;
  const combat = gameState.combat;
  if (combat.phase !== 'declaring-attackers') {
    // Allow via context menu even outside formal phase (casual use)
    // But only if we're in the attack declaration conceptually
    return;
  }

  const card = gameState.battlefieldCards.find(c => c.id === cardId);
  if (!card) return;

  // Must be a creature owned by the active player
  if (!aiIsCreature(card)) return;
  if (card.ownerId !== gameState.currentPlayerIndex) return;

  // Can't attack while tapped
  if (card.tapped) {
    addLogEntry(`⚠ <strong>${card.name}</strong> is tapped and cannot attack.`);
    return;
  }

  // Defender: cannot attack
  if (hasKeyword(card, 'defender')) {
    addLogEntry(`⚠ <strong>${card.name}</strong> has Defender and cannot attack.`);
    return;
  }

  // Summoning sickness check
  if (hasSummoningSickness(card)) {
    addLogEntry(`⚠ <strong>${card.name}</strong> has summoning sickness and cannot attack.`);
    return;
  }

  const existingIdx = combat.attackers.findIndex(a => a.cardId === cardId);
  const cardEl = document.getElementById(`bc-${cardId}`);

  if (existingIdx !== -1) {
    // Remove from attackers
    combat.attackers.splice(existingIdx, 1);
    if (cardEl) cardEl.classList.remove('attacking');
    addLogEntry(`<strong>${card.name}</strong> removed from attackers.`);
  } else {
    // Find a default target (first non-active, non-eliminated player)
    let defaultTarget = -1;
    gameState.players.forEach((p, i) => {
      if (i !== gameState.currentPlayerIndex && !p.eliminated && defaultTarget === -1) {
        defaultTarget = i;
      }
    });
    if (defaultTarget === -1) return;

    combat.attackers.push({ cardId, targetPlayerId: defaultTarget });
    if (cardEl) cardEl.classList.add('attacking');
    addLogEntry(`⚔ <strong>${card.name}</strong> declared as attacker.`);
  }

  refreshCombatOverlay();
  updateCombatArrows();
}

/**
 * Confirm the attacker declaration and advance to Blockers phase.
 */
function confirmAttackers() {
  if (!gameState) return;
  const combat = gameState.combat;

  // Tap all attackers (unless vigilance)
  combat.attackers.forEach(a => {
    const card = gameState.battlefieldCards.find(c => c.id === a.cardId);
    if (!card) return;
    if (!hasKeyword(card, 'vigilance')) {
      card.tapped = true;
      const el = document.getElementById(`bc-${a.cardId}`);
      if (el) { el.classList.add('tapped'); el.classList.add('attacking'); }
    }
  });

  // Fire attack triggers
  fireBattlefieldTriggers('attack');

  if (combat.attackers.length === 0) {
    addLogEntry('⚔ No attackers declared. Skipping to End of Combat.');
    skipCombat();
    return;
  }

  const names = combat.attackers.map(a => {
    const c = gameState.battlefieldCards.find(cc => cc.id === a.cardId);
    const t = gameState.players[a.targetPlayerId]?.name || '?';
    return `${c ? c.name : '#' + a.cardId} → ${t}`;
  }).join(', ');
  addLogEntry(`⚔ Attackers declared: ${names}`);

  // Advance to blockers sub-phase
  gameState.combatPhaseIndex = 2; // 'blockers'
  combat.phase = 'declaring-blockers';
  combat.pendingBlockerFor = null;

  // Run AI blockers immediately for any AI defenders
  aiAssignBlockers();

  refreshCombatOverlay();
  renderPhaseTracker();
  addLogEntry(`Phase: <strong>${getCurrentPhaseName()}</strong>`);
  updateCombatArrows();
}

/**
 * Enter the Declare Blockers phase for human defenders.
 */
function startBlockerDeclaration() {
  if (!gameState) return;
  const combat = gameState.combat;
  combat.phase = 'declaring-blockers';
  combat.pendingBlockerFor = null;

  // Let AI automatically assign blockers for AI defenders
  aiAssignBlockers();

  showCombatOverlay();
  refreshCombatOverlay();
}

/**
 * Toggle a blocker: assign it to block the current pending attacker.
 */
function toggleBlocker(blockerCardId, attackerCardId) {
  if (!gameState) return;
  const combat = gameState.combat;

  const blocker = gameState.battlefieldCards.find(c => c.id === blockerCardId);
  const attacker = gameState.battlefieldCards.find(c => c.id === attackerCardId);
  if (!blocker || !attacker) return;

  // Can't block while tapped
  if (blocker.tapped) {
    addLogEntry(`⚠ <strong>${blocker.name}</strong> is tapped and cannot block.`);
    return;
  }

  // Flying restriction: only flying/reach can block flying
  if (hasKeyword(attacker, 'flying')) {
    if (!hasKeyword(blocker, 'flying') && !hasKeyword(blocker, 'reach')) {
      addLogEntry(`⚠ <strong>${blocker.name}</strong> cannot block <strong>${attacker.name}</strong> (has Flying).`);
      return;
    }
  }

  // Shadow: can only be blocked by creatures with shadow
  if (hasKeyword(attacker, 'shadow')) {
    if (!hasKeyword(blocker, 'shadow')) {
      addLogEntry(`⚠ <strong>${blocker.name}</strong> cannot block <strong>${attacker.name}</strong> (has Shadow — only shadow creatures can block).`);
      return;
    }
  }
  // Shadow blocker: cannot block non-shadow attackers
  if (hasKeyword(blocker, 'shadow') && !hasKeyword(attacker, 'shadow')) {
    addLogEntry(`⚠ <strong>${blocker.name}</strong> (Shadow) cannot block <strong>${attacker.name}</strong> — shadow creatures can only block other shadow creatures.`);
    return;
  }

  // Intimidate: can only be blocked by artifact creatures or creatures sharing a color
  if (hasKeyword(attacker, 'intimidate')) {
    var blockerIsArtifactCr = cardIsArtifactCreature(blocker);
    var sharesColor = false;
    if (attacker.colors && Array.isArray(attacker.colors)) {
      attacker.colors.forEach(function(col) {
        if (cardHasColor(blocker, col)) sharesColor = true;
      });
    }
    if (!blockerIsArtifactCr && !sharesColor) {
      addLogEntry(`⚠ <strong>${blocker.name}</strong> cannot block <strong>${attacker.name}</strong> (Intimidate — must share a color or be an artifact creature).`);
      return;
    }
  }

  // Fear: can only be blocked by artifact creatures or black creatures
  if (hasKeyword(attacker, 'fear')) {
    var blockerIsArtifactCrFear = cardIsArtifactCreature(blocker);
    var blockerIsBlack = cardHasColor(blocker, 'B');
    if (!blockerIsArtifactCrFear && !blockerIsBlack) {
      addLogEntry(`⚠ <strong>${blocker.name}</strong> cannot block <strong>${attacker.name}</strong> (Fear — must be artifact or black creature).`);
      return;
    }
  }

  // Protection: attacker with protection from [quality] can't be blocked by matching creatures
  if (protectionPreventsBlocking(attacker, blocker)) {
    var protList = parseProtectionQualities(attacker).join(', ');
    addLogEntry('\u26a0 <strong>' + blocker.name + '</strong> cannot block <strong>' + attacker.name + '</strong> (protection from ' + protList + ').');
    return;
  }

  // Check if already blocking this attacker
  const existingIdx = combat.blockers.findIndex(
    b => b.cardId === blockerCardId && b.blockingCardId === attackerCardId
  );

  const cardEl = document.getElementById(`bc-${blockerCardId}`);

  if (existingIdx !== -1) {
    // Remove blocker
    combat.blockers.splice(existingIdx, 1);
    if (cardEl) cardEl.classList.remove('blocking');
    addLogEntry(`<strong>${blocker.name}</strong> removed from blockers.`);
  } else {
    // Remove any previous assignment of this blocker (it can only block one attacker)
    const prevIdx = combat.blockers.findIndex(b => b.cardId === blockerCardId);
    if (prevIdx !== -1) {
      combat.blockers.splice(prevIdx, 1);
    }
    combat.blockers.push({ cardId: blockerCardId, blockingCardId: attackerCardId });
    if (cardEl) cardEl.classList.add('blocking');
    addLogEntry(`🛡 <strong>${blocker.name}</strong> blocks <strong>${attacker.name}</strong>.`);
  }

  // Clear the pending selection after assignment
  combat.pendingBlockerFor = null;
  document.querySelectorAll('.battlefield-card.attacker-selected').forEach(el => el.classList.remove('attacker-selected'));

  // Fire block triggers
  fireBattlefieldTriggers('block');

  refreshCombatOverlay();
  updateCombatArrows();
}

/**
 * Confirm blockers and advance to Damage step.
 */
function confirmBlockers() {
  if (!gameState) return;
  const combat = gameState.combat;

  // Menace enforcement: attacker with menace must be blocked by 2+ creatures
  var menaceViolator = checkMenaceViolation();
  if (menaceViolator) {
    // Show warning and prevent confirm
    var warningId = 'menace-warning-' + Date.now();
    var existing = document.getElementById('combat-menace-warning');
    if (existing && existing.parentNode) existing.parentNode.removeChild(existing);
    var warn = document.createElement('div');
    warn.id = 'combat-menace-warning';
    warn.className = 'combat-menace-warning';
    warn.innerHTML = '⚠️ <strong>' + escapeHtml(menaceViolator.name) + '</strong> has <strong>Menace</strong> — must be blocked by 2 or more creatures, or left unblocked.';
    var blockersSection = document.getElementById('combat-blockers-section');
    if (blockersSection) {
      blockersSection.insertBefore(warn, blockersSection.firstChild);
    }
    addLogEntry('⚠ Menace: <strong>' + escapeHtml(menaceViolator.name) + '</strong> must be blocked by 2+ creatures or left unblocked.');
    setTimeout(function() {
      var w = document.getElementById('combat-menace-warning');
      if (w && w.parentNode) w.parentNode.removeChild(w);
    }, 4000);
    return; // Block confirm
  }

  const summary = combat.blockers.length > 0
    ? combat.blockers.map(b => {
        const blocker = gameState.battlefieldCards.find(c => c.id === b.cardId);
        const attacker = gameState.battlefieldCards.find(c => c.id === b.blockingCardId);
        return `${blocker?.name || '#' + b.cardId} blocks ${attacker?.name || '#' + b.blockingCardId}`;
      }).join('; ')
    : 'No blockers assigned.';
  addLogEntry(`🛡 Blockers confirmed: ${summary}`);

  // If this was during an AI turn (human blocking AI attack), resume AI turn
  if (_aiBlockerPauseState) {
    hideCombatOverlay();
    combat.phase = null;
    var resumeFn = _aiBlockerPauseState.resumeFn;
    // Small delay so blocker log is visible before damage
    setTimeout(function() { resumeFn(); }, 400);
    return;
  }

  // Advance to damage sub-phase (normal human-turn flow)
  gameState.combatPhaseIndex = 3; // 'damage'
  renderPhaseTracker();
  addLogEntry(`Phase: <strong>${getCurrentPhaseName()}</strong>`);

  // Show damage preview instead of auto-resolving
  showDamagePreview();
  updateCombatArrows();
}

// ---- AI Blocker Assignment ----

/**
 * AI players that are defenders will automatically assign blockers.
 * Strategy: block biggest threat with smallest creature that can survive,
 * or chump-block if outmatched.
 */
function aiAssignBlockers() {
  if (!gameState) return;
  const combat = gameState.combat;

  // Find all unique defenders
  const defenderSet = new Set(combat.attackers.map(a => a.targetPlayerId));

  defenderSet.forEach(defIdx => {
    const defender = gameState.players[defIdx];
    if (!defender || !defender.isAI) return;

    // Get untapped creatures belonging to this AI defender
    const myCreatures = gameState.battlefieldCards.filter(c =>
      c.ownerId === defIdx && aiIsCreature(c) && !c.tapped
    );

    // Get attackers targeting this defender
    const incomingAttackers = combat.attackers
      .filter(a => a.targetPlayerId === defIdx)
      .map(a => gameState.battlefieldCards.find(c => c.id === a.cardId))
      .filter(Boolean)
      .sort((a, b) => getCreaturePower(b) - getCreaturePower(a)); // Biggest threat first

    const usedBlockers = new Set();

    incomingAttackers.forEach(attacker => {
      // Skip flying attackers if we have no flyers/reach
      if (hasKeyword(attacker, 'flying')) {
        const canBlock = myCreatures.find(b => !usedBlockers.has(b.id) &&
          (hasKeyword(b, 'flying') || hasKeyword(b, 'reach')));
        if (!canBlock) return;
      }

      const atkPow = getCreaturePower(attacker);
      const atkTou = getCreatureToughness(attacker);

      // Find best blocker: smallest that can survive OR just chump
      const available = myCreatures.filter(b =>
        !usedBlockers.has(b.id) &&
        (!hasKeyword(attacker, 'flying') || hasKeyword(b, 'flying') || hasKeyword(b, 'reach'))
      );

      if (available.length === 0) return;

      // Prefer a blocker that can survive
      let chosen = available.find(b => {
        const bTou = getCreatureToughness(b);
        return hasKeyword(attacker, 'deathtouch') ? false : bTou > atkPow;
      });

      // Fall back to chump-block if total damage would kill the AI
      if (!chosen && defender.life <= atkPow) {
        chosen = available[0]; // Chump block
      }

      if (chosen) {
        usedBlockers.add(chosen.id);
        combat.blockers.push({ cardId: chosen.id, blockingCardId: attacker.id });
        const el = document.getElementById(`bc-${chosen.id}`);
        if (el) el.classList.add('blocking');
        addLogEntry(`🤖 🛡 <strong>${defender.name}</strong> blocks <strong>${attacker.name}</strong> with <strong>${chosen.name}</strong>.`);
      }
    });
  });
}

// ---- Combat Damage Resolution ----

/**
 * Full combat damage resolution with keyword ability handling.
 */
function resolveCombatDamage() {
  if (!gameState) return;
  const combat = gameState.combat;
  if (combat.attackers.length === 0) return;

  // Map blockerCardId -> list of blocker cards for each attacker
  const blockerMap = {}; // attackerCardId -> [blockerCard, ...]
  combat.blockers.forEach(b => {
    if (!blockerMap[b.blockingCardId]) blockerMap[b.blockingCardId] = [];
    const bc = gameState.battlefieldCards.find(c => c.id === b.cardId);
    if (bc) blockerMap[b.blockingCardId].push(bc);
  });

  // Damage tracking: cardId -> damage received this combat
  const damageReceived = {};
  // Track which cards received deathtouch damage (any damage is lethal)
  const deathtouchTargets = new Set();

  const logLines = [];

  // --- First Strike damage pass ---
  const firstStrikeAttackers = combat.attackers.filter(a => {
    const c = gameState.battlefieldCards.find(cc => cc.id === a.cardId);
    return c && (hasKeyword(c, 'first strike') || hasKeyword(c, 'double strike'));
  });

  // Process first strike attackers
  firstStrikeAttackers.forEach(a => {
    processCombatant(a, blockerMap, damageReceived, deathtouchTargets, logLines, true);
  });

  // --- Normal damage pass ---
  combat.attackers.forEach(a => {
    // Double-strike already dealt first-strike damage, also deal normal
    // First-strikers only dealt first-strike damage (skip normal unless double-strike)
    const c = gameState.battlefieldCards.find(cc => cc.id === a.cardId);
    if (!c) return;
    const isFirstStrike = hasKeyword(c, 'first strike') && !hasKeyword(c, 'double strike');
    if (isFirstStrike) return; // Already handled
    processCombatant(a, blockerMap, damageReceived, deathtouchTargets, logLines, false);
  });

  // --- Check for lethal damage and send creatures to graveyard ---
  // Also mark damage on creatures using the new damage marking system
  Object.entries(damageReceived).forEach(([cardId, dmg]) => {
    const id = parseInt(cardId, 10);
    const card = gameState.battlefieldCards.find(c => c.id === id);
    if (card && dmg > 0) {
      // Use markDamage to track damage (skip replacement since already applied via combat)
      card.damageMarked = (card.damageMarked || 0) + dmg;
      var dmgEl = document.getElementById('bc-' + id);
      if (dmgEl) {
        var dmgBadge = dmgEl.querySelector('.damage-badge');
        if (!dmgBadge) {
          dmgBadge = document.createElement('div');
          dmgBadge.className = 'damage-badge';
          dmgEl.appendChild(dmgBadge);
        }
        dmgBadge.textContent = card.damageMarked;
        dmgBadge.style.display = 'flex';
      }
    }
  });

  const toKill = [];
  Object.entries(damageReceived).forEach(([cardId, dmg]) => {
    const id = parseInt(cardId, 10);
    const card = gameState.battlefieldCards.find(c => c.id === id);
    if (!card) return;
    if (hasKeyword(card, 'indestructible')) return; // Indestructible can't die from damage

    const toughness = getCreatureToughness(card);
    // A creature dies if it received damage >= toughness,
    // OR if it received ANY damage from a source with deathtouch
    const isLethal = deathtouchTargets.has(id)
      ? dmg > 0
      : dmg >= toughness;

    if (isLethal) {
      toKill.push(id);
      logLines.push(`☠ <strong>${card.name}</strong> is destroyed (${dmg} damage, ${toughness} toughness).`);
    }
  });

  // Log all combat results
  logLines.forEach(line => addLogEntry(line));

  // Send killed creatures to graveyard (after logging)
  toKill.forEach(id => {
    // Remove from combat state too
    combat.attackers = combat.attackers.filter(a => a.cardId !== id);
    combat.blockers = combat.blockers.filter(b => b.cardId !== id && b.blockingCardId !== id);
    moveCardToZone(id, 'graveyard');
  });

  // Fire damage triggers
  if (damageReceived && Object.keys(damageReceived).length > 0) {
    fireBattlefieldTriggers('damage');
  }

  renderPlayerPanels();
  checkStateBasedActions();
}

/**
 * Process one attacker's damage assignment.
 * @param {object} a - attacker entry {cardId, targetPlayerId}
 * @param {object} blockerMap - attackerCardId -> [blockerCards]
 * @param {object} damageReceived - mutable map: cardId -> total damage
 * @param {Set} deathtouchTargets - mutable set of cardIds that received deathtouch damage
 * @param {string[]} logLines - log entries to append
 * @param {boolean} firstStrikePass - true if this is the first-strike damage pass
 */
function processCombatant(a, blockerMap, damageReceived, deathtouchTargets, logLines, firstStrikePass) {
  const attacker = gameState.battlefieldCards.find(c => c.id === a.cardId);
  if (!attacker) return;

  const atkPow = getCreaturePower(attacker);
  const blockers = blockerMap[a.cardId] || [];
  const targetPlayer = gameState.players[a.targetPlayerId];
  const hasDeathtouch = hasKeyword(attacker, 'deathtouch');
  const hasTrample = hasKeyword(attacker, 'trample');
  const hasLifelink = hasKeyword(attacker, 'lifelink');
  const controller = gameState.players[attacker.ownerId];

  if (blockers.length === 0) {
    // Unblocked — deal damage to defending player
    if (atkPow > 0 && targetPlayer && !targetPlayer.eliminated) {
      logLines.push(`⚔ <strong>${attacker.name}</strong> (${atkPow} power) deals <strong>${atkPow}</strong> damage to <strong>${targetPlayer.name}</strong> — unblocked.`);
      adjustLife(a.targetPlayerId, -atkPow);
      // Check if Monarch was hit by combat damage
      checkMonarchCombatDamage(attacker, a.targetPlayerId);
      // Track commander damage
      if (isCommander(attacker)) {
        adjustCommanderDamage(a.targetPlayerId, attacker.ownerId, atkPow);
        logLines.push(`Commander damage: <strong>${attacker.name}</strong> dealt <strong>${atkPow}</strong> commander damage to <strong>${targetPlayer.name}</strong>.`);
      }
      if (hasLifelink && controller) {
        adjustLife(attacker.ownerId, atkPow);
        logLines.push(`♥ Lifelink: <strong>${controller.name}</strong> gains <strong>${atkPow}</strong> life.`);
      }
    }
  } else {
    // Blocked — divide damage among blockers
    let remainingPow = atkPow;

    blockers.forEach((blocker, idx) => {
      if (!gameState.battlefieldCards.find(c => c.id === blocker.id)) return; // Already dead
      const blockerTou = getCreatureToughness(blocker);
      const lethalDmg = hasDeathtouch ? 1 : blockerTou;
      const dmgToBlocker = Math.min(remainingPow, lethalDmg);

      if (dmgToBlocker > 0) {
        // Protection: blocker with protection from attacker's colors prevents damage
        var blockerProt = parseProtectionQualities(blocker);
        if (protectionBlocksSource(blockerProt, attacker)) {
          logLines.push('\ud83d\udd12 <strong>' + blocker.name + '</strong> has protection \u2014 damage prevented from <strong>' + attacker.name + '</strong>.');
          remainingPow -= dmgToBlocker;
        } else {
          damageReceived[blocker.id] = (damageReceived[blocker.id] || 0) + dmgToBlocker;
          if (hasDeathtouch) deathtouchTargets.add(blocker.id);
          remainingPow -= dmgToBlocker;
          logLines.push('\u2694 <strong>' + attacker.name + '</strong> deals <strong>' + dmgToBlocker + '</strong>' + (hasDeathtouch ? ' (deathtouch)' : '') + ' damage to <strong>' + blocker.name + '</strong>.');
          if (hasLifelink && controller) {
            adjustLife(attacker.ownerId, dmgToBlocker);
            logLines.push('\u2665 Lifelink: <strong>' + controller.name + '</strong> gains <strong>' + dmgToBlocker + '</strong> life.');
          }
        }
      }
      // Blocker deals damage back to attacker
      const blockerPow = getCreaturePower(blocker);
      const blockerHasDeathtouch = hasKeyword(blocker, 'deathtouch');
      const isBlockerFirstStrike = hasKeyword(blocker, 'first strike') || hasKeyword(blocker, 'double strike');
      // Only deal blocker damage on same pass logic
      const shouldDealNow = firstStrikePass ? isBlockerFirstStrike : !hasKeyword(blocker, 'first strike');
      if (shouldDealNow && blockerPow > 0) {
        // Protection: attacker with protection from blocker prevents blocker's damage
        var atkProt = parseProtectionQualities(attacker);
        if (protectionBlocksSource(atkProt, blocker)) {
          logLines.push('\ud83d\udd12 <strong>' + attacker.name + '</strong> has protection \u2014 damage prevented from <strong>' + blocker.name + '</strong>.');
        } else {
        damageReceived[attacker.id] = (damageReceived[attacker.id] || 0) + blockerPow;
        if (blockerHasDeathtouch) deathtouchTargets.add(attacker.id);
        logLines.push(`🛡 <strong>${blocker.name}</strong> deals <strong>${blockerPow}</strong>${blockerHasDeathtouch ? ' (deathtouch)' : ''} damage to <strong>${attacker.name}</strong>.`);
        if (hasKeyword(blocker, 'lifelink')) {
          const blockerOwner = gameState.players[blocker.ownerId];
          if (blockerOwner) {
            adjustLife(blocker.ownerId, blockerPow);
            logLines.push(`♥ Lifelink: <strong>${blockerOwner.name}</strong> gains <strong>${blockerPow}</strong> life.`);
          }
        }
        } // end protection else
      }
    });

    // Trample: excess damage goes to player
    if (hasTrample && remainingPow > 0 && targetPlayer && !targetPlayer.eliminated) {
      logLines.push(`🟥 Trample: <strong>${attacker.name}</strong> deals <strong>${remainingPow}</strong> excess damage to <strong>${targetPlayer.name}</strong>.`);
      adjustLife(a.targetPlayerId, -remainingPow);
      // Check if Monarch was hit by trample damage
      checkMonarchCombatDamage(attacker, a.targetPlayerId);
      // Track commander damage from trample overflow
      if (isCommander(attacker)) {
        adjustCommanderDamage(a.targetPlayerId, attacker.ownerId, remainingPow);
        logLines.push(`Commander damage: <strong>${attacker.name}</strong> dealt <strong>${remainingPow}</strong> trample commander damage to <strong>${targetPlayer.name}</strong>.`);
      }
      if (hasLifelink && controller) {
        adjustLife(attacker.ownerId, remainingPow);
        logLines.push(`♥ Lifelink: <strong>${controller.name}</strong> gains <strong>${remainingPow}</strong> life.`);
      }
    }
  }
}

/**
 * Skip combat entirely — advance past all combat phases.
 */
function skipCombat() {
  if (!gameState) return;

  // If skipping during AI turn's blocker pause, resume AI turn (resolve damage with no blockers)
  if (_aiBlockerPauseState) {
    var resumeState = _aiBlockerPauseState;
    _aiBlockerPauseState = null;
    hideCombatOverlay();
    gameState.combat.phase = null;
    addLogEntry('\u{1F6E1} No blockers declared.');
    // Resume the AI turn flow (which resolves damage, then post-combat)
    setTimeout(function() { resumeState.resumeFn(); }, 400);
    return;
  }

  endCombat();
  gameState.inCombat = false;
  gameState.combatPhaseIndex = 0;
  gameState.currentPhaseIndex = 3; // Main Phase 2
  hideCombatOverlay();
  emptyAllManaPools();
  renderPhaseTracker();
  addLogEntry('Combat skipped. Moving to Main Phase 2.');
  showShortcutHint();
}

/**
 * Clean up all combat state and visuals.
 */
function endCombat() {
  if (!gameState) return;
  clearCombatVisuals();
  gameState.combat = {
    attackers: [],
    blockers: [],
    damageAssignments: [],
    phase: null,
    pendingBlockerFor: null,
    damagePreview: null,
  };
  hideCombatOverlay();
}

/**
 * Remove all combat visual classes from battlefield cards.
 */
function clearCombatVisuals() {
  document.querySelectorAll('.battlefield-card.attacking').forEach(el => el.classList.remove('attacking'));
  document.querySelectorAll('.battlefield-card.blocking').forEach(el => el.classList.remove('blocking'));
  document.querySelectorAll('.battlefield-card.attacker-selected').forEach(el => el.classList.remove('attacker-selected'));
  document.querySelectorAll('.battlefield-card.summoning-sick').forEach(el => el.classList.remove('summoning-sick'));
  clearCombatArrows();
}

/**
 * Inline onclick handler for the combat confirm button.
 * Routes to the correct action based on current combat phase.
 */
function handleCombatConfirm() {
  if (!gameState) return;
  const phase = gameState.combat.phase;
  if (phase === 'declaring-attackers') {
    confirmAttackers();
  } else if (phase === 'declaring-blockers') {
    confirmBlockers();
  } else if (phase === 'previewing-damage') {
    applyDamageFromPreview();
  }
}

/**
 * Initialize combat overlay (legacy stub — buttons now use inline onclick).
 */
function initCombatOverlay() {
  // Buttons now use inline onclick handlers (handleCombatConfirm, skipCombat)
}

// ============================================================
// COMBAT DAMAGE CALCULATOR / PREVIEW
// ============================================================

/**
 * Build the damage preview data from current attackers/blockers.
 * Returns an array of matchup objects describing each attacker's
 * damage assignments, keyword interactions, and outcomes.
 */
function buildDamagePreviewData() {
  if (!gameState) return [];
  const combat = gameState.combat;
  const matchups = [];

  // Build blocker map: attackerCardId -> [blockerCard, ...]
  const blockerMap = {};
  combat.blockers.forEach(b => {
    if (!blockerMap[b.blockingCardId]) blockerMap[b.blockingCardId] = [];
    const bc = gameState.battlefieldCards.find(c => c.id === b.cardId);
    if (bc) blockerMap[b.blockingCardId].push(bc);
  });

  combat.attackers.forEach(a => {
    const attacker = gameState.battlefieldCards.find(c => c.id === a.cardId);
    if (!attacker) return;

    const atkPow = getCreaturePower(attacker);
    const atkTou = getCreatureToughness(attacker);
    const blockers = blockerMap[a.cardId] || [];
    const targetPlayer = gameState.players[a.targetPlayerId];
    const controller = gameState.players[attacker.ownerId];

    const atkKeywords = {
      deathtouch: hasKeyword(attacker, 'deathtouch'),
      trample: hasKeyword(attacker, 'trample'),
      lifelink: hasKeyword(attacker, 'lifelink'),
      firstStrike: hasKeyword(attacker, 'first strike'),
      doubleStrike: hasKeyword(attacker, 'double strike'),
      infect: hasKeyword(attacker, 'infect'),
      indestructible: hasKeyword(attacker, 'indestructible'),
    };
    atkKeywords.isCommander = !!attacker.isCommander;

    const matchup = {
      attackerId: a.cardId,
      attackerName: attacker.name,
      attackerPt: attacker.pt || '?/?',
      attackerPower: atkPow,
      attackerToughness: atkTou,
      attackerKeywords: atkKeywords,
      attackerOwnerId: attacker.ownerId,
      targetPlayerId: a.targetPlayerId,
      targetPlaneswalkerCardId: a.targetPlaneswalkerCardId || null,
      targetPlayerName: targetPlayer ? targetPlayer.name : '?',
      targetPlayerLife: targetPlayer ? targetPlayer.life : 0,
      isBlocked: blockers.length > 0,
      blockerDetails: [],
      // Damage assignments (editable for multi-blocker)
      damageToBlockers: [],    // array parallel to blockerDetails: dmg assigned to each
      damageToPlayer: 0,       // damage going through to player (unblocked or trample)
      // Blocker damage back to attacker
      damageToAttacker: 0,
      // Outcomes
      attackerDies: false,
      playerLifeChange: 0,
      playerPoisonChange: 0,
      commanderDamage: 0,
      lifelinkGain: 0,
    };

    if (blockers.length === 0) {
      // Unblocked
      matchup.damageToPlayer = atkPow;
      matchup.playerLifeChange = atkKeywords.infect ? 0 : -atkPow;
      matchup.playerPoisonChange = atkKeywords.infect ? atkPow : 0;
      if (atkKeywords.isCommander) matchup.commanderDamage = atkPow;
      if (atkKeywords.lifelink) matchup.lifelinkGain = atkPow;
      if (atkKeywords.doubleStrike) {
        matchup.damageToPlayer = atkPow * 2;
        matchup.playerLifeChange = atkKeywords.infect ? 0 : -(atkPow * 2);
        matchup.playerPoisonChange = atkKeywords.infect ? atkPow * 2 : 0;
        if (atkKeywords.isCommander) matchup.commanderDamage = atkPow * 2;
        if (atkKeywords.lifelink) matchup.lifelinkGain = atkPow * 2;
      }
    } else {
      // Blocked — assign damage to each blocker
      let remainingPow = atkPow;
      let totalBlockerDmgBack = 0;

      blockers.forEach((blocker, idx) => {
        const bTou = getCreatureToughness(blocker);
        const bPow = getCreaturePower(blocker);
        const bKeywords = {
          deathtouch: hasKeyword(blocker, 'deathtouch'),
          firstStrike: hasKeyword(blocker, 'first strike'),
          doubleStrike: hasKeyword(blocker, 'double strike'),
          lifelink: hasKeyword(blocker, 'lifelink'),
          indestructible: hasKeyword(blocker, 'indestructible'),
          infect: hasKeyword(blocker, 'infect'),
        };

        const lethalDmg = atkKeywords.deathtouch ? 1 : bTou;
        const autoAssign = Math.min(remainingPow, lethalDmg);

        matchup.blockerDetails.push({
          cardId: blocker.id,
          name: blocker.name,
          pt: blocker.pt || '?/?',
          power: bPow,
          toughness: bTou,
          keywords: bKeywords,
          minLethal: lethalDmg,
        });
        matchup.damageToBlockers.push(autoAssign);

        remainingPow -= autoAssign;
        totalBlockerDmgBack += bPow;
      });

      // Trample excess to player
      if (atkKeywords.trample && remainingPow > 0) {
        matchup.damageToPlayer = remainingPow;
        matchup.playerLifeChange = atkKeywords.infect ? 0 : -remainingPow;
        matchup.playerPoisonChange = atkKeywords.infect ? remainingPow : 0;
        if (atkKeywords.isCommander) matchup.commanderDamage = remainingPow;
      }

      matchup.damageToAttacker = totalBlockerDmgBack;
      if (atkKeywords.doubleStrike) {
        // Double strike: all blocker damage assignments double
        matchup.damageToBlockers = matchup.damageToBlockers.map(d => d * 2);
        if (matchup.damageToPlayer > 0) {
          matchup.damageToPlayer *= 2;
          matchup.playerLifeChange *= 2;
          matchup.playerPoisonChange *= 2;
          matchup.commanderDamage *= 2;
        }
      }

      // Compute lifelink on total damage dealt
      if (atkKeywords.lifelink) {
        const totalDealt = matchup.damageToBlockers.reduce((s, d) => s + d, 0) + matchup.damageToPlayer;
        matchup.lifelinkGain = totalDealt;
      }

      // Does attacker die from blockers?
      const anyBlockerDeathtouch = blockers.some(b => hasKeyword(b, 'deathtouch'));
      matchup.attackerDies = !atkKeywords.indestructible &&
        (anyBlockerDeathtouch ? totalBlockerDmgBack > 0 : totalBlockerDmgBack >= atkTou);
    }

    matchups.push(matchup);
  });

  return matchups;
}

/**
 * Render the damage preview panel in the combat overlay.
 * Shows each matchup with keyword badges, damage assignments,
 * and editable sliders for multi-blocker scenarios.
 */
function showDamagePreview() {
  if (!gameState) return;
  const combat = gameState.combat;
  combat.phase = 'previewing-damage';

  // Build preview data and stash on combat state
  combat.damagePreview = buildDamagePreviewData();

  const previewEl = document.getElementById('combat-damage-preview');
  const phaseLabel = document.getElementById('combat-phase-label');
  const instructions = document.getElementById('combat-instructions');
  const confirmBtn = document.getElementById('combat-confirm');
  const attackersList = document.getElementById('combat-attackers-list');
  const blockersSection = document.getElementById('combat-blockers-section');

  if (phaseLabel) phaseLabel.textContent = '\u2694\uFE0F Combat Damage Preview';
  if (instructions) instructions.textContent = 'Review damage assignments. Adjust damage distribution for multi-blocker matchups, then confirm to resolve.';
  if (confirmBtn) confirmBtn.textContent = '\u2620 Resolve Damage';
  if (attackersList) attackersList.innerHTML = '';
  if (blockersSection) blockersSection.style.display = 'none';

  if (!previewEl) return;
  previewEl.style.display = 'block';

  renderDamagePreviewContent();
  showCombatOverlay();
  updateCombatArrows();
}

/**
 * Render the inner content of the damage preview panel.
 */
function renderDamagePreviewContent() {
  const previewEl = document.getElementById('combat-damage-preview');
  if (!previewEl || !gameState) return;

  const matchups = gameState.combat.damagePreview;
  if (!matchups || matchups.length === 0) {
    previewEl.innerHTML = '<div class="dmg-empty">No combat damage to resolve.</div>';
    return;
  }

  // Compute summary totals
  const lifeSummary = {}; // playerId -> net change
  const poisonSummary = {};
  const cmdDmgSummary = {}; // "targetId-sourceId" -> amount
  const lifelinkSummary = {}; // ownerId -> gain
  const deaths = [];

  matchups.forEach((m, mi) => {
    // Player damage
    if (m.playerLifeChange !== 0) {
      lifeSummary[m.targetPlayerId] = (lifeSummary[m.targetPlayerId] || 0) + m.playerLifeChange;
    }
    if (m.playerPoisonChange > 0) {
      poisonSummary[m.targetPlayerId] = (poisonSummary[m.targetPlayerId] || 0) + m.playerPoisonChange;
    }
    if (m.commanderDamage > 0) {
      const key = `${m.targetPlayerId}-${m.attackerOwnerId}`;
      cmdDmgSummary[key] = (cmdDmgSummary[key] || 0) + m.commanderDamage;
    }
    if (m.lifelinkGain > 0) {
      lifelinkSummary[m.attackerOwnerId] = (lifelinkSummary[m.attackerOwnerId] || 0) + m.lifelinkGain;
    }
    // Creature deaths
    if (m.attackerDies) deaths.push(m.attackerName);
    m.blockerDetails.forEach((b, bi) => {
      const dmg = m.damageToBlockers[bi] || 0;
      const lethal = m.attackerKeywords.deathtouch ? (dmg > 0) : (dmg >= b.toughness);
      if (lethal && !b.keywords.indestructible) deaths.push(b.name);
    });
  });

  let html = '<div class="dmg-preview-container">';

  // --- Matchup cards ---
  matchups.forEach((m, mi) => {
    const atkKwBadges = buildKeywordBadges(m.attackerKeywords);

    html += `<div class="dmg-matchup">`;
    html += `<div class="dmg-matchup-header">`;
    html += `<span class="dmg-attacker-info"><span class="dmg-icon">\u2694</span> <strong>${escapeHtml(m.attackerName)}</strong> <span class="dmg-pt">${escapeHtml(m.attackerPt)}</span>${atkKwBadges}</span>`;

    if (!m.isBlocked) {
      html += `<span class="dmg-arrow">\u2192</span><span class="dmg-target-player"><strong>${escapeHtml(m.targetPlayerName)}</strong> (${m.targetPlayerLife}\u2764)</span>`;
    }
    html += `</div>`; // header end

    if (m.isBlocked) {
      // Show blocker assignments
      html += `<div class="dmg-blocker-assignments">`;
      const totalDmgPool = m.attackerKeywords.doubleStrike ? m.attackerPower * 2 : m.attackerPower;
      const usedDmg = m.damageToBlockers.reduce((s, d) => s + d, 0);

      m.blockerDetails.forEach((b, bi) => {
        const dmg = m.damageToBlockers[bi] || 0;
        const isLethal = m.attackerKeywords.deathtouch ? (dmg > 0) : (dmg >= b.toughness);
        const willDie = isLethal && !b.keywords.indestructible;
        const bKwBadges = buildKeywordBadges(b.keywords);

        html += `<div class="dmg-blocker-row ${willDie ? 'dmg-lethal' : ''}">`;
        html += `<span class="dmg-blocker-info"><span class="dmg-icon">\uD83D\uDEE1</span> ${escapeHtml(b.name)} <span class="dmg-pt">${escapeHtml(b.pt)}</span>${bKwBadges}</span>`;

        if (m.blockerDetails.length > 1) {
          // Editable damage for multi-blocker
          html += `<span class="dmg-assign-controls">`;
          html += `<button class="dmg-adj-btn" onclick="adjustBlockerDamage(${mi}, ${bi}, -1)" title="Decrease damage">\u2212</button>`;
          html += `<span class="dmg-assign-value" id="dmg-val-${mi}-${bi}">${dmg}</span>`;
          html += `<button class="dmg-adj-btn" onclick="adjustBlockerDamage(${mi}, ${bi}, 1)" title="Increase damage">+</button>`;
          html += `</span>`;
        } else {
          html += `<span class="dmg-assign-fixed">${dmg} dmg</span>`;
        }

        html += `<span class="dmg-outcome ${willDie ? 'dmg-dies' : 'dmg-survives'}">${willDie ? '\u2620 Dies' : '\u2714 Survives'}</span>`;
        html += `</div>`;
      });

      // Trample line
      if (m.attackerKeywords.trample) {
        const trampleDmg = Math.max(0, totalDmgPool - usedDmg);
        html += `<div class="dmg-trample-row">`;
        html += `<span class="dmg-icon">\uD83E\uDD8F</span> Trample: <strong>${trampleDmg}</strong> to <strong>${escapeHtml(m.targetPlayerName)}</strong>`;
        html += `</div>`;
      }

      // Attacker receives damage from blockers
      if (m.damageToAttacker > 0) {
        html += `<div class="dmg-counterattack">`;
        html += `\uD83D\uDEE1 Blockers deal <strong>${m.damageToAttacker}</strong> to <strong>${escapeHtml(m.attackerName)}</strong>`;
        html += ` — ${m.attackerDies ? '<span class="dmg-dies">\u2620 Dies</span>' : '<span class="dmg-survives">\u2714 Survives</span>'}`;
        html += `</div>`;
      }

      html += `</div>`; // blocker-assignments end
    } else {
      // Unblocked damage display
      html += `<div class="dmg-unblocked">`;
      html += `<span class="dmg-big-number">${m.damageToPlayer}</span>`;
      html += `<span class="dmg-damage-label">${m.attackerKeywords.infect ? 'poison' : 'damage'}</span>`;
      if (m.commanderDamage > 0) {
        html += `<span class="dmg-commander-badge" title="Commander damage">\uD83D\uDC51 ${m.commanderDamage} cmd</span>`;
      }
      html += `</div>`;
    }

    // Lifelink
    if (m.lifelinkGain > 0) {
      const ownerName = gameState.players[m.attackerOwnerId]?.name || '?';
      html += `<div class="dmg-lifelink">\u2764 Lifelink: <strong>${ownerName}</strong> gains <strong>${m.lifelinkGain}</strong> life</div>`;
    }

    html += `</div>`; // matchup end
  });

  // --- Summary ---
  html += `<div class="dmg-summary">`;
  html += `<div class="dmg-summary-title">\u2694 Damage Summary</div>`;

  // Player life changes
  const playerChanges = [];
  Object.entries(lifeSummary).forEach(([pid, change]) => {
    const p = gameState.players[parseInt(pid)];
    if (p) playerChanges.push(`<span class="dmg-summary-item"><strong>${escapeHtml(p.name)}</strong>: ${p.life} \u2192 ${p.life + change} (${change > 0 ? '+' : ''}${change})</span>`);
  });
  Object.entries(lifelinkSummary).forEach(([oid, gain]) => {
    const p = gameState.players[parseInt(oid)];
    if (p) {
      const existing = lifeSummary[oid] || 0;
      playerChanges.push(`<span class="dmg-summary-item dmg-summary-gain"><strong>${escapeHtml(p.name)}</strong>: +${gain} (lifelink)</span>`);
    }
  });
  if (playerChanges.length > 0) {
    html += `<div class="dmg-summary-section">${playerChanges.join('')}</div>`;
  }

  // Poison
  Object.entries(poisonSummary).forEach(([pid, amt]) => {
    const p = gameState.players[parseInt(pid)];
    if (p) html += `<div class="dmg-summary-section"><span class="dmg-summary-item dmg-summary-poison">\u2623 <strong>${escapeHtml(p.name)}</strong>: +${amt} poison (${p.poison} \u2192 ${p.poison + amt})</span></div>`;
  });

  // Commander damage
  Object.entries(cmdDmgSummary).forEach(([key, amt]) => {
    const [tid, sid] = key.split('-').map(Number);
    const tp = gameState.players[tid];
    const sp = gameState.players[sid];
    if (tp && sp) {
      const current = tp.commanderDamage?.[sid] || 0;
      html += `<div class="dmg-summary-section"><span class="dmg-summary-item dmg-summary-cmd">\uD83D\uDC51 <strong>${escapeHtml(tp.name)}</strong>: +${amt} cmd dmg from ${escapeHtml(sp.name)} (${current} \u2192 ${current + amt})</span></div>`;
    }
  });

  // Deaths
  if (deaths.length > 0) {
    html += `<div class="dmg-summary-section"><span class="dmg-summary-item dmg-summary-death">\u2620 To graveyard: ${deaths.map(n => '<strong>' + escapeHtml(n) + '</strong>').join(', ')}</span></div>`;
  }

  html += `</div>`; // summary end
  html += `</div>`; // container end

  previewEl.innerHTML = html;
}

/**
 * Build keyword badges HTML for damage preview.
 */
function buildKeywordBadges(kw) {
  let badges = '';
  if (kw.deathtouch) badges += '<span class="dmg-kw-badge dmg-kw-deathtouch">\u2620 Deathtouch</span>';
  if (kw.trample) badges += '<span class="dmg-kw-badge dmg-kw-trample">\uD83E\uDD8F Trample</span>';
  if (kw.lifelink) badges += '<span class="dmg-kw-badge dmg-kw-lifelink">\u2764 Lifelink</span>';
  if (kw.firstStrike) badges += '<span class="dmg-kw-badge dmg-kw-firststrike">\u26A1 First Strike</span>';
  if (kw.doubleStrike) badges += '<span class="dmg-kw-badge dmg-kw-doublestrike">\u26A1\u26A1 Double Strike</span>';
  if (kw.infect) badges += '<span class="dmg-kw-badge dmg-kw-infect">\u2623 Infect</span>';
  if (kw.indestructible) badges += '<span class="dmg-kw-badge dmg-kw-indestructible">\uD83D\uDC8E Indestructible</span>';
  if (kw.isCommander) badges += '<span class="dmg-kw-badge dmg-kw-commander">\uD83D\uDC51 Commander</span>';
  return badges;
}

/**
 * Adjust damage assigned to a specific blocker in multi-blocker matchup.
 * Ensures total damage doesn't exceed attacker's power and each blocker
 * gets at least 0 damage.
 */
function adjustBlockerDamage(matchupIdx, blockerIdx, delta) {
  if (!gameState || !gameState.combat.damagePreview) return;
  const matchup = gameState.combat.damagePreview[matchupIdx];
  if (!matchup) return;

  const totalPool = matchup.attackerKeywords.doubleStrike
    ? matchup.attackerPower * 2
    : matchup.attackerPower;

  const currentVal = matchup.damageToBlockers[blockerIdx] || 0;
  const usedByOthers = matchup.damageToBlockers.reduce((s, d, i) => i === blockerIdx ? s : s + d, 0);
  const maxForThis = totalPool - usedByOthers;
  const newVal = Math.max(0, Math.min(maxForThis, currentVal + delta));

  matchup.damageToBlockers[blockerIdx] = newVal;

  // Recalculate trample damage
  const totalAssigned = matchup.damageToBlockers.reduce((s, d) => s + d, 0);
  if (matchup.attackerKeywords.trample) {
    const trampleDmg = Math.max(0, totalPool - totalAssigned);
    matchup.damageToPlayer = trampleDmg;
    matchup.playerLifeChange = matchup.attackerKeywords.infect ? 0 : -trampleDmg;
    matchup.playerPoisonChange = matchup.attackerKeywords.infect ? trampleDmg : 0;
    matchup.commanderDamage = matchup.attackerKeywords.isCommander ? trampleDmg : 0;
  }

  // Recalculate lifelink
  if (matchup.attackerKeywords.lifelink) {
    matchup.lifelinkGain = totalAssigned + matchup.damageToPlayer;
  }

  // Re-render
  renderDamagePreviewContent();
}

/**
 * Apply all damage from the preview, resolving life changes, deaths, 
 * commander damage, poison, and lifelink, then clean up combat.
 */
function applyDamageFromPreview() {
  if (!gameState || !gameState.combat.damagePreview) return;
  pushUndoState();

  const matchups = gameState.combat.damagePreview;
  const combat = gameState.combat;
  const toKill = new Set();
  const logLines = [];

  matchups.forEach(m => {
    const attacker = gameState.battlefieldCards.find(c => c.id === m.attackerId);

    // Check if target is a planeswalker
    var isPlaneswalkerTarget = (m.targetPlaneswalkerCardId != null);

    if (!m.isBlocked) {
      // Unblocked — damage to player or planeswalker
      if (m.damageToPlayer > 0) {
        if (isPlaneswalkerTarget) {
          // Damage to planeswalker
          var pwKillId = applyDamageToPlaneswalker(m.targetPlaneswalkerCardId, m.damageToPlayer, logLines);
          if (pwKillId) toKill.add(pwKillId);
          showFloatingDamage('bc-' + m.targetPlaneswalkerCardId, m.damageToPlayer, 'damage');
        } else if (m.attackerKeywords.infect) {
          adjustPoison(m.targetPlayerId, m.damageToPlayer);
          logLines.push(`\u2694 <strong>${escapeHtml(m.attackerName)}</strong> deals <strong>${m.damageToPlayer}</strong> poison to <strong>${escapeHtml(m.targetPlayerName)}</strong> — unblocked.`);
          showFloatingDamage('player-panel-' + m.targetPlayerId, m.damageToPlayer, 'poison');
        } else {
          adjustLife(m.targetPlayerId, -m.damageToPlayer);
          logLines.push(`\u2694 <strong>${escapeHtml(m.attackerName)}</strong> (${m.attackerPower} power) deals <strong>${m.damageToPlayer}</strong> damage to <strong>${escapeHtml(m.targetPlayerName)}</strong> — unblocked.`);
          showFloatingDamage('player-panel-' + m.targetPlayerId, m.damageToPlayer, 'damage');
        }
        // Commander damage
        if (m.commanderDamage > 0 && !isPlaneswalkerTarget) {
          adjustCommanderDamage(m.targetPlayerId, m.attackerOwnerId, m.commanderDamage);
          logLines.push(`\uD83D\uDC51 Commander damage: <strong>${m.commanderDamage}</strong> to <strong>${escapeHtml(m.targetPlayerName)}</strong>.`);
        }
      }
    } else {
      // Blocked — apply damage to each blocker
      m.blockerDetails.forEach((b, bi) => {
        const dmg = m.damageToBlockers[bi] || 0;
        if (dmg > 0) {
          logLines.push(`\u2694 <strong>${escapeHtml(m.attackerName)}</strong> deals <strong>${dmg}</strong>${m.attackerKeywords.deathtouch ? ' (deathtouch)' : ''} to <strong>${escapeHtml(b.name)}</strong>.`);
          // Feature 3: track damage on creature
          var blockerCard = gameState.battlefieldCards.find(function(c) { return c.id === b.cardId; });
          if (blockerCard) {
            if (!blockerCard.damageThisTurn) blockerCard.damageThisTurn = 0;
            blockerCard.damageThisTurn += dmg;
            updateDamageBadge(blockerCard);
          }
          showFloatingDamage('bc-' + b.cardId, dmg, 'damage');
          const isLethal = m.attackerKeywords.deathtouch ? true : (dmg >= b.toughness);
          if (isLethal && !b.keywords.indestructible) {
            toKill.add(b.cardId);
            logLines.push(`\u2620 <strong>${escapeHtml(b.name)}</strong> is destroyed (${dmg} damage, ${b.toughness} toughness).`);
            showFloatingDamage('bc-' + b.cardId, '\u2620', 'death');
          }
        }
      });

      // Blocker damage back to attacker
      if (m.damageToAttacker > 0 && attacker) {
        const anyBlockerDeathtouch = m.blockerDetails.some(b => b.keywords.deathtouch);
        logLines.push(`\uD83D\uDEE1 Blockers deal <strong>${m.damageToAttacker}</strong>${anyBlockerDeathtouch ? ' (deathtouch)' : ''} to <strong>${escapeHtml(m.attackerName)}</strong>.`);
        // Feature 3: track damage on attacker
        if (!attacker.damageThisTurn) attacker.damageThisTurn = 0;
        attacker.damageThisTurn += m.damageToAttacker;
        updateDamageBadge(attacker);
        showFloatingDamage('bc-' + m.attackerId, m.damageToAttacker, 'damage');
        if (m.attackerDies) {
          toKill.add(m.attackerId);
          logLines.push(`\u2620 <strong>${escapeHtml(m.attackerName)}</strong> is destroyed.`);
          showFloatingDamage('bc-' + m.attackerId, '\u2620', 'death');
        }
      }

      // Trample overflow to player
      if (m.damageToPlayer > 0) {
        if (m.attackerKeywords.infect) {
          adjustPoison(m.targetPlayerId, m.damageToPlayer);
          logLines.push(`\uD83E\uDD8F Trample (infect): <strong>${m.damageToPlayer}</strong> poison to <strong>${escapeHtml(m.targetPlayerName)}</strong>.`);
          showFloatingDamage('player-panel-' + m.targetPlayerId, m.damageToPlayer, 'poison');
        } else {
          adjustLife(m.targetPlayerId, -m.damageToPlayer);
          logLines.push(`\uD83E\uDD8F Trample: <strong>${m.damageToPlayer}</strong> damage to <strong>${escapeHtml(m.targetPlayerName)}</strong>.`);
          showFloatingDamage('player-panel-' + m.targetPlayerId, m.damageToPlayer, 'damage');
        }
        if (m.commanderDamage > 0) {
          adjustCommanderDamage(m.targetPlayerId, m.attackerOwnerId, m.commanderDamage);
        }
      }
    }

    // Lifelink
    if (m.lifelinkGain > 0) {
      adjustLife(m.attackerOwnerId, m.lifelinkGain);
      const ownerName = gameState.players[m.attackerOwnerId]?.name || '?';
      logLines.push(`\u2764 Lifelink: <strong>${escapeHtml(ownerName)}</strong> gains <strong>${m.lifelinkGain}</strong> life.`);
      showFloatingDamage('player-panel-' + m.attackerOwnerId, m.lifelinkGain, 'heal');
    }
  });

  // Log all
  logLines.forEach(line => addLogEntry(line));

  // Send killed creatures to graveyard
  toKill.forEach(id => {
    combat.attackers = combat.attackers.filter(a => a.cardId !== id);
    combat.blockers = combat.blockers.filter(b => b.cardId !== id && b.blockingCardId !== id);
    moveCardToZone(id, 'graveyard');
  });

  // Fire damage triggers
  fireBattlefieldTriggers('damage');

  // Feature 4: Show combat recap banner
  showCombatRecap(logLines);

  // Clean up and advance
  hideCombatOverlay();
  clearCombatArrows();
  combat.damagePreview = null;
  gameState.combatPhaseIndex = 4; // end-combat
  renderPlayerPanels();
  renderPhaseTracker();
  addLogEntry('Combat damage resolved.');
  checkStateBasedActions();
  setTimeout(() => nextPhase(), 800);
}


// ============================================================
// COMBAT ENGINE EXPANSION — FEATURE 1: SVG COMBAT ARROWS
// ============================================================

/**
 * Clear all combat arrow SVG paths.
 */
function clearCombatArrows() {
  var svg = document.getElementById('combat-arrows-svg');
  if (!svg) return;
  while (svg.firstChild) svg.removeChild(svg.firstChild);
}

/**
 * Get the center point of an element relative to the combat-arrows-svg container.
 * Returns {x, y} or null if element not found.
 */
function _getElementCenterRelSvg(elId) {
  var svg = document.getElementById('combat-arrows-svg');
  if (!svg) return null;
  var el = document.getElementById(elId);
  if (!el) return null;
  var svgRect = svg.getBoundingClientRect();
  var elRect = el.getBoundingClientRect();
  return {
    x: elRect.left + elRect.width / 2 - svgRect.left,
    y: elRect.top + elRect.height / 2 - svgRect.top
  };
}

/**
 * Draw a single animated curved arrow in the SVG.
 * @param {SVGElement} svg - the SVG container
 * @param {{x,y}} from - start point
 * @param {{x,y}} to - end point
 * @param {string} color - stroke color hex
 * @param {string} markerId - arrowhead marker id
 */
function _drawCombatArrow(svg, from, to, color, markerId) {
  if (!from || !to) return;
  // Quadratic bezier control point (bow outward)
  var dx = to.x - from.x;
  var dy = to.y - from.y;
  var cx = from.x + dx * 0.5 - dy * 0.25;
  var cy = from.y + dy * 0.5 + dx * 0.25;

  var path = document.createElementNS('http://www.w3.org/2000/svg', 'path');
  path.setAttribute('d', 'M' + from.x + ',' + from.y + ' Q' + cx + ',' + cy + ' ' + to.x + ',' + to.y);
  path.setAttribute('stroke', color);
  path.setAttribute('stroke-width', '2.5');
  path.setAttribute('fill', 'none');
  path.setAttribute('opacity', '0.85');
  path.setAttribute('marker-end', 'url(#' + markerId + ')');
  path.classList.add('combat-arrow-path');
  svg.appendChild(path);
}

/**
 * Build arrowhead marker defs in the SVG.
 */
function _buildArrowDefs(svg) {
  var defs = document.createElementNS('http://www.w3.org/2000/svg', 'defs');
  var markers = [
    { id: 'arrow-red',    color: '#D3202A' },
    { id: 'arrow-blue',   color: '#0E68AB' },
    { id: 'arrow-orange', color: '#ff8c00' },
  ];
  markers.forEach(function(m) {
    var marker = document.createElementNS('http://www.w3.org/2000/svg', 'marker');
    marker.setAttribute('id', m.id);
    marker.setAttribute('markerWidth', '8');
    marker.setAttribute('markerHeight', '8');
    marker.setAttribute('refX', '6');
    marker.setAttribute('refY', '3');
    marker.setAttribute('orient', 'auto');
    var poly = document.createElementNS('http://www.w3.org/2000/svg', 'polygon');
    poly.setAttribute('points', '0 0, 6 3, 0 6');
    poly.setAttribute('fill', m.color);
    marker.appendChild(poly);
    defs.appendChild(marker);
  });
  svg.appendChild(defs);
}

/**
 * Update all combat arrows based on current combat state.
 * Called from refreshCombatOverlay, toggleAttacker, toggleBlocker,
 * confirmAttackers, confirmBlockers, showDamagePreview.
 */
function updateCombatArrows() {
  var svg = document.getElementById('combat-arrows-svg');
  if (!svg) return;
  clearCombatArrows();
  if (!gameState) return;
  var combat = gameState.combat;
  if (!combat || !combat.phase) return;

  _buildArrowDefs(svg);

  if (combat.phase === 'declaring-attackers') {
    // Red arrows: attacker card → target player panel (or planeswalker card)
    combat.attackers.forEach(function(a) {
      var from = _getElementCenterRelSvg('bc-' + a.cardId);
      var toId = a.targetPlaneswalkerCardId ? ('bc-' + a.targetPlaneswalkerCardId) : ('player-panel-' + a.targetPlayerId);
      var to   = _getElementCenterRelSvg(toId);
      _drawCombatArrow(svg, from, to, '#D3202A', 'arrow-red');
    });

  } else if (combat.phase === 'declaring-blockers') {
    // Blue arrows: blocker → attacker it's blocking
    var blockedAttackers = new Set();
    combat.blockers.forEach(function(b) {
      var from = _getElementCenterRelSvg('bc-' + b.cardId);
      var to   = _getElementCenterRelSvg('bc-' + b.blockingCardId);
      _drawCombatArrow(svg, from, to, '#0E68AB', 'arrow-blue');
      blockedAttackers.add(b.blockingCardId);
    });
    // Red arrows: unblocked attackers → target player/planeswalker
    combat.attackers.forEach(function(a) {
      if (!blockedAttackers.has(a.cardId)) {
        var from = _getElementCenterRelSvg('bc-' + a.cardId);
        var uToId = a.targetPlaneswalkerCardId ? ('bc-' + a.targetPlaneswalkerCardId) : ('player-panel-' + a.targetPlayerId);
        var to   = _getElementCenterRelSvg(uToId);
        _drawCombatArrow(svg, from, to, '#D3202A', 'arrow-red');
      }
    });

  } else if (combat.phase === 'previewing-damage') {
    // Arrows from preview data
    if (combat.damagePreview) {
      combat.damagePreview.forEach(function(m) {
        if (!m.isBlocked) {
          // Red: attacker → target player/planeswalker
          var from = _getElementCenterRelSvg('bc-' + m.attackerId);
          var pToId = m.targetPlaneswalkerCardId ? ('bc-' + m.targetPlaneswalkerCardId) : ('player-panel-' + m.targetPlayerId);
          var to   = _getElementCenterRelSvg(pToId);
          _drawCombatArrow(svg, from, to, '#D3202A', 'arrow-red');
        } else {
          // Orange: attacker → each blocker
          m.blockerDetails.forEach(function(b) {
            var from = _getElementCenterRelSvg('bc-' + m.attackerId);
            var to   = _getElementCenterRelSvg('bc-' + b.cardId);
            _drawCombatArrow(svg, from, to, '#ff8c00', 'arrow-orange');
          });
          // If trample, also red arrow to player/planeswalker
          if (m.attackerKeywords && m.attackerKeywords.trample && m.damageToPlayer > 0) {
            var from2 = _getElementCenterRelSvg('bc-' + m.attackerId);
            var tToId = m.targetPlaneswalkerCardId ? ('bc-' + m.targetPlaneswalkerCardId) : ('player-panel-' + m.targetPlayerId);
            var to2   = _getElementCenterRelSvg(tToId);
            _drawCombatArrow(svg, from2, to2, '#D3202A', 'arrow-red');
          }
        }
      });
    }
  }
}


// ============================================================
// COMBAT ENGINE EXPANSION — FEATURE 2: FLOATING DAMAGE NUMBERS
// ============================================================

/**
 * Show a floating damage/heal/poison/death number at a card or player element.
 * @param {string} elementId - DOM element ID (e.g. 'bc-123' or 'player-panel-0')
 * @param {number|string} amount - the number or symbol to show
 * @param {string} type - 'damage' | 'heal' | 'poison' | 'death'
 */
function showFloatingDamage(elementId, amount, type) {
  var el = document.getElementById(elementId);
  if (!el) return;

  // Trigger visual flash on the element
  triggerDamageFlash(elementId, type);

  // Screen shake for big damage (10+)
  if (type === 'damage' && typeof amount === 'number' && amount >= 10) {
    triggerScreenShake();
  }

  var rect = el.getBoundingClientRect();

  var div = document.createElement('div');
  div.className = 'floating-damage floating-damage-' + type;

  if (type === 'damage') {
    div.textContent = '-' + amount;
  } else if (type === 'heal') {
    div.textContent = '+' + amount;
  } else if (type === 'poison') {
    div.textContent = '+' + amount + '\u2623';
  } else if (type === 'death') {
    div.textContent = '\u2620';
  } else {
    div.textContent = amount;
  }

  // Randomize x position slightly so multiple numbers don't stack
  var xOff = (Math.random() * 20) - 10;
  div.style.left = (rect.left + rect.width / 2 - 15 + xOff) + 'px';
  div.style.top  = (rect.top + rect.height / 3) + 'px';

  document.body.appendChild(div);

  // Remove after animation completes
  setTimeout(function() {
    if (div.parentNode) div.parentNode.removeChild(div);
  }, 1600);
}


// ============================================================
// COMBAT ENGINE EXPANSION — FEATURE 3: DAMAGE MARKERS
// ============================================================

/**
 * Update the damage badge on a battlefield card.
 * Creates or removes the .bf-damage-badge based on card.damageThisTurn.
 */
function updateDamageBadge(cardData) {
  var cardEl = document.getElementById('bc-' + cardData.id);
  if (!cardEl) return;
  var existing = cardEl.querySelector('.bf-damage-badge');
  if (cardData.damageThisTurn && cardData.damageThisTurn > 0) {
    if (!existing) {
      existing = document.createElement('div');
      existing.className = 'bf-damage-badge';
      cardEl.appendChild(existing);
    }
    existing.textContent = cardData.damageThisTurn;
    // Also update P/T overlay if creature has taken damage
    var ptOverlay = cardEl.querySelector('.card-pt-overlay');
    if (ptOverlay && cardData.pt) {
      var parts = cardData.pt.split('/');
      var origTou = parseInt(parts[1], 10);
      if (!isNaN(origTou)) {
        var remaining = origTou - cardData.damageThisTurn;
        ptOverlay.textContent = parts[0] + '/' + remaining;
        ptOverlay.classList.add('pt-overlay-damaged');
      }
    }
  } else {
    if (existing) existing.parentNode.removeChild(existing);
    // Reset P/T overlay
    var ptOverlay2 = cardEl.querySelector('.card-pt-overlay');
    if (ptOverlay2 && cardData.pt) {
      ptOverlay2.textContent = cardData.pt;
      ptOverlay2.classList.remove('pt-overlay-damaged');
    }
  }
}

/**
 * Clear all damage-this-turn counters from all battlefield cards.
 * Called from nextTurn().
 */
function clearAllDamageCounters() {
  if (!gameState) return;
  gameState.battlefieldCards.forEach(function(card) {
    if (card.damageThisTurn && card.damageThisTurn > 0) {
      card.damageThisTurn = 0;
      updateDamageBadge(card);
    }
  });
}


// ============================================================
// COMBAT ENGINE EXPANSION — FEATURE 4: COMBAT RECAP SUMMARY
// ============================================================

/**
 * Show an animated combat recap banner at the top of the battlefield.
 * Auto-dismisses after 5 seconds or on click.
 * @param {string[]} logLines - array of HTML log lines from combat resolution
 */
function showCombatRecap(logLines) {
  // Remove any existing recap
  var old = document.getElementById('combat-recap-banner');
  if (old && old.parentNode) old.parentNode.removeChild(old);

  if (!logLines || logLines.length === 0) return;

  // Build summary by extracting key events
  var summaryLines = [];

  // Damage to players
  var playerDmgMap = {};
  var lifeGainMap = {};
  var deaths = [];
  var poisonMap = {};

  logLines.forEach(function(line) {
    // Player damage: lines containing "damage to <Player>" not from trample text about a creature
    var dmgMatch = line.match(/deals.*?(\d+).*?damage to <strong>([^<]+)<\/strong>/);
    if (dmgMatch) {
      var amt = parseInt(dmgMatch[1], 10);
      var name = dmgMatch[2];
      // Only player damage (players match names in gameState)
      if (gameState) {
        gameState.players.forEach(function(p) {
          if (p.name === name) {
            playerDmgMap[name] = (playerDmgMap[name] || 0) + amt;
          }
        });
      }
    }
    // Deaths
    var deathMatch = line.match(/\u2620.*?<strong>([^<]+)<\/strong>.*?is destroyed/);
    if (deathMatch) deaths.push(deathMatch[1]);
    // Life gain (lifelink)
    var lifeMatch = line.match(/Lifelink.*?<strong>([^<]+)<\/strong>.*?gains.*?<strong>(\d+)<\/strong>/);
    if (lifeMatch) {
      lifeGainMap[lifeMatch[1]] = (lifeGainMap[lifeMatch[1]] || 0) + parseInt(lifeMatch[2], 10);
    }
    // Poison
    var poisonMatch = line.match(/poison.*?<strong>([^<]+)<\/strong>/);
    if (poisonMatch) {
      poisonMap[poisonMatch[1]] = (poisonMap[poisonMatch[1]] || 0) + 1;
    }
  });

  var parts = [];
  Object.entries(playerDmgMap).forEach(function(pair) {
    parts.push('<span class="recap-dmg">' + escapeHtml(pair[0]) + ' takes ' + pair[1] + ' damage</span>');
  });
  deaths.forEach(function(n) {
    parts.push('<span class="recap-death">\u2620 ' + escapeHtml(n) + ' destroyed</span>');
  });
  Object.entries(lifeGainMap).forEach(function(pair) {
    parts.push('<span class="recap-heal">\u2764 ' + escapeHtml(pair[0]) + ' gains ' + pair[1] + ' life</span>');
  });
  Object.entries(poisonMap).forEach(function(pair) {
    parts.push('<span class="recap-poison">\u2623 ' + escapeHtml(pair[0]) + ' poisoned</span>');
  });

  if (parts.length === 0) return;

  var banner = document.createElement('div');
  banner.id = 'combat-recap-banner';
  banner.className = 'combat-recap-banner';
  banner.innerHTML = '<span class="recap-title">\u2694 Combat: </span>' + parts.join(' &bull; ')
    + '<button class="recap-close" onclick="(function(){var b=document.getElementById(\'combat-recap-banner\');if(b&&b.parentNode)b.parentNode.removeChild(b);})()" title="Dismiss">\u2715</button>';

  var battlefield = document.getElementById('battlefield');
  if (battlefield) {
    battlefield.appendChild(banner);
  } else {
    document.body.appendChild(banner);
  }

  // Auto-dismiss after 5 seconds
  setTimeout(function() {
    var b = document.getElementById('combat-recap-banner');
    if (b && b.parentNode) {
      b.classList.add('recap-fade-out');
      setTimeout(function() {
        var b2 = document.getElementById('combat-recap-banner');
        if (b2 && b2.parentNode) b2.parentNode.removeChild(b2);
      }, 500);
    }
  }, 5000);
}


// ============================================================
// COMBAT ENGINE EXPANSION — FEATURE 5: KEYWORD ENFORCEMENT
// ============================================================

/**
 * Check if a card has a given color.
 * Uses card.colors array or falls back to parsing oracle/type text.
 * @param {object} card
 * @param {string} colorCode - 'W','U','B','R','G'
 */
function cardHasColor(card, colorCode) {
  if (!card) return false;
  // Try colors array first
  if (Array.isArray(card.colors)) {
    return card.colors.indexOf(colorCode.toUpperCase()) !== -1;
  }
  // Try manaCost parsing if available
  if (card.manaCost) {
    var mc = card.manaCost.toUpperCase();
    return mc.indexOf(colorCode.toUpperCase()) !== -1;
  }
  return false;
}

/**
 * Check if a card is an artifact creature (for intimidate/fear blocking).
 */
function cardIsArtifactCreature(card) {
  if (!card || !card.typeLine) return false;
  var tl = card.typeLine.toLowerCase();
  return tl.indexOf('artifact') !== -1 && tl.indexOf('creature') !== -1;
}

/**
 * Menace: check that all menace attackers have 2+ blockers.
 * Returns the first menace attacker with exactly 1 blocker, or null.
 */
function checkMenaceViolation() {
  if (!gameState) return null;
  var combat = gameState.combat;
  for (var i = 0; i < combat.attackers.length; i++) {
    var a = combat.attackers[i];
    var attacker = gameState.battlefieldCards.find(function(c) { return c.id === a.cardId; });
    if (!attacker) continue;
    if (!hasKeyword(attacker, 'menace')) continue;
    // Count blockers assigned to this attacker
    var blockerCount = combat.blockers.filter(function(b) { return b.blockingCardId === a.cardId; }).length;
    if (blockerCount === 1) return attacker;
  }
  return null;
}


// ============================================================
// COMBAT ENGINE EXPANSION — FEATURE 6: PLANESWALKER TARGETS
// ============================================================

/**
 * Get all planeswalker cards on the battlefield controlled by opponents
 * of the current player.
 */
function getOpponentPlaneswalkers() {
  if (!gameState) return [];
  return gameState.battlefieldCards.filter(function(c) {
    if (c.ownerId === gameState.currentPlayerIndex) return false;
    if (!c.typeLine) return false;
    return c.typeLine.toLowerCase().indexOf('planeswalker') !== -1;
  });
}

/**
 * Apply combat damage to a planeswalker target (reduce loyalty counters).
 * @param {number} planeswalkerCardId
 * @param {number} damage
 * @param {string[]} logLines - array to append log entries to
 */
function applyDamageToPlaneswalker(planeswalkerCardId, damage, logLines) {
  if (!gameState) return;
  var pw = gameState.battlefieldCards.find(function(c) { return c.id === planeswalkerCardId; });
  if (!pw) return;
  if (!pw.counters) pw.counters = {};
  var currentLoyalty = pw.counters['loyalty'] || 0;
  var newLoyalty = Math.max(0, currentLoyalty - damage);
  pw.counters['loyalty'] = newLoyalty;
  if (logLines) {
    logLines.push('\u2694 <strong>' + escapeHtml(pw.name) + '</strong> takes ' + damage + ' damage (' + currentLoyalty + ' \u2192 ' + newLoyalty + ' loyalty).');
  }
  // Planeswalker dies at 0 loyalty
  if (newLoyalty <= 0) {
    if (logLines) logLines.push('\u2620 <strong>' + escapeHtml(pw.name) + '</strong> is defeated (0 loyalty).');
    return planeswalkerCardId; // Signal to kill this card
  }
  // Update the card visual
  updateDamageBadge(pw);
  return null;
}

// ============================================================
// PLANESWALKER LOYALTY ABILITY SYSTEM
// ============================================================

/**
 * Reset loyalty ability usage for all planeswalkers at start of turn.
 * Called from advancePhase when transitioning to a new turn.
 */
function resetPlaneswalkerLoyaltyUsage() {
  if (!gameState) return;
  gameState.battlefieldCards.forEach(function(c) {
    if (c.typeLine && /planeswalker/i.test(c.typeLine)) {
      c.loyaltyUsedThisTurn = false;
    }
  });
}

/**
 * Show the loyalty ability picker overlay for a planeswalker card.
 * Only the controller can activate, and only once per turn, at sorcery speed.
 */
function showPlaneswalkerAbilities(cardId) {
  if (!gameState) return;
  var card = gameState.battlefieldCards.find(function(c) { return c.id === cardId; });
  if (!card) return;
  if (!card.typeLine || !/planeswalker/i.test(card.typeLine)) return;

  // Check ownership
  if (card.ownerIndex !== gameState.currentPlayerIndex) {
    addLogEntry('\u26a0 Only the controller can activate loyalty abilities.');
    return;
  }

  // Check if already used this turn
  if (card.loyaltyUsedThisTurn) {
    addLogEntry('\u26a0 <strong>' + card.name + '</strong> has already used a loyalty ability this turn.');
    return;
  }

  // Parse loyalty abilities from oracle text
  var abilities = parseCardAbilities(card.oracleText || '', card.typeLine || '', card.name || '');
  if (!abilities.loyalty || abilities.loyalty.length === 0) {
    addLogEntry('\u26a0 No loyalty abilities found on <strong>' + card.name + '</strong>.');
    return;
  }

  var currentLoyalty = (card.counters && card.counters['loyalty']) || 0;

  // Build overlay
  var existing = document.getElementById('pw-ability-overlay');
  if (existing) existing.remove();

  var overlay = document.createElement('div');
  overlay.id = 'pw-ability-overlay';
  overlay.className = 'pw-ability-overlay';

  var html = '<div class="pw-ability-panel">';
  html += '<div class="pw-ability-header">';
  html += '<span class="pw-ability-name">' + escapeHtml(card.name) + '</span>';
  html += '<span class="pw-ability-loyalty-display">\u25c6 ' + currentLoyalty + '</span>';
  html += '<button class="pw-ability-close" onclick="closePlaneswalkerAbilities()">\u2715</button>';
  html += '</div>';
  html += '<div class="pw-ability-list">';

  for (var i = 0; i < abilities.loyalty.length; i++) {
    var ab = abilities.loyalty[i];
    var costNum = parseInt(ab.cost.replace('\u2212', '-'), 10);
    var canAfford = true;
    // For minus abilities, check if we have enough loyalty
    if (costNum < 0 && currentLoyalty + costNum < 0) {
      canAfford = false;
    }
    var isPlus = ab.cost.startsWith('+');
    var isZero = ab.cost === '0';
    var badgeClass = isPlus ? 'pw-cost-plus' : isZero ? 'pw-cost-zero' : 'pw-cost-minus';
    var disabledClass = canAfford ? '' : ' pw-ability-disabled';
    var disabledAttr = canAfford ? '' : ' disabled';

    html += '<button class="pw-ability-btn' + disabledClass + '"' + disabledAttr;
    html += ' onclick="activatePlaneswalkerAbility(' + cardId + ',' + i + ')">';
    html += '<span class="pw-cost-badge ' + badgeClass + '">' + escapeHtml(ab.cost) + '</span>';
    html += '<span class="pw-ability-effect">' + formatManaSymbols(ab.effect) + '</span>';
    if (!canAfford) {
      html += '<span class="pw-ability-insufficient">(not enough loyalty)</span>';
    }
    html += '</button>';
  }

  html += '</div>';
  html += '</div>';
  overlay.innerHTML = html;

  // Click outside to close
  overlay.addEventListener('click', function(e) {
    if (e.target === overlay) closePlaneswalkerAbilities();
  });

  document.body.appendChild(overlay);
}

function closePlaneswalkerAbilities() {
  var overlay = document.getElementById('pw-ability-overlay');
  if (overlay) overlay.remove();
}

/**
 * Activate a specific loyalty ability on a planeswalker.
 * Adjusts loyalty counters and attempts to execute the effect.
 */
function activatePlaneswalkerAbility(cardId, abilityIndex) {
  if (!gameState) return;
  var card = gameState.battlefieldCards.find(function(c) { return c.id === cardId; });
  if (!card) return;

  var abilities = parseCardAbilities(card.oracleText || '', card.typeLine || '', card.name || '');
  if (!abilities.loyalty || !abilities.loyalty[abilityIndex]) return;

  var ab = abilities.loyalty[abilityIndex];
  var costNum = parseInt(ab.cost.replace('\u2212', '-'), 10);
  if (isNaN(costNum)) costNum = 0;

  if (!card.counters) card.counters = {};
  var currentLoyalty = card.counters['loyalty'] || 0;

  // Verify we can pay
  if (costNum < 0 && currentLoyalty + costNum < 0) {
    addLogEntry('\u26a0 Not enough loyalty on <strong>' + card.name + '</strong> to activate [' + ab.cost + '].');
    closePlaneswalkerAbilities();
    return;
  }

  pushUndoState('PW Ability: ' + card.name);

  // Pay the cost (adjust loyalty)
  var newLoyalty = currentLoyalty + costNum;
  card.counters['loyalty'] = newLoyalty;
  card.loyaltyUsedThisTurn = true;

  addLogEntry('\u25c6 <strong>' + escapeHtml(card.name) + '</strong> [' + ab.cost + ']: ' + escapeHtml(ab.effect) + ' (Loyalty: ' + currentLoyalty + ' \u2192 ' + newLoyalty + ')');

  // Execute the effect
  executePlaneswalkerEffect(card, ab.effect, ab.cost);

  // Check if planeswalker dies from 0 loyalty
  if (newLoyalty <= 0) {
    addLogEntry('\u2620 <strong>' + escapeHtml(card.name) + '</strong> is defeated (0 loyalty).');
    moveCardToZone(cardId, 'graveyard');
  } else {
    // Update the visual
    var bcEl = document.getElementById('bc-' + card.id);
    if (bcEl) bcEl.remove();
    renderBattlefieldCard(card);
  }

  closePlaneswalkerAbilities();
}

/**
 * Attempt to auto-execute common planeswalker ability effects.
 * Falls back to a log message for complex effects.
 */
function executePlaneswalkerEffect(card, effectText, cost) {
  if (!effectText || !gameState) return;
  var owner = card.ownerIndex;
  var text = effectText.toLowerCase();

  // --- Draw cards ---
  var drawMatch = text.match(/draw (a card|one card|two cards?|three cards?|four cards?|five cards?|(\d+) cards?)/i);
  if (drawMatch) {
    var drawCount = 1;
    var drawWords = { 'a card': 1, 'one card': 1, 'two cards': 2, 'three cards': 3, 'four cards': 4, 'five cards': 5 };
    var dKey = drawMatch[1].toLowerCase().replace(/s$/, '').replace(/cards/, 'card');
    if (drawWords[dKey] !== undefined) drawCount = drawWords[dKey];
    else if (drawMatch[2]) drawCount = parseInt(drawMatch[2], 10);
    for (var d = 0; d < drawCount; d++) drawCard(owner);
    addLogEntry('\u2713 Auto-effect: Drew ' + drawCount + ' card(s)');
  }

  // --- Gain life ---
  var gainMatch = text.match(/you gain (\d+) life/i);
  if (gainMatch) {
    var gain = parseInt(gainMatch[1], 10);
    adjustLife(owner, gain);
    addLogEntry('\u2713 Auto-effect: Gained ' + gain + ' life');
  }

  // --- Lose life (opponents) ---
  var oppLoseMatch = text.match(/each opponent loses (\d+) life/i);
  if (oppLoseMatch) {
    var oppLoss = parseInt(oppLoseMatch[1], 10);
    gameState.players.forEach(function(p, i) {
      if (i !== owner && !p.eliminated) {
        adjustLife(i, -oppLoss);
      }
    });
    addLogEntry('\u2713 Auto-effect: Each opponent loses ' + oppLoss + ' life');
  }

  // --- Deal damage ---
  var dmgMatch = text.match(/deals? (\d+) damage to (?:any target|target)/i);
  if (dmgMatch) {
    var dmgAmt = parseInt(dmgMatch[1], 10);
    addLogEntry('\u2b50 Effect: Deal ' + dmgAmt + ' damage to any target \u2014 choose target manually');
  }

  // --- Create tokens ---
  var tokenSpecs = parseTokenCreationAbilities(effectText);
  if (tokenSpecs.length > 0) {
    for (var ti = 0; ti < tokenSpecs.length; ti++) {
      var ts = tokenSpecs[ti];
      createQuickToken(owner, ts.name, ts.power, ts.toughness, ts.typeLine, ts.color, ts.abilities, ts.count);
      addLogEntry('\u2713 Auto-effect: Created ' + ts.displayLabel);
    }
  }

  // --- Create Treasure ---
  if (/create .* treasure/i.test(effectText) && tokenSpecs.length === 0) {
    var treasureCountMatch = effectText.match(/(two|three|four|five|\d+) treasure/i);
    var tCount = 1;
    if (treasureCountMatch) {
      var tw = { two: 2, three: 3, four: 4, five: 5 };
      tCount = tw[treasureCountMatch[1].toLowerCase()] || parseInt(treasureCountMatch[1], 10) || 1;
    }
    createQuickToken(owner, 'Treasure', '', '', 'Artifact \u2014 Treasure', 'C', 'Sacrifice: Add one mana of any color', tCount);
    addLogEntry('\u2713 Auto-effect: Created ' + tCount + 'x Treasure');
  }

  // --- Mill / self-mill ---
  var millMatch = text.match(/mills? (\d+) cards?/i) || text.match(/put the top (\d+) cards? .* into .* graveyard/i);
  if (millMatch) {
    var millAmt = parseInt(millMatch[1], 10);
    millCards(owner, millAmt);
    addLogEntry('\u2713 Auto-effect: Milled ' + millAmt + ' cards');
  }

  // --- Scry ---
  var scryMatch = text.match(/scry (\d+)/i);
  if (scryMatch) {
    var scryAmt = parseInt(scryMatch[1], 10);
    openScryModal(owner, scryAmt);
    addLogEntry('\u2713 Auto-effect: Scry ' + scryAmt);
  }

  // --- Destroy target ---
  if (/destroy (target|all|each)/i.test(text)) {
    addLogEntry('\u2b50 Effect: Destroy \u2014 choose target(s) manually');
  }

  // --- Exile ---
  if (/exile (target|a |up to)/i.test(text)) {
    addLogEntry('\u2b50 Effect: Exile \u2014 choose target(s) manually');
  }

  // --- Return to hand ---
  if (/return .* to .* (hand|owner)/i.test(text)) {
    addLogEntry('\u2b50 Effect: Return \u2014 choose target(s) manually');
  }

  // --- +1/+1 counters ---
  var counterMatch = text.match(/put (a|one|two|three|\d+) \+1\/\+1 counter/i);
  if (counterMatch) {
    var cw = { 'a': 1, 'one': 1, 'two': 2, 'three': 3 };
    var cAmt = cw[counterMatch[1].toLowerCase()] || parseInt(counterMatch[1], 10) || 1;
    addLogEntry('\u2b50 Effect: Put ' + cAmt + ' +1/+1 counter(s) \u2014 choose target manually');
  }

  // --- Ultimate / Emblem ---
  if (/you get an emblem/i.test(text)) {
    addLogEntry('\u2b50 ULTIMATE: You get an emblem \u2014 ' + escapeHtml(effectText));
  }

  // --- Search library ---
  if (/search your library/i.test(text)) {
    addLogEntry('\u2b50 Effect: Search your library \u2014 use deck viewer to find the card');
  }

  // --- Discard ---
  var discardMatch = text.match(/discard (a|\d+) cards?/i);
  if (discardMatch) {
    addLogEntry('\u2b50 Effect: Discard \u2014 choose card(s) from hand manually');
  }
}

// ============================================================
// AI SPELL CAST RESPONSE SYSTEM
// ============================================================

/**
 * Global state for the AI cast pause system.
 * When an AI casts a spell, the action queue is paused until the human responds.
 */
var _aiCastPauseState = null;

/**
 * AI target selection for removal/targeted spells.
 * Returns { targetName, targetCardId, targetType } or null.
 */
function aiSelectSpellTarget(card, aiPlayerIdx) {
  if (!gameState || !card) return null;
  var oracle = (card.oracleText || '').toLowerCase();
  var typeLine = (card.typeLine || '').toLowerCase();

  // Check if this is a targeted spell
  var isRemoval = /destroy target|exile target|deals? \d+ damage to (target|any target|any one target)/.test(oracle);
  var isTargetedBuff = /target creature gets|put .* counter on target|enchant creature/.test(oracle);
  var isTargetedBounce = /return target .* to .* (hand|owner)/.test(oracle);
  var isBoardWipe = /destroy all|all creatures get \-|exile all|each creature/.test(oracle);

  if (isBoardWipe) {
    return { targetName: 'All', targetCardId: null, targetType: 'board_wipe' };
  }

  if (!isRemoval && !isTargetedBounce) return null;

  // Find best target among opponents' battlefield cards
  var candidates = gameState.battlefieldCards.filter(function(c) {
    if (c.ownerIndex === aiPlayerIdx) return false;
    // Match type restriction
    var cType = (c.typeLine || '').toLowerCase();
    if (/destroy target creature|exile target creature|damage to target creature/.test(oracle)) {
      return /creature/.test(cType);
    }
    if (/destroy target artifact/.test(oracle)) return /artifact/.test(cType);
    if (/destroy target enchantment/.test(oracle)) return /enchantment/.test(cType);
    if (/destroy target planeswalker/.test(oracle)) return /planeswalker/.test(cType);
    if (/destroy target permanent|exile target permanent|exile target nonland/.test(oracle)) {
      return !/land/.test(cType) || /destroy target permanent/.test(oracle);
    }
    // Generic "target" — prefer creatures
    return true;
  });

  if (candidates.length === 0) return null;

  // Score candidates by threat (power, CMC, keywords)
  candidates.sort(function(a, b) {
    var scoreA = 0, scoreB = 0;
    var aType = (a.typeLine || '').toLowerCase();
    var bType = (b.typeLine || '').toLowerCase();
    // Prefer creatures with high power
    if (a.power) scoreA += parseInt(a.power, 10) || 0;
    if (b.power) scoreB += parseInt(b.power, 10) || 0;
    // Planeswalkers are high priority
    if (/planeswalker/.test(aType)) scoreA += 5;
    if (/planeswalker/.test(bType)) scoreB += 5;
    // Commander bonus
    if (a.isCommander) scoreA += 4;
    if (b.isCommander) scoreB += 4;
    // Higher CMC = bigger threat
    scoreA += (a.cmc || 0);
    scoreB += (b.cmc || 0);
    // Keywords that make things dangerous
    var aText = (a.oracleText || '').toLowerCase();
    var bText = (b.oracleText || '').toLowerCase();
    if (/flying|trample|double strike|lifelink|hexproof|indestructible/.test(aText)) scoreA += 3;
    if (/flying|trample|double strike|lifelink|hexproof|indestructible/.test(bText)) scoreB += 3;
    return scoreB - scoreA;
  });

  var target = candidates[0];
  return {
    targetName: target.name,
    targetCardId: target.id,
    targetType: /creature/.test((target.typeLine || '').toLowerCase()) ? 'creature' :
                /planeswalker/.test((target.typeLine || '').toLowerCase()) ? 'planeswalker' : 'permanent'
  };
}

/**
 * Show the AI cast response popup.
 * Pauses the AI action queue and gives the human player a chance to respond.
 */
function showAiCastPopup(card, aiPlayerIdx, handIndex, aiTarget) {
  if (!gameState) return;
  var aiPlayer = gameState.players[aiPlayerIdx];
  if (!aiPlayer) return;

  // Store pause state so the AI action queue knows to wait
  _aiCastPauseState = {
    card: card,
    aiPlayerIdx: aiPlayerIdx,
    handIndex: handIndex,
    aiTarget: aiTarget,
  };

  var existing = document.getElementById('ai-cast-popup');
  if (existing) existing.remove();

  var overlay = document.createElement('div');
  overlay.id = 'ai-cast-popup';
  overlay.className = 'ai-cast-overlay';

  var targetHtml = '';
  if (aiTarget) {
    if (aiTarget.targetType === 'board_wipe') {
      targetHtml = '<div class="ai-cast-target"><span class="ai-cast-target-label">Target:</span> <strong>All creatures/permanents</strong></div>';
    } else {
      targetHtml = '<div class="ai-cast-target"><span class="ai-cast-target-label">Target:</span> <strong>' + escapeHtml(aiTarget.targetName) + '</strong> (' + aiTarget.targetType + ')</div>';
    }
  }

  var oraclePreview = card.oracleText ? '<div class="ai-cast-oracle">' + escapeHtml(card.oracleText).substring(0, 250) + '</div>' : '';
  var manaCostHtml = card.manaCost ? '<span class="ai-cast-mana">' + formatManaSymbols(card.manaCost) + '</span>' : '';

  var imgHtml = card.imageUrl ? '<img src="' + card.imageUrl + '" class="ai-cast-card-img" alt="' + escapeHtml(card.name) + '"/>' : '';

  overlay.innerHTML =
    '<div class="ai-cast-panel">' +
      '<div class="ai-cast-header">' +
        '<span class="ai-cast-caster" style="color:' + (aiPlayer.color || '#e74c3c') + '">\ud83e\udd16 ' + escapeHtml(aiPlayer.name) + ' casts:</span>' +
      '</div>' +
      '<div class="ai-cast-body">' +
        '<div class="ai-cast-card-info">' +
          imgHtml +
          '<div class="ai-cast-card-details">' +
            '<div class="ai-cast-card-name">' + escapeHtml(card.name) + ' ' + manaCostHtml + '</div>' +
            '<div class="ai-cast-card-type">' + escapeHtml(card.typeLine || '') + '</div>' +
            oraclePreview +
            targetHtml +
          '</div>' +
        '</div>' +
      '</div>' +
      '<div class="ai-cast-actions">' +
        '<button class="ai-cast-btn ai-cast-allow" onclick="resolveAiCast()">\u2713 Allow (Resolve)</button>' +
        '<button class="ai-cast-btn ai-cast-respond" onclick="respondToAiCast()">\u270b Respond</button>' +
      '</div>' +
    '</div>';

  document.body.appendChild(overlay);
}

/**
 * Human allows the AI spell to resolve. Remove popup and execute the cast.
 */
function resolveAiCast() {
  if (!_aiCastPauseState || !gameState) return;
  var state = _aiCastPauseState;
  _aiCastPauseState = null;

  var popup = document.getElementById('ai-cast-popup');
  if (popup) popup.remove();

  var player = gameState.players[state.aiPlayerIdx];
  if (!player) return;
  var hand = player.zones.hand;

  // Re-find the card in hand (index may have shifted)
  var ci = hand.indexOf(state.card);
  if (ci === -1) {
    // Card no longer in hand, maybe it was removed
    addLogEntry('\u26a0 Spell fizzled \u2014 card no longer in hand.');
    return;
  }

  // Execute the cast
  hand.splice(ci, 1);

  var card = state.card;
  var typeLine = (card.typeLine || '').toLowerCase();
  var isInstantOrSorcery = /instant|sorcery/.test(typeLine);

  if (isInstantOrSorcery) {
    // Execute effect based on AI target
    if (state.aiTarget && state.aiTarget.targetCardId) {
      aiExecuteTargetedSpell(card, state.aiTarget, state.aiPlayerIdx);
    } else if (state.aiTarget && state.aiTarget.targetType === 'board_wipe') {
      aiExecuteBoardWipe(card, state.aiPlayerIdx);
    }
    // Log oracle text for manual resolution of complex effects
    addLogEntry('\u2713 <strong>' + escapeHtml(card.name) + '</strong> resolves.');
    if (card.oracleText) {
      addLogEntry('<em style="color:rgba(255,255,255,0.6);font-size:11px;margin-left:8px">' + escapeHtml(card.oracleText).substring(0, 200) + '</em>');
    }
    // Send to graveyard
    player.zones.graveyard.push({
      name: card.name, imageUrl: card.imageUrl, typeLine: card.typeLine || '',
      oracleText: card.oracleText || '', manaCost: card.manaCost || '', cmc: card.cmc || 0,
      power: card.power || '', toughness: card.toughness || '', pt: card.pt || '',
    });
    updatePlayerZones();
    fireBattlefieldTriggers('cast');
  } else {
    // Permanent: put on battlefield
    addCardToBattlefield(card.name, card.imageUrl, card.typeLine, state.aiPlayerIdx, undefined, undefined, card.oracleText || '',
      { manaCost: card.manaCost || '', power: card.power || '', toughness: card.toughness || '',
        pt: card.pt || '', cmc: card.cmc || 0, loyalty: card.loyalty || '',
        colorIdentity: card.colorIdentity, keywords: card.keywords });
  }

  renderHandArea();
}

/**
 * Human wants to respond to the AI spell. Close popup but keep the spell pending.
 * The spell is "on the stack" conceptually. The human can take actions, then click a
 * "Done Responding" button to let it resolve or counter it.
 */
function respondToAiCast() {
  if (!_aiCastPauseState || !gameState) return;

  var popup = document.getElementById('ai-cast-popup');
  if (popup) popup.remove();

  // Show a small "spell pending" banner with resolve/counter options
  var banner = document.createElement('div');
  banner.id = 'ai-cast-pending-banner';
  banner.className = 'ai-cast-pending-banner';
  var cardName = _aiCastPauseState.card ? _aiCastPauseState.card.name : 'Unknown Spell';
  banner.innerHTML =
    '<span class="ai-cast-pending-text">\ud83d\udcda On the stack: <strong>' + escapeHtml(cardName) + '</strong> \u2014 Take your actions, then:</span>' +
    '<button class="ai-cast-btn ai-cast-allow" onclick="resolveAiCast()">\u2713 Let It Resolve</button>' +
    '<button class="ai-cast-btn ai-cast-counter" onclick="counterAiCast()">\u274c Counter (Fizzle)</button>';
  document.body.appendChild(banner);

  addLogEntry('\u270b You are responding to <strong>' + escapeHtml(cardName) + '</strong>...');
}

/**
 * Counter/fizzle the AI's pending spell.
 */
function counterAiCast() {
  if (!_aiCastPauseState || !gameState) return;
  var state = _aiCastPauseState;
  _aiCastPauseState = null;

  var banner = document.getElementById('ai-cast-pending-banner');
  if (banner) banner.remove();

  var card = state.card;
  var player = gameState.players[state.aiPlayerIdx];
  if (!player) return;

  // Remove from hand
  var ci = player.zones.hand.indexOf(card);
  if (ci !== -1) player.zones.hand.splice(ci, 1);

  // Send to graveyard (countered)
  player.zones.graveyard.push({
    name: card.name, imageUrl: card.imageUrl, typeLine: card.typeLine || '',
    oracleText: card.oracleText || '', manaCost: card.manaCost || '', cmc: card.cmc || 0,
    power: card.power || '', toughness: card.toughness || '', pt: card.pt || '',
  });

  addLogEntry('\u274c <strong>' + escapeHtml(card.name) + '</strong> was countered!');
  updatePlayerZones();
  renderHandArea();
}

/**
 * Execute a targeted AI removal spell effect.
 */
function aiExecuteTargetedSpell(card, target, aiPlayerIdx) {
  if (!gameState || !target || !target.targetCardId) return;
  var oracle = (card.oracleText || '').toLowerCase();

  var targetCard = gameState.battlefieldCards.find(function(c) { return c.id === target.targetCardId; });
  if (!targetCard) {
    addLogEntry('\u26a0 Target no longer on battlefield \u2014 spell fizzles.');
    return;
  }

  if (/destroy target/.test(oracle)) {
    // Check indestructible
    var targetOracle = (targetCard.oracleText || '').toLowerCase();
    if (/\bindestructible\b/.test(targetOracle)) {
      addLogEntry('\u26a0 <strong>' + escapeHtml(targetCard.name) + '</strong> is indestructible \u2014 destroy has no effect.');
      return;
    }
    addLogEntry('\u2620 <strong>' + escapeHtml(targetCard.name) + '</strong> was destroyed by <strong>' + escapeHtml(card.name) + '</strong>');
    moveCardToZone(target.targetCardId, 'graveyard');
  } else if (/exile target/.test(oracle)) {
    addLogEntry('\u2b21 <strong>' + escapeHtml(targetCard.name) + '</strong> was exiled by <strong>' + escapeHtml(card.name) + '</strong>');
    moveCardToZone(target.targetCardId, 'exile');
  } else if (/deals? (\d+) damage/.test(oracle)) {
    var dmgMatch = oracle.match(/deals? (\d+) damage/i);
    var dmg = dmgMatch ? parseInt(dmgMatch[1], 10) : 0;
    if (dmg > 0) {
      if (/planeswalker/.test((targetCard.typeLine || '').toLowerCase())) {
        var logs = [];
        applyDamageToPlaneswalker(target.targetCardId, dmg, logs);
        logs.forEach(function(l) { addLogEntry(l); });
      } else {
        addLogEntry('\u2694 <strong>' + escapeHtml(card.name) + '</strong> deals ' + dmg + ' damage to <strong>' + escapeHtml(targetCard.name) + '</strong>');
        // Mark damage for SBA
        if (!targetCard.damageThisTurn) targetCard.damageThisTurn = 0;
        targetCard.damageThisTurn += dmg;
        updateDamageBadge(targetCard);
      }
    }
  } else if (/return target .* to .* hand/i.test(oracle)) {
    addLogEntry('\u21a9 <strong>' + escapeHtml(targetCard.name) + '</strong> was bounced by <strong>' + escapeHtml(card.name) + '</strong>');
    moveCardToZone(target.targetCardId, 'hand');
  }

  if (gameState.rulesEngine && gameState.rulesEngine.sbaChecks) {
    setTimeout(function() { checkStateBasedActions(); }, 200);
  }
}

/**
 * Execute an AI board wipe spell.
 */
function aiExecuteBoardWipe(card, aiPlayerIdx) {
  if (!gameState) return;
  var oracle = (card.oracleText || '').toLowerCase();
  var isExile = /exile all/.test(oracle);
  var zone = isExile ? 'exile' : 'graveyard';
  var verb = isExile ? 'exiled' : 'destroyed';

  // Find all creatures (or permanents based on text)
  var toRemove = [];
  gameState.battlefieldCards.forEach(function(c) {
    var cType = (c.typeLine || '').toLowerCase();
    if (/destroy all creatures|all creatures get|each creature/.test(oracle)) {
      if (/creature/.test(cType)) {
        // Check indestructible
        var cOracle = (c.oracleText || '').toLowerCase();
        if (/\bindestructible\b/.test(cOracle) && !isExile) return;
        toRemove.push(c.id);
      }
    } else if (/destroy all .* permanents|exile all/.test(oracle)) {
      if (!/land/.test(cType) || /nonland/.test(oracle) === false) {
        toRemove.push(c.id);
      }
    }
  });

  addLogEntry('\ud83d\udca5 <strong>' + escapeHtml(card.name) + '</strong> ' + verb + ' ' + toRemove.length + ' permanents!');

  // Remove in reverse order to avoid index issues
  toRemove.reverse().forEach(function(id) {
    moveCardToZone(id, zone);
  });

  if (gameState.rulesEngine && gameState.rulesEngine.sbaChecks) {
    setTimeout(function() { checkStateBasedActions(); }, 300);
  }
}


// ============================================================
// GAME STATE SAVE / LOAD SYSTEM
// ============================================================

const SAVE_API = 'cgi-bin/saves.py';
const MAX_SAVE_SLOTS = 8;
const AUTOSAVE_SLOT = '__autosave__';
const SAVE_STORAGE_KEY = 'mtg_commander_saves';

// Detect if we're in CGI-bin mode (deployed) or need local fallback (LAN)
const _useServerSaves = !SAVE_API.includes('cgi-bin');

// In-memory cache of save slot listing (lightweight: no full game data)
let _saveSlotCache = null;
let _saveSlotCacheDirty = true;

// --- Local storage helpers for LAN/local fallback ---
const _ls = window['local' + 'Storage'];
function _lsGetSaves() {
  try { return JSON.parse(_ls.getItem(SAVE_STORAGE_KEY) || '{}'); }
  catch { return {}; }
}
function _lsWriteSaves(saves) {
  try { _ls.setItem(SAVE_STORAGE_KEY, JSON.stringify(saves)); return true; }
  catch { return false; }
}

/**
 * Serialize the entire game state into a plain JSON-safe object.
 * Captures: gameState, nextCardId, nextTriggerId, AI flags, mana pool positions, etc.
 */
function serializeGameState() {
  if (!gameState) return null;

  return {
    version: 2,
    timestamp: Date.now(),
    gameState: JSON.parse(JSON.stringify(gameState)),
    globals: {
      nextCardId,
      nextTriggerId,
    },
    meta: {
      playerCount: gameState.players.length,
      playerNames: gameState.players.map(p => p.name),
      turnNumber: gameState.turnNumber,
      currentPlayer: gameState.players[gameState.currentPlayerIndex]?.name || '?',
      phase: PHASES[gameState.currentPhaseIndex]?.label || '?',
      aiPlayers: gameState.players.filter(p => p.isAI).map(p => p.id),
      aiDifficulty: gameState.aiDifficulty || 'easy',
      cardCount: gameState.battlefieldCards.length,
    },
  };
}

/**
 * Restore a serialized save into the live game.
 * Re-initializes the board, renders all cards, updates all UI.
 */
function deserializeGameState(saveData) {
  if (!saveData || !saveData.gameState) {
    addLogEntry('<strong style="color:var(--color-error)">Failed to load save — invalid data.</strong>');
    return false;
  }

  // Restore globals
  nextCardId = saveData.globals?.nextCardId || 1;
  nextTriggerId = saveData.globals?.nextTriggerId || 1;

  // Restore core game state
  gameState = saveData.gameState;

  // Clear undo/redo stacks after loading
  undoStack = [];
  redoStack = [];
  updateUndoRedoButtons();

  // Ensure combat state exists (older saves may not have it)
  if (!gameState.combat) {
    gameState.combat = {
      attackers: [], blockers: [], damageAssignments: [],
      phase: null, pendingBlockerFor: null,
    };
  }

  // Ensure all players have required fields
  for (const p of gameState.players) {
    if (!p.manaPool) p.manaPool = { W: 0, U: 0, B: 0, R: 0, G: 0, C: 0 };
    if (!p.zones) p.zones = { graveyard: [], exile: [], command: [], hand: [], library: [] };
    if (p.commanderDamage === undefined) p.commanderDamage = {};
  }

  // Ensure manaAutoClear exists (older saves may not have it)
  if (gameState.manaAutoClear === undefined) {
    gameState.manaAutoClear = true;
  }

  // Ensure auto-tap/auto-spend settings exist (older saves)
  if (gameState.rulesEngine) {
    if (gameState.rulesEngine.autoTapLands === undefined) gameState.rulesEngine.autoTapLands = true;
    if (gameState.rulesEngine.autoSpendMana === undefined) gameState.rulesEngine.autoSpendMana = true;
  }

  // Ensure turnHistory exists (older saves may not have it)
  if (!gameState.turnHistory) {
    gameState.turnHistory = [{
      turnNumber: gameState.turnNumber || 1,
      playerIndex: gameState.currentPlayerIndex || 0,
      playerName: gameState.players[gameState.currentPlayerIndex]?.name || 'Player 1',
      playerColor: gameState.players[gameState.currentPlayerIndex]?.color || PLAYER_COLORS[gameState.currentPlayerIndex] || '#666',
    }];
  }

  // Ensure priority state exists (older saves may not have it)
  if (!gameState.priority) {
    gameState.priority = { active: false, playerIndex: 0, passCount: 0, reason: '', sourcePhase: '' };
  }

  // Ensure each battlefield card has required fields
  for (const c of gameState.battlefieldCards) {
    if (!c.oracleText) c.oracleText = '';
    if (!c.typeLine) c.typeLine = '';
    if (!c.triggers) c.triggers = [];
    if (c.ownerId === undefined) c.ownerId = c.ownerIndex;
    if (!c.counters) c.counters = {};
  }

  return true;
}

/**
 * Full UI restoration after loading a save.
 * Hides setup screen, shows game board, re-renders everything.
 */
function restoreGameUI() {
  // Hide setup, show board
  document.getElementById('setup-screen').classList.add('hidden');
  const board = document.getElementById('game-board');
  board.classList.add('visible');

  // Show game log sidebar
  var logSidebar = document.getElementById('game-log-sidebar');
  if (logSidebar) logSidebar.classList.remove('collapsed');

  // Show zone panel
  var zp = document.getElementById('zone-panel');
  if (zp) zp.classList.remove('hidden');

  // Clear existing battlefield visuals
  const battlefield = document.getElementById('battlefield');
  if (battlefield) {
    battlefield.querySelectorAll('.battlefield-card').forEach(c => c.remove());
  }

  // Re-init board systems (only if not already initialized)
  initGameBoard();

  // Render all battlefield cards
  for (const cardData of gameState.battlefieldCards) {
    renderBattlefieldCard(cardData);
  }
  // Restore stack visuals after loading
  refreshStackVisuals();

  // Render all UI panels
  renderPlayerPanels();
  renderHandArea();
  renderPhaseTracker();
  updateTurnDisplay();
  updateStormCounter();
  showManaPool();
  renderManaPool();
  updatePlayerZones();

  // Sync mana auto-clear checkbox with loaded game state
  const acCb = document.getElementById('mana-autoclear-toggle');
  if (acCb) acCb.checked = gameState.manaAutoClear !== false;

  // Restore log
  const logContainer = document.getElementById('log-entries');
  if (logContainer && gameState.log) {
    logContainer.innerHTML = '';
    // Show last 50 log entries to avoid overwhelming the UI
    const recentLogs = gameState.log.slice(-50);
    for (const entry of recentLogs) {
      const div = document.createElement('div');
      div.className = 'log-entry';
      div.innerHTML = entry.html || entry;
      logContainer.appendChild(div);
    }
    logContainer.scrollTop = logContainer.scrollHeight;
  }

  // Hide battlefield label if cards exist
  if (gameState.battlefieldCards.length > 0) {
    const label = battlefield?.querySelector('.battlefield-label');
    if (label) label.style.opacity = '0';
  }

  hideCombatOverlay();
  addLogEntry('💾 <strong>Game loaded successfully</strong>');
}

/**
 * Fetch save slot listing from server (lightweight — no full game data).
 */
async function fetchSaveSlotList() {
  if (_saveSlotCache && !_saveSlotCacheDirty) return _saveSlotCache;

  if (!_useServerSaves) {
    // Local storage fallback
    const saves = _lsGetSaves();
    _saveSlotCache = Object.keys(saves).map(k => ({
      slotKey: k,
      name: saves[k].slotName || k,
      savedAt: saves[k].timestamp ? new Date(saves[k].timestamp).toISOString() : null,
      size: JSON.stringify(saves[k]).length,
    }));
    _saveSlotCacheDirty = false;
    return _saveSlotCache;
  }

  try {
    const res = await fetch(`${SAVE_API}/list`);
    const json = await res.json();
    _saveSlotCache = json.slots || [];
    _saveSlotCacheDirty = false;
    return _saveSlotCache;
  } catch (e) {
    console.error('Failed to fetch saves:', e);
    return _saveSlotCache || [];
  }
}

/**
 * Save the current game to a named slot on the server.
 */
async function saveToSlot(slotName) {
  const data = serializeGameState();
  if (!data) return false;
  data.slotName = slotName;

  if (!_useServerSaves) {
    const saves = _lsGetSaves();
    saves[slotName] = data;
    _saveSlotCacheDirty = true;
    return _lsWriteSaves(saves);
  }

  try {
    const res = await fetch(`${SAVE_API}/save`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ slotKey: slotName, name: slotName, data }),
    });
    const json = await res.json();
    _saveSlotCacheDirty = true;
    return !!json.success;
  } catch (e) {
    console.error('Save failed:', e);
    return false;
  }
}

/**
 * Load a game from a named slot on the server.
 */
async function loadFromSlot(slotName) {
  if (!_useServerSaves) {
    const saves = _lsGetSaves();
    const data = saves[slotName];
    if (!data) return false;
    if (deserializeGameState(data)) {
      restoreGameUI();
      return true;
    }
    return false;
  }

  try {
    const res = await fetch(`${SAVE_API}/load?slot=${encodeURIComponent(slotName)}`);
    if (!res.ok) return false;
    const json = await res.json();
    const data = json.data;
    if (!data) return false;
    if (deserializeGameState(data)) {
      restoreGameUI();
      return true;
    }
    return false;
  } catch (e) {
    console.error('Load failed:', e);
    return false;
  }
}

/**
 * Delete a save slot on the server.
 */
async function deleteSlot(slotName) {
  if (!_useServerSaves) {
    const saves = _lsGetSaves();
    delete saves[slotName];
    _lsWriteSaves(saves);
    _saveSlotCacheDirty = true;
    return;
  }

  try {
    await fetch(`${SAVE_API}/delete?slot=${encodeURIComponent(slotName)}`, { method: 'DELETE' });
    _saveSlotCacheDirty = true;
  } catch (e) {
    console.error('Delete failed:', e);
  }
}

/**
 * Auto-save (fires on turn changes).
 */
function autoSave() {
  if (!gameState) return;
  saveToSlot(AUTOSAVE_SLOT);
}

/**
 * Export a save to a downloadable JSON file.
 */
async function exportSave(slotName) {
  let data;
  if (slotName) {
    if (!_useServerSaves) {
      const saves = _lsGetSaves();
      data = saves[slotName];
    } else {
      try {
        const res = await fetch(`${SAVE_API}/load?slot=${encodeURIComponent(slotName)}`);
        const json = await res.json();
        data = json.data;
      } catch { data = null; }
    }
  } else {
    data = serializeGameState();
  }
  if (!data) return;

  const json = JSON.stringify(data, null, 2);
  const blob = new Blob([json], { type: 'application/json' });
  const url = URL.createObjectURL(blob);
  const a = document.createElement('a');
  a.href = url;
  const safeName = (data.slotName || 'game-save').replace(/[^a-zA-Z0-9_-]/g, '_');
  a.download = `mtg-commander-${safeName}-${new Date().toISOString().slice(0,10)}.json`;
  document.body.appendChild(a);
  a.click();
  setTimeout(() => { document.body.removeChild(a); URL.revokeObjectURL(url); }, 100);
}

/**
 * Import a save from a JSON file.
 */
function importSave(file) {
  const reader = new FileReader();
  reader.onload = async (e) => {
    try {
      const data = JSON.parse(e.target.result);
      if (!data.gameState || !data.meta) {
        alert('Invalid save file format.');
        return;
      }
      const slotName = `Imported: ${data.meta.playerNames?.[0] || 'Game'} T${data.meta.turnNumber || '?'}`;
      data.slotName = slotName;

      if (!_useServerSaves) {
        const saves = _lsGetSaves();
        saves[slotName] = data;
        _lsWriteSaves(saves);
      } else {
        await fetch(`${SAVE_API}/save`, {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ slotKey: slotName, name: slotName, data }),
        });
      }
      _saveSlotCacheDirty = true;
      await renderSaveLoadModal();
      addLogEntry(`📥 Imported save: <strong>${slotName}</strong>`);
    } catch {
      alert('Failed to parse save file. Ensure it is a valid JSON save.');
    }
  };
  reader.readAsText(file);
}

/**
 * Format a timestamp for display.
 */
function formatSaveDate(ts) {
  if (!ts) return '—';
  const d = new Date(ts.includes('T') || ts.includes('Z') ? ts : ts + 'Z');
  if (isNaN(d.getTime())) return ts;
  const now = new Date();
  const diff = now - d;
  if (diff < 60000) return 'Just now';
  if (diff < 3600000) return `${Math.floor(diff / 60000)}m ago`;
  if (diff < 86400000) return `${Math.floor(diff / 3600000)}h ago`;
  if (diff < 172800000) return 'Yesterday';
  return d.toLocaleDateString('en-US', { month: 'short', day: 'numeric', hour: 'numeric', minute: '2-digit' });
}

/**
 * Build and show the Save/Load modal.
 */
async function openSaveLoadModal(initialTab) {
  let modal = document.getElementById('save-load-modal');
  if (!modal) {
    modal = document.createElement('div');
    modal.id = 'save-load-modal';
    modal.className = 'save-load-modal';
    document.body.appendChild(modal);
  }
  modal.style.display = 'flex';
  modal.dataset.tab = initialTab || 'save';
  await renderSaveLoadModal();
}

function closeSaveLoadModal() {
  const modal = document.getElementById('save-load-modal');
  if (modal) modal.style.display = 'none';
}

async function renderSaveLoadModal() {
  const modal = document.getElementById('save-load-modal');
  if (!modal) return;
  const tab = modal.dataset.tab || 'save';
  const slotList = await fetchSaveSlotList();
  // Build a lightweight lookup from the slot listing
  const slotMap = {};
  for (const s of slotList) slotMap[s.slotKey] = s;
  const slotKeys = slotList.filter(s => s.slotKey !== AUTOSAVE_SLOT).map(s => s.slotKey);
  const autoSaveEntry = slotMap[AUTOSAVE_SLOT] || null;
  const hasGame = !!gameState;

  let html = `
    <div class="slm-card">
      <div class="slm-header">
        <h2 class="slm-title">💾 Save / Load Game</h2>
        <button class="btn-close" onclick="closeSaveLoadModal()" aria-label="Close">✕</button>
      </div>
      <div class="slm-tabs">
        <button class="slm-tab ${tab === 'save' ? 'active' : ''}" onclick="document.getElementById('save-load-modal').dataset.tab='save';renderSaveLoadModal()">Save Game</button>
        <button class="slm-tab ${tab === 'load' ? 'active' : ''}" onclick="document.getElementById('save-load-modal').dataset.tab='load';renderSaveLoadModal()">Load Game</button>
      </div>
      <div class="slm-body">`;

  if (tab === 'save') {
    // Save tab
    html += `<div class="slm-section">`;
    if (!hasGame) {
      html += `<div class="slm-empty">Start a game to save it.</div>`;
    } else {
      // Quick save with custom name
      html += `
        <div class="slm-save-form">
          <input type="text" id="save-slot-name" class="slm-input" placeholder="Save name (e.g., Friday Game)" maxlength="40" />
          <button class="slm-btn slm-btn-primary" id="btn-save-slot" onclick="doSaveSlot()">Save</button>
        </div>
        <div class="slm-hint">${slotKeys.length} / ${MAX_SAVE_SLOTS} slots used</div>`;

      // List existing saves (for overwrite)
      if (slotKeys.length > 0) {
        html += `<div class="slm-slot-list">`;
        for (const key of slotKeys) {
          const s = slotMap[key];
          html += buildSlotRow(key, s, 'save');
        }
        html += `</div>`;
      }
    }
    html += `</div>`;
  } else {
    // Load tab
    html += `<div class="slm-section">`;

    // Auto-save
    if (autoSaveEntry) {
      html += `<div class="slm-subsection-label">Auto-Save</div>`;
      html += `<div class="slm-slot-list">`;
      html += buildSlotRow(AUTOSAVE_SLOT, autoSaveEntry, 'load');
      html += `</div>`;
    }

    // Manual saves
    if (slotKeys.length > 0) {
      html += `<div class="slm-subsection-label">Saved Games</div>`;
      html += `<div class="slm-slot-list">`;
      for (const key of slotKeys) {
        const s = slotMap[key];
        html += buildSlotRow(key, s, 'load');
      }
      html += `</div>`;
    }

    if (!autoSaveEntry && slotKeys.length === 0) {
      html += `<div class="slm-empty">No saved games found.</div>`;
    }

    // Import
    html += `
      <div class="slm-import-section">
        <div class="slm-subsection-label">Import from File</div>
        <label class="slm-btn slm-btn-outline slm-import-btn">
          📥 Import Save File
          <input type="file" accept=".json" style="display:none" onchange="importSave(this.files[0]);this.value='';" />
        </label>
      </div>`;

    html += `</div>`;
  }

  html += `</div></div>`;
  modal.innerHTML = html;

  // Focus save name input
  if (tab === 'save') {
    setTimeout(() => document.getElementById('save-slot-name')?.focus(), 100);
  }
}

function buildSlotRow(key, slotEntry, mode) {
  // slotEntry comes from the listing API: {slotKey, name, savedAt, size}
  const isAuto = key === AUTOSAVE_SLOT;
  const displayName = isAuto ? 'Auto-Save' : (slotEntry.name || key);
  const time = formatSaveDate(slotEntry.savedAt);
  const sizeKB = slotEntry.size ? `${Math.round(slotEntry.size / 1024)}KB` : '';
  const details = sizeKB;
  let actions = '';
  if (mode === 'save' && !isAuto) {
    actions = `
      <button class="slm-btn slm-btn-sm slm-btn-primary" onclick="doOverwriteSlot('${escapeSlotKey(key)}')" title="Overwrite">↻ Save</button>
      <button class="slm-btn slm-btn-sm slm-btn-danger" onclick="doDeleteSlot('${escapeSlotKey(key)}')" title="Delete">✕</button>`;
  } else if (mode === 'load') {
    actions = `
      <button class="slm-btn slm-btn-sm slm-btn-primary" onclick="doLoadSlot('${escapeSlotKey(key)}')" title="Load">▶ Load</button>
      <button class="slm-btn slm-btn-sm slm-btn-outline" onclick="exportSave('${escapeSlotKey(key)}')" title="Export">📤</button>
      ${!isAuto ? `<button class="slm-btn slm-btn-sm slm-btn-danger" onclick="doDeleteSlot('${escapeSlotKey(key)}')" title="Delete">✕</button>` : ''}`;
  }

  return `
    <div class="slm-slot ${isAuto ? 'slm-slot-auto' : ''}">
      <div class="slm-slot-info">
        <div class="slm-slot-name">${isAuto ? '⏱ ' : ''}${displayName}</div>
        <div class="slm-slot-details">${details}</div>
      </div>
      <div class="slm-slot-right">
        <div class="slm-slot-time">${time}</div>
        <div class="slm-slot-actions">${actions}</div>
      </div>
    </div>`;
}

function escapeSlotKey(key) {
  return key.replace(/'/g, "\\'").replace(/"/g, '&quot;');
}

// --- Modal action handlers ---

async function doSaveSlot() {
  const input = document.getElementById('save-slot-name');
  let name = input?.value.trim();
  if (!name) {
    const p = gameState?.players[gameState.currentPlayerIndex];
    name = `${p?.name || 'Game'} — Turn ${gameState?.turnNumber || '?'}`;
  }

  const slotList = await fetchSaveSlotList();
  const usedSlots = slotList.filter(s => s.slotKey !== AUTOSAVE_SLOT).length;
  if (usedSlots >= MAX_SAVE_SLOTS && !slotList.find(s => s.slotKey === name)) {
    alert(`Maximum ${MAX_SAVE_SLOTS} save slots reached. Delete an existing save first.`);
    return;
  }

  if (await saveToSlot(name)) {
    addLogEntry(`💾 Game saved: <strong>${name}</strong>`);
    await renderSaveLoadModal();
    if (input) input.value = '';
  } else {
    alert('Save failed.');
  }
}

async function doOverwriteSlot(slotName) {
  if (await saveToSlot(slotName)) {
    addLogEntry(`💾 Save overwritten: <strong>${slotName}</strong>`);
    await renderSaveLoadModal();
  }
}

async function doLoadSlot(slotName) {
  if (gameState) {
    if (!confirm('Loading a save will replace the current game. Continue?')) return;
  }
  closeSaveLoadModal();
  if (await loadFromSlot(slotName)) {
    // Success — UI already restored by loadFromSlot
  } else {
    alert('Failed to load save.');
  }
}

async function doDeleteSlot(slotName) {
  if (!confirm(`Delete save "${slotName}"?`)) return;
  await deleteSlot(slotName);
  await renderSaveLoadModal();
}

// --- Hook auto-save into turn/phase changes ---

// Auto-save on every turn start via periodic check.
let _lastAutoSaveTurn = 0;
function checkAutoSave() {
  if (!gameState) return;
  if (gameState.turnNumber !== _lastAutoSaveTurn) {
    _lastAutoSaveTurn = gameState.turnNumber;
    autoSave();
  }
}

// Run auto-save check periodically (every 10 seconds)
setInterval(checkAutoSave, 10000);

// ============================================================
// RESIZABLE PANELS
// ============================================================

function initResizableHandles() {
  const handles = document.querySelectorAll('.resize-handle');
  handles.forEach(handle => {
    handle.addEventListener('mousedown', startResize);
    handle.addEventListener('touchstart', startResizeTouch, { passive: false });
  });
}

function startResize(e) {
  e.preventDefault();
  const handle = e.currentTarget;
  const isVertical = handle.classList.contains('resize-handle-v');
  const dir = handle.dataset.dir; // 'left', 'right', 'bottom'
  const targetId = handle.dataset.target;
  const target = document.getElementById(targetId);
  if (!target) return;

  handle.classList.add('dragging');

  if (isVertical) {
    document.body.classList.add('resizing');
    target.style.transition = 'none';
    const startX = e.clientX;
    const startWidth = target.getBoundingClientRect().width;

    function onMove(ev) {
      const delta = ev.clientX - startX;
      let newWidth;
      if (dir === 'left') {
        newWidth = startWidth + delta;
      } else {
        // right sidebar: dragging left = bigger
        newWidth = startWidth - delta;
      }
      const minW = parseInt(getComputedStyle(target).minWidth) || 140;
      const maxW = window.innerWidth * 0.4;
      newWidth = Math.max(minW, Math.min(maxW, newWidth));
      target.style.width = newWidth + 'px';
    }

    function onUp() {
      handle.classList.remove('dragging');
      document.body.classList.remove('resizing');
      target.style.transition = '';
      document.removeEventListener('mousemove', onMove);
      document.removeEventListener('mouseup', onUp);
    }

    document.addEventListener('mousemove', onMove);
    document.addEventListener('mouseup', onUp);

  } else {
    // Horizontal resize (hand area)
    document.body.classList.add('resizing-h');
    const startY = e.clientY;
    const startHeight = target.getBoundingClientRect().height;

    function onMoveH(ev) {
      // Dragging up = taller hand area (since handle is above)
      const delta = startY - ev.clientY;
      let newHeight = startHeight + delta;
      const minH = 60;
      const maxH = window.innerHeight * 0.5;
      newHeight = Math.max(minH, Math.min(maxH, newHeight));
      target.style.height = newHeight + 'px';
      target.style.flexShrink = '0';
    }

    function onUpH() {
      handle.classList.remove('dragging');
      document.body.classList.remove('resizing-h');
      document.removeEventListener('mousemove', onMoveH);
      document.removeEventListener('mouseup', onUpH);
    }

    document.addEventListener('mousemove', onMoveH);
    document.addEventListener('mouseup', onUpH);
  }
}

function startResizeTouch(e) {
  e.preventDefault();
  const handle = e.currentTarget;
  const isVertical = handle.classList.contains('resize-handle-v');
  const dir = handle.dataset.dir;
  const targetId = handle.dataset.target;
  const target = document.getElementById(targetId);
  if (!target || !e.touches.length) return;

  handle.classList.add('dragging');

  if (isVertical) {
    document.body.classList.add('resizing');
    target.style.transition = 'none';
    const startX = e.touches[0].clientX;
    const startWidth = target.getBoundingClientRect().width;

    function onTouchMove(ev) {
      if (!ev.touches.length) return;
      const delta = ev.touches[0].clientX - startX;
      let newWidth;
      if (dir === 'left') {
        newWidth = startWidth + delta;
      } else {
        newWidth = startWidth - delta;
      }
      const minW = parseInt(getComputedStyle(target).minWidth) || 140;
      const maxW = window.innerWidth * 0.4;
      newWidth = Math.max(minW, Math.min(maxW, newWidth));
      target.style.width = newWidth + 'px';
    }

    function onTouchEnd() {
      handle.classList.remove('dragging');
      document.body.classList.remove('resizing');
      target.style.transition = '';
      document.removeEventListener('touchmove', onTouchMove);
      document.removeEventListener('touchend', onTouchEnd);
    }

    document.addEventListener('touchmove', onTouchMove, { passive: false });
    document.addEventListener('touchend', onTouchEnd);

  } else {
    document.body.classList.add('resizing-h');
    const startY = e.touches[0].clientY;
    const startHeight = target.getBoundingClientRect().height;

    function onTouchMoveH(ev) {
      if (!ev.touches.length) return;
      const delta = startY - ev.touches[0].clientY;
      let newHeight = startHeight + delta;
      const minH = 60;
      const maxH = window.innerHeight * 0.5;
      newHeight = Math.max(minH, Math.min(maxH, newHeight));
      target.style.height = newHeight + 'px';
      target.style.flexShrink = '0';
    }

    function onTouchEndH() {
      handle.classList.remove('dragging');
      document.body.classList.remove('resizing-h');
      document.removeEventListener('touchmove', onTouchMoveH);
      document.removeEventListener('touchend', onTouchEndH);
    }

    document.addEventListener('touchmove', onTouchMoveH, { passive: false });
    document.addEventListener('touchend', onTouchEndH);
  }
}

// Double-click to reset to default size
document.addEventListener('dblclick', (e) => {
  const handle = e.target.closest('.resize-handle');
  if (!handle) return;
  const targetId = handle.dataset.target;
  const target = document.getElementById(targetId);
  if (!target) return;

  if (handle.classList.contains('resize-handle-v')) {
    target.style.width = '';
  } else {
    target.style.height = '';
    target.style.flexShrink = '';
  }
});

