var _floatingLogMinimized = false;

function toggleFloatingLog() {
  _floatingLogMinimized = !_floatingLogMinimized;
  var panel = document.getElementById('floating-game-log');
  var btn = document.getElementById('fgl-minimize-btn');
  if (panel) {
    panel.classList.toggle('minimized', _floatingLogMinimized);
  }
  if (btn) {
    btn.innerHTML = _floatingLogMinimized ? '&#x2795;' : '&#x2796;';
    btn.title = _floatingLogMinimized ? 'Expand' : 'Minimize';
  }
}

function addFloatingLogEntry(text, category) {
  var container = document.getElementById('fgl-entries');
  if (!container) return;
  // Clear the placeholder
  var empty = container.querySelector('.fgl-empty');
  if (empty) empty.remove();

  var cat = category || 'general';
  var catInfo = (typeof LOG_CATEGORY_ICONS !== 'undefined' && LOG_CATEGORY_ICONS[cat]) ? LOG_CATEGORY_ICONS[cat] : { icon: '>', color: '#888' };
  var turnNum = (gameState && gameState.turnNumber) ? gameState.turnNumber : 1;
  var now = new Date();
  var time = now.getHours().toString().padStart(2,'0') + ':' + now.getMinutes().toString().padStart(2,'0');

  var entry = document.createElement('div');
  entry.className = 'fgl-entry';
  entry.innerHTML =
    '<span class="fgl-cat-icon" style="color:' + catInfo.color + '">' + catInfo.icon + '</span>' +
    '<span class="fgl-time">[T' + turnNum + ' ' + time + ']</span> ' +
    '<span class="fgl-text">' + text + '</span>';
  container.insertBefore(entry, container.firstChild);

  // Keep max 60 entries
  while (container.children.length > 60) container.removeChild(container.lastChild);
}

// ============================================================
// RULES ENGINE EXPANSION — CLEANUP STEP
// ============================================================

/**
 * Cleanup step: runs at end of each turn after end step.
 * - Clears damage counters on all creatures
 * - Removes 'until end of turn' effects (if tracked)
 * - Checks state-based actions one more time
 */
function performCleanupStep() {
  if (!gameState) return;
  // Clear damage counters on all creatures
  var clearedCount = 0;
  gameState.battlefieldCards.forEach(function(card) {
    if (card.damageThisTurn && card.damageThisTurn > 0) {
      card.damageThisTurn = 0;
      clearedCount++;
      updateDamageBadge(card);
    }
  });
  if (clearedCount > 0) {
    addLogEntry('\u2728 Cleanup: damage cleared from ' + clearedCount + ' creature' + (clearedCount > 1 ? 's' : '') + '.');
  }

  // Remove 'until end of turn' temporary effects
  var removedEffects = 0;
  gameState.battlefieldCards.forEach(function(card) {
    if (card.tempEffects && card.tempEffects.length > 0) {
      card.tempEffects = card.tempEffects.filter(function(e) {
        if (e.until === 'end_of_turn') {
          removedEffects++;
          return false;
        }
        return true;
      });
    }
  });
  if (removedEffects > 0) {
    addLogEntry('\u2728 Cleanup: ' + removedEffects + ' temporary effect' + (removedEffects > 1 ? 's' : '') + ' expired.');
  }

  // Run SBAs after cleanup
  if (gameState.rulesEngine && gameState.rulesEngine.sbaChecks) {
    checkStateBasedActions();
  }
}

// ============================================================
// RULES ENGINE EXPANSION — MONARCH MECHANIC
// ============================================================

/**
 * Become the Monarch. The Monarch draws an extra card at end step.
 * If the Monarch is dealt combat damage by a creature, that creature's controller
 * becomes the new Monarch.
 * @param {number} playerIndex
 */
function becomeMonarch(playerIndex) {
  if (!gameState) return;
  var oldMonarch = gameState.monarchPlayerIndex;
  gameState.monarchPlayerIndex = playerIndex;
  var player = gameState.players[playerIndex];
  if (!player) return;
  addLogEntry('\ud83d\udc51 <strong>' + player.name + '</strong> becomes the Monarch!');
  if (oldMonarch !== undefined && oldMonarch !== null && oldMonarch !== playerIndex) {
    var old = gameState.players[oldMonarch];
    if (old) {
      addLogEntry('\ud83d\udc51 <strong>' + old.name + '</strong> is no longer the Monarch.');
    }
  }
  renderPlayerPanels();
  updateMonarchBadges();
}

/**
 * Check if combat damage to the Monarch should transfer monarchy.
 * Called after combat damage is dealt to a player.
 */
function checkMonarchCombatDamage(attackerCard, targetPlayerId) {
  if (!gameState) return;
  if (gameState.monarchPlayerIndex === undefined || gameState.monarchPlayerIndex === null) return;
  if (targetPlayerId !== gameState.monarchPlayerIndex) return;
  // The attacker's controller becomes the new Monarch
  if (attackerCard && attackerCard.ownerId !== undefined) {
    becomeMonarch(attackerCard.ownerId);
  }
}

/**
 * Update visual monarch badges on player panels.
 */
function updateMonarchBadges() {
  if (!gameState) return;
  // Remove all existing monarch badges
  document.querySelectorAll('.monarch-badge').forEach(function(el) { el.remove(); });
  // Add badge to current monarch's panel
  if (gameState.monarchPlayerIndex !== undefined && gameState.monarchPlayerIndex !== null) {
    var panel = document.getElementById('player-panel-' + gameState.monarchPlayerIndex);
    if (panel) {
      var badge = document.createElement('div');
      badge.className = 'monarch-badge';
      badge.title = 'The Monarch \u2014 draws an extra card at end step';
      badge.textContent = '\ud83d\udc51';
      panel.appendChild(badge);
    }
  }
}

// ============================================================
// RULES ENGINE EXPANSION — LETHAL DAMAGE SBA
// ============================================================

/**
 * Enhanced SBA: check creatures with accumulated damage >= toughness.
 * This catches damage from non-combat sources (e.g. burn spells).
 * Called from checkStateBasedActions().
 */
function checkLethalDamageSBA(alerts) {
  if (!gameState) return;
  gameState.battlefieldCards.forEach(function(card) {
    if (!card.typeLine || !/creature/i.test(card.typeLine)) return;
    if (!card.damageThisTurn || card.damageThisTurn <= 0) return;
    if (hasKeyword(card, 'indestructible')) return;

    var toughness = getCreatureToughness(card);
    // Also account for any -1/-1 counters reducing effective toughness
    if (card.counters && card.counters['-1/-1']) {
      toughness -= card.counters['-1/-1'];
    }
    if (card.damageThisTurn >= toughness) {
      alerts.push({
        type: 'lethal_damage',
        player: (gameState.players[card.ownerIndex] || {}).name || 'Unknown',
        playerIdx: card.ownerIndex,
        cardId: card.id,
        cardName: card.name,
        msg: card.name + ' has ' + card.damageThisTurn + ' damage (toughness ' + toughness + ') \u2014 should be destroyed',
      });
    }
  });
}


