// ============================================================
// VISUAL POLISH: UNDO HISTORY VIEWER
// ============================================================

// undoHistoryVisible declared in ui.js

function toggleUndoHistory() {
  undoHistoryVisible = !undoHistoryVisible;
  var panel = document.getElementById('undo-history-panel');
  if (!panel) return;
  if (undoHistoryVisible) {
    panel.classList.add('visible');
    renderUndoHistory();
  } else {
    panel.classList.remove('visible');
  }
}

function closeUndoHistory() {
  undoHistoryVisible = false;
  var panel = document.getElementById('undo-history-panel');
  if (panel) panel.classList.remove('visible');
}

function renderUndoHistory() {
  var list = document.getElementById('undo-history-list');
  var countEl = document.getElementById('undo-history-count');
  if (!list) return;

  if (typeof undoStack === 'undefined' || undoStack.length === 0) {
    list.innerHTML = '<div class="undo-history-empty">No actions to undo.</div>';
    if (countEl) countEl.textContent = '0 steps';
    return;
  }

  if (countEl) countEl.textContent = undoStack.length + ' step' + (undoStack.length !== 1 ? 's' : '');

  var html = '';
  // Show most recent first
  for (var i = undoStack.length - 1; i >= 0; i--) {
    var snap = undoStack[i];
    var desc = snap._description || 'Action';
    var num = undoStack.length - i;
    html += '<div class="undo-history-item" onclick="undoToStep(' + i + ')">' +
      '<span class="uhi-num">' + num + '</span>' +
      '<span class="uhi-desc">' + desc + '</span>' +
      '<span class="uhi-undo-btn">Undo to here</span>' +
    '</div>';
  }
  list.innerHTML = html;
}

function undoToStep(targetIndex) {
  if (typeof undoStack === 'undefined') return;
  // Undo repeatedly until we reach the target
  var steps = undoStack.length - 1 - targetIndex;
  for (var s = 0; s < steps; s++) {
    if (undoStack.length === 0) break;
    var current = deepCloneState();
    if (current) redoStack.push(current);
    undoStack.pop();
  }
  // Now do the final undo
  if (undoStack.length > 0) {
    var current2 = deepCloneState();
    if (current2) redoStack.push(current2);
    var prev = undoStack.pop();
    restoreFromSnapshot(prev);
    addLogEntry('\u21A9 <em>Undo (' + (steps + 1) + ' steps)</em>');
    updateUndoRedoButtons();
  }
  renderUndoHistory();
}

