function setupHandCardPreview() {
  // Delegate mouseover/mouseout on hand-cards container
  var handCardsEl = document.getElementById('hand-cards');
  if (!handCardsEl) return;

  handCardsEl.addEventListener('mouseover', function(e) {
    var cardEl = e.target.closest('.hand-card');
    if (!cardEl || !gameState) return;
    var playerId = 0; // Player 1 hand
    var idx = Array.from(handCardsEl.querySelectorAll('.hand-card')).indexOf(cardEl);
    if (idx < 0) return;
    var player = gameState.players[playerId];
    if (!player) return;
    var card = player.zones.hand[idx];
    if (!card) return;
    var img = card.imageUrl || '';
    if (img) {
      showFloatingCardPreview(img, e, {
        name: card.name,
        typeLine: card.typeLine,
        oracleText: card.oracleText,
        manaCost: card.manaCost || '',
        power: card.power,
        toughness: card.toughness,
        pt: card.pt,
        loyalty: card.loyalty
      });
      var preview = document.getElementById('card-preview');
      if (preview) preview.classList.add('hand-preview-mode');
    }
  });

  handCardsEl.addEventListener('mouseout', function(e) {
    var cardEl = e.target.closest('.hand-card');
    if (cardEl) {
      hideFloatingCardPreview();
      var preview = document.getElementById('card-preview');
      if (preview) preview.classList.remove('hand-preview-mode');
    }
  });

  handCardsEl.addEventListener('mousemove', function(e) {
    var cardEl = e.target.closest('.hand-card');
    if (cardEl) positionFloatingPreview(e);
  });
}


// ============================================================
// AI SELF-PLAY TRAINING ENGINE (Heuristic Hill-Climbing)
// ============================================================

var aiTrainingState = {
  running: false,
  generation: 0,
  totalGens: 0,
  bestScore: -Infinity,
  bestWeights: null,
  currentPhase: 'combat',  // 'combat', 'stack', 'politics'
  log: [],
  gamesPerEval: 6,
  improvementsFound: 0,
  startTime: 0,
  cancelled: false,
};

// --- Headless (DOM-free) game simulation for fast self-play ---

function headlessCreatePlayer(name, deckCards, idx) {
  var hand = [];
  var library = [];
  deckCards.forEach(function(c, i) {
    library.push({
      id: 90000 + idx * 1000 + i,
      name: c.name || 'Card ' + i,
      typeLine: c.typeLine || '',
      oracleText: c.oracleText || '',
      manaCost: c.manaCost || '',
      cmc: c.cmc || 0,
      pt: c.pt || '',
      isRamp: c.isRamp || false,
      isRemoval: c.isRemoval || false,
      isBoardWipe: c.isBoardWipe || false,
      isCommander: false,
    });
  });
  // Shuffle
  for (var i = library.length - 1; i > 0; i--) {
    var j = Math.floor(Math.random() * (i + 1));
    var tmp = library[i]; library[i] = library[j]; library[j] = tmp;
  }
  // Draw 7
  for (var d = 0; d < 7 && library.length > 0; d++) {
    hand.push(library.pop());
  }
  return {
    name: name,
    life: 40,
    isAI: true,
    eliminated: false,
    color: idx === 0 ? '#e8a04a' : idx === 1 ? '#6ba3e8' : idx === 2 ? '#6be86b' : '#e86b6b',
    zones: { hand: hand, library: library, graveyard: [], exile: [], command: [] },
    manaPool: { W: 0, U: 0, B: 0, R: 0, G: 0, C: 0 },
    commanderDamageDealt: {},
    commanderCastCount: 0,
  };
}

function headlessSimGame(weightsA, weightsB, deckA, deckB) {
  // Minimal game state for evaluation
  var sim = {
    players: [
      headlessCreatePlayer('Player A', deckA, 0),
      headlessCreatePlayer('Player B', deckB, 1),
    ],
    battlefieldCards: [],
    turn: 0,
    maxTurns: 20,
    currentPlayerIndex: 0,
    combat: { attackers: [], blockers: [] },
    nextCardId: 80000,
  };

  var allWeights = [weightsA, weightsB];

  for (var turn = 0; turn < sim.maxTurns; turn++) {
    for (var pi = 0; pi < 2; pi++) {
      sim.currentPlayerIndex = pi;
      var p = sim.players[pi];
      if (p.eliminated) continue;
      var w = allWeights[pi];

      // Draw a card
      if (p.zones.library.length > 0) {
        p.zones.hand.push(p.zones.library.pop());
      }

      // Simulate land drop (find land in hand, add to battlefield as mana source)
      var landIdx = -1;
      for (var li = 0; li < p.zones.hand.length; li++) {
        if (p.zones.hand[li].typeLine && p.zones.hand[li].typeLine.toLowerCase().indexOf('land') !== -1) {
          landIdx = li;
          break;
        }
      }
      if (landIdx !== -1) {
        var landCard = p.zones.hand.splice(landIdx, 1)[0];
        landCard.ownerId = pi;
        landCard.tapped = false;
        landCard.id = sim.nextCardId++;
        sim.battlefieldCards.push(landCard);
      }

      // Count available mana (untapped lands)
      var availableMana = 0;
      sim.battlefieldCards.forEach(function(c) {
        if (c.ownerId === pi && !c.tapped && c.typeLine && c.typeLine.toLowerCase().indexOf('land') !== -1) {
          availableMana++;
        }
      });

      // Score and play best affordable non-land card
      var playable = [];
      for (var hi = 0; hi < p.zones.hand.length; hi++) {
        var card = p.zones.hand[hi];
        if (card.typeLine && card.typeLine.toLowerCase().indexOf('land') !== -1) continue;
        var cmc = card.cmc || 0;
        if (cmc <= availableMana) {
          playable.push({ card: card, idx: hi, score: headlessScoreCard(card, w) });
        }
      }
      playable.sort(function(a, b) { return b.score - a.score; });

      // Play up to 2 cards per turn
      var played = 0;
      while (playable.length > 0 && played < 2) {
        var best = playable.shift();
        var handPos = p.zones.hand.indexOf(best.card);
        if (handPos === -1) continue;
        var playedCard = p.zones.hand.splice(handPos, 1)[0];
        playedCard.ownerId = pi;
        playedCard.tapped = false;
        playedCard.id = sim.nextCardId++;
        playedCard.turnPlayed = turn;

        // Tap lands to pay
        var manaNeeded = playedCard.cmc || 0;
        sim.battlefieldCards.forEach(function(c) {
          if (manaNeeded <= 0) return;
          if (c.ownerId === pi && !c.tapped && c.typeLine && c.typeLine.toLowerCase().indexOf('land') !== -1) {
            c.tapped = true;
            manaNeeded--;
          }
        });

        // Handle removal: destroy strongest opponent creature
        if (playedCard.isRemoval) {
          var oppCreatures = sim.battlefieldCards.filter(function(c) {
            return c.ownerId !== pi && c.typeLine && c.typeLine.toLowerCase().indexOf('creature') !== -1;
          });
          if (oppCreatures.length > 0) {
            oppCreatures.sort(function(a, b) {
              return headlessScoreCard(b, w) - headlessScoreCard(a, w);
            });
            var killed = oppCreatures[0];
            sim.battlefieldCards = sim.battlefieldCards.filter(function(c) { return c.id !== killed.id; });
            sim.players[killed.ownerId].zones.graveyard.push(killed);
          }
          p.zones.graveyard.push(playedCard);
        } else if (playedCard.isBoardWipe) {
          var surviving = [];
          sim.battlefieldCards.forEach(function(c) {
            if (c.typeLine && c.typeLine.toLowerCase().indexOf('creature') !== -1) {
              sim.players[c.ownerId].zones.graveyard.push(c);
            } else {
              surviving.push(c);
            }
          });
          sim.battlefieldCards = surviving;
          p.zones.graveyard.push(playedCard);
        } else {
          sim.battlefieldCards.push(playedCard);
        }
        played++;
        // Recalculate available mana
        availableMana = 0;
        sim.battlefieldCards.forEach(function(c) {
          if (c.ownerId === pi && !c.tapped && c.typeLine && c.typeLine.toLowerCase().indexOf('land') !== -1) {
            availableMana++;
          }
        });
      }

      // --- COMBAT PHASE ---
      var myCreatures = sim.battlefieldCards.filter(function(c) {
        return c.ownerId === pi &&
               c.typeLine && c.typeLine.toLowerCase().indexOf('creature') !== -1 &&
               !c.tapped &&
               (turn > 0 || c.turnPlayed !== turn); // Pseudo summoning sickness
      });

      var oppIdx = 1 - pi;
      var opp = sim.players[oppIdx];
      if (opp.eliminated || myCreatures.length === 0) {
        // Untap
        sim.battlefieldCards.forEach(function(c) { if (c.ownerId === pi) c.tapped = false; });
        continue;
      }

      var oppBlockers = sim.battlefieldCards.filter(function(c) {
        return c.ownerId === oppIdx &&
               c.typeLine && c.typeLine.toLowerCase().indexOf('creature') !== -1 &&
               !c.tapped;
      });

      // Decide which creatures to attack with
      var attackers = [];
      myCreatures.forEach(function(atk) {
        var aPow = headlessGetPower(atk);
        var aTou = headlessGetToughness(atk);
        var hasFlying = headlessHasKw(atk, 'flying');
        var hasTrample = headlessHasKw(atk, 'trample');

        // Check if any blocker can kill us
        var canDie = oppBlockers.some(function(b) {
          if (hasFlying && !headlessHasKw(b, 'flying') && !headlessHasKw(b, 'reach')) return false;
          return headlessGetPower(b) >= aTou || headlessHasKw(b, 'deathtouch');
        });

        if (!canDie || hasFlying || hasTrample || aPow >= 4) {
          attackers.push(atk);
          atk.tapped = true;
        }
      });

      // Simple blocking: opponent assigns biggest blocker to biggest attacker
      var totalDamage = 0;
      var usedBlockers = {};
      attackers.forEach(function(atk) {
        var aPow = headlessGetPower(atk);
        var aTou = headlessGetToughness(atk);
        var hasFlying = headlessHasKw(atk, 'flying');

        var validBlockers = oppBlockers.filter(function(b) {
          if (usedBlockers[b.id]) return false;
          if (hasFlying && !headlessHasKw(b, 'flying') && !headlessHasKw(b, 'reach')) return false;
          return true;
        });

        if (validBlockers.length > 0 && !headlessHasKw(atk, 'menace')) {
          // Block with creature that can survive, or chump if life is low
          var blocker = validBlockers.find(function(b) { return headlessGetToughness(b) > aPow; });
          if (!blocker && opp.life <= aPow * 2) blocker = validBlockers[0]; // chump
          if (blocker) {
            usedBlockers[blocker.id] = true;
            // Assign damage
            var bPow = headlessGetPower(blocker);
            if (aPow >= headlessGetToughness(blocker) || headlessHasKw(atk, 'deathtouch')) {
              sim.battlefieldCards = sim.battlefieldCards.filter(function(c) { return c.id !== blocker.id; });
              sim.players[oppIdx].zones.graveyard.push(blocker);
            }
            if (bPow >= aTou || headlessHasKw(blocker, 'deathtouch')) {
              sim.battlefieldCards = sim.battlefieldCards.filter(function(c) { return c.id !== atk.id; });
              sim.players[pi].zones.graveyard.push(atk);
            }
            if (headlessHasKw(atk, 'trample') && aPow > headlessGetToughness(blocker)) {
              totalDamage += aPow - headlessGetToughness(blocker);
            }
            return;
          }
        }
        // Unblocked
        totalDamage += aPow;
        if (headlessHasKw(atk, 'lifelink')) p.life += aPow;
      });

      opp.life -= totalDamage;
      if (opp.life <= 0) opp.eliminated = true;

      // Untap all our stuff for next turn
      sim.battlefieldCards.forEach(function(c) { if (c.ownerId === pi) c.tapped = false; });
    }

    // Check if game is over
    var alive = sim.players.filter(function(p) { return !p.eliminated; });
    if (alive.length <= 1) break;
  }

  // Evaluate result
  var pA = sim.players[0];
  var pB = sim.players[1];

  // Score: higher is better for player A
  var scoreA = 0;
  if (pA.eliminated && !pB.eliminated) scoreA = -100;
  else if (!pA.eliminated && pB.eliminated) scoreA = 100;
  else {
    // Both alive: score by life difference and board state
    scoreA = (pA.life - pB.life);
    var aBoard = sim.battlefieldCards.filter(function(c) { return c.ownerId === 0; }).length;
    var bBoard = sim.battlefieldCards.filter(function(c) { return c.ownerId === 1; }).length;
    scoreA += (aBoard - bBoard) * 2;
  }

  return scoreA;
}

function headlessScoreCard(card, w) {
  var cmc = card.cmc || 0;
  var score = 10 - cmc * (w.card_baseCmcPenalty || 1);
  if (card.pt) {
    var pts = card.pt.split('/');
    score += ((parseInt(pts[0]) || 0) + (parseInt(pts[1]) || 0)) * (w.card_ptBonus || 1);
  }
  var text = (card.oracleText || '').toLowerCase();
  if (text.indexOf('flying') !== -1) score += (w.kw_flying || 2.5);
  if (text.indexOf('deathtouch') !== -1) score += (w.kw_deathtouch || 2.5);
  if (text.indexOf('haste') !== -1) score += (w.kw_haste || 2.5);
  if (text.indexOf('trample') !== -1) score += (w.kw_trample || 1.5);
  if (text.indexOf('lifelink') !== -1) score += (w.kw_lifelink || 1.5);
  if (card.isRamp) score += (w.spell_ramp || 6);
  if (card.isRemoval) score += (w.spell_destroy || 5);
  return score;
}

function headlessGetPower(card) {
  if (!card.pt) return 0;
  return parseInt(card.pt.split('/')[0]) || 0;
}
function headlessGetToughness(card) {
  if (!card.pt) return 0;
  return parseInt(card.pt.split('/')[1]) || 0;
}
function headlessHasKw(card, kw) {
  var text = (card.oracleText || '').toLowerCase();
  return text.indexOf(kw) !== -1;
}

// --- Generate a synthetic deck for training ---
function generateTrainingDeck() {
  var deck = [];
  // 37 lands
  for (var i = 0; i < 37; i++) {
    deck.push({ name: 'Forest', typeLine: 'Basic Land - Forest', oracleText: '{T}: Add {G}', cmc: 0, pt: '' });
  }
  // 20 creatures of varying sizes
  var creatures = [
    { name: 'Llanowar Elves', typeLine: 'Creature - Elf Druid', oracleText: '{T}: Add {G}', cmc: 1, pt: '1/1', isRamp: true },
    { name: 'Elvish Mystic', typeLine: 'Creature - Elf Druid', oracleText: '{T}: Add {G}', cmc: 1, pt: '1/1', isRamp: true },
    { name: 'Grizzly Bears', typeLine: 'Creature - Bear', oracleText: '', cmc: 2, pt: '2/2' },
    { name: 'Runeclaw Bear', typeLine: 'Creature - Bear', oracleText: '', cmc: 2, pt: '2/2' },
    { name: 'Centaur Courser', typeLine: 'Creature - Centaur', oracleText: '', cmc: 3, pt: '3/3' },
    { name: 'Alpine Grizzly', typeLine: 'Creature - Bear', oracleText: '', cmc: 3, pt: '4/2' },
    { name: 'Garruk\'s Companion', typeLine: 'Creature - Beast', oracleText: 'Trample', cmc: 2, pt: '3/2' },
    { name: 'Leatherback Baloth', typeLine: 'Creature - Beast', oracleText: '', cmc: 3, pt: '4/5' },
    { name: 'Territorial Scythecat', typeLine: 'Creature - Cat', oracleText: 'Trample', cmc: 3, pt: '2/2' },
    { name: 'Charging Badger', typeLine: 'Creature - Badger', oracleText: 'Trample', cmc: 1, pt: '1/1' },
    { name: 'Sentinel Spider', typeLine: 'Creature - Spider', oracleText: 'Vigilance, reach', cmc: 5, pt: '4/4' },
    { name: 'Vorstclaw', typeLine: 'Creature - Elemental', oracleText: '', cmc: 6, pt: '7/7' },
    { name: 'Pelakka Wurm', typeLine: 'Creature - Wurm', oracleText: 'Trample. When this enters the battlefield, you gain 7 life.', cmc: 7, pt: '7/7' },
    { name: 'Typhoid Rats', typeLine: 'Creature - Rat', oracleText: 'Deathtouch', cmc: 1, pt: '1/1' },
    { name: 'Vampire Nighthawk', typeLine: 'Creature - Vampire', oracleText: 'Flying, deathtouch, lifelink', cmc: 3, pt: '2/3' },
    { name: 'Serra Angel', typeLine: 'Creature - Angel', oracleText: 'Flying, vigilance', cmc: 5, pt: '4/4' },
    { name: 'Air Elemental', typeLine: 'Creature - Elemental', oracleText: 'Flying', cmc: 5, pt: '4/4' },
    { name: 'Giant Spider', typeLine: 'Creature - Spider', oracleText: 'Reach', cmc: 4, pt: '2/4' },
    { name: 'Kalonian Tusker', typeLine: 'Creature - Beast', oracleText: '', cmc: 2, pt: '3/3' },
    { name: 'Baloth Woodcrasher', typeLine: 'Creature - Beast', oracleText: 'Trample', cmc: 6, pt: '4/4' },
  ];
  creatures.forEach(function(c) { deck.push(c); });

  // 6 removal spells
  for (var r = 0; r < 3; r++) {
    deck.push({ name: 'Murder', typeLine: 'Instant', oracleText: 'Destroy target creature.', cmc: 3, pt: '', isRemoval: true });
    deck.push({ name: 'Beast Within', typeLine: 'Instant', oracleText: 'Destroy target permanent.', cmc: 3, pt: '', isRemoval: true });
  }

  // 2 board wipes
  deck.push({ name: 'Wrath of God', typeLine: 'Sorcery', oracleText: 'Destroy all creatures.', cmc: 4, pt: '', isBoardWipe: true });
  deck.push({ name: 'Damnation', typeLine: 'Sorcery', oracleText: 'Destroy all creatures.', cmc: 4, pt: '', isBoardWipe: true });

  // 3 draw spells
  deck.push({ name: 'Harmonize', typeLine: 'Sorcery', oracleText: 'Draw three cards.', cmc: 4, pt: '' });
  deck.push({ name: 'Divination', typeLine: 'Sorcery', oracleText: 'Draw two cards.', cmc: 3, pt: '' });
  deck.push({ name: 'Concentrate', typeLine: 'Sorcery', oracleText: 'Draw three cards.', cmc: 4, pt: '' });

  // 2 ramp
  deck.push({ name: 'Rampant Growth', typeLine: 'Sorcery', oracleText: 'Search your library for a basic land card and put it onto the battlefield tapped.', cmc: 2, pt: '', isRamp: true });
  deck.push({ name: 'Cultivate', typeLine: 'Sorcery', oracleText: 'Search your library for up to two basic land cards.', cmc: 3, pt: '', isRamp: true });

  return deck;
}

// --- Mutate weights: small random perturbation ---
function mutateWeights(weights, mutationRate) {
  var mutated = JSON.parse(JSON.stringify(weights));
  var keys = Object.keys(mutated);
  for (var i = 0; i < keys.length; i++) {
    var k = keys[i];
    if (typeof mutated[k] === 'boolean') continue; // Skip booleans
    if (Math.random() < mutationRate) {
      // Perturb by up to +/- 30%
      var delta = (Math.random() - 0.5) * 0.6 * Math.abs(mutated[k] || 1);
      mutated[k] = Math.round((mutated[k] + delta) * 100) / 100;
    }
  }
  return mutated;
}

// --- Run one generation of self-play training ---
function runTrainingGeneration(callback) {
  var st = aiTrainingState;
  if (st.cancelled) {
    st.running = false;
    renderTrainingUI();
    return;
  }

  st.generation++;
  var deckA = generateTrainingDeck();
  var deckB = generateTrainingDeck();
  var candidateWeights = mutateWeights(st.bestWeights || aiWeights, 0.3);

  // Play multiple games and average the score
  var totalScore = 0;
  for (var g = 0; g < st.gamesPerEval; g++) {
    // Alternate who goes first
    if (g % 2 === 0) {
      totalScore += headlessSimGame(candidateWeights, st.bestWeights || aiWeights, deckA, deckB);
    } else {
      totalScore -= headlessSimGame(st.bestWeights || aiWeights, candidateWeights, deckA, deckB);
    }
  }

  var avgScore = totalScore / st.gamesPerEval;

  // Hill climbing: accept if better
  if (avgScore > st.bestScore) {
    st.bestScore = avgScore;
    st.bestWeights = candidateWeights;
    st.improvementsFound++;
    st.log.push('Gen ' + st.generation + ': IMPROVED (score: ' + avgScore.toFixed(1) + ')');
  } else {
    st.log.push('Gen ' + st.generation + ': no improvement (score: ' + avgScore.toFixed(1) + ')');
  }

  // Keep log manageable
  if (st.log.length > 100) st.log = st.log.slice(-50);

  renderTrainingUI();

  if (st.generation < st.totalGens && !st.cancelled) {
    // Use setTimeout to avoid blocking the UI
    setTimeout(function() { runTrainingGeneration(callback); }, 1);
  } else {
    st.running = false;
    if (callback) callback();
    renderTrainingUI();
  }
}

function startAiTraining(numGenerations, phase) {
  var st = aiTrainingState;
  if (st.running) return;

  st.running = true;
  st.cancelled = false;
  st.generation = 0;
  st.totalGens = numGenerations || 50;
  st.bestScore = -Infinity;
  st.bestWeights = JSON.parse(JSON.stringify(aiWeights));
  st.currentPhase = phase || 'combat';
  st.improvementsFound = 0;
  st.startTime = Date.now();
  st.log = ['Training started: Phase ' + st.currentPhase + ', ' + st.totalGens + ' generations'];

  renderTrainingUI();

  setTimeout(function() {
    runTrainingGeneration(function() {
      st.log.push('Training complete! ' + st.improvementsFound + ' improvements found in ' +
        ((Date.now() - st.startTime) / 1000).toFixed(1) + 's');
      renderTrainingUI();
    });
  }, 10);
}

function stopAiTraining() {
  aiTrainingState.cancelled = true;
  aiTrainingState.log.push('Training stopped by user at gen ' + aiTrainingState.generation);
}

function applyTrainedWeights() {
  if (!aiTrainingState.bestWeights) return;
  aiWeights = JSON.parse(JSON.stringify(aiTrainingState.bestWeights));
  saveAiWeights();
  aiTrainingState.log.push('Trained weights applied and saved!');
  renderTrainingUI();
}

// ============================================================
// TRAINING UI — Renders inside the AI Settings tab
// ============================================================

function renderTrainingUI() {
  var container = document.getElementById('ai-training-panel') || document.getElementById('ai-training-modal-panel');
  if (!container) return;
  // Also update the modal panel if it exists
  var modalPanel = document.getElementById('ai-training-modal-panel');
  var settingsPanel = document.getElementById('ai-training-panel');

  var st = aiTrainingState;
  var html = '';

  // Progress bar
  if (st.running) {
    var pct = st.totalGens > 0 ? Math.round((st.generation / st.totalGens) * 100) : 0;
    html += '<div style="margin-bottom:10px">';
    html += '<div style="display:flex;justify-content:space-between;font-size:11px;color:rgba(255,255,255,0.6);margin-bottom:4px">';
    html += '<span>Generation ' + st.generation + ' / ' + st.totalGens + '</span>';
    html += '<span>' + st.improvementsFound + ' improvements</span>';
    html += '</div>';
    html += '<div style="height:6px;background:rgba(255,255,255,0.1);border-radius:3px;overflow:hidden">';
    html += '<div style="height:100%;width:' + pct + '%;background:linear-gradient(90deg,#e8a04a,#e86b6b);border-radius:3px;transition:width 0.3s"></div>';
    html += '</div>';
    html += '</div>';
  }

  // Controls
  html += '<div style="display:flex;gap:6px;flex-wrap:wrap;margin-bottom:10px">';
  if (!st.running) {
    html += '<button class="settings-radio-btn" onclick="startAiTraining(50,\'combat\')" style="font-size:11px;padding:5px 10px">Train 50 gens</button>';
    html += '<button class="settings-radio-btn" onclick="startAiTraining(200,\'combat\')" style="font-size:11px;padding:5px 10px">Train 200 gens</button>';
    html += '<button class="settings-radio-btn" onclick="startAiTraining(500,\'combat\')" style="font-size:11px;padding:5px 10px">Train 500 gens</button>';
  } else {
    html += '<button class="settings-radio-btn active" onclick="stopAiTraining()" style="font-size:11px;padding:5px 10px;background:rgba(232,107,107,0.3);border-color:rgba(232,107,107,0.5)">Stop Training</button>';
  }
  html += '</div>';

  // Apply / Reset
  if (st.bestWeights && !st.running) {
    html += '<div style="display:flex;gap:6px;margin-bottom:10px">';
    html += '<button class="settings-radio-btn" onclick="applyTrainedWeights()" style="font-size:11px;padding:5px 10px;background:rgba(107,232,107,0.15);border-color:rgba(107,232,107,0.4)">Apply Trained Weights</button>';
    html += '<button class="settings-radio-btn" onclick="resetAiWeights();renderTrainingUI();renderSettingsPanel()" style="font-size:11px;padding:5px 10px">Reset to Defaults</button>';
    html += '</div>';
  }

  // Weight diff summary
  if (st.bestWeights) {
    var diffCount = 0;
    var diffs = [];
    var keys = Object.keys(AI_DEFAULT_WEIGHTS);
    for (var i = 0; i < keys.length; i++) {
      var k = keys[i];
      if (typeof AI_DEFAULT_WEIGHTS[k] === 'boolean') continue;
      var def = AI_DEFAULT_WEIGHTS[k];
      var cur = st.bestWeights[k];
      if (cur !== undefined && Math.abs(cur - def) > 0.01) {
        diffCount++;
        var pctChange = def !== 0 ? Math.round(((cur - def) / Math.abs(def)) * 100) : 0;
        var arrow = pctChange > 0 ? '+' : '';
        diffs.push(k.replace(/_/g, ' ') + ': ' + def + ' -> ' + cur + ' (' + arrow + pctChange + '%)');
      }
    }
    if (diffCount > 0) {
      html += '<div style="font-size:11px;color:rgba(255,255,255,0.5);margin-bottom:4px">' + diffCount + ' weights changed:</div>';
      html += '<div style="max-height:80px;overflow-y:auto;font-size:10px;color:rgba(255,255,255,0.4);background:rgba(0,0,0,0.2);border-radius:4px;padding:4px 6px;margin-bottom:8px">';
      html += diffs.slice(0, 20).join('<br>');
      if (diffs.length > 20) html += '<br>...and ' + (diffs.length - 20) + ' more';
      html += '</div>';
    }
  }

  // Log
  if (st.log.length > 0) {
    html += '<div style="font-size:11px;color:rgba(255,255,255,0.5);margin-bottom:4px">Training Log:</div>';
    html += '<div style="max-height:100px;overflow-y:auto;font-size:10px;color:rgba(255,255,255,0.4);background:rgba(0,0,0,0.2);border-radius:4px;padding:4px 6px;font-family:monospace">';
    var recentLogs = st.log.slice(-20);
    for (var li = 0; li < recentLogs.length; li++) {
      var logLine = recentLogs[li];
      if (logLine.indexOf('IMPROVED') !== -1) {
        html += '<div style="color:rgba(107,232,107,0.8)">' + logLine + '</div>';
      } else {
        html += '<div>' + logLine + '</div>';
      }
    }
    html += '</div>';
  }

  // Current weight status
  var isCustom = false;
  var ks = Object.keys(AI_DEFAULT_WEIGHTS);
  for (var ci = 0; ci < ks.length; ci++) {
    if (typeof AI_DEFAULT_WEIGHTS[ks[ci]] === 'boolean') continue;
    if (Math.abs(aiWeights[ks[ci]] - AI_DEFAULT_WEIGHTS[ks[ci]]) > 0.01) { isCustom = true; break; }
  }
  html += '<div style="font-size:10px;color:rgba(255,255,255,0.3);margin-top:8px">';
  html += 'Active weights: ' + (isCustom ? '<span style="color:rgba(232,160,74,0.8)">Custom (trained)</span>' : 'Default');
  html += '</div>';

  container.innerHTML = html;
  // Write to both panels if both exist
  if (modalPanel && modalPanel !== container) modalPanel.innerHTML = html;
  if (settingsPanel && settingsPanel !== container) settingsPanel.innerHTML = html;
}

// --- Modal open/close for setup screen access ---
function openAiTrainingModal() {
  var modal = document.getElementById('ai-training-modal');
  if (modal) {
    modal.style.display = 'flex';
    renderTrainingUI();
  }
}

function closeAiTrainingModal() {
  var modal = document.getElementById('ai-training-modal');
  if (modal) modal.style.display = 'none';
}

// ============================================================
// DECK TESTER — Monte Carlo simulation against precon decks
// ============================================================

var deckTesterState = {
  running: false,
  cancelled: false,
  results: null,
  progress: 0,
  total: 0,
  currentMatchup: '',
  // Configuration
  gamesPerMatchup: 50,
  maxTurns: 25,
  selectedPrecons: [],  // indexes into PRECON_DATA
  customDeck: null,     // { name, commander, cards[] }
};

// --- Parse a precon decklist string into card objects ---
function parseDecklistToCards(decklistStr) {
  if (!decklistStr) return [];
  var cards = [];
  var lines = decklistStr.split('\n');
  for (var i = 0; i < lines.length; i++) {
    var line = lines[i].trim();
    if (!line || line.indexOf('//') === 0) continue;
    var match = line.match(/^(\d+)\s+(.+)$/);
    if (match) {
      var qty = parseInt(match[1]) || 1;
      var name = match[2].trim();
      for (var q = 0; q < qty; q++) {
        cards.push({ name: name, typeLine: '', oracleText: '', cmc: 0, pt: '', manaCost: '' });
      }
    }
  }
  return cards;
}

// --- Enrich cards with type/cost guesses for headless sim ---
function enrichCardForSim(card) {
  var name = (card.name || '').toLowerCase();
  var typeLine = (card.typeLine || '').toLowerCase();
  var oracleText = (card.oracleText || '').toLowerCase();

  // Already has data from Scryfall
  if (card.cmc > 0 || typeLine.length > 5) return card;

  // Guess from name patterns for precon cards without data
  var c = JSON.parse(JSON.stringify(card));

  // Basic lands
  if (/^(plains|island|swamp|mountain|forest)$/i.test(c.name)) {
    var landColors = { plains: 'W', island: 'U', swamp: 'B', mountain: 'R', forest: 'G' };
    var cl = landColors[c.name.toLowerCase()] || 'C';
    c.typeLine = 'Basic Land - ' + c.name;
    c.oracleText = '{T}: Add {' + cl + '}';
    c.cmc = 0;
    return c;
  }

  // Common artifacts
  if (/sol ring/i.test(c.name)) {
    c.typeLine = 'Artifact'; c.cmc = 1; c.oracleText = '{T}: Add {C}{C}'; c.isRamp = true; return c;
  }
  if (/arcane signet|fellwar stone|talisman|signet/i.test(c.name)) {
    c.typeLine = 'Artifact'; c.cmc = 2; c.oracleText = '{T}: Add one mana'; c.isRamp = true; return c;
  }
  if (/commander.?s sphere/i.test(c.name)) {
    c.typeLine = 'Artifact'; c.cmc = 3; c.oracleText = '{T}: Add one mana'; c.isRamp = true; return c;
  }

  // Common instants / removal
  if (/swords to plowshares|path to exile/i.test(c.name)) {
    c.typeLine = 'Instant'; c.cmc = 1; c.oracleText = 'Exile target creature.'; c.isRemoval = true; return c;
  }
  if (/beast within|chaos warp|generous gift/i.test(c.name)) {
    c.typeLine = 'Instant'; c.cmc = 3; c.oracleText = 'Destroy target permanent.'; c.isRemoval = true; return c;
  }
  if (/murder|go for the throat|hero.?s downfall/i.test(c.name)) {
    c.typeLine = 'Instant'; c.cmc = 3; c.oracleText = 'Destroy target creature.'; c.isRemoval = true; return c;
  }
  if (/counterspell|negate|arcane denial/i.test(c.name)) {
    c.typeLine = 'Instant'; c.cmc = 2; c.oracleText = 'Counter target spell.'; c.isRemoval = true; return c;
  }

  // Common board wipes
  if (/wrath of god|damnation|blasphemous act|day of judgment|farewell|toxic deluge/i.test(c.name)) {
    c.typeLine = 'Sorcery'; c.cmc = 4; c.oracleText = 'Destroy all creatures.'; c.isBoardWipe = true; return c;
  }

  // Common ramp
  if (/rampant growth|nature.?s lore/i.test(c.name)) {
    c.typeLine = 'Sorcery'; c.cmc = 2; c.oracleText = 'Search your library for a basic land.'; c.isRamp = true; return c;
  }
  if (/cultivate|kodama.?s reach/i.test(c.name)) {
    c.typeLine = 'Sorcery'; c.cmc = 3; c.oracleText = 'Search your library for two basic lands.'; c.isRamp = true; return c;
  }
  if (/farseek|three visits/i.test(c.name)) {
    c.typeLine = 'Sorcery'; c.cmc = 2; c.oracleText = 'Search your library for a land.'; c.isRamp = true; return c;
  }

  // Common draw
  if (/harmonize|concentrate/i.test(c.name)) {
    c.typeLine = 'Sorcery'; c.cmc = 4; c.oracleText = 'Draw three cards.'; return c;
  }

  // Default: treat as a creature with CMC based on position in list
  if (!c.typeLine || c.typeLine.length < 3) {
    // Estimate CMC from how "big" the card name sounds
    var estimatedCmc = Math.floor(Math.random() * 5) + 2;
    var estimatedPow = Math.max(1, estimatedCmc - 1);
    c.typeLine = 'Creature';
    c.cmc = estimatedCmc;
    c.pt = estimatedPow + '/' + estimatedPow;
    c.power = String(estimatedPow);
    c.toughness = String(estimatedPow);
  }

  return c;
}

// --- Build a simulation-ready deck from dbCurrentDeck ---
function buildSimDeckFromDeckBuilder() {
  var deck = [];
  var db = dbCurrentDeck;
  if (!db || !db.cards || db.cards.length === 0) return null;

  // Add commander first (as a card in deck for sim purposes)
  if (db.commander) {
    var cmd = enrichCardForSim({
      name: db.commander.name || db.commander,
      typeLine: db.commander.typeLine || 'Legendary Creature',
      oracleText: db.commander.oracleText || '',
      cmc: db.commander.cmc || 5,
      pt: db.commander.pt || '4/4',
      manaCost: db.commander.manaCost || '',
      isCommander: true
    });
    deck.push(cmd);
  }

  db.cards.forEach(function(c) {
    var qty = c.quantity || 1;
    for (var q = 0; q < qty; q++) {
      deck.push(enrichCardForSim({
        name: c.name,
        typeLine: c.typeLine || '',
        oracleText: c.oracleText || '',
        cmc: c.cmc || 0,
        pt: c.pt || '',
        manaCost: c.manaCost || '',
        power: c.power || '',
        toughness: c.toughness || '',
        colorIdentity: c.colorIdentity,
        isRamp: c.isRamp || false,
        isRemoval: c.isRemoval || false,
        isBoardWipe: c.isBoardWipe || false
      }));
    }
  });

  return deck;
}

// --- Build a simulation-ready deck from a precon ---
function buildSimDeckFromPrecon(preconIdx) {
  var precon = (typeof PRECON_DATA !== 'undefined') ? PRECON_DATA[preconIdx] : null;
  if (!precon) return null;
  var rawCards = parseDecklistToCards(precon.decklist || '');
  var deck = rawCards.map(function(c) { return enrichCardForSim(c); });
  return deck;
}

// --- Headless create player (reuse from training engine) ---
function dtCreatePlayer(name, deck, idx) {
  var shuffled = deck.slice();
  for (var i = shuffled.length - 1; i > 0; i--) {
    var j = Math.floor(Math.random() * (i + 1));
    var t = shuffled[i]; shuffled[i] = shuffled[j]; shuffled[j] = t;
  }
  var hand = shuffled.splice(0, 7);
  return {
    name: name,
    life: 40,
    eliminated: false,
    ownerId: idx,
    zones: { library: shuffled, hand: hand, graveyard: [], exile: [] },
    stats: {
      cardsDrawn: 7,   // starting hand
      landsPlayed: 0,
      spellsCast: 0,
      creaturesPlayed: 0,
      removalUsed: 0,
      boardWipesUsed: 0,
      rampPlayed: 0,
      damageDealt: 0,
      damageReceived: 0,
      maxBoardSize: 0,
      turnsAlive: 0,
      manaSpent: 0,
    }
  };
}

// --- Enhanced headless sim for deck testing (richer stats tracking) ---
function dtSimGame(deckA, deckB, nameA, nameB) {
  var w = (typeof aiWeights !== 'undefined') ? aiWeights : AI_DEFAULT_WEIGHTS;

  var sim = {
    players: [
      dtCreatePlayer(nameA, deckA, 0),
      dtCreatePlayer(nameB, deckB, 1),
    ],
    battlefieldCards: [],
    turn: 0,
    maxTurns: deckTesterState.maxTurns || 25,
    nextCardId: 90000,
  };

  var turnLog = [];

  for (var turn = 0; turn < sim.maxTurns; turn++) {
    for (var pi = 0; pi < 2; pi++) {
      var p = sim.players[pi];
      if (p.eliminated) continue;
      p.stats.turnsAlive++;

      // Draw
      if (p.zones.library.length > 0) {
        p.zones.hand.push(p.zones.library.pop());
        p.stats.cardsDrawn++;
      }

      // Land drop
      var landIdx = -1;
      for (var li = 0; li < p.zones.hand.length; li++) {
        if (p.zones.hand[li].typeLine && /land/i.test(p.zones.hand[li].typeLine)) {
          landIdx = li; break;
        }
      }
      if (landIdx !== -1) {
        var landCard = p.zones.hand.splice(landIdx, 1)[0];
        landCard.ownerId = pi; landCard.tapped = false; landCard.id = sim.nextCardId++;
        sim.battlefieldCards.push(landCard);
        p.stats.landsPlayed++;
      }

      // Available mana
      var availableMana = 0;
      sim.battlefieldCards.forEach(function(c) {
        if (c.ownerId === pi && !c.tapped && c.typeLine && /land/i.test(c.typeLine)) availableMana++;
      });

      // Play spells
      var playable = [];
      for (var hi = 0; hi < p.zones.hand.length; hi++) {
        var card = p.zones.hand[hi];
        if (card.typeLine && /land/i.test(card.typeLine)) continue;
        var cmc = card.cmc || 0;
        if (cmc <= availableMana) {
          playable.push({ card: card, idx: hi, score: headlessScoreCard(card, w) });
        }
      }
      playable.sort(function(a, b) { return b.score - a.score; });

      var played = 0;
      while (playable.length > 0 && played < 2) {
        var best = playable.shift();
        var handPos = p.zones.hand.indexOf(best.card);
        if (handPos === -1) continue;
        var playedCard = p.zones.hand.splice(handPos, 1)[0];
        playedCard.ownerId = pi; playedCard.tapped = false;
        playedCard.id = sim.nextCardId++; playedCard.turnPlayed = turn;

        // Pay mana
        var manaNeeded = playedCard.cmc || 0;
        sim.battlefieldCards.forEach(function(c) {
          if (manaNeeded <= 0) return;
          if (c.ownerId === pi && !c.tapped && c.typeLine && /land/i.test(c.typeLine)) {
            c.tapped = true; manaNeeded--;
          }
        });
        p.stats.manaSpent += (playedCard.cmc || 0);
        p.stats.spellsCast++;

        // Handle removal
        if (playedCard.isRemoval) {
          p.stats.removalUsed++;
          var oppCreatures = sim.battlefieldCards.filter(function(c) {
            return c.ownerId !== pi && c.typeLine && /creature/i.test(c.typeLine);
          });
          if (oppCreatures.length > 0) {
            oppCreatures.sort(function(a, b) { return headlessScoreCard(b, w) - headlessScoreCard(a, w); });
            var killed = oppCreatures[0];
            sim.battlefieldCards = sim.battlefieldCards.filter(function(c) { return c.id !== killed.id; });
            sim.players[killed.ownerId].zones.graveyard.push(killed);
          }
          p.zones.graveyard.push(playedCard);
        } else if (playedCard.isBoardWipe) {
          p.stats.boardWipesUsed++;
          var surviving = [];
          sim.battlefieldCards.forEach(function(c) {
            if (c.typeLine && /creature/i.test(c.typeLine)) {
              sim.players[c.ownerId].zones.graveyard.push(c);
            } else {
              surviving.push(c);
            }
          });
          sim.battlefieldCards = surviving;
          p.zones.graveyard.push(playedCard);
        } else {
          sim.battlefieldCards.push(playedCard);
          if (playedCard.typeLine && /creature/i.test(playedCard.typeLine)) p.stats.creaturesPlayed++;
          if (playedCard.isRamp) p.stats.rampPlayed++;
        }
        played++;

        // Recalculate mana
        availableMana = 0;
        sim.battlefieldCards.forEach(function(c) {
          if (c.ownerId === pi && !c.tapped && c.typeLine && /land/i.test(c.typeLine)) availableMana++;
        });
      }

      // Track board size
      var boardSize = sim.battlefieldCards.filter(function(c) { return c.ownerId === pi; }).length;
      if (boardSize > p.stats.maxBoardSize) p.stats.maxBoardSize = boardSize;

      // --- COMBAT ---
      var myCreatures = sim.battlefieldCards.filter(function(c) {
        return c.ownerId === pi && c.typeLine && /creature/i.test(c.typeLine) && !c.tapped && (turn > 0 || c.turnPlayed !== turn);
      });

      var oppIdx = 1 - pi;
      var opp = sim.players[oppIdx];
      if (opp.eliminated || myCreatures.length === 0) {
        sim.battlefieldCards.forEach(function(c) { if (c.ownerId === pi) c.tapped = false; });
        continue;
      }

      var oppBlockers = sim.battlefieldCards.filter(function(c) {
        return c.ownerId === oppIdx && c.typeLine && /creature/i.test(c.typeLine) && !c.tapped;
      });

      // Decide attackers
      var attackers = [];
      myCreatures.forEach(function(atk) {
        var aPow = headlessGetPower(atk);
        var aTou = headlessGetToughness(atk);
        var hasFlying = headlessHasKw(atk, 'flying');
        var hasTrample = headlessHasKw(atk, 'trample');
        var canDie = oppBlockers.some(function(b) {
          if (hasFlying && !headlessHasKw(b, 'flying') && !headlessHasKw(b, 'reach')) return false;
          return headlessGetPower(b) >= aTou || headlessHasKw(b, 'deathtouch');
        });
        if (!canDie || hasFlying || hasTrample || aPow >= 4) {
          attackers.push(atk); atk.tapped = true;
        }
      });

      // Blocking and damage
      var totalDamage = 0;
      var usedBlockers = {};
      attackers.forEach(function(atk) {
        var aPow = headlessGetPower(atk);
        var aTou = headlessGetToughness(atk);
        var hasFlying = headlessHasKw(atk, 'flying');
        var validBlockers = oppBlockers.filter(function(b) {
          if (usedBlockers[b.id]) return false;
          if (hasFlying && !headlessHasKw(b, 'flying') && !headlessHasKw(b, 'reach')) return false;
          return true;
        });

        if (validBlockers.length > 0 && !headlessHasKw(atk, 'menace')) {
          var blocker = validBlockers.find(function(b) { return headlessGetToughness(b) > aPow; });
          if (!blocker && opp.life <= aPow * 2) blocker = validBlockers[0];
          if (blocker) {
            usedBlockers[blocker.id] = true;
            var bPow = headlessGetPower(blocker);
            if (aPow >= headlessGetToughness(blocker) || headlessHasKw(atk, 'deathtouch')) {
              sim.battlefieldCards = sim.battlefieldCards.filter(function(c) { return c.id !== blocker.id; });
              sim.players[oppIdx].zones.graveyard.push(blocker);
            }
            if (bPow >= aTou || headlessHasKw(blocker, 'deathtouch')) {
              sim.battlefieldCards = sim.battlefieldCards.filter(function(c) { return c.id !== atk.id; });
              sim.players[pi].zones.graveyard.push(atk);
            }
            if (headlessHasKw(atk, 'trample') && aPow > headlessGetToughness(blocker)) {
              totalDamage += aPow - headlessGetToughness(blocker);
            }
            if (headlessHasKw(atk, 'lifelink')) p.life += Math.min(aPow, headlessGetToughness(blocker));
            return;
          }
        }
        totalDamage += aPow;
        if (headlessHasKw(atk, 'lifelink')) p.life += aPow;
      });

      opp.life -= totalDamage;
      p.stats.damageDealt += totalDamage;
      opp.stats.damageReceived += totalDamage;
      if (opp.life <= 0) opp.eliminated = true;

      // Untap
      sim.battlefieldCards.forEach(function(c) { if (c.ownerId === pi) c.tapped = false; });
    }

    // Check game over
    var alive = sim.players.filter(function(p) { return !p.eliminated; });
    if (alive.length <= 1) break;
  }

  // Determine winner
  var winner = -1;
  if (sim.players[0].eliminated && !sim.players[1].eliminated) winner = 1;
  else if (!sim.players[0].eliminated && sim.players[1].eliminated) winner = 0;
  else {
    // Both alive or both dead: compare life
    winner = sim.players[0].life >= sim.players[1].life ? 0 : 1;
  }

  return {
    winner: winner,
    turns: Math.min(turn + 1, sim.maxTurns),
    playerA: { name: nameA, life: sim.players[0].life, eliminated: sim.players[0].eliminated, stats: sim.players[0].stats },
    playerB: { name: nameB, life: sim.players[1].life, eliminated: sim.players[1].eliminated, stats: sim.players[1].stats }
  };
}

// --- Run full deck test suite ---
function runDeckTester() {
  var st = deckTesterState;
  if (st.running) return;

  // Build custom deck
  var customDeck = buildSimDeckFromDeckBuilder();
  if (!customDeck || customDeck.length < 20) {
    var container = document.getElementById('dt-results');
    if (container) container.innerHTML = '<div class="dt-error">Deck needs at least 20 cards to test. Add more cards in the Deck Builder.</div>';
    return;
  }
  st.customDeck = customDeck;

  // Get selected precons
  var preconCheckboxes = document.querySelectorAll('.dt-precon-cb:checked');
  st.selectedPrecons = [];
  preconCheckboxes.forEach(function(cb) {
    st.selectedPrecons.push(parseInt(cb.value));
  });
  if (st.selectedPrecons.length === 0) {
    var container = document.getElementById('dt-results');
    if (container) container.innerHTML = '<div class="dt-error">Select at least one precon deck to test against.</div>';
    return;
  }

  // Get games per matchup
  var gpmInput = document.getElementById('dt-games-per');
  st.gamesPerMatchup = gpmInput ? parseInt(gpmInput.value) || 50 : 50;

  st.running = true;
  st.cancelled = false;
  st.progress = 0;
  st.total = st.selectedPrecons.length * st.gamesPerMatchup;
  st.results = {
    deckName: dbCurrentDeck.name || 'Custom Deck',
    deckSize: customDeck.length,
    matchups: [],
    aggregate: { wins: 0, losses: 0, draws: 0, totalGames: 0 }
  };

  renderDeckTesterProgress();

  // Run matchups async
  var matchupIdx = 0;
  function runNextMatchup() {
    if (st.cancelled || matchupIdx >= st.selectedPrecons.length) {
      st.running = false;
      renderDeckTesterResults();
      return;
    }

    var preconIdx = st.selectedPrecons[matchupIdx];
    var precon = (typeof PRECON_DATA !== 'undefined') ? PRECON_DATA[preconIdx] : null;
    if (!precon) { matchupIdx++; runNextMatchup(); return; }

    var preconDeck = buildSimDeckFromPrecon(preconIdx);
    if (!preconDeck || preconDeck.length < 10) { matchupIdx++; runNextMatchup(); return; }

    st.currentMatchup = precon.name;
    var matchupResult = {
      preconName: precon.name,
      preconSet: precon.set || '',
      preconColors: precon.colors || '',
      preconTheme: precon.theme || '',
      wins: 0, losses: 0, draws: 0,
      avgTurns: 0, avgLifeDiff: 0,
      avgDamageDealt: 0, avgDamageReceived: 0,
      avgSpellsCast: 0, avgCreaturesPlayed: 0,
      avgRemovalUsed: 0, avgRampPlayed: 0,
      avgCardsDrawn: 0, avgBoardSize: 0,
      avgManaSpent: 0,
      winByTurn: {},  // turn# -> count of wins on that turn
      games: []
    };

    var gameIdx = 0;
    function runNextGame() {
      if (st.cancelled || gameIdx >= st.gamesPerMatchup) {
        // Finalize matchup
        var g = matchupResult.wins + matchupResult.losses + matchupResult.draws;
        if (g > 0) {
          matchupResult.avgTurns = Math.round(matchupResult.avgTurns / g * 10) / 10;
          matchupResult.avgLifeDiff = Math.round(matchupResult.avgLifeDiff / g * 10) / 10;
          matchupResult.avgDamageDealt = Math.round(matchupResult.avgDamageDealt / g * 10) / 10;
          matchupResult.avgDamageReceived = Math.round(matchupResult.avgDamageReceived / g * 10) / 10;
          matchupResult.avgSpellsCast = Math.round(matchupResult.avgSpellsCast / g * 10) / 10;
          matchupResult.avgCreaturesPlayed = Math.round(matchupResult.avgCreaturesPlayed / g * 10) / 10;
          matchupResult.avgRemovalUsed = Math.round(matchupResult.avgRemovalUsed / g * 10) / 10;
          matchupResult.avgRampPlayed = Math.round(matchupResult.avgRampPlayed / g * 10) / 10;
          matchupResult.avgCardsDrawn = Math.round(matchupResult.avgCardsDrawn / g * 10) / 10;
          matchupResult.avgBoardSize = Math.round(matchupResult.avgBoardSize / g * 10) / 10;
          matchupResult.avgManaSpent = Math.round(matchupResult.avgManaSpent / g * 10) / 10;
        }
        st.results.matchups.push(matchupResult);
        st.results.aggregate.wins += matchupResult.wins;
        st.results.aggregate.losses += matchupResult.losses;
        st.results.aggregate.draws += matchupResult.draws;
        st.results.aggregate.totalGames += g;

        matchupIdx++;
        renderDeckTesterProgress();
        setTimeout(runNextMatchup, 1);
        return;
      }

      var result = dtSimGame(st.customDeck.slice(), preconDeck.slice(), st.results.deckName, precon.name);

      if (result.winner === 0) {
        matchupResult.wins++;
        var wt = result.turns;
        matchupResult.winByTurn[wt] = (matchupResult.winByTurn[wt] || 0) + 1;
      } else if (result.winner === 1) {
        matchupResult.losses++;
      } else {
        matchupResult.draws++;
      }

      var myStats = result.playerA.stats;
      matchupResult.avgTurns += result.turns;
      matchupResult.avgLifeDiff += (result.playerA.life - result.playerB.life);
      matchupResult.avgDamageDealt += myStats.damageDealt;
      matchupResult.avgDamageReceived += myStats.damageReceived;
      matchupResult.avgSpellsCast += myStats.spellsCast;
      matchupResult.avgCreaturesPlayed += myStats.creaturesPlayed;
      matchupResult.avgRemovalUsed += myStats.removalUsed;
      matchupResult.avgRampPlayed += myStats.rampPlayed;
      matchupResult.avgCardsDrawn += myStats.cardsDrawn;
      matchupResult.avgBoardSize += myStats.maxBoardSize;
      matchupResult.avgManaSpent += myStats.manaSpent;

      st.progress++;
      gameIdx++;

      // Update progress every 10 games
      if (gameIdx % 10 === 0) {
        renderDeckTesterProgress();
        setTimeout(runNextGame, 1);
      } else {
        runNextGame();
      }
    }

    runNextGame();
  }

  runNextMatchup();
}

function cancelDeckTester() {
  deckTesterState.cancelled = true;
}

// --- Render progress bar ---
function renderDeckTesterProgress() {
  var st = deckTesterState;
  var container = document.getElementById('dt-results');
  if (!container) return;

  var pct = st.total > 0 ? Math.round(st.progress / st.total * 100) : 0;
  container.innerHTML =
    '<div class="dt-progress-wrap">' +
      '<div class="dt-progress-label">Simulating: <strong>' + (st.currentMatchup || '...') + '</strong></div>' +
      '<div class="dt-progress-bar"><div class="dt-progress-fill" style="width:' + pct + '%"></div></div>' +
      '<div class="dt-progress-text">' + st.progress + ' / ' + st.total + ' games (' + pct + '%)</div>' +
      '<button class="dt-cancel-btn" onclick="cancelDeckTester()">Cancel</button>' +
    '</div>';
}

// --- Render full results dashboard ---
function renderDeckTesterResults() {
  var st = deckTesterState;
  var container = document.getElementById('dt-results');
  if (!container || !st.results) return;

  var r = st.results;
  var agg = r.aggregate;
  var winRate = agg.totalGames > 0 ? Math.round(agg.wins / agg.totalGames * 100) : 0;

  var html = '';

  // --- Overall Summary ---
  html += '<div class="dt-summary">';
  html += '<div class="dt-summary-title">' + escapeHtml(r.deckName) + ' <span class="dt-deck-size">(' + r.deckSize + ' cards)</span></div>';
  html += '<div class="dt-overall-stats">';
  html += '<div class="dt-big-stat">';
  html += '<div class="dt-big-num ' + (winRate >= 50 ? 'dt-win' : 'dt-loss') + '">' + winRate + '%</div>';
  html += '<div class="dt-big-label">Win Rate</div>';
  html += '</div>';
  html += '<div class="dt-big-stat">';
  html += '<div class="dt-big-num">' + agg.wins + '</div>';
  html += '<div class="dt-big-label">Wins</div>';
  html += '</div>';
  html += '<div class="dt-big-stat">';
  html += '<div class="dt-big-num">' + agg.losses + '</div>';
  html += '<div class="dt-big-label">Losses</div>';
  html += '</div>';
  html += '<div class="dt-big-stat">';
  html += '<div class="dt-big-num">' + agg.totalGames + '</div>';
  html += '<div class="dt-big-label">Games</div>';
  html += '</div>';
  html += '</div>'; // overall-stats
  html += '</div>'; // summary

  // --- Win Rate Bar Chart ---
  html += '<div class="dt-section">';
  html += '<div class="dt-section-title">Win Rate by Matchup</div>';
  html += '<div class="dt-matchup-bars">';
  r.matchups.forEach(function(m) {
    var total = m.wins + m.losses + m.draws;
    var wr = total > 0 ? Math.round(m.wins / total * 100) : 0;
    var barClass = wr >= 60 ? 'dt-bar-great' : wr >= 45 ? 'dt-bar-ok' : 'dt-bar-bad';
    html += '<div class="dt-matchup-row">';
    html += '<div class="dt-matchup-name" title="' + escapeHtml(m.preconSet) + '">';
    html += '<span class="dt-matchup-colors">' + escapeHtml(m.preconColors) + '</span> ' + escapeHtml(m.preconName);
    html += '</div>';
    html += '<div class="dt-bar-wrap">';
    html += '<div class="dt-bar ' + barClass + '" style="width:' + wr + '%"></div>';
    html += '</div>';
    html += '<div class="dt-matchup-pct">' + wr + '% <span class="dt-matchup-record">(' + m.wins + '-' + m.losses + ')</span></div>';
    html += '</div>';
  });
  html += '</div></div>';

  // --- Detailed Stats Table ---
  html += '<div class="dt-section">';
  html += '<div class="dt-section-title">Performance Metrics (Averages per Game)</div>';
  html += '<div class="dt-table-wrap"><table class="dt-table">';
  html += '<thead><tr><th>Matchup</th><th>Turns</th><th>Dmg Dealt</th><th>Dmg Taken</th><th>Spells</th><th>Creatures</th><th>Removal</th><th>Ramp</th><th>Cards Drawn</th><th>Max Board</th></tr></thead>';
  html += '<tbody>';
  r.matchups.forEach(function(m) {
    html += '<tr>';
    html += '<td class="dt-td-name">' + escapeHtml(m.preconName) + '</td>';
    html += '<td>' + m.avgTurns + '</td>';
    html += '<td>' + m.avgDamageDealt + '</td>';
    html += '<td>' + m.avgDamageReceived + '</td>';
    html += '<td>' + m.avgSpellsCast + '</td>';
    html += '<td>' + m.avgCreaturesPlayed + '</td>';
    html += '<td>' + m.avgRemovalUsed + '</td>';
    html += '<td>' + m.avgRampPlayed + '</td>';
    html += '<td>' + m.avgCardsDrawn + '</td>';
    html += '<td>' + m.avgBoardSize + '</td>';
    html += '</tr>';
  });
  html += '</tbody></table></div>';
  html += '</div>';

  // --- Aggregate Stats Summary ---
  var totalMatchups = r.matchups.length;
  var avgDmg = 0, avgRcv = 0, avgSpells = 0, avgCreatures = 0, avgRemoval = 0, avgRamp = 0, avgDraw = 0, avgBoard = 0, avgTurns = 0;
  r.matchups.forEach(function(m) {
    avgDmg += m.avgDamageDealt; avgRcv += m.avgDamageReceived;
    avgSpells += m.avgSpellsCast; avgCreatures += m.avgCreaturesPlayed;
    avgRemoval += m.avgRemovalUsed; avgRamp += m.avgRampPlayed;
    avgDraw += m.avgCardsDrawn; avgBoard += m.avgBoardSize;
    avgTurns += m.avgTurns;
  });
  if (totalMatchups > 0) {
    avgDmg = Math.round(avgDmg / totalMatchups * 10) / 10;
    avgRcv = Math.round(avgRcv / totalMatchups * 10) / 10;
    avgSpells = Math.round(avgSpells / totalMatchups * 10) / 10;
    avgCreatures = Math.round(avgCreatures / totalMatchups * 10) / 10;
    avgRemoval = Math.round(avgRemoval / totalMatchups * 10) / 10;
    avgRamp = Math.round(avgRamp / totalMatchups * 10) / 10;
    avgDraw = Math.round(avgDraw / totalMatchups * 10) / 10;
    avgBoard = Math.round(avgBoard / totalMatchups * 10) / 10;
    avgTurns = Math.round(avgTurns / totalMatchups * 10) / 10;
  }

  html += '<div class="dt-section">';
  html += '<div class="dt-section-title">Deck Profile (Across All Matchups)</div>';
  html += '<div class="dt-profile-grid">';
  var profileCards = [
    { label: 'Avg Game Length', value: avgTurns + ' turns', icon: '&#9203;' },
    { label: 'Damage Output', value: avgDmg + ' / game', icon: '&#9876;' },
    { label: 'Damage Taken', value: avgRcv + ' / game', icon: '&#128737;' },
    { label: 'Spells Cast', value: avgSpells + ' / game', icon: '&#127183;' },
    { label: 'Creatures Played', value: avgCreatures + ' / game', icon: '&#128050;' },
    { label: 'Interaction', value: avgRemoval + ' / game', icon: '&#9760;' },
    { label: 'Ramp Spells', value: avgRamp + ' / game', icon: '&#127793;' },
    { label: 'Cards Drawn', value: avgDraw + ' / game', icon: '&#128195;' },
    { label: 'Peak Board Size', value: avgBoard + ' permanents', icon: '&#127968;' },
  ];
  profileCards.forEach(function(pc) {
    html += '<div class="dt-profile-card">';
    html += '<div class="dt-profile-icon">' + pc.icon + '</div>';
    html += '<div class="dt-profile-value">' + pc.value + '</div>';
    html += '<div class="dt-profile-label">' + pc.label + '</div>';
    html += '</div>';
  });
  html += '</div></div>';

  // --- Action buttons ---
  html += '<div class="dt-actions">';
  html += '<button class="dt-btn dt-btn-primary" onclick="runDeckTester()">Re-run Test</button>';
  html += '<button class="dt-btn" onclick="exportDeckTesterResults()">Export Results</button>';
  html += '</div>';

  container.innerHTML = html;
}

// --- Export results as text ---
function exportDeckTesterResults() {
  var st = deckTesterState;
  if (!st.results) return;
  var r = st.results;
  var agg = r.aggregate;
  var winRate = agg.totalGames > 0 ? Math.round(agg.wins / agg.totalGames * 100) : 0;

  var text = '=== DECK TESTER RESULTS ===\n';
  text += 'Deck: ' + r.deckName + ' (' + r.deckSize + ' cards)\n';
  text += 'Overall: ' + winRate + '% win rate (' + agg.wins + 'W - ' + agg.losses + 'L in ' + agg.totalGames + ' games)\n\n';

  r.matchups.forEach(function(m) {
    var total = m.wins + m.losses + m.draws;
    var wr = total > 0 ? Math.round(m.wins / total * 100) : 0;
    text += 'vs ' + m.preconName + ' (' + m.preconColors + '): ' + wr + '% (' + m.wins + '-' + m.losses + ')\n';
    text += '  Avg turns: ' + m.avgTurns + ', Dmg: ' + m.avgDamageDealt + ', Spells: ' + m.avgSpellsCast + ', Creatures: ' + m.avgCreaturesPlayed + '\n';
  });

  // Copy to clipboard
  if (navigator.clipboard && navigator.clipboard.writeText) {
    navigator.clipboard.writeText(text);
  }
  var btn = document.querySelector('.dt-actions .dt-btn:last-child');
  if (btn) {
    var orig = btn.textContent;
    btn.textContent = 'Copied!';
    setTimeout(function() { btn.textContent = orig; }, 1500);
  }
}

// --- Open / Close ---
function openDeckTester() {
  var modal = document.getElementById('deck-tester-modal');
  if (modal) {
    modal.style.display = 'flex';
    renderDeckTesterSetup();
  }
}

function closeDeckTester() {
  var modal = document.getElementById('deck-tester-modal');
  if (modal) modal.style.display = 'none';
  if (deckTesterState.running) cancelDeckTester();
}

// --- Render setup panel with precon selection ---
function renderDeckTesterSetup() {
  var container = document.getElementById('dt-results');
  if (!container) return;

  var deckName = (dbCurrentDeck && dbCurrentDeck.name) ? dbCurrentDeck.name : 'No deck loaded';
  var cardCount = (dbCurrentDeck && dbCurrentDeck.cards) ? dbCurrentDeck.cards.reduce(function(s, c) { return s + (c.quantity || 1); }, 0) : 0;
  var cmdName = (dbCurrentDeck && dbCurrentDeck.commander) ? (dbCurrentDeck.commander.name || dbCurrentDeck.commander) : 'None';

  var html = '';

  // Deck info
  html += '<div class="dt-deck-info">';
  html += '<div class="dt-deck-info-name">' + escapeHtml(deckName) + '</div>';
  html += '<div class="dt-deck-info-detail">Commander: ' + escapeHtml(String(cmdName)) + ' | ' + cardCount + ' cards</div>';
  html += '</div>';

  // Config
  html += '<div class="dt-config">';
  html += '<label class="dt-config-label">Games per matchup: ';
  html += '<input type="number" id="dt-games-per" class="dt-config-input" value="50" min="10" max="200" step="10">';
  html += '</label>';
  html += '</div>';

  // Precon selection
  html += '<div class="dt-precon-section">';
  html += '<div class="dt-precon-header">';
  html += '<span>Select opponents:</span>';
  html += '<button class="dt-btn-sm" onclick="dtSelectAll(true)">All</button>';
  html += '<button class="dt-btn-sm" onclick="dtSelectAll(false)">None</button>';
  html += '</div>';
  html += '<div class="dt-precon-grid">';

  if (typeof PRECON_DATA !== 'undefined') {
    PRECON_DATA.forEach(function(p, i) {
      html += '<label class="dt-precon-item">';
      html += '<input type="checkbox" class="dt-precon-cb" value="' + i + '" checked>';
      html += '<span class="dt-precon-colors">' + escapeHtml(p.colors || '') + '</span>';
      html += '<span class="dt-precon-pname">' + escapeHtml(p.name) + '</span>';
      html += '<span class="dt-precon-set">' + escapeHtml(p.set || '') + '</span>';
      html += '</label>';
    });
  }

  html += '</div></div>';

  // Run button
  html += '<div class="dt-actions">';
  html += '<button class="dt-btn dt-btn-primary" onclick="runDeckTester()">Run Simulation</button>';
  html += '</div>';

  container.innerHTML = html;
}

function dtSelectAll(checked) {
  document.querySelectorAll('.dt-precon-cb').forEach(function(cb) { cb.checked = checked; });
}

// ============================================================
// ENGINE-TO-UI BRIDGE
// These are stub implementations that ui.js overrides.
// The engine calls these; the UI provides real DOM implementations.
// ============================================================

// Logging — ui.js overrides this
if (typeof addLogEntry !== 'function') {
  window.addLogEntry = function(text, category) {
    if (typeof window._engineLog === 'undefined') window._engineLog = [];
    window._engineLog.push({ text: text, category: category, ts: Date.now() });
    if (window._uiLogCallback) window._uiLogCallback(text, category);
  };
}

// These DOM functions are called by engine logic that mixes concerns.
// ui.js overrides them with real implementations.
function _safeRender(fn, ...args) {
  if (typeof window[fn] === 'function') {
    try { window[fn](...args); } catch(e) {}
  }
}
